INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (1, 'A', '営業とは「問題解決」である', NULL, 15, '新卒', '{"goal": "「営業＝押し売り」という固定観念から脱却し、「営業＝顧客の課題を解決する仕事」という認識を持つ", "quote": {"text": "人は商品を買っているのではない。より良い自分、より良い生活を買っているのだ。", "author": "セス・ゴーディン（マーケター）"}, "purpose": "営業を「売り込み」ではなく「顧客の問題解決」と捉え直すことで、営業に対するネガティブなイメージを払拭し、仕事への誇りとやりがいを持てるようになります。", "summary": ["営業は「売り込み」ではなく「問題解決」", "顧客の課題を見つけ、最適な解決策を提案することが仕事", "良い営業は、顧客から感謝される仕事"], "sections": [{"type": "comparison", "title": "営業に対するよくある誤解", "content": "❌ 誤った営業のイメージ：相手が必要としていないものを売りつける / しつこく付きまとう / 嘘をついてでも売る / 自分の成績のために行動する\n\n✅ 本来の営業：顧客の課題を見つける / 最適な解決策を提案する / 顧客の成功をサポートする / 信頼関係を築く"}, {"type": "text", "title": "営業の本質：問題解決", "content": "営業とは、顧客が抱える「問題」と、それを解決する「商品・サービス」を結びつける仕事です。顧客の問題（入力作業が大変、手数料が高い、在庫が見つからない）を発見し、解決策を提案し、導入をサポートすることで、業務効率化・コスト削減・売上アップという成果を生み出します。"}, {"type": "list", "title": "Symphony営業の社会的意義", "content": ["中古車販売店の経営課題を解決する：業務効率化、コスト削減、売上向上", "地域経済を支える：中小企業が元気になれば、地域全体が活性化する", "顧客（エンドユーザー）にも貢献：効率化された販売店はより良いサービスを提供できる"]}]}'::jsonb, 1, '2026-01-21T18:04:40.768974+00:00', '2026-01-21T18:04:40.768974+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (2, 'A', '第一印象の科学', 'メラビアンの法則', 15, '新卒', '{"goal": "初対面の3〜5秒で「この人の話を聞いてみよう」と思ってもらえる第一印象を作れるようになる", "purpose": "第一印象がいかに重要か、そしてそれがどのように形成されるかを科学的に理解し、意図的に良い第一印象を作る技術を習得します。", "summary": ["第一印象は3〜5秒で決まり、挽回が難しい", "視覚55%、聴覚38%、言語7%（メラビアンの法則）", "笑顔・アイコンタクト・姿勢・声のトーンを意識する"], "sections": [{"type": "list", "title": "第一印象はなぜ重要か", "content": ["第一印象は3〜5秒で決まる：その後の関係性に大きく影響", "初頭効果：最初に得た情報が、その後の判断に影響を与え続ける", "確証バイアス：第一印象を裏付ける情報ばかり集めてしまう心理", "→ 第一印象が悪いと、挽回するのに非常に時間がかかる！"]}, {"type": "text", "title": "メラビアンの法則", "content": "心理学者アルバート・メラビアンの研究によると、矛盾したメッセージを受け取った時、人は以下の割合で判断します。\n\n視覚情報（55%）：見た目・表情・姿勢・身振り・服装\n聴覚情報（38%）：声のトーン・速さ・大きさ・抑揚\n言語情報（7%）：話の内容・言葉そのもの\n\n→「何を言うか」より「どう見えるか」「どう聞こえるか」が圧倒的に重要！"}, {"type": "list", "title": "第一印象を良くする具体的行動", "content": ["① 視覚（55%）：笑顔（口角を上げる）、アイコンタクト（7割程度）、姿勢（背筋を伸ばす）、清潔感", "② 聴覚（38%）：明るい声（1トーン高めを意識）、適度な速さ、はっきり発音（特に名前と社名）", "③ 言語（7%）：挨拶、自己紹介、感謝の言葉"]}]}'::jsonb, 2, '2026-01-21T18:04:41.461519+00:00', '2026-01-21T18:04:41.461519+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (3, 'A', '「断られる」ことへの正しい向き合い方', NULL, 20, '新卒', '{"goal": "断られても落ち込みすぎず、次の行動に繋げられるメンタリティを身につける", "quote": {"text": "私は失敗したことがない。ただ、1万通りのうまくいかない方法を見つけただけだ。", "author": "トーマス・エジソン"}, "purpose": "営業で「断られる」ことは避けられません。断りを個人攻撃と捉えず、学びの機会として活用するレジリエンス（回復力）を身につけます。", "summary": ["営業で断られるのは「普通」。成功率は決して高くない", "断りは「自分への否定」ではなく「タイミングや条件のミスマッチ」", "断りを分析し、次に活かすことで成長できる"], "sections": [{"type": "text", "title": "営業における「断り」の現実", "content": "統計的に、営業活動の成功率は決して高くありません。\n\nテレアポのアポ獲得率：1〜3%（100件中1〜3件）\n商談からの成約率：20〜30%（10件中2〜3件）\n\n→ つまり、断られることの方が圧倒的に多いのが「普通」！"}, {"type": "comparison", "title": "断りの正しい捉え方", "content": "❌ 間違った捉え方：「自分がダメだから断られた」「自分には営業の才能がない」「もう二度と電話したくない」\n\n✅ 正しい捉え方：「今はタイミングではなかった」「提案内容がフィットしなかった」「次に活かせる学びがあった」"}, {"type": "list", "title": "断りを成長に変える3ステップ", "content": ["1. 受け止める：「断られた」という事実をそのまま受け入れる。否定も肯定もしない", "2. 分析する：なぜ断られたのか？タイミング？提案内容？競合？自分のスキル？", "3. 次に活かす：分析結果を踏まえて、次のアクションを決める"]}]}'::jsonb, 3, '2026-01-21T18:04:42.957625+00:00', '2026-01-21T18:04:42.957625+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (4, 'A', '目標設定の技術', 'SMARTゴール', 15, '新卒', '{"goal": "自分の営業目標を、SMARTの5要素を満たす形で言語化できるようになる", "purpose": "漠然とした目標ではなく、達成可能で測定可能な目標を設定するフレームワーク「SMART」を習得します。", "summary": ["目標設定はSMARTの5要素を満たすように", "Specific（具体的）、Measurable（測定可能）、Achievable（達成可能）", "Relevant（関連性）、Time-bound（期限）"], "sections": [{"type": "list", "title": "なぜ目標設定が重要か", "content": ["方向性が明確になる：何に集中すべきかがわかる", "モチベーションが維持できる：ゴールが見えていると頑張れる", "進捗が測定できる：自分がどこにいるかがわかる", "達成感が得られる：クリアすると自信になる"]}, {"type": "list", "title": "SMARTゴールとは", "content": ["S（Specific）具体的：何を達成するのか具体的に明確にする。「頑張る」→「新規アポを取る」", "M（Measurable）測定可能：数値で測定できるようにする。「たくさん」→「10件」", "A（Achievable）達成可能：現実的に達成可能な範囲で設定する。高すぎず、低すぎず", "R（Relevant）関連性：会社・チームの目標と関連している。自分の成長にも繋がる目標", "T（Time-bound）期限：いつまでに達成するか期限を設定する。「いつか」→「今月末までに」"]}, {"type": "comparison", "title": "SMARTゴールの例", "content": "❌ NG（SMARTではない）：「営業を頑張る」「アポをたくさん取る」「成績を上げる」\n\n✅ OK（SMART）：「今月末までに、ワンプラ新規登録を10件獲得する」「今週中に、テレアポを50件かける」「Q2で、Symphony販売管理を3件成約する」"}]}'::jsonb, 4, '2026-01-21T18:04:43.517918+00:00', '2026-01-21T18:04:43.517918+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (5, 'A', '時間管理の基本', '緊急×重要マトリクス', 20, '新卒', '{"goal": "日々のタスクを4象限に分類し、優先順位を意識した行動ができるようになる", "quote": {"text": "重要なことは緊急になることはめったにないし、緊急なことが重要であることもめったにない。", "author": "ドワイト・D・アイゼンハワー"}, "purpose": "限られた時間を有効に使うために、タスクの優先順位を判断するフレームワーク「アイゼンハワー・マトリクス」を習得します。", "summary": ["タスクは「緊急」×「重要」の2軸で4象限に分類する", "第1象限（緊急×重要）は今すぐやる", "第2象限（重要だが緊急ではない）に意識的に時間を確保する"], "sections": [{"type": "text", "title": "アイゼンハワー・マトリクス", "content": "アメリカ第34代大統領ドワイト・D・アイゼンハワーが考案した優先順位付けのフレームワークです。\n\n第1象限（緊急×重要）：今すぐやる - 危機対応、締切直前のタスク、クレーム対応、重要な商談\n第2象限（緊急ではない×重要）：計画してやる - 準備、計画、学習、関係構築、提案書作成、スキルアップ\n第3象限（緊急×重要ではない）：任せる/減らす - 突発の依頼、一部の会議、重要でない電話・メール\n第4象限（緊急ではない×重要ではない）：やらない - 暇つぶし、過度なSNS、意味のない作業"}, {"type": "text", "title": "最も大切なのは「第2象限」", "content": "多くの人は「緊急」なことに追われて、「重要だが緊急ではない」第2象限をおろそかにしがちです。しかし、成果を出し続ける人は第2象限に時間を投資しています。"}, {"type": "list", "title": "営業における第2象限の例", "content": ["提案資料のブラッシュアップ（急ぎではないが、質を高める）", "業界知識の学習（すぐには使わないが、将来役立つ）", "既存顧客との関係維持（急ぎではないが、紹介に繋がる）", "営業スキルの研鑽（今日すぐ必要ではないが、成長に繋がる）"]}]}'::jsonb, 5, '2026-01-21T18:04:44.444626+00:00', '2026-01-21T18:04:44.444626+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (6, 'A', '報連相の極意', '上司が本当に求めていること', 15, '新卒', '{"goal": "適切なタイミング・内容・方法で報連相ができ、上司からの信頼を得られるようになる", "purpose": "「報告・連絡・相談」の基本を理解し、上司や先輩が「本当に求めている」報連相ができるようになります。", "summary": ["報連相は信頼を築く基本。タイミングと内容が重要", "結論ファースト、事実と意見を分ける", "悪い報告ほど早く。隠すと事態は悪化する"], "sections": [{"type": "list", "title": "報連相の基本", "content": ["報告：指示された業務の進捗・結果を伝える。「〇〇の件、完了しました」「△△の進捗は現在□□です」", "連絡：関係者に必要な情報を共有する。「〇〇様から△△と連絡がありました」「明日の会議は□□に変更です」", "相談：判断に迷った時、助言を求める。「〇〇の件で迷っているのですが...」「△△についてご意見いただけますか」"]}, {"type": "list", "title": "上司が本当に求めていること", "content": ["① 結論ファースト：上司は忙しい。最初に結論を言い、詳細は聞かれたら答える。❌「〇〇があって、△△で、それで...」→ ✅「結論から申しますと、□□です。理由は...」", "② 事実と意見を分ける：「事実（Fact）」と「自分の解釈・意見（Opinion）」を明確に分けて伝える", "③ 悪い報告ほど早く：「怒られるかも」と後回しにするほど、状況は悪化する。悪い報告ほど早くする"]}]}'::jsonb, 6, '2026-01-21T18:04:44.982092+00:00', '2026-01-21T18:04:44.982092+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (7, 'A', '失敗から学ぶ技術', '振り返りフレームワーク', 20, '若手', '{"goal": "商談や営業活動の後に、効果的な振り返りを行い、継続的に改善できるようになる", "purpose": "失敗を「なかったこと」にせず、次に活かすための振り返り手法（KPT、YWT）を習得します。", "summary": ["失敗は「なかったこと」にせず、振り返って学びに変える", "KPT（Keep/Problem/Try）で簡単に振り返る習慣をつける", "振り返りを習慣化することで、継続的に成長できる"], "sections": [{"type": "text", "title": "KPT法", "content": "シンプルで使いやすい振り返りフレームワークです。\n\nK（Keep）続けること：良かったこと、うまくいったこと。「アイスブレイクで場が和んだ」「PREP法で説明がわかりやすかった」\nP（Problem）問題点：改善が必要なこと。「価格の質問に即答できなかった」「クロージングのタイミングを逃した」\nT（Try）次に試すこと：改善のためのアクション。「価格表を常に持参する」「テストクロージングを途中で入れる」"}, {"type": "text", "title": "YWT法", "content": "より内省的な振り返りに適したフレームワークです。\n\nY（やったこと）：実際に行動したこと、事実を振り返る。「何をしたか」を客観的に記述\nW（わかったこと）：行動から得た気づき、学び。「何を学んだか」を言語化\nT（次にやること）：学びを活かした次のアクション。具体的で実行可能な形で設定"}, {"type": "list", "title": "振り返りの習慣化", "content": ["毎日5分：今日の営業活動を簡単に振り返る", "商談直後：移動中に頭の中でKPTを回す", "週1回：1週間の活動をまとめて振り返る"]}]}'::jsonb, 7, '2026-01-21T18:04:45.696896+00:00', '2026-01-21T18:04:45.696896+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (8, 'A', 'プロフェッショナルとしての身だしなみ', NULL, 15, '新卒', '{"goal": "業界・顧客に合った身だしなみで、第一印象から信頼を得られるようになる", "purpose": "中古車業界における適切な身だしなみの基準を理解し、プロフェッショナルとして信頼される外見を整えます。", "summary": ["身だしなみは「清潔感」「TPO」「敬意」の3原則", "朝出発前にチェックリストで確認する習慣をつける", "「相手のために整える」という意識を持つ"], "sections": [{"type": "list", "title": "身だしなみの3原則", "content": ["1. 清潔感：汚れ・シワ・匂いがないこと。これが最も重要", "2. TPOに合っている：業界・顧客・場面に適切であること", "3. 相手への敬意：「あなたに会うために整えてきました」というメッセージ"]}, {"type": "list", "title": "チェックリスト", "content": ["髪：清潔に整っているか。寝癖がないか。長すぎないか（男性は耳にかからない程度）", "顔：髭を剃っているか（男性）。化粧が適切か（女性）。目やにがないか", "服装：シワ・汚れがないか。サイズが合っているか。ボタンが取れていないか", "靴：磨いてあるか。かかとがすり減っていないか。歩きやすさも重要", "爪・手：爪は短く切っているか。手が荒れていないか（名刺交換で見られる）", "匂い：口臭・体臭・タバコ臭がないか。香水は控えめに"]}, {"type": "list", "title": "中古車業界での服装", "content": ["スーツが基本：ただし、店舗によってはビジネスカジュアルも可", "動きやすさも考慮：展示場を歩いたり、車を見たりする場面がある", "季節に合わせる：夏場の訪問は上着なしのワイシャツスタイルでも可"]}]}'::jsonb, 8, '2026-01-21T18:04:46.256912+00:00', '2026-01-21T18:04:46.256912+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (9, 'A', 'ストレスマネジメント入門', NULL, 20, '若手', '{"goal": "自分のストレスサインに気づき、適切な対処法を実践できるようになる", "purpose": "営業職特有のストレス要因を理解し、セルフケアの基本を身につけます。ストレスをゼロにするのではなく、上手に付き合う方法を学びます。", "summary": ["ストレスはゼロにできない。上手に付き合うことが大切", "自分のストレスサインを知り、早めに対処する", "4つのR（休息・リラックス・気分転換・転換）を意識する"], "sections": [{"type": "list", "title": "営業職のストレス要因", "content": ["ノルマ・目標のプレッシャー：数字に追われる緊張感", "断られることの連続：精神的なダメージの蓄積", "顧客対応のストレス：クレーム、理不尽な要求", "競争環境：同僚との比較、ランキング", "不規則な生活：移動時間、残業、接待"]}, {"type": "text", "title": "ストレス反応の3段階", "content": "① 警告反応期：イライラ、不安、集中力低下、ミス増加\n② 抵抗期：疲労感、睡眠の問題、食欲変化、頭痛\n③ 疲弊期：燃え尽き、うつ状態、身体的な病気\n\n→ ①の段階で対処することが重要！"}, {"type": "list", "title": "セルフケアの基本", "content": ["4つのR：Rest（休息）、Relaxation（リラックス）、Recreation（気分転換）、Retreat（転換）", "ストレスコーピング：問題焦点型（原因そのものを解決）と情動焦点型（感情の処理に焦点）"]}]}'::jsonb, 9, '2026-01-21T18:04:47.477202+00:00', '2026-01-21T18:04:47.477202+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (10, 'A', '成長マインドセット vs 固定マインドセット', NULL, 15, '新卒', '{"goal": "困難な状況でも「まだできないだけ」と捉え、成長の機会として前向きに取り組めるようになる", "quote": {"text": "あなたの能力は努力次第で伸ばすことができる。大切なのは、今の自分がどうかではなく、これからどう成長するかだ。", "author": "キャロル・ドゥエック"}, "purpose": "スタンフォード大学のキャロル・ドゥエック教授が提唱した「マインドセット理論」を理解し、成長し続ける思考法を身につけます。", "summary": ["固定マインドセット：才能は生まれつき。失敗を恐れる", "成長マインドセット：才能は努力で伸ばせる。失敗は学びの機会", "「できない」を「まだできない」に変えることから始める"], "sections": [{"type": "comparison", "title": "2つのマインドセット", "content": "固定マインドセット（Fixed Mindset）：「才能は生まれつき決まっている」自分の能力を証明しようとする / 失敗を恐れ、挑戦を避ける / 努力は才能がない証拠と考える / 批判を無視する\n\n成長マインドセット（Growth Mindset）：「才能は努力で伸ばせる」自分の能力を高めようとする / 失敗を学びの機会と捉える / 努力は成長の手段と考える / 批判から学ぶ"}, {"type": "text", "title": "営業における思考の違い", "content": "断られた時\n固定：「自分には営業の才能がない」→ 成長：「何を改善すれば次はうまくいくか」\n\n難しい案件\n固定：「無理だ、できない」→ 成長：「やりがいがある。成長できる」\n\n先輩の成功\n固定：「あの人は才能があるから」→ 成長：「何をしているのか学ぼう」"}, {"type": "list", "title": "「まだ」の力", "content": ["成長マインドセットの魔法の言葉は「まだ（yet）」です", "「できない」→「まだできない」", "「無理だ」→「まだ方法が見つかっていない」", "「うまくいかない」→「まだ成長の途中」"]}]}'::jsonb, 10, '2026-01-21T18:04:48.133079+00:00', '2026-01-21T18:04:48.133079+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (11, 'B', 'Symphonyシリーズ全体像', '製品ポートフォリオ理解', 20, '全レベル', '{"goal": "Symphonyシリーズの全製品を説明でき、顧客の課題に応じた製品選択ができるようになる", "quote": {"text": "すべての業務が、つながる。すべてのデータが、活きる。", "author": "Symphonyブランドメッセージ"}, "purpose": "Symphonyシリーズの全体像と各製品の位置づけを理解し、顧客の課題に応じた最適な製品提案ができるようになります。", "summary": ["Symphonyは中古車販売店の統合プラットフォーム", "「分かりやすい」「つながる」「売上が伸びる」の3つの価値", "顧客の課題に応じて製品を組み合わせて提案"], "sections": [{"type": "text", "title": "Symphonyシリーズとは", "content": "Symphonyシリーズは、中古車販売店の業務を一元管理し、すべてのデータをつなげる統合プラットフォームです。「分かりやすい」「つながる」「売上が伸びる」の3つの価値を提供し、中古車販売の「困った」を解決します。販売管理を中心として、店舗の成長に合わせて必要な機能を追加できる柔軟な設計が特徴です。"}, {"type": "list", "title": "製品ラインナップ", "content": ["Symphony販売管理：車両登録から広告掲載、販売、顧客管理まで一元管理する基幹システム", "Symphony整備請求：整備・車検の見積から請求、顧客フォローまで管理するシステム", "シンフォニーワンプラ（AS-NET）：7万台の共有在庫から仕入れ、業販で売却できるプラットフォーム", "データ分析・可視化システム：数十万件のリアルタイム車両データをAI分析（coming soon）"]}, {"type": "list", "title": "Symphonyの3つの価値", "content": ["分かりやすい：複雑な業務をワンストップで完結、ペーパーレス化で手間を削減、誰でもすぐに使いこなせる", "つながる：全国の業者とつながり仕入れルート拡大、10以上の広告メディアに一括掲載、一度の入力で販路拡大", "売上が伸びる：100万件超のデータによる適正価格判断、在庫回転率アップ、整備請求で車販以外の収益源確保"]}, {"type": "table", "title": "顧客課題と製品マッピング", "content": "顧客の課題 | 推奨製品\n入力作業が二度手間 | Symphony販売管理\n在庫が見つからない | シンフォニーワンプラ\n売れ残りが困る | シンフォニーワンプラ（業販出品）\n整備の請求管理が大変 | Symphony整備請求\nデータ分析ができない | データ分析システム（将来）"}]}'::jsonb, 11, '2026-01-21T18:04:48.741897+00:00', '2026-01-21T18:04:48.741897+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (12, 'B', 'Symphony販売管理', '基本機能と競合優位性', 25, '全レベル', '{"goal": "Symphony販売管理の主要機能を説明でき、競合優位性を顧客に伝えられるようになる", "quote": {"text": "これさえあれば中古車販売ができます。", "author": "導入店舗オーナー様の声"}, "purpose": "Symphony販売管理の機能と価値を深く理解し、競合との差別化ポイントを明確に説明できるようになります。", "summary": ["一度の入力で全メディア掲載、業務を一元管理", "車両・顧客・契約・納車をワンストップで管理", "ワンプラ・整備請求との連携で価値が最大化"], "sections": [{"type": "text", "title": "Symphony販売管理の概要", "content": "Symphony販売管理は、車両登録から広告掲載、販売、顧客管理まで、中古車販売のすべての業務を一元管理するクラウド型システムです。「一度の入力で、すべて完結」をコンセプトに、本質的な営業活動に集中できる環境を提供します。"}, {"type": "list", "title": "主要機能", "content": ["車両管理：車両情報の登録、写真管理、在庫ステータス管理", "広告連携：カーセンサー、グーネット、Yahoo!オークションなど10以上のメディアに一括掲載", "顧客管理（CRM）：顧客情報、商談履歴、フォロー管理", "契約書作成：注文書、契約書のペーパーレス作成", "納車管理：納車スケジュール、ToDo管理", "粗利計算：仕入れから販売までの粗利を自動計算"]}, {"type": "comparison", "title": "競合優位性", "content": "【他社システムの課題】\n・複数システムへの二重入力が必要\n・広告メディアごとに別々の管理画面\n・データが分散して分析できない\n\n【Symphony販売管理の強み】\n・一度の入力で全メディアに掲載\n・すべてのデータが一元管理\n・ワンプラ、整備請求との連携でさらに効率化"}, {"type": "list", "title": "導入効果（実績ベース）", "content": ["入力作業時間：約50%削減（二重入力解消）", "広告掲載の手間：約70%削減（一括掲載）", "粗利管理の精度：大幅向上（自動計算）", "顧客フォロー漏れ：激減（CRM機能）"]}]}'::jsonb, 12, '2026-01-21T18:04:49.381807+00:00', '2026-01-21T18:04:49.381807+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (13, 'B', 'Symphony整備請求', '機能と導入メリット', 25, '全レベル', '{"goal": "整備請求システムの価値を説明でき、販売管理とのセット提案ができるようになる", "quote": {"text": "車を売って終わりじゃない。整備で長くお付き合いする。", "author": "導入店舗オーナー様の声"}, "purpose": "Symphony整備請求の機能と導入メリットを理解し、販売店の第二の収益源である整備ビジネスを支援する提案ができるようになります。", "summary": ["整備・車検の見積から請求、顧客フォローまで一元管理", "販売後も途切れない顧客関係でリピート率向上", "販売管理との連携でLTV最大化を実現"], "sections": [{"type": "text", "title": "Symphony整備請求の概要", "content": "Symphony整備請求は、整備・車検の見積から請求、顧客フォローまでを管理するシステムです。「販売後も、つながり続ける」をコンセプトに、販売後も途切れない顧客関係を構築し、リピート率向上と整備収益の最大化を実現します。"}, {"type": "list", "title": "主要機能", "content": ["見積作成：整備・車検見積を簡単作成、部品マスタ連携", "請求書発行：見積から請求書への変換、消費税計算", "顧客フォロー：車検時期、点検時期の自動アラート", "整備履歴管理：車両ごとの整備履歴を蓄積", "売上分析：整備部門の売上・粗利を可視化"]}, {"type": "text", "title": "整備ビジネスの重要性", "content": "中古車販売店の収益構造を見ると、車両販売だけでなく整備・車検が重要な収益源です。車両販売は価格競争が激しく利益率が低下傾向にある中、整備は安定した継続収益を生み出します。特に車検は2年に1回必ず発生するため、顧客との長期関係構築の起点になります。"}, {"type": "list", "title": "販売管理との連携メリット", "content": ["顧客情報の共有：販売時の顧客情報が整備でも活用できる", "車両情報の引継ぎ：販売した車両の整備履歴を一元管理", "クロスセル機会の創出：整備来店時に新車両の提案", "LTV最大化：販売→整備→再販売のサイクル構築"]}]}'::jsonb, 13, '2026-01-21T18:04:49.986825+00:00', '2026-01-21T18:04:49.986825+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (14, 'B', 'シンフォニーワンプラ', 'サービス詳細と料金体系', 20, '全レベル', '{"goal": "ワンプラのサービス内容、料金、メリットを説明でき、顧客の課題に応じた提案ができる", "quote": {"text": "仕入れルートが増えて、在庫処分もできる。一石二鳥です。", "author": "導入店舗オーナー様の声"}, "purpose": "シンフォニーワンプラのサービス内容と料金体系を理解し、仕入れ・在庫処分の課題を持つ顧客に適切な提案ができるようになります。", "summary": ["7万台の共有在庫から仕入れ、業販で売却できるプラットフォーム", "業界最安水準の手数料、24時間利用可能", "Symphony連携で在庫データを自動出品"], "sections": [{"type": "text", "title": "シンフォニーワンプラとは", "content": "シンフォニーワンプラは、全国の中古車販売店をつなぐ在庫共有・業販プラットフォームです。「在庫を流動化、コストを最小化」をコンセプトに、7万台の共有在庫から仕入れ、売れない在庫は業販で売却できます。業界最安水準の手数料で、在庫リスクとコストを大幅削減します。"}, {"type": "list", "title": "2つの使い方", "content": ["仕入れ：7万台の共有在庫から24時間いつでも検索・仕入れ。オークションを補完する第三の仕入れルート", "業販出品：売れない在庫、長期在庫を全国の業者に販売。オークション出品より手数料が安い"]}, {"type": "list", "title": "ワンプラの強み", "content": ["業界最安水準の手数料：成約時のみ手数料発生、固定費なし", "場所を選ばない：PCやスマホでどこでも仕入れ・出品", "時間を選ばない：24時間いつでも検索・交渉可能", "Symphony連携：在庫データを自動で出品、手間が激減", "全国ネットワーク：地域を超えた仕入れ・販売が可能"]}, {"type": "comparison", "title": "こんな課題を解決", "content": "【仕入れの課題】\n・オークションだけでは欲しい車が見つからない\n・仕入れ単価が高騰している\n・オークション会費が負担\n\n【在庫の課題】\n・長期在庫を処分したい\n・オークション出品は手数料が高い\n・在庫回転率を上げたい"}]}'::jsonb, 14, '2026-01-21T18:04:51.167815+00:00', '2026-01-21T18:04:51.167815+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (15, 'B', 'ワンプラの競合比較', '他社サービスとの違い', 20, '全レベル', '{"goal": "主要競合との違いを説明でき、ワンプラを選ぶべき理由を顧客に伝えられる", "purpose": "ワンプラと競合サービスの違いを明確に理解し、競合優位性を説得力を持って説明できるようになります。", "summary": ["業界最安水準の手数料、固定費ゼロが強み", "Symphony連携による業務効率化が差別化ポイント", "具体的な数字で競合優位性を伝える"], "sections": [{"type": "text", "title": "業販プラットフォームの市場", "content": "中古車の業販（業者間取引）市場には複数のプラットフォームが存在します。オークションを補完する仕入れ・販売ルートとして、各社が独自のサービスを展開しています。ワンプラは「低コスト」「簡単」「Symphony連携」を武器に差別化しています。"}, {"type": "table", "title": "競合サービスとの比較", "content": "項目 | ワンプラ | A社 | B社\n手数料 | 業界最安水準 | 高め | 中程度\n掲載台数 | 7万台 | 5万台 | 3万台\n固定費 | なし | 月額あり | 月額あり\n24時間利用 | ○ | △ | ○\nシステム連携 | Symphony連携 | なし | 限定的"}, {"type": "list", "title": "ワンプラを選ぶべき理由", "content": ["コスト優位性：成約時のみ手数料、固定費ゼロで始められる", "Symphony連携：販売管理の在庫データを自動で出品、二重入力不要", "使いやすさ：シンプルなUI、スマホからも操作可能", "サポート体制：専任担当による導入・活用支援", "ファブリカグループの信頼性：東証スタンダード上場グループ"]}, {"type": "list", "title": "競合優位性の伝え方", "content": ["「他社より手数料が安い」→ 具体的な金額差を試算して見せる", "「Symphony連携で手間が減る」→ 二重入力の時間を計算して見せる", "「まず試してみませんか」→ 低コストなので気軽に始められる"]}]}'::jsonb, 15, '2026-01-21T18:04:51.842016+00:00', '2026-01-21T18:04:51.842016+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (16, 'B', '製品間連携の価値', 'クロスセルの論理構築', 25, '全レベル', '{"goal": "製品連携の価値を説明でき、顧客の成長に合わせたクロスセル提案ができる", "quote": {"text": "1+1を3にする。それがSymphony連携の価値。", "author": "Symphony営業格言"}, "purpose": "Symphony各製品の連携によるシナジー効果を理解し、複数製品のセット提案（クロスセル）ができるようになります。", "summary": ["製品連携でデータが自動連携、二重入力不要", "販売管理を中心に、ワンプラ・整備請求と連携", "顧客の成長・課題に合わせてクロスセル提案"], "sections": [{"type": "text", "title": "製品連携の全体像", "content": "Symphonyシリーズは、販売管理を中心として各製品が連携することで、単体導入以上の価値を発揮します。データが自動連携され、二重入力が不要になるだけでなく、業務全体の最適化と意思決定の高度化が実現します。"}, {"type": "list", "title": "販売管理 × ワンプラ連携", "content": ["在庫データの自動出品：販売管理の在庫情報がワンプラに自動連携", "成約情報の自動反映：ワンプラで売れた車両のステータスが自動更新", "仕入れ情報の取り込み：ワンプラで仕入れた車両を販売管理に自動登録", "効果：入力作業50%削減、在庫回転率20%向上（実績値）"]}, {"type": "list", "title": "販売管理 × 整備請求連携", "content": ["顧客情報の共有：販売時の顧客情報が整備でも活用可能", "車両情報の引継ぎ：販売車両の情報が整備システムに自動連携", "整備履歴の蓄積：販売・整備の履歴を一元管理", "効果：顧客フォロー漏れ80%削減、リピート率15%向上（実績値）"]}, {"type": "list", "title": "クロスセルのタイミング", "content": ["導入時：最初から複数製品をセット提案（割引メリット訴求）", "定着後：1つの製品で成功したら「次の課題」を提案", "課題発生時：「仕入れに困っている」→ワンプラ、「整備管理が大変」→整備請求", "成長時：店舗拡大、スタッフ増加のタイミングで追加提案"]}]}'::jsonb, 16, '2026-01-21T18:04:52.40062+00:00', '2026-01-21T18:04:52.40062+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (17, 'B', '導入事例研究①', '小規模店舗（10台以下）', 20, '全レベル', '{"goal": "小規模店舗の課題と導入効果を説明でき、具体的な事例として提案に活用できる", "purpose": "小規模店舗へのSymphony導入事例を学び、同規模の見込み客への提案に活用できるようになります。", "summary": ["小規模店舗は「時間がない」が最大の課題", "事務作業削減 → 接客強化 → 売上アップのストーリー", "まずは販売管理から小さく始める提案が有効"], "sections": [{"type": "list", "title": "小規模店舗の特徴と課題", "content": ["在庫台数：10台以下", "スタッフ：オーナー1人〜数名", "特徴：少人数で全業務をこなす、ITに不慣れなことも多い", "主な課題：時間がない、手書き・エクセル管理の限界、広告掲載が面倒"]}, {"type": "text", "title": "導入事例：A店（在庫8台・オーナー1人）", "content": "【導入前の課題】オーナー1人で仕入れから販売まで全てを担当。手書きの在庫管理、各広告サイトへの個別入力で1日3時間以上を事務作業に費やしていた。「本当は接客に時間を使いたいのに...」\n\n【導入製品】Symphony販売管理\n\n【導入後の効果】広告掲載作業が1/3に短縮。手書き管理から解放され、粗利計算も自動化。空いた時間で来店接客を強化し、成約率が15%向上。"}, {"type": "list", "title": "小規模店舗への提案ポイント", "content": ["「時間がない」に響く：事務作業削減 → 接客時間増加 → 売上アップ", "「難しそう」への対応：シンプルなUI、サポート体制を強調", "「コストが心配」への対応：投資対効果を具体的に計算", "まずは販売管理から：小さく始めて効果を実感してもらう"]}, {"type": "text", "title": "ROI試算例", "content": "【A店のROI試算】\n・削減時間：月60時間（1日3時間 × 20日）\n・時給換算：60時間 × 1,500円 = 90,000円/月\n・年間効果：90,000円 × 12ヶ月 = 1,080,000円\n・Symphony費用：月額〇〇円\n・投資回収：約〇ヶ月で回収"}]}'::jsonb, 17, '2026-01-21T18:04:53.350079+00:00', '2026-01-21T18:04:53.350079+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (18, 'B', '導入事例研究②', '中規模店舗（30〜50台）', 20, '全レベル', '{"goal": "中規模店舗の課題と導入効果を説明でき、具体的な事例として提案に活用できる", "purpose": "中規模店舗へのSymphony導入事例を学び、同規模の見込み客への提案に活用できるようになります。", "summary": ["中規模店舗は「情報共有」「在庫回転」が課題", "販売管理 + ワンプラのセット提案が有効", "成長に合わせた段階的なクロスセル"], "sections": [{"type": "list", "title": "中規模店舗の特徴と課題", "content": ["在庫台数：30〜50台", "スタッフ：5〜10名程度", "特徴：営業・整備・事務の分業が始まる、情報共有が課題に", "主な課題：スタッフ間の情報共有、在庫回転率、仕入れルートの拡大"]}, {"type": "text", "title": "導入事例：B店（在庫40台・スタッフ7名）", "content": "【導入前の課題】営業3名、整備2名、事務2名体制。営業と整備の情報共有ができず、顧客フォロー漏れが頻発。仕入れはオークションのみで、欲しい車が見つからないことも。\n\n【導入製品】Symphony販売管理 + ワンプラ\n\n【導入後の効果】顧客情報の一元管理で、フォロー漏れが激減。ワンプラで仕入れルートが拡大し、在庫回転率が25%向上。年間売上が1.3倍に成長。"}, {"type": "list", "title": "中規模店舗への提案ポイント", "content": ["「情報共有」に響く：スタッフ全員が同じ情報を見られる", "「在庫回転」に響く：ワンプラで仕入れ・業販の両方を提案", "「成長したい」に響く：データを活用した経営判断", "販売管理 + ワンプラのセット提案が有効"]}, {"type": "list", "title": "クロスセルの流れ", "content": ["Step 1：販売管理で業務効率化・情報共有を実現", "Step 2：ワンプラで仕入れルート拡大・在庫処分", "Step 3：整備請求で整備部門の収益最大化", "成長に合わせて段階的に提案"]}]}'::jsonb, 18, '2026-01-21T18:04:53.988004+00:00', '2026-01-21T18:04:53.988004+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (19, 'B', '導入事例研究③', '大規模・多店舗展開', 20, '全レベル', '{"goal": "大規模企業の課題と導入効果を説明でき、具体的な事例として提案に活用できる", "purpose": "大規模・多店舗展開企業へのSymphony導入事例を学び、同規模の見込み客への提案に活用できるようになります。", "summary": ["大規模企業は「一元管理」「経営判断」「店舗間連携」が課題", "全製品フル導入で最大効果を提案", "パイロット → 展開 → 統合の段階的アプローチ"], "sections": [{"type": "list", "title": "大規模・多店舗の特徴と課題", "content": ["在庫台数：100台以上、または複数店舗", "スタッフ：20名以上", "特徴：店舗間の在庫共有、本部での一元管理が必要", "主な課題：店舗間連携、データの一元管理、経営判断のスピード"]}, {"type": "text", "title": "導入事例：C社（3店舗・在庫150台・スタッフ25名）", "content": "【導入前の課題】3店舗それぞれで在庫・顧客管理。店舗間の在庫移動に手間がかかり、機会損失が発生。本部での売上・在庫の把握にタイムラグ。\n\n【導入製品】Symphony販売管理 + 整備請求 + ワンプラ（全店舗）\n\n【導入後の効果】全店舗の在庫・顧客をリアルタイムで一元管理。店舗間在庫共有で機会損失が大幅減。本部でのデータ分析により、仕入れ・価格戦略の精度が向上。グループ全体で年商20%増。"}, {"type": "list", "title": "大規模企業への提案ポイント", "content": ["「一元管理」に響く：全店舗のデータをリアルタイムで把握", "「経営判断」に響く：データに基づく意思決定の高速化", "「店舗間連携」に響く：在庫共有、顧客引継ぎがスムーズ", "全製品のフル導入で最大効果を提案"]}, {"type": "list", "title": "導入プロジェクトの進め方", "content": ["フェーズ1：1店舗でパイロット導入、効果検証", "フェーズ2：成功事例を基に他店舗へ展開", "フェーズ3：全店舗統合、本部管理体制構築", "段階的な展開で確実に定着させる"]}]}'::jsonb, 19, '2026-01-21T18:04:54.493516+00:00', '2026-01-21T18:04:54.493516+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (20, 'B', 'ROI計算の実践', '投資対効果の可視化', 25, '全レベル', '{"goal": "顧客の状況に応じたROI試算ができ、投資対効果を明確に説明できる", "quote": {"text": "数字は嘘をつかない。ROIで語れば、顧客は動く。", "author": "Symphony営業格言"}, "purpose": "Symphony導入のROI（投資対効果）を顧客ごとに計算し、説得力のある数字で提案できるようになります。", "summary": ["具体的な数字でROIを示すことで意思決定を後押し", "時間削減、売上増加、コスト削減の3軸で効果を算出", "顧客ごとにカスタマイズしたROI試算が武器になる"], "sections": [{"type": "text", "title": "ROI計算の重要性", "content": "「いくら儲かるのか」「いつ回収できるのか」は顧客の最大の関心事です。感覚的なメリットではなく、具体的な数字でROIを示すことで、導入の意思決定を後押しできます。Symphony営業では、顧客ごとにカスタマイズしたROI試算が強力な武器になります。"}, {"type": "text", "title": "ROI計算の基本式", "content": "【基本式】\nROI = (導入効果 - 導入コスト) ÷ 導入コスト × 100%\n\n【回収期間】\n回収期間（月） = 導入コスト ÷ 月間効果\n\n例：初期費用30万円、月額2万円、月間効果10万円の場合\n・1年目コスト：30万円 + 24万円 = 54万円\n・1年目効果：10万円 × 12ヶ月 = 120万円\n・1年目ROI：(120万円 - 54万円) ÷ 54万円 × 100% = 122%"}, {"type": "list", "title": "効果の算出項目", "content": ["時間削減効果：削減時間（時間） × 時給 = 金額換算", "売上増加効果：在庫回転率向上、成約率向上による売上増", "コスト削減効果：手数料削減、人件費削減など", "機会損失の回避：フォロー漏れ防止、在庫切れ防止など"]}, {"type": "list", "title": "ROI試算シートの使い方", "content": ["Step 1：顧客の現状をヒアリング（在庫台数、スタッフ数、課題）", "Step 2：削減できる時間・コストを見積もり", "Step 3：増加が見込める売上を試算", "Step 4：Symphony費用との比較でROIを算出", "Step 5：顧客と一緒に数字を確認、納得を得る"]}]}'::jsonb, 20, '2026-01-21T18:04:55.192785+00:00', '2026-01-21T18:04:55.192785+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (21, 'B', 'よくある質問（FAQ）', '完全対応・ベストアンサー集', 20, '全レベル', '{"goal": "主要なFAQに対して、自信を持って回答できるようになる", "purpose": "顧客からよく聞かれる質問と、説得力のある回答パターンを習得し、商談での対応力を高めます。", "summary": ["価格、機能、導入・サポートの3カテゴリが頻出", "まず受け止め、正直に、具体的に回答する", "分からないことは持ち帰り、必ずフォローする"], "sections": [{"type": "list", "title": "価格・コストに関するFAQ", "content": ["Q：「高くないですか？」→ A：「初期費用〇〇円、月額〇〇円です。ROI試算では〇ヶ月で回収できます。費用対効果で見ると、非常にお得です」", "Q：「他社と比べてどうですか？」→ A：「単純な価格比較では〇〇ですが、Symphony連携による効率化を含めると、トータルコストでは優位です」", "Q：「解約金はありますか？」→ A：「契約条件により異なりますが、〇〇となっています。詳しくはご説明します」"]}, {"type": "list", "title": "機能・使いやすさに関するFAQ", "content": ["Q：「使いこなせるか不安」→ A：「直感的なUIで、ITが苦手な方も安心です。導入時の研修と、専任サポートがつきます」", "Q：「今使っているシステムからの移行は？」→ A：「データ移行のサポートがあります。並行稼働期間を設けて、スムーズに移行できます」", "Q：「スマホでも使えますか？」→ A：「はい、スマホ・タブレットでも操作可能です。外出先でも在庫確認や商談管理ができます」"]}, {"type": "list", "title": "導入・サポートに関するFAQ", "content": ["Q：「導入にどれくらい時間がかかる？」→ A：「最短〇週間で稼働可能です。規模や要件により異なりますので、詳しくご相談ください」", "Q：「トラブル時の対応は？」→ A：「電話・メールでのサポート窓口があり、〇〇時間以内に対応します」", "Q：「導入実績は？」→ A：「全国〇〇店舗以上にご導入いただいています。同業他社様の事例もご紹介できます」"]}, {"type": "list", "title": "回答の基本姿勢", "content": ["まず受け止める：「良いご質問ですね」「ご懸念はもっともです」", "正直に答える：分からないことは「確認してご連絡します」", "具体的に答える：数字、事例、エビデンスを添える", "次のアクションにつなげる：「詳しくは〇〇でご説明できます」"]}]}'::jsonb, 21, '2026-01-21T18:04:55.838974+00:00', '2026-01-21T18:04:55.838974+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (22, 'B', 'デモンストレーションの技術', '効果的なデモの構成と話法', 30, '全レベル', '{"goal": "デモの構成、話法、注意点を理解し、説得力のあるデモができるようになる", "quote": {"text": "百聞は一見にしかず、百見は一験にしかず。体験させれば、顧客は動く。", "author": "Symphony営業格言"}, "purpose": "Symphonyのデモンストレーションを効果的に行う技術を習得し、顧客に「使ってみたい」と思わせる体験を提供できるようになります。", "summary": ["デモの目的は「機能を見せる」ではなく「価値を体験してもらう」", "顧客の課題に絞り、ビフォーアフターを見せる", "ゆっくり、顧客の言葉で、体験を交えて説明する"], "sections": [{"type": "text", "title": "デモの目的", "content": "デモンストレーションの目的は「機能を見せること」ではなく「顧客に価値を体験してもらうこと」です。顧客の課題を解決する場面を具体的にイメージしてもらい、「これを使えば楽になりそう」「これなら自分でもできそう」と感じてもらうことがゴールです。"}, {"type": "list", "title": "デモの基本構成", "content": ["1. オープニング（2分）：デモの目的と流れを説明", "2. 課題の確認（3分）：「〇〇でお困りとのことでしたね」と課題を再確認", "3. 解決シーン（10分）：課題を解決する機能をデモ（メイン）", "4. 追加価値（5分）：課題解決以外の便利機能を紹介", "5. クロージング（5分）：質疑応答、次のステップ"]}, {"type": "list", "title": "デモの話法", "content": ["「〇〇でお困りでしたよね。この画面で解決できます」：課題と機能を紐づける", "「今この作業に何分かかっていますか？→ これだと〇秒です」：ビフォーアフターを見せる", "「実際に触ってみていただけますか？」：体験してもらう", "「同じ課題を持つ〇〇店さんでは、こう活用されています」：事例を添える"]}, {"type": "comparison", "title": "デモの注意点", "content": "【NG】\n・機能を網羅的に説明する（顧客は覚えられない）\n・操作を早く見せる（ついてこれない）\n・専門用語を多用する（理解できない）\n\n【OK】\n・顧客の課題に絞って説明する\n・ゆっくり、一つずつ見せる\n・顧客の言葉で説明する"}, {"type": "list", "title": "トラブル対応", "content": ["画面が動かない：「少々お待ちください」と落ち着いて対処。復旧しない場合は別の方法で説明", "想定外の質問：「良いご質問ですね。確認して後ほどご回答します」", "時間が押した：「本日のメインポイントは以上です。続きは次回に」と区切る"]}]}'::jsonb, 22, '2026-01-21T18:04:56.459911+00:00', '2026-01-21T18:04:56.459911+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (23, 'C', '中古車流通の全体像', NULL, 25, '新卒', '{"goal": "中古車の仕入れから販売までの流れを説明でき、「業界をわかってる営業」として顧客と会話できるようになる", "quote": {"text": "顧客を理解するには、まず顧客のビジネスを理解せよ。", "author": "ピーター・ドラッカー"}, "purpose": "中古車がどのように流通しているかの全体像を理解し、販売店の仕事の流れを把握します。営業として顧客のビジネスを理解する第一歩です。", "summary": ["仕入れはオークション70%、下取り20%、業販10%", "「商品化」に手間とコストがかかる（5〜15万円/台）", "在庫期間が長いほど価値が下がる（相場変動リスク）"], "sections": [{"type": "list", "title": "中古車流通の3つの仕入れルート", "content": ["オークション（70%）：全国約130か所、年間約700万台が流通", "下取り・買取（20%）：顧客から直接仕入れ、手数料節約", "業販（10%）：業者間取引、オンラインで全国から仕入れ可能"]}, {"type": "text", "title": "「商品化」という重要プロセス", "content": "仕入れた車をそのまま売ることはできません。点検、整備、清掃、写真撮影、ネット掲載...この一連の作業を「商品化」と呼びます。平均コストは5〜15万円/台。販売店の手間と技術が詰まった工程です。"}, {"type": "list", "title": "販売ルートの多様化", "content": ["小売（一般顧客への販売）：メイン収益源", "業販（業者間取引）：長期在庫の処分手段として活用", "輸出：国内で売れない車も海外では売れることも"]}]}'::jsonb, 23, '2026-01-21T18:04:56.990042+00:00', '2026-01-21T18:04:56.990042+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (24, 'C', 'オートオークションの仕組み', NULL, 20, '新卒', '{"goal": "オークションの評価点、セリの流れ、販売店の苦労を理解し、顧客との会話で活用できるようになる", "purpose": "中古車流通の心臓部であるオートオークションの仕組みを理解し、販売店がどのように仕入れを行っているかを学びます。", "summary": ["オークションは中古車流通の心臓部（年間約700万台）", "評価点4以上が小売向けの目安", "時間・体力の負担が大きいのが課題"], "sections": [{"type": "list", "title": "主要オークション会社", "content": ["USS（ユー・エス・エス）：業界最大手、全国19会場、年間約250万台", "JU：業界団体系、全国約50会場、中小販売店に人気", "HAA：関西圏に強み、神戸会場が有名", "TAA：トヨタ系、品質に定評"]}, {"type": "text", "title": "評価点の見方", "content": "S：新車同様（走行1万km未満）\n6：非常に良い（走行3万km未満）\n5：良い（走行5万km未満、軽微な傷）\n4.5：やや良い（走行10万km未満）\n4：普通（一般的な中古車）\n3.5：やや劣る（傷・へこみあり）\nR：修復歴あり（事故車）\n\n小売向けは評価点4以上が目安です。"}, {"type": "list", "title": "オークションの課題", "content": ["時間がかかる：往復の移動時間、セリに半日", "体力勝負：早朝から現車確認で歩き回る", "空振りリスク：欲しい車がない日もある"]}]}'::jsonb, 24, '2026-01-21T18:04:57.556771+00:00', '2026-01-21T18:04:57.556771+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (25, 'C', '業販プラットフォームの市場動向', NULL, 20, '若手', '{"goal": "業販の仕組みとトレンドを理解し、顧客に対してワンプラの価値を提案できるようになる", "purpose": "オークションを補完する「第三の仕入れルート」として注目される業販プラットフォームの市場動向を理解し、ワンプラの価値を説明できるようになります。", "summary": ["業販＝業者間販売（販売店同士の取引）", "オークションを補完する第三の仕入れルート", "Symphony連携でワンプラの価値が最大化"], "sections": [{"type": "text", "title": "業販とは", "content": "業販＝業者間販売の略。中古車販売店同士が車を売買することです。オークションを通さずに直接取引するため、いつでもどこでも取引可能で、価格交渉もできます。"}, {"type": "list", "title": "市場トレンド", "content": ["オンライン化の加速：コロナ禍を経て一般化", "地方販売店の利用増加：オークション会場が遠い店舗の命綱", "専門店の増加：輸入車専門、スポーツカー専門など", "効率化ニーズ：人手不足の中、時間を買う感覚で活用"]}, {"type": "list", "title": "ワンプラとSymphony連携の価値", "content": ["場所を選ばない：PCやスマホでどこでも仕入れ", "時間を選ばない：24時間いつでも検索・交渉", "Symphony連携：在庫データを自動で出品、手間が激減"]}]}'::jsonb, 25, '2026-01-21T18:04:58.292946+00:00', '2026-01-21T18:04:58.292946+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (26, 'C', '販売店の経営課題', '類型別', 25, '若手', '{"goal": "小規模・中規模・大規模それぞれの課題を理解し、規模に応じた提案ポイントを把握する", "quote": {"text": "顧客が買うものは、企業が売っていると思っているものとは違うことが多い。", "author": "ピーター・ドラッカー"}, "purpose": "販売店の規模によって経営課題が異なることを理解し、顧客に合わせた提案ができるようになります。", "summary": ["小規模：時間創出が最優先", "中規模：在庫管理の効率化が最優先", "大規模：統合管理・データ活用が最優先"], "sections": [{"type": "list", "title": "小規模店（在庫10台以下）の課題", "content": ["家族経営、従業員1〜3名", "社長が仕入れも整備も営業も全部やる", "最優先課題：時間がない", "提案ポイント：「これで時間が空きますよ」"]}, {"type": "list", "title": "中規模店（在庫30〜50台）の課題", "content": ["従業員5〜15名、部門分業が始まっている", "在庫管理の複雑化、部門間連携が課題", "最優先課題：在庫管理", "提案ポイント：「在庫の見える化ができますよ」"]}, {"type": "list", "title": "大規模店（在庫100台以上）の課題", "content": ["多店舗展開、専門部署あり", "各店舗の状況がリアルタイムで見えない", "最優先課題：統合管理", "提案ポイント：「全店舗を一元管理できますよ」"]}]}'::jsonb, 26, '2026-01-21T18:04:58.913865+00:00', '2026-01-21T18:04:58.913865+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (27, 'C', '在庫回転率と資金繰り', NULL, 20, '中堅', '{"goal": "在庫回転率の計算方法と重要性を理解し、顧客の経営課題に共感できるようになる", "quote": {"text": "現金は王様だ。", "author": "ビジネス格言"}, "purpose": "在庫回転率が経営に与える影響を理解し、販売店の財務的な課題を把握できるようになります。", "summary": ["在庫回転率＝年間販売台数/平均在庫台数", "6回転以上が優良、4回転未満は要改善", "長期在庫は値下げ必至。早期発見が重要"], "sections": [{"type": "text", "title": "在庫回転率の計算", "content": "在庫回転率 = 年間販売台数 / 平均在庫台数\n\n例：年間120台販売、平均在庫30台の場合\n120 / 30 = 4回転/年\n→ 1台あたり平均3ヶ月で売れている計算"}, {"type": "list", "title": "業界の目安", "content": ["6回転以上：優良（平均2ヶ月以内で販売）", "4〜6回転：標準", "4回転未満：要改善（在庫が滞留）"]}, {"type": "text", "title": "在庫と資金の関係", "content": "在庫＝お金が車に変わっている状態です。100万円の車を10台仕入れると、1,000万円が在庫に固定されます。売れるまで現金に戻らないため、在庫が増えると次の仕入れができなくなる悪循環に陥ります。「在庫は寝かせると腐る」のです。"}]}'::jsonb, 27, '2026-01-21T18:04:59.561529+00:00', '2026-01-21T18:04:59.561529+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (28, 'C', '価格形成メカニズム', NULL, 20, '若手', '{"goal": "価格を決める要素と季節変動を理解し、業界をわかってる営業として信頼を得られるようになる", "quote": {"text": "価格は払うもの。価値は得るものだ。", "author": "ウォーレン・バフェット"}, "purpose": "中古車の価格がどのように決まるかを理解し、顧客との会話で相場知識を活用できるようになります。", "summary": ["価格は7つの要素で決まる", "1〜3月が相場が高い（年度末需要）", "相場知識は信頼構築の武器になる"], "sections": [{"type": "list", "title": "価格を決める7つの要素", "content": ["車種・グレード：人気車種は高値維持", "年式：新しいほど高い", "走行距離：少ないほど高い（5万km・10万kmが節目）", "ボディカラー：白・黒・シルバーが人気", "装備・オプション：ナビ、安全装備等", "修復歴：あり→大幅減額", "車検残：長いほど有利"]}, {"type": "text", "title": "季節変動", "content": "高い時期：1〜3月（年度末需要）、7〜8月（ボーナス）\n低い時期：4〜6月（需要の谷間）、10〜12月\n\n賢い仕入れは、需要が高まる前に仕入れて高い時期に売ること。"}, {"type": "list", "title": "値落ちしにくい車種（2025年）", "content": ["トヨタ ランドクルーザー", "トヨタ アルファード/ヴェルファイア", "スズキ ジムニー", "ホンダ N-BOX", "トヨタ プリウス"]}]}'::jsonb, 28, '2026-01-21T18:05:00.132036+00:00', '2026-01-21T18:05:00.132036+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (29, 'C', '整備・車検ビジネスの収益構造', NULL, 20, '中堅', '{"goal": "整備部門の収益構造と課題を理解し、トータル提案ができるようになる", "purpose": "販売店の「第二の収益源」である整備・車検ビジネスを理解し、Symphony整備請求の価値を提案できるようになります。", "summary": ["整備は販売店の「第二の収益源」（約20%）", "車検は安定した継続収益", "Symphony整備請求でトータル提案が可能"], "sections": [{"type": "list", "title": "収益構造", "content": ["車両販売粗利：70%", "整備・車検：20%", "その他（保険、ローン手数料等）：10%"]}, {"type": "list", "title": "整備ビジネスの種類", "content": ["車検（2年に1回）：単価5〜15万円、粗利率30〜50%", "定期点検：単価1〜3万円、顧客との接点維持", "一般整備（オイル交換等）：頻度が高い", "修理・板金：単価は高いが技術力が必要"]}, {"type": "list", "title": "整備部門の課題", "content": ["整備士不足：若手のなり手減少、離職率高い", "業務効率の低さ：見積もり作成に時間がかかる", "顧客管理の不備：車検期限の把握漏れ", "収益管理の曖昧さ：どの作業が儲かっているか不明"]}]}'::jsonb, 29, '2026-01-21T18:05:01.577201+00:00', '2026-01-21T18:05:01.577201+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (30, 'C', '業界の法規制', '古物商・登録', 25, '新卒', '{"goal": "古物営業法、自動車登録制度の基本を理解し、顧客との会話の幅を広げる", "purpose": "中古車業界に関わる法規制の基本を理解し、コンプライアンス意識を高めます。知らなかったでは済まされない重要知識です。", "summary": ["古物商許可は必須（違反は重い罰則）", "名義変更は15日以内", "法規制の基本知識は信頼構築に役立つ"], "sections": [{"type": "list", "title": "古物営業法", "content": ["中古車は「古物」に該当、古物商許可が必須", "許可なく営業：3年以下の懲役または100万円以下の罰金", "本人確認義務：買取時に運転免許等で確認", "取引記録義務：古物台帳への記録（3年間保存）"]}, {"type": "list", "title": "自動車登録制度", "content": ["移転登録（名義変更）：売買後15日以内に手続き必要", "車庫証明：使用本拠から直線距離2km以内が条件", "取得日数：通常3〜5営業日"]}, {"type": "list", "title": "その他の関連法規制", "content": ["自動車リサイクル法：使用済み自動車の適正処理", "景品表示法：不当な価格表示・おとり広告の禁止", "消費者契約法：重要事項の不実告知は契約取消可能", "個人情報保護法：顧客情報の適切な管理義務"]}]}'::jsonb, 30, '2026-01-21T18:05:02.150173+00:00', '2026-01-21T18:05:02.150173+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (31, 'C', '輸出市場と海外販路', NULL, 20, '中堅', '{"goal": "輸出市場の規模と人気車種を理解し、長期在庫の相談に対して輸出という選択肢を提案できるようになる", "quote": {"text": "グローバルに考え、ローカルに行動せよ。", "author": "ルネ・デュボス"}, "purpose": "日本の中古車輸出市場を理解し、国内で売れない車の処分手段として輸出を提案できるようになります。", "summary": ["日本の中古車輸出は年間約130万台", "国内で売れない車も海外では売れる", "輸出は在庫処分の選択肢"], "sections": [{"type": "list", "title": "日本車が人気の理由", "content": ["品質が高い（日本の車検制度）", "走行距離が少ない（平均1万km/年）", "右ハンドル需要（旧英連邦諸国）", "4WD・SUVが豊富（アフリカで人気）", "Made in Japanブランド"]}, {"type": "list", "title": "主要仕向地と人気車種", "content": ["アフリカ（最大市場）：ランクル、ハイエース、ハイラックス", "東南アジア：セダン、コンパクトカー", "ロシア・中央アジア：SUV、セダン", "オセアニア：ファミリーカー、ハイブリッド"]}, {"type": "list", "title": "販売店の活用方法", "content": ["輸出業者への売却：長期在庫の処分手段", "輸出サイトへの出品：BE FORWARD、SBT等", "ワンプラ経由で輸出業者に流すことも可能"]}]}'::jsonb, 31, '2026-01-21T18:05:02.728379+00:00', '2026-01-21T18:05:02.728379+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (32, 'C', '業界トレンド', 'EV・CASE・サブスク', 25, '若手', '{"goal": "業界トレンドを理解し、Symphonyを「変化対応の基盤」として提案できるようになる", "quote": {"text": "変化だけが唯一の不変である。", "author": "ヘラクレイトス"}, "purpose": "自動車業界の大変革（CASE）と中古車市場への影響を理解し、変化の時代を生き抜く戦略を提案できるようになります。", "summary": ["CASEが自動車業界を根本から変える", "サブスクは脅威でありチャンス", "Symphonyは変化対応の「基盤」になる"], "sections": [{"type": "list", "title": "CASE - 自動車業界の大変革", "content": ["C（Connected）：車がインターネットに常時接続", "A（Autonomous）：自動運転の普及", "S（Shared）：カーシェア、所有から利用へ", "E（Electric）：EV、HV、PHVの普及"]}, {"type": "list", "title": "中古EV市場の課題", "content": ["バッテリー劣化の懸念：交換費用50〜100万円", "残価予測が難しい：技術進化が早い", "充電インフラの問題：地域差あり", "整備ノウハウの不足：高電圧の専門資格必要"]}, {"type": "list", "title": "変化への対応戦略", "content": ["デジタル化の推進：Symphonyで業務効率化", "顧客との長期関係構築：LTVの最大化", "新しい収益モデルの検討", "専門性の強化"]}]}'::jsonb, 32, '2026-01-21T18:05:03.565338+00:00', '2026-01-21T18:05:03.565338+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (33, 'D', '影響力の6原則', 'チャルディーニ理論', 25, '若手', '{"goal": "影響力の6原則を説明でき、各原則がSymphony営業でどう活用できるか具体例を挙げられる", "quote": {"text": "心理学は「武器」にも「防具」にもなる。顧客を守るために使え。", "author": "ロバート・チャルディーニ「影響力の武器」より"}, "purpose": "ロバート・チャルディーニの「影響力の武器」6原則を理解し、Symphony営業で倫理的に活用する方法を学びます。心理学を「知っている」だけでなく「使える」レベルに昇華させます。", "summary": ["チャルディーニの6原則：返報性、一貫性、社会的証明、好意、権威、希少性", "心理テクニックは「倫理的活用」と「操作的悪用」の境界線を意識する", "判断基準は「1年後も良い関係でいられるか」"], "sections": [{"type": "list", "title": "チャルディーニの「影響力の6原則」", "content": ["返報性（Reciprocity）：もらったら返したくなる心理。業界レポートや相場情報を先に提供することで関係構築", "一貫性（Commitment & Consistency）：一度YESと言うと続けたい心理。小さなYESから大きなYESへ", "社会的証明（Social Proof）：みんながやっているなら正しいと感じる心理。導入実績や事例で安心感を提供", "好意（Liking）：好きな人の言うことは聞きやすい心理。共通点を見つけ、具体的に褒める", "権威（Authority）：専門家の言うことは正しいと感じる心理。業界知識を惜しみなく提供", "希少性（Scarcity）：手に入りにくいものは価値があると感じる心理。本当の期限・限定条件で決断を促す"]}, {"type": "comparison", "title": "倫理的活用と操作的悪用の境界線", "content": "✅ 倫理的活用（OK）：顧客の利益になる提案をより伝わりやすくする / 本当に良い製品を正しく理解してもらう / 顧客が気づいていない課題を顕在化させる / 迷っている顧客の背中を適切に押す\n\n❌ 操作的悪用（NG）：必要のない商品を心理テクニックで買わせる / 嘘の情報（偽の実績、偽の希少性）で誘導する / 顧客の弱みにつけ込んで契約を迫る / 一度きりの取引で「勝ち逃げ」する"}, {"type": "text", "title": "判断基準", "content": "「1年後、この顧客と良い関係でいられるか？」\n\n長期的な信頼関係を築けない手法は、最終的に自分を傷つけます。心理テクニックは「武器」にも「防具」にもなります。顧客を守るために使いましょう。"}]}'::jsonb, 33, '2026-01-21T18:05:04.151309+00:00', '2026-01-21T18:05:04.151309+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (34, 'D', '一貫性の原理とフット・イン・ザ・ドア', '【実践編】', 20, '若手', '{"goal": "小さなコミットメントから大きな決断へ導く質問設計ができるようになる", "quote": {"text": "千里の道も一歩から。契約への道も、小さなYESから。", "author": "Symphony営業格言"}, "purpose": "一貫性の原理が働くメカニズムを理解し、フット・イン・ザ・ドア・テクニックを営業で活用できるようになります。", "summary": ["人は「自分の言動に矛盾がない」ことを強く望む", "小さなYESを積み重ねると、大きなYESに繋がりやすい", "各ステップで「NO」と言いにくい小ささにすることがポイント"], "sections": [{"type": "text", "title": "一貫性の原理とは", "content": "人間は「自分の言動に矛盾がない」ことを強く望む生き物です。一度「私は環境に配慮している」と公言すると、エコバッグを持参する確率が上がります。\n\n一貫性が働く3つの条件：\n1. 自発的に発言・行動した（強制されたものは一貫性を感じない）\n2. 公に表明した（人前で言うと後に引けない）\n3. 努力を伴った（苦労して得たものは大切にする）"}, {"type": "text", "title": "フット・イン・ザ・ドア・テクニック", "content": "Freedman & Fraser (1966)の有名な実験：\n\n【実験1】いきなり「庭に大きな看板を立てさせてください」→ 承諾率17%\n【実験2】まず「小さなステッカーを貼ってください」→ 2週間後に「大きな看板を」→ 承諾率76%\n\n最初の小さなYESが「私は協力的な人」というセルフイメージを作り、一貫性を保とうとするのです。"}, {"type": "list", "title": "Symphony営業での「YESの階段」設計", "content": ["Step 1（超小さなYES）：「業務効率化って、関心おありですか？」→「まあ、そりゃあるよ」", "Step 2（小さなYES）：「どんな業務に時間がかかっていますか？」→「在庫管理かな...」", "Step 3（中くらいのYES）：「他の販売店さんがどう解決したか、5分だけお話ししてもいいですか？」", "Step 4（やや大きなYES）：「実際の画面、15分ほど見ていただけますか？」", "Step 5（大きなYES）：「2週間の無料トライアル、いかがですか？」", "Step 6（最大のYES）：「本導入、ご検討いただけますか？」"]}]}'::jsonb, 34, '2026-01-21T18:05:05.048828+00:00', '2026-01-21T18:05:05.048828+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (35, 'D', '返報性の原理', '「与える」ことの戦略的価値', 20, '若手', '{"goal": "返報性を活用した関係構築ができるようになる", "quote": {"text": "与えよ、さらば与えられん。ただし、見返りは期待するな。", "author": "Symphony営業格言"}, "purpose": "返報性の原理が働く心理メカニズムを理解し、営業における「先に与える」の具体的方法を学びます。", "summary": ["返報性：「もらったら返さなきゃ」という普遍的心理", "「売り込み」の前に「役立つ何か」を渡す", "黄金ルール：与えたことを忘れ、もらったことを忘れない"], "sections": [{"type": "text", "title": "返報性の原理（Reciprocity）", "content": "「もらったら、お返ししなきゃ」という普遍的心理\n\nなぜ人は「お返し」したくなるのか？\n1. 社会的規範：「もらいっぱなし」は恥ずかしい\n2. 心理的負債：借りを作ると落ち着かない\n3. 公平性欲求：ギブ＆テイクのバランスを取りたい\n\n出典: Gouldner (1960) \"The Norm of Reciprocity\""}, {"type": "list", "title": "営業が「先に与えられる」価値", "content": ["【情報】業界レポート・市場動向情報 / オークション相場のまとめ / 競合製品の客観的比較表 / 法改正・制度変更の早期情報", "【知識・ノウハウ】業務改善のヒント / 成功事例の共有 / 他社でうまくいった施策の紹介", "【時間・労力】顧客の課題を一緒に整理する / 提案資料をカスタマイズする", "【人脈・紹介】他の顧客とのマッチング / 専門家・業者の紹介"]}, {"type": "comparison", "title": "正しい使い方と間違った使い方", "content": "✅ 正しい使い方（Give & Give → Natural Take）：見返りを期待せず、まず価値を提供する / 相手が本当に必要としている情報を渡す / 長期的な信頼関係を築くことを目的とする\n\n❌ 間違った使い方（計算高い返報性）：「これあげたんだから、契約してよ」という態度 / 相手が求めていないものを押し付ける / 恩を売る→すぐに回収しようとする"}]}'::jsonb, 35, '2026-01-21T18:05:06.152854+00:00', '2026-01-21T18:05:06.152854+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (36, 'D', '社会的証明', '事例・実績の効果的な使い方', 20, '若手', '{"goal": "顧客に響く「似た事例」を選び、効果的に伝えられるようになる", "quote": {"text": "事例は鏡。顧客が「自分の姿」を見られる鏡を差し出せ。", "author": "Symphony営業格言"}, "purpose": "社会的証明が働く心理メカニズムを理解し、効果的な事例紹介の方法を学びます。", "summary": ["社会的証明：「みんながやっているなら正しい」という心理", "事例は類似性・具体性・ストーリーの3原則で伝える", "嘘の実績は絶対NG。信頼崩壊に繋がる"], "sections": [{"type": "text", "title": "社会的証明（Social Proof）", "content": "「みんながやっているなら、きっと正しい」という心理\n\n行列のできるラーメン屋は美味しいと感じる / レビューの多い商品を選びがち / 同業他社が使っていると安心\n\n【社会的証明が特に強く働く状況】\n1. 不確実性が高い時\n2. 類似性が高い時（自分に似た人の行動）\n3. 数が多い時"}, {"type": "list", "title": "事例紹介の「3つの原則」", "content": ["【原則1】類似性：「自分と似ている」と感じさせる\n❌ 悪い例：「全国で1,000社に導入されています」\n✅ 良い例：「御社と同じ○○県内で、同規模の△△モータースさんが先月導入されました」", "【原則2】具体性：数字と結果を明確に\n❌ 悪い例：「導入後、業務が楽になったそうです」\n✅ 良い例：「導入後3ヶ月で、在庫回転率が1.2倍に、月の事務作業が20時間削減できたそうです」", "【原則3】ストーリー：Before/Afterを語る\n❌ 悪い例：「○○社に導入しました」（事実のみ）\n✅ 良い例：「○○社さんも、最初は御社と同じ悩みを抱えていらっしゃいました。でも導入後は...」"]}]}'::jsonb, 36, '2026-01-21T18:05:07.22883+00:00', '2026-01-21T18:05:07.22883+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (37, 'D', '希少性の原理', '限定・期限の心理効果', 15, '若手', '{"goal": "嘘の希少性が信頼を破壊することを理解し、本当の希少性だけを活用できるようになる", "quote": {"text": "希少性は諸刃の剣。真実を武器に、嘘は墓穴。", "author": "Symphony営業格言"}, "purpose": "希少性が意思決定を促進するメカニズムを理解し、倫理的な希少性の演出方法を学びます。", "summary": ["希少性：「手に入りにくいものは価値がある」という心理", "数量限定・期間限定の2パターンが効果的", "嘘の希少性は信頼を完全に破壊する"], "sections": [{"type": "text", "title": "希少性の原理（Scarcity）", "content": "「手に入りにくいものは、価値がある」という心理\n\n【有名な実験】Worchel et al. (1975)\nクッキー10枚の瓶 vs クッキー2枚の瓶\n→ 2枚の方が「美味しい」「価値がある」と評価された\n\n【希少性が効く2つのパターン】\n1. 数量限定「残り3台！」\n2. 期間限定「本日限り！」\n\n人は「手に入らなくなる恐怖」で動く"}, {"type": "comparison", "title": "「本当の希少性」と「嘘の希少性」", "content": "✅ 本当の希少性（OK）：「このキャンペーン価格は今月末までです」 / 「導入サポートの枠が今月あと2社分です」 / 「この条件でのご提案は初回限りです」\n\n❌ 嘘の希少性（絶対NG）：「今日中に決めないとこの価格は無理です」→明日も同じ価格で提案できるのに嘘をつく / 「他社も検討していて、今週中に決まりそうです」→架空の競合を作り出す"}, {"type": "text", "title": "嘘の希少性がバレた時", "content": "信頼は一瞬で崩壊。二度と話を聞いてもらえなくなります。\n\n希少性は諸刃の剣。真実を武器に、嘘は墓穴。"}]}'::jsonb, 37, '2026-01-21T18:05:08.294158+00:00', '2026-01-21T18:05:08.294158+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (38, 'D', 'アンカリング効果', '価格提示の順序戦略', 20, '中堅', '{"goal": "顧客のアンカーを適切に設定・調整できるようになる", "quote": {"text": "最初の数字が勝負を決める。アンカーを制する者が交渉を制す。", "author": "Symphony営業格言"}, "purpose": "アンカリング効果が判断に与える影響を理解し、価格提示の最適な順序を設計できるようになります。", "summary": ["アンカリング：最初に見た数字がその後の判断基準になる", "価格は「高い数字」を先に見せてから「提案価格」を伝える", "ROI（投資対効果）を先に見せると、価格が「妥当」に感じられる"], "sections": [{"type": "text", "title": "アンカリング効果（Anchoring Effect）", "content": "「最初に見た数字が、その後の判断の基準になる」\n\n【有名な実験】Tversky & Kahneman (1974)\nグループA：最初に「10」を見せられた → 平均回答：25%\nグループB：最初に「65」を見せられた → 平均回答：45%\n※最初の数字は「全く無関係」なのに、回答に影響！\n\n出典: Kahneman (2011) \"Thinking, Fast and Slow\""}, {"type": "list", "title": "価格提示の3つの戦略", "content": ["【戦略1】高→低（ハイアンカー）\n「通常価格は月額50,000円ですが、今なら月額35,000円でご利用いただけます」\n→ 50,000円がアンカーになり、35,000円が「お得」に感じる", "【戦略2】競合比較（相対アンカー）\n「A社さんが月額60,000円、B社さんが月額45,000円、弊社は月額35,000円です」\n→ 競合価格がアンカーになり、自社が「安い」と感じる", "【戦略3】効果対比（ROIアンカー）\n「月20時間の業務削減効果があります。人件費に換算すると月50,000円相当です。それに対して、費用は月額35,000円」\n→ 削減効果がアンカーになり、費用が「元が取れる」と感じる"]}, {"type": "text", "title": "価格提示の順序", "content": "① 効果（ROI）→ ② 通常価格 → ③ 特別条件\n\n最初の数字が勝負を決める。アンカーを制する者が交渉を制す。"}]}'::jsonb, 38, '2026-01-21T18:05:09.027463+00:00', '2026-01-21T18:05:09.027463+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (39, 'D', '損失回避バイアス', '「失う恐怖」の活用', 20, '中堅', '{"goal": "機会損失を可視化するトークができるようになる", "quote": {"text": "人は『得る』ためには動かないが、『失う』ことを避けるためには動く。", "author": "ダニエル・カーネマン"}, "purpose": "損失回避バイアス（プロスペクト理論）を理解し、「得られる利益」より「失う損失」で訴求する技術を習得します。", "summary": ["人は「得る」より「失う」に2倍以上強く反応する", "「〇〇できます」より「〇〇を失い続けています」の方が効果的", "脅しではなく「気づき」を提供する姿勢が大切"], "sections": [{"type": "text", "title": "損失回避バイアス（Loss Aversion）", "content": "「人は『得る喜び』より『失う恐怖』を強く感じる」\n\n【プロスペクト理論】Kahneman & Tversky (1979)\n10,000円もらえる喜び = 100\n10,000円失う悲しみ = 200〜250\n\n→ 同じ金額でも「失う」方が2〜2.5倍強く感じる\n\nノーベル経済学賞（2002年）受賞理論"}, {"type": "comparison", "title": "「得る」訴求 vs 「失う」訴求", "content": "【得る訴求（弱い）】❌\n「Symphonyを導入すると、月20時間の業務効率化ができます」\n→ 顧客の反応：「へー、いいね」（でも行動しない）\n\n【失う訴求（強い）】✅\n「今のやり方を続けると、毎月20時間を無駄にし続けることになります。年間240時間、5年で1,200時間。人件費に換算すると約150万円を失い続けることに...」\n→ 顧客の反応：「それはまずいな...」（行動する）"}, {"type": "list", "title": "損失訴求の「やりすぎ」に注意", "content": ["❌ NGパターン：恐怖を煽りすぎる「このままでは会社が潰れますよ」 / 根拠のない損失額を提示 / 顧客を責めるような言い方", "✅ OKパターン：客観的なデータに基づく / 顧客と一緒に計算する / 課題認識の後に解決策を提示", "ポイント：脅しではなく「気づき」を提供する姿勢"]}]}'::jsonb, 39, '2026-01-21T18:05:09.647373+00:00', '2026-01-21T18:05:09.647373+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (40, 'D', '認知的不協和', '決断後の心理サポート', 20, '中堅', '{"goal": "顧客満足度を高め、紹介につなげる技術を習得する", "quote": {"text": "契約はゴールではない、スタートだ。本当の仕事は、契約の後から始まる。", "author": "Symphony営業格言"}, "purpose": "認知的不協和とバイヤーズリモースを理解し、契約後の「後悔」を防ぐフォロー方法を学びます。", "summary": ["高額な買い物後は「本当によかったのか」という不安が生じる", "契約直後こそ手厚いフォローで「決断は正しかった」と確認させる", "定期的に効果を可視化し、満足度と紹介意欲を高める"], "sections": [{"type": "text", "title": "認知的不協和（Cognitive Dissonance）", "content": "「自分の行動と考えに矛盾があると、不快になる」\n\n【購入後の心理】\n購入決定! → 「本当にこれでよかったのか...？」 → 「もっと安いのがあったかも...」 → 「他の機能の方がよかったかも...」\n\n= バイヤーズリモース（Buyer''s Remorse）\n\n高額な買い物ほど、この心理は強く働く\n\n出典: Festinger (1957)"}, {"type": "list", "title": "認知的不協和を解消する3ステップ", "content": ["Step 1: 決断を称える「素晴らしいご決断だと思います」", "Step 2: 選択の正しさを再確認「○○という点で、御社にピッタリの選択です」", "Step 3: 具体的な成功イメージを提供「3ヶ月後には、こんな状態になっているはずです」", "ポイント: 契約直後こそ、手厚いフォローが必要"]}, {"type": "list", "title": "契約後フォローの具体的アクション", "content": ["【契約直後（当日）】お礼メール「本日はご契約いただき、誠にありがとうございました。御社の業務効率化に貢献できることを楽しみにしています」", "【1週間後】フォローコール「導入準備は順調に進んでいますか？何かご不明点があれば、何でもお聞きください」", "【1ヶ月後】効果レポート「導入1ヶ月目のレポートをお持ちしました。この1ヶ月で、○時間の業務削減ができていますね。御社の決断は、データからも正しかったことがわかります」"]}]}'::jsonb, 40, '2026-01-21T18:05:10.199304+00:00', '2026-01-21T18:05:10.199304+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (41, 'D', 'ミラーリングとラポール構築', NULL, 20, '若手', '{"goal": "ラポール（信頼関係）構築の具体的方法を3つ以上実行できるようになる", "quote": {"text": "人は『似た人』を信じる。まずは相手の鏡になれ。", "author": "Symphony営業格言"}, "purpose": "ミラーリングの心理効果を理解し、言語・非言語でのミラーリング技法を実践できるようになります。", "summary": ["ミラーリング：相手の動作・声・言葉を鏡のように合わせる", "人は「自分に似た人」に好意を持つ（カメレオン効果）", "ラポール構築：共通点、名前、相槌、オウム返し、感情の反映"], "sections": [{"type": "text", "title": "ミラーリング（Mirroring）", "content": "「相手の動作や話し方を鏡のように合わせる」技法\n\n【なぜ効果があるのか？】\n人は「自分に似た人」に好意を持つ → 無意識に「この人、なんか波長が合う」と感じる → 親近感・信頼感が生まれる\n\n【有名な研究】Chartrand & Bargh (1999)\n実験者がミラーリングした被験者は、「会話が楽しかった」「相手に好感を持った」と回答\n→ これを「カメレオン効果」と呼ぶ"}, {"type": "list", "title": "ミラーリングの3つの要素", "content": ["【1. 姿勢・動作のミラーリング】相手が腕を組んだら→さりげなく腕を組む / 相手が前のめりになったら→自分も少し前に / 相手がお茶を飲んだら→少し遅れてお茶を飲む ⚠️注意: 露骨に真似ると逆効果。2〜3秒遅らせて、さりげなく", "【2. 声のミラーリング】トーン: 相手が低い声なら、少し低めに / スピード: 相手がゆっくりなら、自分もゆっくりに / ボリューム: 相手が小声なら、自分も抑えめに", "【3. 言葉のミラーリング】相手の使った言葉をそのまま使う\n顧客「在庫が見えないんだよね」→ 営業「在庫が見えない、というのは...」\n❌「在庫管理ができない、ということですね」→相手の言葉を勝手に言い換えない"]}, {"type": "list", "title": "ラポール構築の5つのテクニック", "content": ["【1】共通点を見つける「社長、ゴルフされるんですか？実は私も...」", "【2】相手の名前を呼ぶ「○○社長、先ほどおっしゃった件ですが...」", "【3】相槌とうなずき「なるほど」「そうなんですね」「おっしゃる通りです」", "【4】オウム返し 顧客「最近、仕入れが難しくてね」→営業「仕入れが難しい、と」", "【5】感情の反映 顧客「去年は本当に大変だったよ」→営業「大変でいらっしゃったんですね...」（共感）"]}]}'::jsonb, 41, '2026-01-21T18:05:10.89656+00:00', '2026-01-21T18:05:10.89656+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (42, 'D', '選択のパラドックス', '選択肢の最適数', 15, '中堅', '{"goal": "顧客の意思決定を促す提案設計ができるようになる", "quote": {"text": "選択肢は武器にも、麻痺にもなる。3つに絞れば、顧客は動ける。", "author": "Symphony営業格言"}, "purpose": "選択のパラドックス（選択過多）の心理を理解し、最適な選択肢の数（3つの法則）を学びます。", "summary": ["選択肢が多すぎると、人は選べなくなる（ジャムの実験）", "選択肢は「3つ」が最適。本命を真ん中に置く", "顧客に「選んだ」という実感を持たせることが大切"], "sections": [{"type": "text", "title": "選択のパラドックス（Paradox of Choice）", "content": "「選択肢が多すぎると、人は選べなくなる」\n\n【有名な実験】Iyengar & Lepper (2000) — ジャムの実験\n\n24種類のジャム → 試食した人60%、購入した人3%\n6種類のジャム → 試食した人40%、購入した人30% ← 10倍！\n\n【なぜ選べなくなるのか？】\n1. 比較疲れ：選択肢が多いと比較が大変\n2. 後悔の予感：「他のにすればよかった」と思いそう\n3. 決断回避：「また今度考えよう」と先延ばし\n\n出典: Barry Schwartz (2004) \"The Paradox of Choice\""}, {"type": "text", "title": "「3つの法則」— 最適な選択肢の数", "content": "選択肢は「3つ」が最も意思決定しやすい\n\n1つ → 「押し売り感」「他にないの？」\n2つ → 「どっちか迷う」「妥協感」\n3つ → 「ちょうどいい」「選んだ感」✓\n4つ以上 → 「多すぎ」「決められない」\n\n【3つの提案の設計パターン】\nベーシック：最低限の機能・低価格\nスタンダード：バランス型・中価格 ← 本命\nプレミアム：フル機能・高価格\n\n多くの人は「真ん中」を選ぶ（極端回避性）→「本命」を真ん中に置く"}, {"type": "comparison", "title": "Symphony提案の「3プラン」設計例", "content": "❌ NG例：選択肢が多すぎる\n「販売管理、整備請求、ワンプラ、それぞれ単体もあるし、2つの組み合わせもあるし、3つセットもあります。料金プランもレギュラーとプラチナがあって...」\n→ 顧客「...ちょっと検討します」（決められない）\n\n✅ OK例：3つに絞る\n「御社の状況に合わせて、3つのプランをご用意しました」\nライトプラン（販売管理のみ）月額15,000円\nスタンダード（販売管理+ワンプラ）月額28,000円 ← おすすめ\nフルプラン（全部入り）月額45,000円\n→ 顧客「じゃあ、スタンダードで」（決めやすい）"}]}'::jsonb, 42, '2026-01-21T18:05:12.029392+00:00', '2026-01-21T18:05:12.029392+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (43, 'E', '傾聴の技術', 'アクティブリスニング入門', 20, '新卒', '{"goal": "アクティブリスニングの3要素を説明でき、商談で実践できるようになる", "quote": {"text": "人の話を聴くとき、私たちはつい自分の経験に照らして理解しようとする。しかし本当の傾聴とは、相手の世界に入り込み、相手の目で見、相手の心で感じることである。", "author": "カール・ロジャーズ（Carl Rogers）"}, "purpose": "カール・ロジャーズが提唱したアクティブリスニング（積極的傾聴）の理論的背景を理解し、営業場面で顧客の本音を引き出すための実践的な傾聴スキルを習得します。", "summary": ["アクティブリスニングは「共感的理解」「無条件の肯定的配慮」「自己一致」の3要素で構成される", "トップセールスは話すより聴く時間が長い（商談の60〜70%は顧客が話す）", "SOLERの姿勢で非言語的にも「聴いている」ことを伝える", "言い換え・感情の反映・要約・沈黙の4技法を使い分ける"], "sections": [{"type": "text", "title": "アクティブリスニングとは", "content": "アクティブリスニング（Active Listening）は、1957年にカール・ロジャーズ（Carl Rogers）とリチャード・ファーソン（Richard Farson）が提唱した傾聴技法です。単に「黙って聞く」のではなく、相手の言葉の背後にある感情や意図を理解しようと能動的に関わる聴き方を指します。\n\nロジャーズは「来談者中心療法（Client-Centered Therapy）」の創始者であり、その核心は「人は適切な環境が整えば、自ら問題を解決する力を持っている」という人間観にあります。営業においても、顧客は自らの課題を最もよく知っています。私たちの役割は、その課題を顧客自身が言語化できるよう「聴く」ことで支援することです。\n\n出典: Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago."}, {"type": "list", "title": "アクティブリスニングの3つの核心要素", "content": ["【1. 共感的理解（Empathic Understanding）】相手の立場に立ち、相手の内的世界をあたかも自分自身のものであるかのように感じ取ること。ただし「あたかも（as if）」という条件を失わないこと。\n\n営業での実践：「在庫管理が大変なんですよね」と言われたら、単に「そうですか」ではなく「毎日の棚卸しで残業が増えて、ご家族との時間も減っているのでは...」と相手の感情レベルまで想像する", "【2. 無条件の肯定的配慮（Unconditional Positive Regard）】相手を評価・判断せず、ありのままを受け入れる姿勢。「それは間違っている」「そうすべきではない」という判断を保留する。\n\n営業での実践：顧客が競合製品を褒めても、「いやいや、うちの方が...」と否定せず、「〇〇の点を評価されているんですね」とまず受け止める", "【3. 自己一致（Congruence / Genuineness）】聴き手自身が自分の感情に正直であり、表面的な役割演技をしないこと。本心と言動が一致していること。\n\n営業での実践：「正直に申し上げると、その用途では弊社製品より〇〇社さんの方が適しているかもしれません」と言える誠実さ"]}, {"type": "text", "title": "傾聴の4つのレベル", "content": "スティーブン・コヴィー（Stephen Covey）は著書『7つの習慣』で、聴くことの4つのレベルを提唱しました。\n\n【レベル1】無視する聴き方：相手の話を聞いているふりをしながら、自分のことを考えている\n【レベル2】選択的な聴き方：自分に都合の良い部分だけを拾い聞きする\n【レベル3】注意深い聴き方：相手の言葉に集中するが、自分のフレームで解釈する\n【レベル4】共感的な聴き方：相手のフレーム（視点・価値観）で理解しようとする ← アクティブリスニング\n\n出典: Covey, S. R. (1989). The 7 Habits of Highly Effective People."}, {"type": "list", "title": "実践テクニック：SOLER", "content": ["心理学者ジェラード・イーガン（Gerard Egan）が提唱した、効果的な傾聴のための非言語行動の頭文字です。", "S（Squarely）：相手に正対する。斜めや横向きではなく、体を相手に向ける", "O（Open）：開いた姿勢。腕や足を組まず、オープンな姿勢を保つ", "L（Lean）：適度に前傾する。関心を示すために、やや前のめりの姿勢", "E（Eye Contact）：適切なアイコンタクト。凝視しすぎず、自然な視線を保つ", "R（Relaxed）：リラックスした態度。緊張せず、自然体でいる", "出典: Egan, G. (1975). The Skilled Helper."]}, {"type": "text", "title": "営業における傾聴の効果（実証研究）", "content": "ニール・ラッカム（Neil Rackham）がXerox社との共同研究で35,000件以上の商談を分析した結果、トップセールスは平均的な営業よりも「質問」と「傾聴」に多くの時間を費やしていることが判明しました。\n\n【研究結果のハイライト】\n・成功した商談では、営業の発言は全体の30〜40%、顧客の発言が60〜70%\n・失敗した商談では、営業の発言が60%以上を占めることが多い\n・トップセールスは「状況質問」よりも「問題質問」「示唆質問」を多用する\n\n出典: Rackham, N. (1988). SPIN Selling. McGraw-Hill."}, {"type": "list", "title": "傾聴を妨げる5つの壁", "content": ["【1. 先入観の壁】「この顧客はどうせ買わない」「中古車販売店はITに弱い」などの思い込み", "【2. 自己防衛の壁】批判や反論を恐れて、相手の本音を聞こうとしない", "【3. 評価の壁】「それは間違っている」「そうすべきだ」と判断してしまう", "【4. 解決急ぎの壁】相手の話を最後まで聞かず、すぐに解決策を提示しようとする", "【5. 自分語りの壁】相手の話を聞きながら、自分が話すことを考えている"]}, {"type": "comparison", "title": "明日から使える傾聴フレーズ", "content": "【言い換え（Paraphrasing）】\n「つまり、○○ということでしょうか」\n「○○とおっしゃるのは、△△という意味ですか」\n\n【感情の反映（Reflecting Feelings）】\n「それは大変でしたね」\n「〇〇という状況は、ご不安だったのではないですか」\n\n【要約（Summarizing）】\n「ここまでのお話をまとめると、①○○、②△△、③□□の3点が課題ということですね」\n\n【沈黙の活用（Silence）】\n相手が考えている時は、あえて何も言わない。沈黙は「もっと話していいですよ」というメッセージになる"}]}'::jsonb, 43, '2026-01-21T18:05:13.705184+00:00', '2026-01-21T18:05:13.705184+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (44, 'E', '質問力①', 'オープン/クローズド質問の使い分け', 20, '新卒', '{"goal": "オープン質問とクローズド質問の違いを説明でき、商談で適切に使い分けられるようになる", "quote": {"text": "質の良い質問は、質の良い答えを引き出す。営業の成果は、質問の質で決まる。", "author": "Symphony営業格言"}, "purpose": "質問には「オープン質問」と「クローズド質問」の2種類があり、それぞれ異なる効果を持ちます。両者の特性を理解し、商談の場面に応じて使い分けるスキルを習得します。", "summary": ["オープン質問は情報収集・深掘りに、クローズド質問は確認・合意形成に使う", "商談序盤はオープン質問で広く聞き、終盤はクローズド質問で絞り込む", "質問の漏斗技法で「広く→狭く」の順序を意識する"], "sections": [{"type": "comparison", "title": "2つの質問タイプ", "content": "【オープン質問】\n・「何」「なぜ」「どのように」で始まる\n・相手が自由に答えられる\n・情報収集・深掘りに有効\n・例：「どのような課題をお持ちですか？」\n\n【クローズド質問】\n・「はい/いいえ」で答えられる\n・選択肢を提示する\n・確認・合意形成に有効\n・例：「在庫管理でお困りですか？」"}, {"type": "list", "title": "商談での使い分け", "content": ["【序盤】オープン質問で情報収集「今、どのようなことでお困りですか？」", "【中盤】オープン質問で深掘り「それはなぜでしょうか？」「具体的にはどのような状況ですか？」", "【終盤】クローズド質問で確認「つまり、○○ということでよろしいですか？」", "【クロージング】クローズド質問で合意「来週の火曜日、ご都合いかがですか？」"]}, {"type": "text", "title": "質問の漏斗（ファネル）技法", "content": "効果的な質問は「広く→狭く」の順序で行います。\n\n1. 広いオープン質問：「事業で困っていることは？」\n2. 絞り込みオープン質問：「在庫管理について詳しく教えてください」\n3. 具体化オープン質問：「月に何時間くらいかかっていますか？」\n4. 確認クローズド質問：「月20時間ということですね？」\n\nいきなり狭い質問をすると、重要な情報を見逃す可能性があります。"}]}'::jsonb, 44, '2026-01-21T18:05:14.253758+00:00', '2026-01-21T18:05:14.253758+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (45, 'E', '質問力②', 'SPIN話法の基本', 25, '若手', '{"goal": "SPIN質問の4種類を説明でき、商談で実践できるようになる", "quote": {"text": "顧客は自分で発見した問題しか、本気で解決しようとしない。", "author": "ニール・ラッカム（Neil Rackham）"}, "purpose": "ニール・ラッカムが35,000件の商談分析から導き出したSPIN話法を理解し、顧客の潜在ニーズを顕在化させる質問技法を習得します。", "summary": ["SPIN = 状況→問題→示唆→解決の順番で質問する", "状況質問は最小限に、問題質問・示唆質問で課題を顕在化", "解決質問で、顧客自身に解決策の価値を語らせる"], "sections": [{"type": "text", "title": "SPIN話法とは", "content": "SPIN話法は、ニール・ラッカム（Neil Rackham）がHuthwaite社で12年間、35,000件以上の商談を分析して導き出した科学的な質問技法です。\n\nS = Situation Questions（状況質問）\nP = Problem Questions（問題質問）\nI = Implication Questions（示唆質問）\nN = Need-payoff Questions（解決質問）\n\n出典: Rackham, N. (1988). SPIN Selling. McGraw-Hill."}, {"type": "list", "title": "4つの質問タイプ", "content": ["【S: 状況質問】顧客の現状を把握する\n例：「現在、何人の従業員がいらっしゃいますか？」「今の在庫管理はどのようにされていますか？」\n注意：聞きすぎると尋問になる。事前調査で減らす", "【P: 問題質問】顧客の課題・不満を引き出す\n例：「在庫管理で困っていることはありますか？」「今のやり方で不便な点は？」\nポイント：顧客自身に問題を語らせる", "【I: 示唆質問】問題の深刻さを認識させる\n例：「その状況が続くと、どのような影響がありますか？」「月20時間のロスは、年間でいくらのコストになりますか？」\nポイント：問題を放置するリスクを考えさせる", "【N: 解決質問】解決策の価値を顧客に語らせる\n例：「もし在庫管理が自動化できたら、どのようなメリットがありますか？」「空いた時間で何ができそうですか？」\nポイント：営業が価値を語るのではなく、顧客に語らせる"]}, {"type": "text", "title": "SPINの効果（研究結果）", "content": "ラッカムの研究では、以下のことが判明しました：\n\n・成功した商談では、状況質問は少なく、問題質問・示唆質問が多い\n・トップセールスは示唆質問を平均の4倍使う\n・解決質問は、顧客の「欲しい」という気持ちを引き出す\n\n「顧客は自分で気づいた問題しか本気で解決しない」これがSPINの核心です。"}]}'::jsonb, 45, '2026-01-21T18:05:14.868331+00:00', '2026-01-21T18:05:14.868331+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (46, 'E', '雑談力', 'アイスブレイクの技術', 15, '新卒', '{"goal": "初対面の相手と自然に雑談でき、本題にスムーズに移行できるようになる", "quote": {"text": "雑談は無駄話ではない。信頼関係を築く大切な投資時間である。", "author": "Symphony営業格言"}, "purpose": "商談の冒頭で緊張をほぐし、信頼関係を築くための雑談（アイスブレイク）の技術を学びます。適切な話題選びと会話の進め方を習得します。", "summary": ["雑談の目的は緊張をほぐし、信頼関係の土台を作ること", "「木戸に立てかけし衣食住」で話題に困らない", "2〜3分を目安に、スムーズに本題へ移行する"], "sections": [{"type": "list", "title": "雑談の目的", "content": ["緊張をほぐす（自分も相手も）", "相手との共通点を見つける", "相手の人となりを知る", "「この人と話しやすい」という印象を作る", "本題に入りやすい雰囲気を作る"]}, {"type": "text", "title": "鉄板の雑談ネタ「木戸に立てかけし衣食住」", "content": "き：気候・季節「今日は暑いですね」\nど：道楽・趣味「ゴルフされるんですか？」\nに：ニュース「最近の○○のニュース、ご覧になりましたか？」\nた：旅・旅行「お盆はどこかに行かれましたか？」\nて：天気「この雨、週末まで続くみたいですね」\nか：家族「お子さん、おいくつですか？」\nけ：健康「お忙しそうですが、お体大丈夫ですか？」\nし：仕事「創業何年になるんですか？」\n衣：ファッション「素敵なネクタイですね」\n食：食べ物「この辺りで美味しいお店ありますか？」\n住：住まい「この地域、いいところですね」"}, {"type": "list", "title": "避けるべき話題", "content": ["政治・宗教（意見が分かれやすい）", "他社の悪口・批判", "プライベートすぎる話題（初対面では）", "自分の話ばかり（相手に興味を持つ）"]}, {"type": "text", "title": "雑談から本題への移行フレーズ", "content": "「ところで、今日お伺いしたのは...」\n「さて、本題に入らせていただきますと...」\n「お忙しいところ恐れ入りますが、本日は...」\n\n雑談は2〜3分が目安。長すぎると「何しに来たの？」と思われます。"}]}'::jsonb, 46, '2026-01-21T18:05:15.393312+00:00', '2026-01-21T18:05:15.393312+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (47, 'E', '電話応対の基本', '声だけで信頼を築く', 20, '新卒', '{"goal": "電話で好印象を与え、目的を達成できるようになる", "quote": {"text": "電話の向こうにも、人がいる。顔が見えなくても、心は通じる。", "author": "Symphony営業格言"}, "purpose": "電話は顔が見えないコミュニケーション。声のトーン、話すスピード、言葉遣いだけで信頼を築く技術を習得します。", "summary": ["電話の第一声は明るく・ゆっくり・笑声で", "電話では「声」の印象が86%を占める", "3コール以内に出る、保留は30秒以内、復唱で確認"], "sections": [{"type": "text", "title": "電話の第一声の重要性", "content": "電話では最初の15秒で印象が決まると言われています。\n\n【良い第一声の3要素】\n1. 明るいトーン：普段より少し高めの声で\n2. ゆっくり話す：対面の1.2倍遅く\n3. 笑声（えごえ）：笑顔で話すと声に表れる\n\n「お忙しいところ恐れ入ります。○○社の△△と申します」\n※電話でも「笑顔」は伝わります。鏡を見ながら練習しましょう。"}, {"type": "text", "title": "電話で伝わる印象の構成", "content": "メラビアンの法則によれば、対面では視覚情報が55%を占めます。しかし電話では視覚情報がゼロになるため：\n\n対面：視覚55% / 聴覚38% / 言語7%\n電話：聴覚86% / 言語14%（比率換算）\n\nつまり、電話では「声」の印象がほぼ全てです。"}, {"type": "list", "title": "電話応対の基本フロー", "content": ["【かける時】①名乗る→②相手を確認→③用件を簡潔に→④都合を確認", "【受ける時】①3コール以内で出る→②社名・名前を名乗る→③相手の名前を復唱→④用件を聞く", "【取り次ぐ時】「○○でございますね。少々お待ちください」→保留→「○○様からお電話です。△△の件とのことです」", "【不在時】「あいにく○○は外出しております。○時頃戻る予定です。折り返しお電話いたしましょうか？」"]}, {"type": "list", "title": "電話でのNG行動", "content": ["「もしもし」で始める（ビジネスでは不適切）", "相手の名前を聞き返しすぎる（メモを取る）", "「わかりません」「できません」で終わる（代替案を提示）", "保留が長い（30秒以上なら折り返し提案）", "ながら電話（キーボード音、資料をめくる音）"]}]}'::jsonb, 47, '2026-01-21T18:05:15.963757+00:00', '2026-01-21T18:05:15.963757+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (48, 'E', 'メール・チャットの書き方', '簡潔で伝わる文章', 20, '新卒', '{"goal": "相手に負担をかけない、読みやすいメール・チャットが書けるようになる", "quote": {"text": "良いメールは、相手の時間を奪わない。読む人への思いやりが文章に表れる。", "author": "Symphony営業格言"}, "purpose": "ビジネスメール・チャットの基本マナーと、簡潔で伝わる文章の書き方を習得します。", "summary": ["件名で用件がわかるように。本文は結論から書く", "1文50文字以内、箇条書きを活用して読みやすく", "返信は24時間以内。すぐに答えられなくても「受領」の一報を"], "sections": [{"type": "list", "title": "ビジネスメールの基本構成", "content": ["【件名】用件がわかる具体的な件名「【ご確認依頼】○月○日の打合せ日程について」", "【宛名】会社名・部署名・氏名・敬称「株式会社○○ 営業部 △△様」", "【挨拶】「お世話になっております。○○社の△△です。」", "【本文】結論→詳細→依頼の順序。1文を短く", "【結び】「ご検討のほど、よろしくお願いいたします。」", "【署名】会社名・部署・氏名・連絡先"]}, {"type": "text", "title": "読みやすい文章の書き方", "content": "【PREP法で構成する】\nPoint（結論）：「〇〇についてご連絡いたします」\nReason（理由）：「なぜなら〜だからです」\nExample（具体例）：「例えば〜」\nPoint（結論）：「つきましては〜をお願いします」\n\n【読みやすさのポイント】\n・1文は50文字以内\n・漢字3割、ひらがな7割\n・箇条書きを活用\n・適度に改行を入れる"}, {"type": "list", "title": "チャット（Slack・Teams等）のマナー", "content": ["即レスは期待しない、させない（非同期が前提）", "用件は1メッセージに完結させる（分割しない）", "メンションは必要な人だけに", "長文はメールか別途MTGで", "スタンプ・絵文字は文化に合わせて"]}, {"type": "text", "title": "返信スピードの目安", "content": "【社内メール】24時間以内\n【社外メール】当日中が理想、遅くとも翌営業日\n【緊急案件】「確認中です。○時までに回答します」と一報\n\n※すぐに回答できない場合は「受領しました」だけでも返す"}]}'::jsonb, 48, '2026-01-21T18:05:16.528619+00:00', '2026-01-21T18:05:16.528619+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (49, 'E', '非言語コミュニケーション', '表情・姿勢・視線', 20, '新卒', '{"goal": "非言語で好印象を与え、言葉と態度を一致させられるようになる", "quote": {"text": "言葉は嘘をつけるが、体は嘘をつかない。非言語を制する者が、コミュニケーションを制す。", "author": "Symphony営業格言"}, "purpose": "言葉以外で伝わる「非言語コミュニケーション」の重要性を理解し、表情・姿勢・視線・ジェスチャーを意識的にコントロールする技術を習得します。", "summary": ["非言語情報は言葉以上に相手に伝わる（視覚55%、聴覚38%）", "笑顔、前傾姿勢、オープンな姿勢で好印象を作る", "アイコンタクトは30〜60%。凝視も逸らしすぎもNG"], "sections": [{"type": "text", "title": "非言語コミュニケーションの影響力", "content": "アルバート・メラビアン（1967）の研究によると、感情や態度の伝達において：\n\n言語情報（言葉の内容）：7%\n聴覚情報（声のトーン・速さ）：38%\n視覚情報（表情・姿勢・視線）：55%\n\n※この法則は「矛盾したメッセージ」の場合に限定されますが、非言語の影響力の大きさを示しています。\n\n言葉で「大丈夫です」と言っても、表情が不安そうなら「大丈夫じゃない」と伝わります。"}, {"type": "list", "title": "表情のコントロール", "content": ["【笑顔】口角を上げ、目尻を下げる。「目が笑っていない笑顔」は逆効果", "【真剣な表情】相手の話を聞く時は、軽くうなずきながら真剣な表情", "【共感の表情】相手が困っている話をしている時は、眉を寄せて共感を示す", "【NGな表情】無表情、退屈そう、見下したような表情"]}, {"type": "text", "title": "姿勢とジェスチャー", "content": "【良い姿勢】\n・背筋を伸ばす\n・やや前傾（関心を示す）\n・腕を組まない（オープンな姿勢）\n・相手に体を向ける\n\n【ジェスチャー】\n・手のひらを見せる（誠実さ）\n・適度な手の動き（熱意）\n・相手の動きに合わせる（ミラーリング）\n\n【NGな姿勢】\n・腕を組む（拒絶のサイン）\n・足を組む（くだけすぎ）\n・椅子にもたれる（偉そう）\n・そわそわする（落ち着きがない）"}, {"type": "text", "title": "アイコンタクト", "content": "【適切なアイコンタクト】\n・会話時間の30〜60%程度\n・話す時より聞く時に多く\n・眉間〜鼻のあたりを見ると自然\n・3〜5秒見たら、一度外す\n\n【NGなアイコンタクト】\n・凝視（威圧感）\n・目を合わせない（自信がない、嘘をついている印象）\n・キョロキョロする（落ち着きがない）"}]}'::jsonb, 49, '2026-01-21T18:05:17.072601+00:00', '2026-01-21T18:05:17.072601+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (50, 'E', '説明力', 'PREP法で論理的に伝える', 20, '若手', '{"goal": "PREP法を使って、1分で要点を伝えられるようになる", "quote": {"text": "話の長い人は、結論がない人。結論から話せる人は、信頼される人。", "author": "Symphony営業格言"}, "purpose": "複雑な情報や提案を、相手にわかりやすく論理的に伝えるための「PREP法」を習得します。", "summary": ["PREP法 = Point(結論)→Reason(理由)→Example(具体例)→Point(結論)", "結論から話すことで、相手は「何の話か」を最初に理解できる", "具体例には数字を入れ、全体で1分以内を目指す"], "sections": [{"type": "text", "title": "PREP法とは", "content": "PREP法は、論理的でわかりやすい説明をするためのフレームワークです。\n\nP = Point（結論）：最も伝えたいことを最初に\nR = Reason（理由）：なぜそう言えるのか\nE = Example（具体例）：イメージしやすい例を挙げる\nP = Point（結論）：もう一度結論を強調\n\n「結論→理由→具体例→結論」の順序で話すと、相手は理解しやすくなります。"}, {"type": "text", "title": "PREP法の使用例", "content": "【提案の説明】\nP：「Symphonyの導入をお勧めします」\nR：「なぜなら、御社の在庫管理の課題を解決できるからです」\nE：「例えば、同規模の○○モータース様では、導入後に月20時間の業務削減ができました」\nP：「ですので、御社にもSymphonyの導入をお勧めします」\n\n【報告の説明】\nP：「今月の目標は達成できそうです」\nR：「理由は、大型案件が2件決まる見込みがあるからです」\nE：「具体的には、○○社が来週契約予定、△△社も最終調整中です」\nP：「以上の理由から、目標達成は問題ないと考えています」"}, {"type": "comparison", "title": "アンチパターン（悪い説明）", "content": "❌ 時系列で話す\n「昨日、○○社に行ったんですけど、最初は断られて、でも粘って話を聞いたら、実は在庫管理で困っていて...（長い）...だから提案したいんです」\n\n✅ PREP法で話す\n「○○社に提案したいです。在庫管理で困っていることがわかったからです。具体的には月末の棚卸しに3日かかっているそうです。ですので、Symphonyを提案させてください」"}, {"type": "list", "title": "PREP法を使いこなすコツ", "content": ["最初の「P」を一文で言い切る練習をする", "「なぜなら」「例えば」「ですので」を接続詞として使う", "具体例は数字を入れると説得力が増す", "全体で1分以内に収める意識を持つ"]}]}'::jsonb, 50, '2026-01-21T18:05:17.635772+00:00', '2026-01-21T18:05:17.635772+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (51, 'E', '交渉の基本', 'Win-Winを目指す姿勢', 25, '若手', '{"goal": "Win-Winの交渉マインドを持ち、基本的な交渉技法を実践できるようになる", "quote": {"text": "交渉は戦いではない。共に解決策を見つける共同作業である。", "author": "ウィリアム・ユーリー（William Ury）"}, "purpose": "交渉を「勝ち負け」ではなく「Win-Win」で捉える考え方を学び、双方が満足できる合意形成の技術を習得します。", "summary": ["Win-Winを目指す。一度の勝ちより、長期的な関係を重視", "ハーバード流4原則：人と問題を分離、利害に焦点、選択肢を創造、客観的基準", "BATNAを持つことで、無理な譲歩をせずに済む"], "sections": [{"type": "text", "title": "交渉の4つのパターン", "content": "【Win-Win】自分も相手も満足。長期的な関係が続く\n【Win-Lose】自分だけ満足。相手は次から取引しない\n【Lose-Win】相手だけ満足。自分が疲弊する\n【Lose-Lose】両方不満足。関係が終わる\n\n営業で目指すべきはWin-Win。一度の取引で「勝ち」を取っても、長期的には必ず負ける。\n\n出典: Covey, S. R. (1989). The 7 Habits of Highly Effective People."}, {"type": "list", "title": "ハーバード流交渉術の4原則", "content": ["【1. 人と問題を分離する】感情的にならず、課題に集中。「あなたが悪い」ではなく「この問題をどう解決するか」", "【2. 立場ではなく利害に焦点を当てる】「値引きしろ」（立場）ではなく「なぜ値引きが必要か」（利害）を探る", "【3. 双方に有利な選択肢を創造する】「これかあれか」ではなく「第三の案」を一緒に考える", "【4. 客観的基準を用いる】市場価格、業界慣行、前例など、主観ではない基準で合意形成"]}, {"type": "text", "title": "BATNA（バトナ）を持つ", "content": "BATNA = Best Alternative To a Negotiated Agreement\n（交渉が決裂した場合の最善の代替案）\n\n交渉前に「この交渉がまとまらなかった場合、自分はどうするか」を考えておく。\n\nBATNAがあると：\n・無理な譲歩をしなくて済む\n・自信を持って交渉できる\n・「この条件でなければ他へ行く」という選択肢がある\n\n出典: Fisher, R., & Ury, W. (1981). Getting to Yes."}, {"type": "list", "title": "交渉で使える言い回し", "content": ["「御社のご要望は理解しました。一方で、弊社としては○○という事情があります」", "「お互いにとって良い着地点を一緒に探しませんか？」", "「もし○○していただけるなら、△△することは可能です」", "「この条件では難しいのですが、別の形でお役に立てることはないでしょうか？」"]}]}'::jsonb, 51, '2026-01-21T18:05:18.264368+00:00', '2026-01-21T18:05:18.264368+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (52, 'E', 'クレーム対応の基本', '怒りを鎮める技術', 25, '若手', '{"goal": "クレーム対応の基本プロセスを実行でき、二次クレームを防げるようになる", "quote": {"text": "クレームは、顧客が与えてくれた改善のチャンス。適切に対応すれば、ファンになってくれる。", "author": "Symphony営業格言"}, "purpose": "クレームを「ピンチ」ではなく「チャンス」と捉え、適切な対応で信頼回復につなげる技術を習得します。", "summary": ["クレームは「氷山の一角」。言ってくれる顧客は貴重な存在", "5ステップ：傾聴→謝罪→事実確認→解決策→感謝", "二次クレームを防ぐ：たらい回し、言い訳、約束不履行はNG"], "sections": [{"type": "text", "title": "クレームの捉え方", "content": "【クレームは「氷山の一角」】\n不満を持った顧客のうち、クレームを言うのは4%だけ。残り96%は黙って離れていく（グッドマンの法則）。\n\nつまり、クレームを言ってくれる顧客は「まだ関係を続けたい」と思っている貴重な存在。\n\n【クレーム対応の効果】\n・適切に対応されたクレーム顧客の再購入率は、不満のない顧客より高い\n・クレーム対応に満足した顧客は、良い口コミを広める"}, {"type": "list", "title": "クレーム対応の5ステップ", "content": ["【1. 傾聴】まず最後まで話を聞く。途中で言い訳・反論しない。「おっしゃる通りです」「それは大変でしたね」と共感", "【2. 謝罪】事実確認の前でも「ご不快な思いをさせて申し訳ございません」と、感情に対してまず謝る", "【3. 事実確認】「詳しく状況を教えていただけますか？」5W1Hで正確に把握", "【4. 解決策提示】「○○させていただきます」と具体的に。できないことは理由と代替案を", "【5. 感謝】「ご指摘いただきありがとうございました。今後の改善に活かします」"]}, {"type": "list", "title": "二次クレームを防ぐポイント", "content": ["【たらい回しにしない】「担当者に確認します」で放置しない。必ず折り返す", "【言い訳から入らない】「でも」「ただ」で始めない", "【約束は必ず守る】「○時までに連絡します」と言ったら、必ず連絡", "【上から目線にならない】「規定ですので」「通常はこうなっています」はNG", "【記録を残す】対応内容を記録し、社内で共有"]}, {"type": "text", "title": "怒りを鎮める心理テクニック", "content": "【クッション言葉を使う】\n「恐れ入りますが」「差し支えなければ」「お手数ですが」\n\n【相手の名前を呼ぶ】\n「○○様のおっしゃる通りです」名前を呼ばれると冷静になりやすい\n\n【限定謝罪】\n事実確認前は「ご不快な思いをさせて」「ご不便をおかけして」など、感情に対して謝る。全面的な非を認める謝罪は事実確認後に"}]}'::jsonb, 52, '2026-01-21T18:05:19.0426+00:00', '2026-01-21T18:05:19.0426+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (53, 'F', '営業プロセスの全体設計', '成約までの道筋を描く', 20, '若手', '{"goal": "営業プロセスの全体像を説明でき、自分の活動が今どの段階にあるか意識できるようになる", "quote": {"text": "プロセスを管理する者が、結果をコントロールする。", "author": "Symphony営業格言"}, "purpose": "営業活動は闇雲に行っても成果は出ません。見込み客の発掘から成約、フォローアップまでの全体プロセスを理解し、計画的に営業活動を進める基盤を学びます。", "summary": ["営業プロセス：リスト→アプローチ→ヒアリング→提案→クロージング→フォロー", "ファネルの考え方で、各ステップの数と転換率を管理する", "結果だけでなくプロセスを管理することで、再現性が生まれる"], "sections": [{"type": "text", "title": "営業プロセスとは", "content": "営業プロセスとは、見込み客を顧客に変えるまでの一連のステップです。\n\n標準的な営業プロセス：\n1. リスト作成（ターゲット選定）\n2. アプローチ（テレアポ・飛び込み）\n3. ヒアリング（ニーズ把握）\n4. 提案（プレゼンテーション）\n5. クロージング（契約締結）\n6. フォローアップ（継続関係）\n\nこの流れを理解することで、「今、何をすべきか」が明確になります。"}, {"type": "list", "title": "各プロセスの目的", "content": ["【リスト作成】質の高い見込み客を特定する。数より質が重要", "【アプローチ】最初の接点を作る。次のステップ（商談）につなげることが目的", "【ヒアリング】顧客の課題・ニーズを深く理解する。提案の土台を作る", "【提案】顧客の課題に対する解決策を提示する。価値を伝える", "【クロージング】顧客の決断を促す。契約を締結する", "【フォローアップ】顧客満足を維持し、リピート・紹介につなげる"]}, {"type": "text", "title": "ファネル（漏斗）の考え方", "content": "営業プロセスは「ファネル（漏斗）」の形をしています。\n\n【ファネルのイメージ】\nリスト100件 → アポ獲得20件 → 商談10件 → 提案5件 → 成約2件\n\n各ステップで絞り込まれていくため、上流（リスト・アプローチ）の量と質が最終成果を左右します。\n\n【ファネル管理のポイント】\n・各ステップの数を把握する\n・転換率（コンバージョン率）を測定する\n・ボトルネック（詰まっている箇所）を特定する\n・改善策を講じる"}, {"type": "text", "title": "プロセス管理の重要性", "content": "「結果」だけを見ていては改善できません。「プロセス」を管理することで、再現性のある営業が可能になります。\n\n【結果管理 vs プロセス管理】\n結果管理：「今月の売上は○○円だった」\nプロセス管理：「アポ○件、商談○件、提案○件から売上○○円だった」\n\nプロセス管理をすることで：\n・何が上手くいっているか分かる\n・何を改善すべきか分かる\n・将来の売上を予測できる"}]}'::jsonb, 53, '2026-01-21T18:05:19.959055+00:00', '2026-01-21T18:05:19.959055+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (54, 'F', 'ターゲットリストの作り方', '質の高い見込み客を見つける', 20, '若手', '{"goal": "ターゲット選定の基準を理解し、自分で質の高いリストを作成できるようになる", "quote": {"text": "良いリストは、営業の半分を成功させる。", "author": "Symphony営業格言"}, "purpose": "「誰に売るか」を間違えると、どんなに努力しても成果は出ません。効率的に成果を出すための「質の高いターゲットリスト」の作り方を学びます。", "summary": ["「誰に売るか」を間違えると努力が無駄になる", "ICPを設定し、理想的な顧客像を明確にする", "ABC分析で優先順位をつけ、効率的にアプローチする"], "sections": [{"type": "text", "title": "なぜターゲット選定が重要か", "content": "「全員に売ろう」とすると、誰にも売れません。\n\n【ターゲット選定の効果】\n・限られた時間を高確率の顧客に集中できる\n・顧客に刺さるメッセージを作れる\n・成約率が上がり、効率が向上する\n\n【80:20の法則（パレートの法則）】\n売上の80%は、20%の顧客から生まれる。\nその20%を最初から狙えば、効率が飛躍的に向上します。"}, {"type": "list", "title": "理想顧客像（ICP）の設定", "content": ["【ICP = Ideal Customer Profile】自社の製品・サービスから最も価値を得られる顧客の特徴", "【業種】どの業種に課題があるか？（例：自動車整備業）", "【規模】従業員数、売上規模は？（例：従業員10〜50名）", "【地域】商圏はどこか？（例：関東圏）", "【課題】どのような課題を持っているか？（例：在庫管理に困っている）", "【既存顧客分析】成約した顧客の共通点を分析し、ICPを精緻化する"]}, {"type": "list", "title": "リストの情報源", "content": ["【業界団体・協会名簿】業種特化のリストが手に入る", "【企業データベース】帝国データバンク、東京商工リサーチなど", "【展示会・セミナー参加者】課題意識が高い見込み客", "【既存顧客からの紹介】最も質が高い", "【Webからの問い合わせ】自らアクションした見込み客", "【地域の商工会・商工会議所】地域密着型のリスト"]}, {"type": "text", "title": "リストの優先順位付け", "content": "リストは優先順位をつけて攻めます。\n\n【ABC分析】\nAランク：ICPに完全一致、すぐにアプローチ\nBランク：ICPに部分一致、Aの次にアプローチ\nCランク：可能性はあるが優先度は低い\n\n【SymphonyでのAランク例】\n・自動車整備業\n・従業員20〜50名\n・関東圏\n・創業10年以上（IT投資余力あり）\n・ホームページがある（IT意識あり）"}]}'::jsonb, 54, '2026-01-21T18:05:21.226523+00:00', '2026-01-21T18:05:21.226523+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (55, 'F', 'テレアポの極意', '電話でアポイントを獲得する', 25, '若手', '{"goal": "テレアポの基本スクリプトを使いこなし、アポイント獲得率を向上させる", "quote": {"text": "テレアポは、断られることを楽しむゲームだ。", "author": "Symphony営業格言"}, "purpose": "テレアポは多くの営業パーソンが苦手とする業務ですが、正しいやり方を知れば成果は劇的に変わります。アポイント獲得のための電話スクリプトと心構えを学びます。", "summary": ["テレアポの目的は「アポイントを取ること」。電話で売り込まない", "基本スクリプト：名乗り→用件→興味喚起→アポ打診→日程調整", "断られて当たり前。数をこなして上達する"], "sections": [{"type": "text", "title": "テレアポの目的を明確にする", "content": "テレアポの目的は「アポイントを取ること」です。\n電話で売り込むことではありません。\n\n【テレアポの目的】\n✅ 次の商談（訪問・オンライン）の約束を取る\n❌ 電話で商品を説明する\n❌ 電話で契約を取る\n\n【ゴールの明確化】\n「○月○日○時に、30分お時間をいただく約束」\nこれ以上でも以下でもありません。"}, {"type": "text", "title": "テレアポの基本スクリプト", "content": "【基本スクリプト例】\n\n①名乗り\n「お忙しいところ恐れ入ります。○○社の△△と申します」\n\n②用件の明示\n「本日は、御社の在庫管理についてお役に立てる情報をお伝えしたく、お電話いたしました」\n\n③興味喚起\n「同業の○○様で、月20時間の作業削減ができた事例がございます」\n\n④アポ打診\n「詳しくご説明する機会をいただけないでしょうか。30分程度で結構です」\n\n⑤日程調整\n「来週の火曜日か水曜日、ご都合いかがでしょうか」"}, {"type": "list", "title": "断られた時の切り返し", "content": ["【「忙しい」と言われたら】「お忙しいところ申し訳ございません。それでは、いつ頃でしたらお時間いただけますでしょうか」", "【「興味がない」と言われたら】「突然のお電話で失礼いたしました。ちなみに、在庫管理で特にお困りのことはございませんか？」", "【「資料を送って」と言われたら】「承知いたしました。せっかくですので、15分だけ直接ご説明させてください」", "【「今は必要ない」と言われたら】「承知いたしました。状況が変わられた際にお役に立てるよう、資料をお送りしてもよろしいでしょうか」"]}, {"type": "list", "title": "テレアポの心構え", "content": ["【断られて当たり前】アポ獲得率は5〜10%。90%以上は断られる", "【数をこなす】上手くなるには量が必要。最初から上手い人はいない", "【声のトーンは明るく】電話は声が全て。笑顔で話す", "【立って電話する】立つと声に張りが出る", "【午前中が狙い目】決裁者がいる確率が高い時間帯を狙う"]}]}'::jsonb, 55, '2026-01-21T18:05:21.844741+00:00', '2026-01-21T18:05:21.844741+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (56, 'F', '飛び込み営業の技術', '直接訪問でチャンスを掴む', 25, '若手', '{"goal": "飛び込み営業の基本的な流れを理解し、次回訪問につながるアクションが取れるようになる", "quote": {"text": "飛び込み営業は、100回断られて1回成功するゲームだ。断られることを恐れるな。", "author": "Symphony営業格言"}, "purpose": "飛び込み営業は効率が悪いと思われがちですが、正しいやり方を知れば強力な武器になります。初対面の相手から信頼を得るための訪問技術を学びます。", "summary": ["飛び込みの目的は「次のアポを取る」こと。初回で売り込まない", "断られても「置き土産」を残す（名刺、資料、次回訪問の約束）", "第一印象が勝負。笑顔、清潔感、ハキハキした声で臨む"], "sections": [{"type": "text", "title": "飛び込み営業の目的", "content": "飛び込み営業の目的は、テレアポと同じく「次のアポを取ること」です。\n初回訪問で契約を取ろうとしないでください。\n\n【飛び込み営業の目的】\n✅ 名刺交換し、次の訪問約束を取る\n✅ キーパーソン（決裁者）を特定する\n✅ 簡単なニーズをヒアリングする\n\n【現実的なゴール】\n・名刺をもらう\n・次回訪問の約束を取る\n・「また来てください」と言ってもらう"}, {"type": "list", "title": "飛び込み営業の基本フロー", "content": ["【①入口で名乗る】「お忙しいところ恐れ入ります。○○社の△△と申します」", "【②用件を伝える】「御社のお役に立てる情報がありまして、ご挨拶に伺いました」", "【③キーパーソンを聞く】「こういったお話は、どなた様にさせていただければよろしいでしょうか」", "【④短く自己紹介】「自動車整備業向けのシステムを提供しております」", "【⑤次回アポを取る】「改めて詳しくお話しする機会をいただけませんか」"]}, {"type": "text", "title": "断られた時の対処法", "content": "【「社長は不在です」と言われたら】\n「承知いたしました。それでは名刺をお渡しいただけますでしょうか。また改めてお伺いします」\n\n【「うちは間に合っています」と言われたら】\n「承知いたしました。ご参考までに資料だけお渡ししてもよろしいでしょうか」\n\n【「忙しい」と言われたら】\n「お忙しいところ申し訳ございません。1分だけお時間いただけませんか。ダメでしたら名刺だけでも...」\n\n【ポイント】\n何か一つでも「置き土産」を残す（名刺、資料、次回訪問の約束）"}, {"type": "list", "title": "飛び込み営業のコツ", "content": ["【第一印象が全て】笑顔、清潔感、ハキハキした声", "【滞在時間は短く】長居しない。5分以内が目安", "【近隣を回る】1件行ったら、近くの3〜5件も回る", "【時間帯を選ぶ】10時〜11時半、14時〜16時が狙い目", "【記録を残す】訪問結果を必ずメモし、次回に活かす"]}]}'::jsonb, 56, '2026-01-21T18:05:22.895787+00:00', '2026-01-21T18:05:22.895787+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (57, 'F', 'ヒアリング設計', '聞くべきことを漏れなく聞く', 25, '若手', '{"goal": "ヒアリング項目を設計でき、商談で必要な情報を漏れなく収集できるようになる", "quote": {"text": "顧客の話を聞かずに提案する営業は、患者を診ずに薬を出す医者と同じだ。", "author": "Symphony営業格言"}, "purpose": "良い提案は良いヒアリングから生まれます。顧客の課題・ニーズを漏れなく把握するための「ヒアリング設計」の技術を学びます。", "summary": ["ヒアリングなき提案は、診察なき処方。まず聞く、そして提案", "BANT（予算・決裁者・ニーズ・時期）を必ず押さえる", "ヒアリングシートで聞き漏れを防ぐ"], "sections": [{"type": "text", "title": "ヒアリングの重要性", "content": "「ヒアリングなき提案は、診察なき処方」です。\n顧客の状況を理解せずに提案しても、的外れになります。\n\n【ヒアリングの目的】\n・顧客の現状を把握する\n・課題・ニーズを特定する\n・提案の方向性を決める\n・予算・スケジュール・決裁者を確認する\n\n【ヒアリングと提案の比率】\n初回商談では、ヒアリング7：提案3が目安。\nまず聞く、そして提案する。"}, {"type": "list", "title": "BANT情報を押さえる", "content": ["【B = Budget（予算）】「ご予算はお決まりですか」「どのくらいの投資をお考えですか」", "【A = Authority（決裁権）】「最終的にはどなたがお決めになりますか」「他に確認される方はいらっしゃいますか」", "【N = Needs（ニーズ）】「どのような課題をお持ちですか」「なぜ今、検討されているのですか」", "【T = Timeline（時期）】「いつ頃の導入をお考えですか」「決定の期限はございますか」"]}, {"type": "text", "title": "ヒアリングシートの設計", "content": "ヒアリングシートを事前に準備しておくと、聞き漏れを防げます。\n\n【Symphonyでのヒアリング項目例】\n\n■現状把握\n・現在の在庫管理方法は？\n・使用しているシステム・ツールは？\n・従業員数、拠点数は？\n\n■課題把握\n・在庫管理で困っていることは？\n・棚卸しにかかる時間は？\n・ミス・ロスの発生頻度は？\n\n■BANT\n・予算感は？\n・決裁者は誰か？\n・なぜ今検討しているか？\n・導入希望時期は？"}, {"type": "list", "title": "ヒアリングの進め方", "content": ["【オープニング】アイスブレイク→本日の流れを説明", "【広い質問から】「まずは御社の状況を教えていただけますか」", "【深掘り質問】「それはなぜですか」「具体的には？」", "【BANT確認】予算、決裁者、時期を自然に聞く", "【要約・確認】「つまり○○ということでよろしいですか」", "【次のステップ】「では、○○を踏まえて提案を作成しますね」"]}]}'::jsonb, 57, '2026-01-21T18:05:23.465797+00:00', '2026-01-21T18:05:23.465797+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (58, 'F', 'ニーズの顕在化', '潜在ニーズを引き出す', 25, '中堅', '{"goal": "潜在ニーズと顕在ニーズの違いを理解し、SPIN話法でニーズを顕在化できるようになる", "quote": {"text": "顧客は自分で発見した問題しか、本気で解決しようとしない。", "author": "ニール・ラッカム（Neil Rackham）"}, "purpose": "顧客は自分のニーズに気づいていないことがあります。潜在ニーズを顕在化させ、顧客自身が「解決したい」と思うように導く技術を学びます。", "summary": ["潜在ニーズを顕在化させることで、競合と差別化できる", "SPIN話法で、顧客自身に問題の深刻さを気づかせる", "営業が「伝える」のではなく、顧客に「気づかせる」"], "sections": [{"type": "comparison", "title": "潜在ニーズと顕在ニーズ", "content": "【顕在ニーズ】\n・顧客自身が認識しているニーズ\n・「○○が欲しい」と明確に言える\n・例：「在庫管理システムを探している」\n\n【潜在ニーズ】\n・顧客自身が気づいていないニーズ\n・言語化されていない\n・例：「棚卸しに時間がかかるが、仕方ないと思っている」\n\n【潜在ニーズを顕在化させる価値】\n競合は顕在ニーズにしか対応できない。潜在ニーズを掘り起こせれば、独占的なポジションを取れる。"}, {"type": "text", "title": "SPIN話法でニーズを顕在化", "content": "SPIN話法は、潜在ニーズを顕在化させるための質問技法です。\n\n【S = Situation（状況質問）】\n現状を把握する\n「在庫管理はどのようにされていますか？」\n\n【P = Problem（問題質問）】\n課題を引き出す\n「その方法で困っていることはありますか？」\n\n【I = Implication（示唆質問）】★重要\n問題の深刻さを認識させる\n「その状況が続くと、どんな影響がありますか？」\n\n【N = Need-payoff（解決質問）】\n解決の価値を顧客に語らせる\n「もし解決できたら、どうなりますか？」"}, {"type": "list", "title": "示唆質問（I）の威力", "content": ["【問題の拡大】「棚卸しに3日かかると、その間の営業活動はどうなりますか？」", "【金銭的影響】「年間で考えると、どれくらいのコストになりますか？」", "【人的影響】「スタッフの残業は増えていませんか？」", "【競合への影響】「競合他社はこの問題をどう対処していると思いますか？」", "【将来への影響】「事業が拡大した時、この問題はさらに大きくなりませんか？」"]}, {"type": "text", "title": "顧客に「気づかせる」技術", "content": "ニーズの顕在化で大切なのは、「顧客自身に気づかせる」ことです。\n\n【営業が言う場合】\n「御社は年間100時間の無駄があります」\n→ 押し売りに聞こえる\n\n【顧客が気づく場合】\n「年間で考えると...100時間くらいロスしてるかも」\n→ 自分で発見した問題として認識\n\n【原則】\n顧客は、自分で気づいた問題しか本気で解決しようとしない。\n営業の役割は、気づきを「引き出す」こと。"}]}'::jsonb, 58, '2026-01-21T18:05:24.11902+00:00', '2026-01-21T18:05:24.11902+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (59, 'F', '提案書作成の基本', '顧客を動かす提案書', 25, '若手', '{"goal": "提案書の基本構成を理解し、顧客に響く提案書を作成できるようになる", "quote": {"text": "良い提案書は、顧客が社内で営業してくれるツールだ。", "author": "Symphony営業格言"}, "purpose": "提案書は、商談の成否を左右する重要なツールです。顧客の課題を解決し、行動を促す「伝わる提案書」の作り方を学びます。", "summary": ["提案書の目的は「顧客に行動してもらうこと」", "課題→解決策→効果→事例→費用→次のステップの構成", "顧客視点、数字、次のアクション明示がポイント"], "sections": [{"type": "text", "title": "提案書の目的", "content": "提案書の目的は「顧客に行動してもらうこと」です。\n\n【提案書の役割】\n・商談の内容を文書化し、社内共有を促す\n・不在の決裁者に情報を届ける\n・検討の材料を提供する\n・契約に向けた意思決定を促す\n\n【良い提案書の条件】\n・顧客の課題に焦点が当たっている\n・解決策が明確に示されている\n・導入効果が具体的に示されている\n・次のアクションが明確"}, {"type": "list", "title": "提案書の基本構成", "content": ["【①表紙】会社名、日付、提案タイトル", "【②エグゼクティブサマリー】提案の要点を1ページで。忙しい決裁者向け", "【③課題の整理】ヒアリングで把握した顧客の課題を整理", "【④解決策の提示】自社製品・サービスがどう課題を解決するか", "【⑤導入効果】定量的な効果（コスト削減額、時間削減など）", "【⑥導入事例】類似企業の成功事例", "【⑦費用・スケジュール】見積もり、導入までのスケジュール", "【⑧次のステップ】契約に向けたアクションを明示"]}, {"type": "list", "title": "提案書作成のポイント", "content": ["【顧客視点で書く】「弊社は〜」ではなく「御社は〜」で始める", "【課題から始める】製品説明から入らない。顧客の課題から始める", "【数字で示す】「大幅に効率化」ではなく「月20時間削減」", "【ビジュアルを活用】図、表、グラフで視覚的に伝える", "【1ページ1メッセージ】詰め込みすぎない", "【次のアクションを明示】「ご検討ください」ではなく「○日までにご回答ください」"]}, {"type": "text", "title": "NGな提案書の特徴", "content": "【自社目線の提案書】\n・自社の歴史、組織図、理念から始まる\n・製品の機能一覧が延々と続く\n・顧客の課題が書かれていない\n\n【具体性のない提案書】\n・「業務効率化」「コスト削減」など曖昧な表現\n・数字がない\n・事例がない\n\n【次のステップがない提案書】\n・「ご検討ください」で終わる\n・いつまでに何をすべきか不明"}]}'::jsonb, 59, '2026-01-21T18:05:24.884078+00:00', '2026-01-21T18:05:24.884078+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (60, 'F', 'プレゼンテーションの技術', '心を動かすプレゼン', 30, '中堅', '{"goal": "プレゼンの基本構成を理解し、顧客を惹きつけるプレゼンができるようになる", "quote": {"text": "プレゼンは、スライドを読み上げる場ではない。顧客の心を動かす場だ。", "author": "Symphony営業格言"}, "purpose": "どんなに良い提案書も、伝え方が悪ければ響きません。顧客の心を動かし、行動を促すプレゼンテーションの技術を学びます。", "summary": ["プレゼンの目的は「顧客を次のステップに進めること」", "最初の3分で興味を引く。結論・価値を先に伝える", "機能説明より事例・ストーリー。聴衆を見て話す"], "sections": [{"type": "text", "title": "プレゼンの目的", "content": "プレゼンの目的は「顧客を次のステップに進めること」です。\n\n【プレゼンの役割】\n・提案内容を口頭で補足し、理解を深める\n・顧客の反応を見ながら、調整できる\n・質疑応答で疑問を解消する\n・熱意を伝え、信頼を獲得する\n\n【プレゼンと提案書の違い】\n提案書：読み手のペースで読まれる、詳細を記載\nプレゼン：話し手のペースで進む、要点を絞る"}, {"type": "list", "title": "プレゼンの基本構成", "content": ["【①オープニング】アイスブレイク、本日のアジェンダ、所要時間を伝える", "【②課題の確認】「前回のヒアリングで○○とおっしゃっていました」", "【③解決策の提示】「そこで本日は○○をご提案します」", "【④効果の説明】「これにより○○が改善されます」", "【⑤事例紹介】「同業の○○社では○○という成果が出ています」", "【⑥費用・スケジュール】「お見積もりは○○、導入は○月を想定」", "【⑦クロージング】「ご質問はございますか」「次のステップとして○○を」"]}, {"type": "list", "title": "プレゼンを成功させるコツ", "content": ["【最初の3分が勝負】冒頭で興味を引く。結論・価値を先に伝える", "【聴衆を見る】資料ではなく、聴衆の目を見て話す", "【一方的に話さない】「ここまでよろしいですか」「ご質問ありますか」", "【ストーリーで伝える】機能説明より、事例・ストーリーが記憶に残る", "【シンプルなスライド】1スライド1メッセージ。文字は少なく", "【練習する】本番前に必ずリハーサルを行う"]}, {"type": "text", "title": "質疑応答の対処法", "content": "【質問を歓迎する姿勢】\n「良いご質問ですね」と受け止める\n\n【わからない質問への対応】\n「確認して後日ご回答します」正直に言う\n\n【反論・異議への対応】\n「おっしゃる通りです。ただ一方で...」\n一度受け止めてから、反論する\n\n【想定問答の準備】\n事前に想定される質問と回答を準備しておく"}]}'::jsonb, 60, '2026-01-21T18:05:25.784532+00:00', '2026-01-21T18:05:25.784532+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (61, 'F', 'クロージングの技術', '決断を促す最後の一押し', 25, '中堅', '{"goal": "クロージングの基本技法を理解し、適切なタイミングでクロージングできるようになる", "quote": {"text": "クロージングを恐れるな。顧客は、決断を後押ししてほしいと思っている。", "author": "Symphony営業格言"}, "purpose": "どんなに良い商談でも、クロージングができなければ成約に至りません。顧客の決断を促し、契約を締結するためのクロージング技術を学びます。", "summary": ["クロージングは強引に押し切ることではなく、決断の後押し", "買いシグナルを見逃さず、適切なタイミングでクロージング", "断られても関係を維持。次の機会につなげる"], "sections": [{"type": "text", "title": "クロージングとは", "content": "クロージングとは、顧客の決断を促し、契約を締結することです。\n\n【クロージングの重要性】\n・営業プロセスの最終段階\n・ここで失敗すると、全ての努力が無駄になる\n・多くの営業が苦手とするフェーズ\n\n【クロージングの誤解】\n❌ 強引に押し切ること\n❌ 顧客を騙すこと\n✅ 顧客が決断しやすいよう、後押しすること\n\n顧客は迷っているだけ。営業の役割は、その背中を押すこと。"}, {"type": "list", "title": "クロージングのタイミング", "content": ["【買いシグナルを見逃さない】顧客が前向きな発言をした時がタイミング", "【買いシグルの例】「導入後のサポートは？」「他社の事例は？」「値引きは可能？」", "【沈黙のサイン】顧客が黙り込んだ時は、考えている証拠。待つ", "【質問がなくなった時】疑問が解消されたサイン。クロージングのチャンス", "【早すぎるクロージングは逆効果】信頼が築けていない段階では待つ"]}, {"type": "list", "title": "クロージングの基本技法", "content": ["【直接クロージング】「では、ご契約いただけますか」シンプルに聞く", "【選択肢クロージング】「月額プランと年額プラン、どちらがよろしいですか」Yes/Noではなく、選択肢を提示", "【仮定クロージング】「導入するとしたら、いつ頃がよろしいですか」導入を前提にした質問", "【期限クロージング】「今月中でしたら○○の特典があります」期限を設けて決断を促す", "【試用クロージング】「まずは1ヶ月お試しいただけますか」リスクを下げて決断を促す"]}, {"type": "text", "title": "クロージングで断られた時", "content": "【「検討します」と言われたら】\n「ありがとうございます。ちなみに、ご検討のポイントは何でしょうか」\n→ 懸念を特定し、解消を試みる\n\n【「上に相談します」と言われたら】\n「承知いたしました。上の方にご説明する機会をいただけますか」\n→ 決裁者へのアプローチを試みる\n\n【「予算がない」と言われたら】\n「予算確保の可能性があるのはいつ頃でしょうか」\n→ 時期をずらす提案\n\n【断られても関係を維持】\n今回ダメでも、次の機会につながる関係を維持する"}]}'::jsonb, 61, '2026-01-21T18:05:26.970536+00:00', '2026-01-21T18:05:26.970536+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (62, 'F', '契約手続きとオンボーディング', '成約後の顧客体験を設計する', 20, '若手', '{"goal": "契約手続きを滞りなく進め、顧客がスムーズにサービスを利用開始できるよう支援できる", "quote": {"text": "契約はゴールではなく、顧客との関係のスタートラインだ。", "author": "Symphony営業格言"}, "purpose": "契約締結は終わりではなく、始まりです。スムーズな契約手続きと、顧客が成功するためのオンボーディング（導入支援）を学びます。", "summary": ["契約手続きはスピードが命。必要書類と承認プロセスを事前に確認", "オンボーディングは「顧客の成功」を支援するプロセス", "最初の90日で顧客満足度が決まる。早期に成功体験を提供"], "sections": [{"type": "text", "title": "契約手続きの重要性", "content": "契約手続きがスムーズにいかないと、せっかくの成約が流れることがあります。\n\n【契約手続きで起こりがちな問題】\n・必要書類が揃わない\n・決裁者の承認が遅れる\n・法務チェックで止まる\n・支払い条件で折り合わない\n\n【営業の役割】\n・必要書類を明確に伝える\n・社内の承認プロセスを確認する\n・法務チェックに必要な情報を提供する\n・こまめに進捗を確認する"}, {"type": "list", "title": "契約手続きの基本フロー", "content": ["【①契約条件の最終確認】価格、支払い条件、契約期間を書面で確認", "【②契約書の作成・送付】契約書を作成し、相手に送付", "【③法務チェック】相手企業の法務部門によるチェック対応", "【④修正・調整】必要に応じて契約条件を修正", "【⑤署名・捺印】双方の署名・捺印を取得", "【⑥契約書の保管】原本を双方で保管"]}, {"type": "text", "title": "オンボーディングとは", "content": "オンボーディングとは、顧客がサービスを使いこなせるようになるまでの導入支援です。\n\n【オンボーディングの目的】\n・顧客がサービスの価値を実感できるようにする\n・初期の疑問・不安を解消する\n・長期的な利用・リピートにつなげる\n\n【オンボーディングの重要性】\n・最初の90日で顧客の満足度が決まる\n・オンボーディングが不十分だと解約につながる\n・成功体験を早期に提供することが重要"}, {"type": "list", "title": "Symphonyでのオンボーディング例", "content": ["【①キックオフミーティング】導入の流れ、スケジュールを説明", "【②初期設定サポート】マスタデータの登録、初期設定を支援", "【③操作トレーニング】実際の画面を見せながら操作方法を説明", "【④運用開始】本番利用を開始、質問に随時対応", "【⑤1週間後フォロー】困りごとがないか確認", "【⑥1ヶ月後レビュー】利用状況を確認、活用促進のアドバイス"]}]}'::jsonb, 62, '2026-01-21T18:05:27.52344+00:00', '2026-01-21T18:05:27.52344+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (63, 'F', 'フォローアップ設計', '継続関係を築く', 20, '若手', '{"goal": "フォローアップの重要性を理解し、計画的に既存顧客をフォローできるようになる", "quote": {"text": "売った後にどれだけ関われるかが、営業の真価を問われる。", "author": "Symphony営業格言"}, "purpose": "新規獲得の5倍のコストがかかると言われる新規営業より、既存顧客との関係維持は効率的です。リピート・紹介につなげるフォローアップの設計を学びます。", "summary": ["新規獲得より既存顧客維持の方が5倍効率的", "導入直後、1週間、1ヶ月、3ヶ月、定期的にフォロー", "フォローは「売り込み」ではなく「価値提供」"], "sections": [{"type": "text", "title": "フォローアップの重要性", "content": "【1:5の法則】\n新規顧客獲得コストは、既存顧客維持コストの5倍かかる。\n\n【5:25の法則】\n顧客離れを5%改善すれば、利益は25%以上向上する。\n\n【既存顧客の価値】\n・リピート購入の可能性\n・アップセル・クロスセルの機会\n・紹介による新規顧客獲得\n・長期的な安定収益"}, {"type": "list", "title": "フォローアップのタイミング", "content": ["【導入直後】困りごとがないか確認。早期に問題を発見・解消", "【1週間後】使い始めて出てきた疑問に対応", "【1ヶ月後】利用状況を確認。活用が進んでいなければサポート", "【3ヶ月後】効果の確認。導入効果を数値で示す", "【契約更新前】更新の意思確認。追加ニーズのヒアリング", "【定期的】年に2〜4回は接点を持つ。ニュース、事例の共有"]}, {"type": "list", "title": "フォローアップの内容", "content": ["【利用状況の確認】「システムは問題なくお使いいただけていますか」", "【効果の確認】「導入前と比べて、どのような変化がありましたか」", "【追加ニーズの確認】「他にお困りのことはございませんか」", "【情報提供】「新機能のご案内です」「他社の活用事例をお伝えします」", "【紹介依頼】「お知り合いで同じ課題をお持ちの方はいらっしゃいますか」"]}, {"type": "text", "title": "顧客との接点を増やす工夫", "content": "【定期的なコミュニケーション】\n・ニュースレター、メルマガの配信\n・新機能のお知らせ\n・業界ニュースの共有\n・季節の挨拶（年賀状、暑中見舞い）\n\n【イベント・セミナー】\n・ユーザー会の開催\n・活用セミナーへの招待\n・展示会での再会\n\n【訪問・対面】\n・定期的な訪問\n・経営層への表敬訪問\n・導入効果のレビュー会議"}]}'::jsonb, 63, '2026-01-21T18:05:28.061939+00:00', '2026-01-21T18:05:28.061939+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (64, 'F', '案件管理', 'パイプラインで売上を予測する', 25, '中堅', '{"goal": "パイプライン管理の概念を理解し、自分の案件を適切に管理できるようになる", "quote": {"text": "測定できないものは、改善できない。案件を数値で管理せよ。", "author": "ピーター・ドラッカー（意訳）"}, "purpose": "営業活動を「感覚」ではなく「データ」で管理することで、売上予測と目標達成の精度が向上します。パイプライン管理の技術を学びます。", "summary": ["パイプライン管理で、案件の進捗と売上予測を可視化", "金額×確度で加重金額を算出し、精度の高い予測を", "毎日更新、週次レビューで案件を「管理」する"], "sections": [{"type": "text", "title": "パイプライン管理とは", "content": "パイプライン管理とは、商談の進捗を段階ごとに管理し、売上を予測する手法です。\n\n【パイプラインのイメージ】\nリスト → アポ → 初回商談 → 提案 → 交渉 → 成約\n\n【パイプライン管理のメリット】\n・現在の案件状況が一目でわかる\n・将来の売上を予測できる\n・ボトルネックを特定できる\n・優先すべき案件が明確になる"}, {"type": "list", "title": "パイプラインの段階設計", "content": ["【①リード】見込み客を特定した段階", "【②アポ獲得】商談の約束を取り付けた段階", "【③初回商談】初めて顧客と商談した段階", "【④ニーズ把握】顧客の課題・ニーズを把握した段階", "【⑤提案】提案書を提出した段階", "【⑥交渉】価格・条件を交渉している段階", "【⑦成約】契約が締結された段階", "【⑧失注】案件が失われた段階（理由を記録）"]}, {"type": "text", "title": "案件の評価指標", "content": "【金額】案件の予想売上金額\n【確度】成約の確率（%）\n【予想時期】成約が見込まれる時期\n【加重金額】金額×確度で算出\n\n【例】\n案件A：100万円 × 80% = 80万円（加重金額）\n案件B：200万円 × 30% = 60万円（加重金額）\n\n加重金額を合計すると、より精度の高い売上予測ができます。\n\n【確度の目安】\n10%：ニーズ確認前\n30%：ニーズ確認済み\n50%：提案済み\n80%：交渉中（価格・条件の調整）\n100%：成約"}, {"type": "list", "title": "パイプライン管理の実践", "content": ["【毎日更新】案件の進捗を毎日記録。放置しない", "【週次レビュー】週に1回、全案件を見直す", "【停滞案件への対処】2週間動きがない案件はアクションを起こす", "【パイプラインの健全性】各段階に適切な数の案件があるか確認", "【KPIの設定】各段階の転換率を目標設定し、改善を図る"]}]}'::jsonb, 64, '2026-01-21T18:05:29.280153+00:00', '2026-01-21T18:05:29.280153+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (65, 'G', '反論対処の基本フレームワーク', 'LSCPA法', 20, '若手', '{"goal": "顧客の反論を恐れずに受け止め、LSCPA法で冷静に対処できるようになる", "quote": {"text": "反論は拒絶ではない。それは、もっと情報が欲しいという要求だ。", "author": "ブライアン・トレーシー"}, "purpose": "顧客の反論は「関心」のサインです。反論に動じず、適切に対処するための基本フレームワーク「LSCPA法」を習得します。", "summary": ["反論は「関心」のサイン。恐れる必要はない", "LSCPA法：傾聴→共感→明確化→提示→確認の5ステップ", "まず聞き、共感してから、解決策を提示する"], "sections": [{"type": "text", "title": "反論は「関心」のサイン", "content": "顧客の反論は、ネガティブなものではありません。\n\n【反論の意味】\n・興味があるから質問している\n・納得したいから確認している\n・不安を解消したいと思っている\n\n興味がなければ、反論すらしません。反論は「もっと説明してほしい」というサインなのです。"}, {"type": "list", "title": "LSCPA法とは", "content": ["【L = Listen（傾聴）】まず顧客の話を最後まで聞く。遮らない、否定しない", "【S = Share（共感）】「おっしゃる通りですね」「そのように感じるのは当然です」と共感を示す", "【C = Clarify（明確化）】「具体的には、どの点が気になりますか」と真の懸念を特定する", "【P = Present（提示）】懸念に対する解決策や情報を提示する", "【A = Ask（確認）】「これで疑問は解消されましたか」と確認し、次のステップへ"]}, {"type": "text", "title": "LSCPA法の実践例", "content": "【顧客】「ちょっと高いですね」\n\n【L：傾聴】「なるほど...」（最後まで聞く）\n【S：共感】「おっしゃる通り、初期投資としては気になる金額ですよね」\n【C：明確化】「ちなみに、他のサービスと比較されての印象でしょうか、それとも予算との兼ね合いでしょうか」\n【P：提示】「実は、月々に換算すると○○円で、導入3ヶ月で元が取れる計算になります」\n【A：確認】「この投資対効果で考えると、いかがでしょうか」"}, {"type": "list", "title": "反論対処のNG行動", "content": ["【即座に反論する】「いえ、そうではなくて...」→ 顧客を否定している印象を与える", "【言い訳をする】「でも、それは...」→ 防御的に聞こえる", "【話を遮る】顧客が話している途中で反論 → 聞いていないと感じさせる", "【感情的になる】「そんなことはありません！」→ 信頼を失う"]}]}'::jsonb, 65, '2026-01-21T18:05:30.463875+00:00', '2026-01-21T18:05:30.463875+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (66, 'G', '「高い」と言われた時の対処法', NULL, 20, '若手', '{"goal": "「高い」と言われても動じず、価値を伝えることで価格への懸念を解消できるようになる", "quote": {"text": "価格は忘れられるが、品質は記憶に残る。", "author": "グッチオ・グッチ"}, "purpose": "「高い」は営業が最も多く受ける反論です。価格ではなく「価値」で勝負するための対処法を学びます。", "summary": ["「高い」には3つの意味がある。まず何と比較しているか確認", "価格ではなく「価値」で説明する（ROI、時間削減、事例）", "簡単に値引きしない。する場合は条件をつける"], "sections": [{"type": "list", "title": "「高い」の3つの意味", "content": ["【①予算オーバー】本当に予算がない。金額を下げるか、分割を提案", "【②価値が見えない】価格に見合う価値がわからない。価値を再説明", "【③交渉のポーズ】値引きを引き出したい。すぐに値引きしない"]}, {"type": "text", "title": "「高い」への基本対応", "content": "【ステップ1：受け止める】\n「確かに、金額だけ見ると高く感じますよね」\n\n【ステップ2：何と比較しているか確認】\n「ちなみに、何と比較されての印象でしょうか」\n- 競合製品と比較 → 差別化ポイントを説明\n- 予算と比較 → 予算感を確認\n- 漠然と「高い」→ 価値を再説明\n\n【ステップ3：価値で説明】\n「月額で考えると1日○○円、コーヒー1杯分です」\n「年間○○時間の削減効果があり、時給換算で○○円の価値があります」"}, {"type": "list", "title": "価値で伝える技術", "content": ["【分解する】「月額○○円、1日あたり○○円です」", "【比較する】「競合A社は○○円ですが、弊社は△△の機能が追加でついています」", "【ROIで示す】「3ヶ月で投資回収できます」", "【損失を示す】「導入しない場合、年間○○円のロスが続きます」", "【事例で示す】「同規模のB社様は、導入後○○の効果が出ています」"]}, {"type": "text", "title": "値引き要求への対応", "content": "【原則】簡単に値引きしない\n\n値引きすると：\n・製品の価値が下がる\n・「最初から高く言っていた」と思われる\n・次回も値引きを求められる\n\n【値引きする場合】\n必ず「条件」をつける：\n「年間契約いただけるなら」\n「今月中にご決断いただけるなら」\n「3拠点同時導入いただけるなら」"}]}'::jsonb, 66, '2026-01-21T18:05:31.056647+00:00', '2026-01-21T18:05:31.056647+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (67, 'G', '「検討します」を突破する技術', NULL, 20, '若手', '{"goal": "「検討します」で終わらせず、具体的な次のステップを約束できるようになる", "quote": {"text": "曖昧な約束は、約束ではない。", "author": "Symphony営業格言"}, "purpose": "「検討します」は最も厄介な反論です。真意を見極め、次のアクションにつなげる技術を学びます。", "summary": ["「検討します」の真意を質問で確認する", "「ご検討のポイントはどこですか」と具体化する", "必ず「次のアクション」を約束して終わる"], "sections": [{"type": "list", "title": "「検討します」の真意", "content": ["【①本当に検討したい】情報が足りない、社内確認が必要", "【②断りの婉曲表現】「お引き取りください」の遠回し", "【③決断を先延ばし】今決められない、決めたくない", "【④興味がない】話を早く終わらせたい"]}, {"type": "text", "title": "真意を確認する質問", "content": "「ありがとうございます。ぜひ前向きにご検討いただければと思います」\n\n...で終わってはダメ！\n\n【真意を確認する質問】\n「ちなみに、ご検討のポイントはどのあたりでしょうか」\n「他にご確認されたいことはありますか」\n「いつ頃までにご判断される予定でしょうか」\n「ご検討いただくにあたり、追加の資料は必要でしょうか」"}, {"type": "list", "title": "パターン別対応", "content": ["【「社内で相談したい」】→「いつ頃お話しされますか。その後、私からご連絡してもよろしいですか」", "【「資料を見て検討」】→「来週、ご質問にお答えする機会をいただけますか」", "【「予算を確認したい」】→「次年度予算に組み込んでいただくために、何が必要ですか」", "【「他社も見たい」】→「ご比較のポイントをお聞かせください。弊社の優位点をお伝えできます」"]}, {"type": "text", "title": "次のアクションを約束する", "content": "「検討します」で終わらせない秘訣は、具体的な「次のアクション」を約束することです。\n\n【約束すべきこと】\n・いつ連絡するか（「来週火曜日にお電話します」）\n・何を確認するか（「○○についてご確認ください」）\n・いつまでに決めるか（「今月中にご判断いただけますか」）\n\n曖昧な「検討」を、具体的な「約束」に変換しましょう。"}]}'::jsonb, 67, '2026-01-21T18:05:31.804829+00:00', '2026-01-21T18:05:31.804829+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (68, 'G', '「他社と比較したい」への対応', NULL, 20, '中堅', '{"goal": "競合比較を恐れず、自社に有利な比較軸を設定して提案できるようになる", "quote": {"text": "競争相手を批判するな。自分自身を際立たせよ。", "author": "ダン・ケネディ"}, "purpose": "競合比較は避けられません。むしろ歓迎し、比較の「軸」をコントロールすることで優位に立つ技術を学びます。", "summary": ["競合比較は歓迎する。検討フェーズに入っている証拠", "比較の「軸」を自社に有利なものに設定する", "競合を批判せず、自社の強みで勝負する"], "sections": [{"type": "text", "title": "比較を歓迎する姿勢", "content": "「他社と比較したい」と言われた時、焦る必要はありません。\n\n【歓迎する理由】\n・検討フェーズに入っている証拠\n・比較することで自社の良さがわかる\n・比較の「軸」を提示できるチャンス\n\n【対応】\n「ぜひ比較してください。比較していただければ、弊社の良さがわかると思います」"}, {"type": "list", "title": "比較の軸をコントロールする", "content": ["【価格だけで比較させない】「価格だけでなく、サポート体制も比較してみてください」", "【自社が強い軸を提示】「導入実績数で比較いただくと、弊社は業界No.1です」", "【顧客の課題に紐づける】「御社の課題は○○でしたよね。その解決力で比較してみてください」", "【TCO（総所有コスト）で比較】「初期費用だけでなく、運用コストも含めた3年間の総額で比較してみてください」"]}, {"type": "text", "title": "競合の弱みを知る", "content": "競合を批判してはいけませんが、弱みは把握しておきます。\n\n【知っておくべきこと】\n・競合の価格帯\n・競合が弱い機能・サービス\n・競合の評判（良い点・悪い点）\n・競合から乗り換えた顧客の声\n\n【伝え方】\n❌「A社は○○がダメです」\n○「弊社は○○に強みがあります。この点で比較していただければと思います」"}, {"type": "list", "title": "比較検討中のフォロー", "content": ["【情報提供を続ける】比較に役立つ資料、事例を送る", "【質問を促す】「ご不明点があればいつでもご連絡ください」", "【期限を意識させる】「今月中でしたら○○の特典があります」", "【決定プロセスを確認】「いつ頃、どなたがご決定されますか」"]}]}'::jsonb, 68, '2026-01-21T18:05:32.872163+00:00', '2026-01-21T18:05:32.872163+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (69, 'G', '「今は必要ない」を覆す方法', NULL, 20, '中堅', '{"goal": "「今は必要ない」の真意を把握し、潜在ニーズを顕在化させることができるようになる", "quote": {"text": "顧客は自分で気づいた問題しか、本気で解決しようとしない。", "author": "ニール・ラッカム"}, "purpose": "「今は必要ない」は時期の問題なのか、興味がないのかを見極め、適切に対応する技術を学びます。", "summary": ["「今は必要ない」の真意を質問で確認する", "潜在ニーズを顕在化させることで、必要性に気づいてもらう", "今は無理でも、関係を維持して将来につなげる"], "sections": [{"type": "list", "title": "「今は必要ない」の真意", "content": ["【①タイミングの問題】本当に今は忙しい、予算がない、他の優先事項がある", "【②現状に満足】今のやり方で困っていない（と思っている）", "【③価値が伝わっていない】必要性を感じていない", "【④断りの口実】やんわり断りたい"]}, {"type": "text", "title": "真意を確認する質問", "content": "「なるほど、今はご必要ないのですね」で終わらせず、掘り下げます。\n\n【質問例】\n「ちなみに、今は○○でお困りではないということでしょうか」\n「いつ頃でしたら、ご検討いただけそうですか」\n「現在は、どのような方法で○○をされていますか」\n「もし○○という状況になったら、ご検討いただけますか」"}, {"type": "text", "title": "潜在ニーズを顕在化させる", "content": "顧客は「困っていない」と思っていても、実は問題に気づいていないだけかもしれません。\n\n【SPIN話法で気づかせる】\n「在庫管理は今どのようにされていますか」（状況質問）\n「棚卸しにどれくらい時間がかかっていますか」（問題質問）\n「月3日の棚卸しが、年間だと36日になりますね。その時間、他に使えたらどうですか」（示唆質問）\n「もし棚卸しが1日で終わるようになったら、何に時間を使いたいですか」（解決質問）\n\n問題の大きさに気づいてもらうことで、「今は必要ない」が「今こそ必要」に変わります。"}, {"type": "list", "title": "関係を維持する", "content": ["【今は無理でも関係は続ける】「状況が変わりましたら、ぜひお声がけください」", "【定期的に連絡】半年後、1年後にフォローアップ", "【情報提供を続ける】役立つ情報を送り、関係を維持", "【紹介を依頼】「もし同業でお困りの方がいらっしゃれば、ご紹介いただけますか」"]}]}'::jsonb, 69, '2026-01-21T18:05:33.923515+00:00', '2026-01-21T18:05:33.923515+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (70, 'G', '「上に相談しないと」への対応', NULL, 20, '中堅', '{"goal": "担当者を味方につけ、決裁者への橋渡しを成功させることができるようになる", "quote": {"text": "決裁者に会えなければ、決裁者の代わりに営業してくれる人を作れ。", "author": "Symphony営業格言"}, "purpose": "決裁者が別にいる場合の対応技術を学びます。目の前の担当者を「社内営業」の味方にする方法を習得します。", "summary": ["「上に相談」は決裁プロセスを知るチャンス", "担当者を味方につけ、社内営業の武器を渡す", "可能であれば、決裁者に直接説明する機会を得る"], "sections": [{"type": "text", "title": "「上に相談」への基本姿勢", "content": "「上に相談しないと」は、決裁プロセスの確認ができるチャンスです。\n\n【ポジティブに捉える】\n・担当者は前向きに検討している\n・社内稟議のプロセスがわかる\n・決裁者を知る機会\n\n【やってはいけないこと】\n・担当者を飛ばして決裁者に直接アプローチ\n・「あなたには決定権がないのですか」と言う\n・がっかりした態度を見せる"}, {"type": "list", "title": "確認すべき情報", "content": ["【決裁者は誰か】「最終的にどなたがお決めになりますか」", "【決裁プロセス】「社内でどのような流れで決まりますか」", "【決裁基準】「ご判断のポイントは何でしょうか」", "【スケジュール】「いつ頃、お話しされる予定ですか」", "【担当者の意見】「○○様ご自身は、いかがお感じですか」"]}, {"type": "text", "title": "担当者を「社内営業」の味方にする", "content": "担当者が社内で「営業」してくれるよう、武器を渡します。\n\n【提供すべきもの】\n・決裁者向けの要約資料（1ページ）\n・ROIの数字（経営者は数字で判断する）\n・導入事例（同業他社の成功例）\n・FAQ（想定される質問への回答）\n\n【担当者の立場を理解する】\n担当者は「失敗したくない」と思っています。\n「この導入は成功する」という安心感を与えましょう。"}, {"type": "list", "title": "決裁者へのアプローチ", "content": ["【同席を依頼】「上の方にご説明する機会をいただけませんか」", "【オンラインを提案】「お忙しければ、15分のオンラインでも」", "【役員レター】「弊社の役員からご挨拶させていただけませんか」", "【事例セミナー招待】「経営者向けセミナーにご招待させてください」"]}]}'::jsonb, 70, '2026-01-21T18:05:34.978651+00:00', '2026-01-21T18:05:34.978651+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (71, 'G', '価格交渉の原則', '値引きせずに合意する', 25, '上級', '{"goal": "価格交渉において、安易な値引きをせず、Win-Winの合意を導き出せるようになる", "quote": {"text": "価格で負ける営業は、価値を伝えきれていないだけだ。", "author": "Symphony営業格言"}, "purpose": "価格交渉は営業の腕の見せどころです。値引きに頼らず、価値を維持しながら合意に至る交渉技術を学びます。", "summary": ["値引きは最後の手段。まずは価値で勝負する", "譲歩する場合は必ず条件をつける", "値引き以外の選択肢（支払い条件、付加価値）を提案する"], "sections": [{"type": "text", "title": "値引きの罠", "content": "簡単に値引きすることの問題点：\n\n【値引きがもたらす悪影響】\n・利益率の低下（10%の値引き≒50%の利益減）\n・製品・サービスの価値が下がる\n・「最初から高く言っていた」と思われる\n・次回も値引きを期待される\n・他の顧客との公平性が崩れる\n\n【原則】\n値引きは最後の手段。まずは価値で勝負する。"}, {"type": "list", "title": "価格交渉の基本原則", "content": ["【①最初の価格を維持する】簡単に譲らない。最初の価格には根拠がある", "【②価値を再確認する】「価格の根拠」を説明する。なぜこの価格なのか", "【③譲歩には条件をつける】「年間契約なら」「今月中なら」「3拠点同時なら」", "【④全体の価値を広げる】値引きの代わりに付加価値を提供する", "【⑤ゼロサムで考えない】双方が得をする解決策を探す"]}, {"type": "list", "title": "値引き以外の選択肢", "content": ["【支払い条件の調整】分割払い、支払いサイトの延長", "【付加価値の追加】追加研修、サポート期間延長、機能追加", "【スコープの調整】機能を絞って価格を下げる（値引きではない）", "【将来の約束】「次の契約で優遇します」", "【非金銭的価値】導入事例への協力、紹介の約束"]}, {"type": "text", "title": "交渉の技術", "content": "【アンカリング効果】\n最初に提示した価格が基準になる。最初の価格は自信を持って提示する。\n\n【サイレント・クロージング】\n価格を提示したら黙る。沈黙に耐える。先に話した方が譲歩する。\n\n【BATNA（交渉決裂時の代替案）】\n「この顧客がダメでも他がある」という状態が交渉力を高める。\n\n【Win-Winの追求】\n「どうすればお互いにとって良い結果になりますか」と聞く。"}]}'::jsonb, 71, '2026-01-21T18:05:35.791883+00:00', '2026-01-21T18:05:35.791883+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (72, 'G', '競合プレゼン対策', '後出しで勝つ戦略', 25, '上級', '{"goal": "競合プレゼンにおいて、戦略的なポジショニングで勝率を高めることができるようになる", "quote": {"text": "敵を知り己を知れば百戦殆からず。", "author": "孫子"}, "purpose": "コンペ（競合プレゼン）での勝率を上げるための戦略を学びます。特に「後出し」のポジションを活かす技術を習得します。", "summary": ["可能であれば「後攻」を取る。後出しは有利", "競合情報を収集し、差別化ポイントを明確にする", "競合を批判せず、自社の強みで勝負する"], "sections": [{"type": "text", "title": "コンペの順番戦略", "content": "プレゼンの順番は勝敗に影響します。\n\n【先攻のメリット】\n・比較の「基準」を作れる\n・印象に残りやすい（初頭効果）\n\n【後攻のメリット】\n・競合の内容を踏まえて調整できる\n・最後の印象が残る（親近効果）\n・顧客の疑問が明確になっている\n\n【戦略】\n可能であれば「最後」を取る。後出しは圧倒的に有利。"}, {"type": "list", "title": "競合情報の収集", "content": ["【事前に聞く】「他にどちらの会社とご比較されていますか」", "【顧客から聞く】「他社のプレゼンはいかがでしたか」「どんな提案がありましたか」", "【業界情報】競合の価格帯、強み、弱み、最近の動向", "【過去の経験】以前の競合案件での情報を蓄積しておく"]}, {"type": "text", "title": "後出しで勝つ戦術", "content": "【競合の提案内容がわかった場合】\n\n①競合が言わなかったことを強調\n「他社ではあまり触れられないかもしれませんが、弊社は○○に強みがあります」\n\n②競合の弱点を自社の強みで突く\n（競合を批判せずに）「弊社は特に○○を重視しており、この点で選ばれることが多いです」\n\n③競合が出した価格に対応\n「御社のご予算感は○○円程度とお聞きしました。弊社は△△円ですが、○○という価値を考えると...」"}, {"type": "list", "title": "プレゼン後のフォロー", "content": ["【御礼と追加情報】「本日はありがとうございました。追加資料をお送りします」", "【疑問点の確認】「ご質問やご不明点はございませんか」", "【決定プロセスの確認】「いつ頃、どのようにご決定されますか」", "【キーパーソンへのアプローチ】決裁者に別途アプローチできるか確認"]}]}'::jsonb, 72, '2026-01-21T18:05:36.485585+00:00', '2026-01-21T18:05:36.485585+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (73, 'G', '膠着状態の打開', '交渉のデッドロック解消', 25, '上級', '{"goal": "交渉が膠着した時に、創造的な解決策で打開できるようになる", "quote": {"text": "交渉とは、お互いが100%満足することではない。お互いが「これなら受け入れられる」と思える点を見つけることだ。", "author": "ウィリアム・ユーリー"}, "purpose": "交渉が行き詰まった時、どのように打開するか。膠着状態（デッドロック）を解消する高度な交渉技術を学びます。", "summary": ["膠着の原因を特定する（立場の対立、コミュニケーション不足など）", "立場から利害へ、フレーミングの変更、パイを広げるなどの技術で打開", "すべてダメなら撤退も選択肢。ただし関係は維持する"], "sections": [{"type": "list", "title": "膠着状態の原因", "content": ["【立場の対立】お互いが自分の立場に固執している", "【コミュニケーション不足】真のニーズが共有されていない", "【感情的な対立】過去の経緯、担当者間の相性", "【構造的な問題】予算、権限、社内政治の制約", "【情報の非対称性】一方だけが情報を持っている"]}, {"type": "list", "title": "デッドロック解消の技術", "content": ["【①立場から利害へ】「なぜその条件が必要なのですか」と真のニーズを探る", "【②フレーミングの変更】問題の捉え方を変える。「コストの問題」を「投資対効果の問題」に", "【③パイを広げる】ゼロサムではなく、双方の利益を増やす解決策を探す", "【④分割して合意】全体で合意できなくても、部分で合意を積み重ねる", "【⑤条件の交換】「○○は譲る代わりに、△△をいただけますか」"]}, {"type": "text", "title": "具体的な打開策", "content": "【一度離れる】\n「少し時間をおきましょう」\n冷却期間を置くことで、冷静になれる。\n\n【第三者を入れる】\n「上司を連れてきます」「技術担当を同席させます」\n新しい視点が入ることで、打開できることも。\n\n【論点を変える】\n「価格の話は一旦置いて、導入スケジュールについて話しませんか」\n合意できる論点から攻める。\n\n【仮定の質問】\n「もし○○が可能だとしたら、ご検討いただけますか」\n条件を変えて可能性を探る。"}, {"type": "text", "title": "最終手段：交渉決裂", "content": "すべての手を尽くしても合意できない場合、「交渉決裂」も選択肢です。\n\n【撤退の判断基準】\n・採算が合わない\n・将来的にも見込みがない\n・関係が悪化するリスクがある\n\n【撤退の仕方】\n「今回は残念ですが、条件が合わないようです。またの機会がございましたら、よろしくお願いいたします」\n\n関係は維持する。将来、状況が変わることもある。"}]}'::jsonb, 73, '2026-01-21T18:05:37.261634+00:00', '2026-01-21T18:05:37.261634+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (74, 'G', '「NO」と言われた後の関係維持', NULL, 20, '中堅', '{"goal": "断られても適切に関係を維持し、将来的なビジネスチャンスにつなげることができるようになる", "quote": {"text": "今日の「NO」は、明日の「YES」になることがある。関係を絶やすな。", "author": "Symphony営業格言"}, "purpose": "断られた後も関係を維持し、将来の機会につなげる技術を学びます。「NO」は終わりではなく、関係の始まりです。", "summary": ["「NO」は終わりではなく、関係の新たな始まり", "断られた理由を確認し、学びに変える", "定期的なフォローで関係を維持し、将来の機会を待つ"], "sections": [{"type": "text", "title": "「NO」の受け止め方", "content": "断られた時の正しい姿勢：\n\n【やってはいけないこと】\n・感情的になる\n・しつこく食い下がる\n・嫌味を言う\n・二度と連絡しない\n\n【正しい対応】\n「承知いたしました。ご検討いただきありがとうございました」\n潔く引くことで、むしろ印象が良くなる。"}, {"type": "list", "title": "断られた理由を確認する", "content": ["【質問例】「差し支えなければ、今回見送られた理由をお聞かせいただけますか」", "【競合に負けた場合】「どの点が決め手になりましたか」「今後の参考にさせてください」", "【タイミングの問題】「いつ頃でしたら、再度ご提案できそうですか」", "【学びに変える】断られた理由を記録し、次に活かす"]}, {"type": "list", "title": "関係維持の方法", "content": ["【御礼を伝える】「お時間をいただきありがとうございました」", "【将来への布石】「状況が変わりましたら、ぜひお声がけください」", "【定期的な接点】半年〜1年後にフォローアップ。ニュースレター、情報提供", "【紹介を依頼】「もし同業でお困りの方がいらっしゃれば、ご紹介いただけますか」", "【SNSでつながる】LinkedInなどで緩やかにつながりを維持"]}, {"type": "text", "title": "「NO」からの逆転事例", "content": "一度断られても、将来的に受注できることは珍しくありません。\n\n【逆転のきっかけ】\n・競合に不満が出た\n・担当者が変わった\n・予算がついた\n・課題が顕在化した\n\n【統計】\n断られた案件の約30%は、1年以内に再検討されるというデータもあります。\n\n関係を維持し続けることで、そのタイミングで声がかかる可能性があります。"}]}'::jsonb, 74, '2026-01-21T18:05:37.951784+00:00', '2026-01-21T18:05:37.951784+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (75, 'H', 'DiSC理論による顧客タイプ分類', NULL, 25, '中堅', '{"goal": "顧客の言動からDiSCタイプを見極め、タイプに合わせた対応ができるようになる", "quote": {"text": "Treat others as they want to be treated.", "author": "プラチナルール"}, "purpose": "DiSC理論を用いて顧客の行動特性を4つのタイプに分類し、タイプに応じた最適なコミュニケーション方法を習得します。", "summary": ["DiSCは行動特性を4タイプに分類する理論", "顧客の言動からタイプを見極める", "タイプに合わせて対応を変える", "自分のタイプも理解しておく"], "sections": [{"type": "text", "title": "DiSC理論とは", "content": "DiSCは、人間の行動特性を4つのタイプに分類する心理学モデルです。1920年代に心理学者ウィリアム・マーストンが提唱し、現在は世界中のビジネスで活用されています。\n\nD（Dominance/主導型）：結果重視、決断が速い\ni（Influence/感化型）：人間関係重視、楽観的\nS（Steadiness/安定型）：協調性重視、慎重\nC（Conscientiousness/慎重型）：正確性重視、分析的"}, {"type": "list", "title": "各タイプの特徴", "content": ["D型：「結論から言え」「無駄話は不要」が口癖。決断が速く、主導権を握りたがる", "i型：「楽しそう！」「一緒にやろう」が口癖。雑談好きで、人間関係を重視", "S型：「みんなはどう思う？」「急がなくていい」が口癖。変化を嫌い、安定を好む", "C型：「データは？」「根拠は？」が口癖。細部にこだわり、慎重に判断"]}, {"type": "list", "title": "タイプ別対応の基本", "content": ["D型には：結論ファースト、選択肢を提示、時間を奪わない", "i型には：雑談から入る、褒める、楽しさを演出", "S型には：急かさない、安心感を与える、チームの意見を聞く", "C型には：データ・根拠を示す、詳細を説明、質問に丁寧に答える"]}]}'::jsonb, 75, '2026-01-21T18:05:38.539077+00:00', '2026-01-21T18:05:38.539077+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (76, 'H', '主導型（D）オーナーへの対応', NULL, 20, '中堅', '{"goal": "D型顧客に対して、結論ファーストで効率的な提案ができるようになる", "quote": {"text": "Time is money.", "author": "ベンジャミン・フランクリン"}, "purpose": "主導型（D）タイプの顧客の特徴を深く理解し、彼らが求めるコミュニケーションスタイルを習得します。", "summary": ["D型は結果重視・即断即決タイプ", "結論ファーストで話す", "選択肢を提示して主導権を渡す", "時間を奪わない効率的な提案を"], "sections": [{"type": "list", "title": "D型オーナーの特徴", "content": ["結果・成果を重視する", "決断が速く、即断即決を好む", "主導権を握りたがる", "無駄な時間を嫌う", "競争心が強い"]}, {"type": "list", "title": "D型への対応ポイント", "content": ["結論から話す：「本日お伝えしたいのは3点です」", "選択肢を提示：「AとBどちらがよろしいですか？」", "時間を奪わない：「5分だけお時間ください」", "数字で語る：「売上20%アップの実績があります」", "主導権を渡す：「ご判断はお任せします」"]}, {"type": "list", "title": "D型へのNG対応", "content": ["長い前置き、回りくどい説明", "優柔不断な態度", "細かすぎる説明", "決断を急かさない姿勢（逆に急かしてOK）"]}]}'::jsonb, 76, '2026-01-21T18:05:39.641605+00:00', '2026-01-21T18:05:39.641605+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (77, 'H', '感化型（i）オーナーへの対応', NULL, 20, '中堅', '{"goal": "i型顧客に対して、楽しく人間関係を重視した提案ができるようになる", "quote": {"text": "People dont care how much you know until they know how much you care.", "author": "セオドア・ルーズベルト"}, "purpose": "感化型（i）タイプの顧客の特徴を深く理解し、彼らが求めるコミュニケーションスタイルを習得します。", "summary": ["i型は人間関係重視・楽観タイプ", "雑談から入り関係を築く", "褒めて承認欲求を満たす", "楽しさとビジョンを伝える"], "sections": [{"type": "list", "title": "i型オーナーの特徴", "content": ["人間関係を重視する", "楽観的でポジティブ", "雑談が好き、話が長い", "承認欲求が強い", "新しいことが好き"]}, {"type": "list", "title": "i型への対応ポイント", "content": ["雑談から入る：「最近お店の調子いかがですか？」", "褒める：「さすがですね！」「素晴らしい取り組みですね」", "楽しさを演出：「これ、面白い機能なんですよ」", "人の話をする：「他のオーナーさんも喜んでました」", "ビジョンを語る：「これで〇〇が実現できます」"]}, {"type": "list", "title": "i型へのNG対応", "content": ["いきなり本題に入る", "データや数字ばかりの説明", "否定的な言葉", "細かい契約条件の話"]}]}'::jsonb, 77, '2026-01-21T18:05:40.196614+00:00', '2026-01-21T18:05:40.196614+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (78, 'H', '安定型（S）オーナーへの対応', NULL, 20, '中堅', '{"goal": "S型顧客に対して、安心感を与える丁寧な提案ができるようになる", "quote": {"text": "Slow and steady wins the race.", "author": "イソップ寓話"}, "purpose": "安定型（S）タイプの顧客の特徴を深く理解し、彼らが求めるコミュニケーションスタイルを習得します。", "summary": ["S型は協調性重視・安定志向タイプ", "急かさず安心感を与える", "チームの意見を尊重する", "リスクも正直に伝える"], "sections": [{"type": "list", "title": "S型オーナーの特徴", "content": ["協調性を重視する", "変化を嫌い、安定を好む", "慎重で決断に時間がかかる", "チームや家族の意見を大切にする", "争いを避けたがる"]}, {"type": "list", "title": "S型への対応ポイント", "content": ["急かさない：「ゆっくりご検討ください」", "安心感を与える：「サポートは万全です」", "チームの意見を聞く：「スタッフの方のご意見は？」", "リスクを説明：「デメリットも正直にお伝えします」", "実績を示す：「10年以上の実績があります」"]}, {"type": "list", "title": "S型へのNG対応", "content": ["急かす、プレッシャーをかける", "大きな変化を一度に提案", "リスクを隠す", "「今すぐ決めてください」"]}]}'::jsonb, 78, '2026-01-21T18:05:40.994835+00:00', '2026-01-21T18:05:40.994835+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (79, 'H', '慎重型（C）オーナーへの対応', NULL, 20, '中堅', '{"goal": "C型顧客に対して、データと論理に基づいた提案ができるようになる", "quote": {"text": "In God we trust. All others must bring data.", "author": "W・エドワーズ・デミング"}, "purpose": "慎重型（C）タイプの顧客の特徴を深く理解し、彼らが求めるコミュニケーションスタイルを習得します。", "summary": ["C型は正確性重視・分析タイプ", "データと根拠で語る", "詳細を丁寧に説明する", "質問には誠実に答える"], "sections": [{"type": "list", "title": "C型オーナーの特徴", "content": ["正確性・品質を重視する", "データや根拠を求める", "細部にこだわる", "慎重で分析的", "感情より論理を重視"]}, {"type": "list", "title": "C型への対応ポイント", "content": ["データで語る：「導入企業の87%が効果を実感」", "根拠を示す：「この機能は〇〇の研究に基づいています」", "詳細を説明：「仕組みを詳しくご説明します」", "質問に丁寧に答える：「良いご質問ですね」", "資料を残す：「詳細資料をお渡しします」"]}, {"type": "list", "title": "C型へのNG対応", "content": ["感覚的な説明「なんとなく良い」", "大雑把な数字", "質問をはぐらかす", "「みんな使ってます」だけの説明"]}]}'::jsonb, 79, '2026-01-21T18:05:41.588174+00:00', '2026-01-21T18:05:41.588174+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (80, 'H', '世代別コミュニケーション', 'ベテラン経営者編', 20, '上級', '{"goal": "ベテラン経営者に対して、経験と実績を尊重した提案ができるようになる", "quote": {"text": "Experience is the teacher of all things.", "author": "ユリウス・カエサル"}, "purpose": "ベテラン経営者（50代以上）の価値観と経験を理解し、彼らに響くコミュニケーション方法を習得します。", "summary": ["ベテラン経営者の経験を尊重する", "教えを請う謙虚な姿勢で", "変化の必要性は丁寧に説明", "段階的な提案で安心感を"], "sections": [{"type": "list", "title": "ベテラン経営者の特徴", "content": ["豊富な経験と実績がある", "「昔ながらのやり方」への愛着", "人間関係・信頼を重視", "新しい技術への抵抗感がある場合も", "「若造に何がわかる」と思われがち"]}, {"type": "list", "title": "ベテラン経営者への対応ポイント", "content": ["経験を尊重：「長年のご経験から〇〇ですよね」", "教えを請う姿勢：「ぜひ教えていただきたいのですが」", "変化の必要性を丁寧に：「時代の変化で〇〇が変わってきています」", "段階的な提案：「まずは小さく始めてみませんか」", "成功事例を示す：「同世代のオーナー様も〇〇で成果を」"]}, {"type": "list", "title": "NG対応", "content": ["「今どきは〜」と上から目線", "専門用語の羅列", "経験を否定する言い方", "急激な変化の押し付け"]}]}'::jsonb, 80, '2026-01-21T18:05:42.173473+00:00', '2026-01-21T18:05:42.173473+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (81, 'H', '世代別コミュニケーション', '若手経営者編', 20, '上級', '{"goal": "若手経営者に対して、効率性とビジョンを重視した提案ができるようになる", "quote": {"text": "Move fast and break things.", "author": "マーク・ザッカーバーグ"}, "purpose": "若手経営者（30-40代）の価値観と志向を理解し、彼らに響くコミュニケーション方法を習得します。", "summary": ["若手経営者は効率性を重視", "デジタル・スピード・コスパで訴求", "ビジョンと成長機会を語る", "対等なパートナーとして接する"], "sections": [{"type": "list", "title": "若手経営者の特徴", "content": ["デジタルネイティブ世代", "効率性・生産性を重視", "新しいことへの抵抗が少ない", "SNSやオンラインに強い", "ワークライフバランスを重視"]}, {"type": "list", "title": "若手経営者への対応ポイント", "content": ["効率化を訴求：「作業時間が50%削減できます」", "デジタル活用：「スマホで完結します」", "スピード感：「すぐに始められます」", "コスパを示す：「ROI200%の実績」", "ビジョンを語る：「業界を変える取り組みです」"]}, {"type": "list", "title": "NG対応", "content": ["「若いのに立派ですね」と上から目線", "紙ベースの資料だけ", "非効率なプロセス", "過去の成功体験の押し付け"]}]}'::jsonb, 81, '2026-01-21T18:05:42.830085+00:00', '2026-01-21T18:05:42.830085+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (82, 'H', '複数キーパーソンへの対応', '社内政治の読み方', 25, '上級', '{"goal": "複数のキーパーソンを特定し、それぞれに適切なアプローチができるようになる", "quote": {"text": "Politics is the art of the possible.", "author": "オットー・フォン・ビスマルク"}, "purpose": "組織内に複数の意思決定者がいる場合の対応方法を学び、社内政治を読み解く力を養います。", "summary": ["キーパーソンは複数存在する", "決裁者だけでなく影響者も重要", "反対者の懸念を先に把握", "担当者を社内営業マンにする"], "sections": [{"type": "list", "title": "キーパーソンの種類", "content": ["決裁者（Decision Maker）：最終決定権を持つ人", "影響者（Influencer）：決裁者に影響を与える人", "利用者（User）：実際に使う現場の人", "門番（Gatekeeper）：情報をコントロールする人", "反対者（Blocker）：導入に反対する人"]}, {"type": "list", "title": "社内政治を読むポイント", "content": ["「誰が本当の決裁者か」を見極める", "「誰の意見が重視されるか」を観察", "「反対しそうな人は誰か」を把握", "「担当者の社内での立場」を理解", "「意思決定のプロセス」を確認"]}, {"type": "list", "title": "複数キーパーソンへの対応", "content": ["全員の利益を考えた提案をする", "反対者の懸念を先に潰す", "影響者を味方につける", "担当者が社内で説明しやすい資料を渡す", "各人に合わせた伝え方を使い分ける"]}]}'::jsonb, 82, '2026-01-21T18:05:43.438817+00:00', '2026-01-21T18:05:43.438817+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (83, 'I', '戦略的アカウントプランニング', NULL, 30, '上級', '{"goal": "キーアカウントに対する12ヶ月のアカウントプランを策定し、戦略的な関係構築ができるようになる", "quote": {"text": "最も重要な顧客の20%が、売上の80%を生み出す。その20%に戦略的に取り組むことが成功への道だ。", "author": "パレートの法則より"}, "purpose": "重要顧客（キーアカウント）に対して、場当たり的な営業ではなく、中長期的な視点で戦略的にアプローチする方法を習得します。顧客のビジネス全体を理解し、パートナーとして価値を提供し続ける関係構築を目指します。", "summary": ["アカウントプランニングは重要顧客への戦略的アプローチ手法", "顧客プロファイル、関係性マップ、機会分析、目標、アクションの5要素で構成", "推進者（Champion）を見つけ、育てることが成功の鍵"], "sections": [{"type": "text", "title": "アカウントプランニングとは", "content": "アカウントプランニングとは、重要顧客に対して戦略的・計画的にアプローチするための手法です。単発の商談ではなく、顧客のビジネス全体を理解し、長期的なパートナーシップを築くことを目指します。\n\n一般的な営業：製品を売ることが目的 / 商談単位で考える / 短期的な売上重視\n戦略的アカウント：顧客の成功が目的 / 年間計画で考える / 長期的な関係重視"}, {"type": "list", "title": "アカウントプランの5つの構成要素", "content": ["1. 顧客プロファイル：企業情報、組織図、キーパーソン、意思決定プロセス、現在の課題", "2. 関係性マップ：誰が意思決定者か、誰が影響力を持つか、誰が協力者になりうるか", "3. 機会分析：現在の取引状況、拡大余地、クロスセル/アップセル機会、競合状況", "4. 目標設定：売上目標、関係深化目標、具体的なマイルストーン", "5. アクションプラン：四半期ごとの具体的なアクション、接点計画、提案タイミング"]}, {"type": "text", "title": "関係性マップの作り方", "content": "顧客組織内の人間関係を可視化することで、効果的なアプローチが可能になります。\n\n意思決定者（Decision Maker）：最終決裁権を持つ人\n影響者（Influencer）：意思決定に影響を与える人\n推進者（Champion）：社内で推進してくれる協力者\n利用者（User）：実際に製品を使う人\n門番（Gatekeeper）：情報をコントロールする人\n\n→ 推進者（Champion）を見つけ、育てることが成功の鍵！"}]}'::jsonb, 83, '2026-01-21T18:05:44.08316+00:00', '2026-01-21T18:05:44.08316+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (84, 'I', 'ソリューションセリング', '課題解決型営業の極意', 30, '上級', '{"goal": "顧客の表面的なニーズではなく、本質的な課題を発見し、ソリューションとして提案できるようになる", "quote": {"text": "顧客は4分の1インチのドリルが欲しいのではない。4分の1インチの穴が欲しいのだ。", "author": "セオドア・レビット（ハーバード・ビジネススクール教授）"}, "purpose": "製品の機能を売るのではなく、顧客の課題を解決する「ソリューション」を提案する営業手法を習得します。顧客のビジネス課題を深く理解し、最適な解決策を共に創り上げるスキルを身につけます。", "summary": ["製品を売るのではなく、課題解決という「価値」を売る", "課題発見→定量化→ソリューション設計→価値証明の4ステップ", "顧客自身に課題の重要性を認識してもらうことが成約への近道"], "sections": [{"type": "comparison", "title": "製品営業 vs ソリューション営業", "content": "❌ 製品営業のアプローチ：「この製品はこんな機能があります」「今ならお得なキャンペーン中です」「競合より安いです」→ 価格競争に巻き込まれる\n\n✅ ソリューション営業のアプローチ：「御社の課題は何ですか？」「その課題が解決されると、どのような効果がありますか？」「最適な解決策を一緒に考えましょう」→ 価値で選ばれる"}, {"type": "list", "title": "ソリューションセリングの4ステップ", "content": ["1. 課題発見：顧客が認識している課題だけでなく、潜在的な課題も発見する。「なぜ？」を5回繰り返して本質に迫る", "2. 課題の定量化：課題を数値化し、ビジネスインパクトを明確にする。「この課題によって、年間いくらの損失が出ていますか？」", "3. ソリューション設計：製品・サービスを組み合わせて、最適な解決策を設計する。顧客と共に創り上げる意識が重要", "4. 価値の証明：導入効果を具体的に示し、投資対効果（ROI）を明確にする。事例やシミュレーションを活用"]}, {"type": "text", "title": "課題を深掘りする質問技法", "content": "表面的な課題から本質的な課題へ深掘りする質問パターン：\n\n状況質問：「現在、○○についてどのように対応されていますか？」\n問題質問：「○○について、困っていることはありますか？」\n示唆質問：「もしこの状況が続くと、どのような影響がありますか？」\n解決質問：「もしこの課題が解決されたら、どのような効果がありますか？」\n\n→ 顧客自身に課題の重要性を認識してもらうことがポイント"}]}'::jsonb, 84, '2026-01-21T18:05:44.683922+00:00', '2026-01-21T18:05:44.683922+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (85, 'I', 'コンサルティブセリング', '信頼されるアドバイザーへ', 30, '上級', '{"goal": "顧客から「この人に相談したい」と思われる信頼されるアドバイザーになる", "quote": {"text": "人は、あなたが自分のことをどれだけ気にかけているかを知るまで、あなたがどれだけ知っているかなど気にしない。", "author": "セオドア・ルーズベルト"}, "purpose": "単なる「営業担当者」から、顧客にとって信頼される「アドバイザー」へと進化するための考え方とスキルを習得します。顧客のビジネスパートナーとして、長期的な信頼関係を構築します。", "summary": ["信頼されるアドバイザー = 専門性 + 誠実さ + 親密さ - 自己利益", "顧客の利益を最優先に考え、時には売らない勇気も必要", "製品を超えた価値提供で、長期的な信頼関係を構築する"], "sections": [{"type": "list", "title": "信頼されるアドバイザーの条件", "content": ["1. 専門性（Expertise）：業界知識、製品知識、課題解決の知見を持っている", "2. 誠実さ（Integrity）：顧客の利益を最優先に考え、正直に行動する", "3. 親密さ（Intimacy）：顧客のビジネスと個人的な関心事を深く理解している", "4. 自己利益の低さ（Low Self-Orientation）：自分の売上より顧客の成功を優先する"]}, {"type": "text", "title": "信頼の方程式", "content": "信頼 = (専門性 + 誠実さ + 親密さ) ÷ 自己利益\n\n→ 分子を大きく、分母を小さくすることで信頼が高まる\n\n自己利益が高い行動（避けるべき）：\n・自社製品を強引に勧める\n・顧客の話を聞かずに説明する\n・短期的な売上を優先する\n\n自己利益が低い行動（目指すべき）：\n・時には競合製品を勧めることも\n・売れなくても正直にデメリットを伝える\n・長期的な関係を重視する"}, {"type": "list", "title": "アドバイザーとして価値を提供する方法", "content": ["業界トレンドの情報提供：「最近の業界動向として...」", "他社事例の共有（守秘義務の範囲で）：「似たような課題を持つA社では...」", "客観的な視点の提供：「外から見ると、御社の強みは...」", "人脈の紹介：「○○にお詳しい方をご紹介しましょうか」", "製品を超えた相談対応：「その件は私の専門外ですが、調べてみます」"]}]}'::jsonb, 85, '2026-01-21T18:05:45.221217+00:00', '2026-01-21T18:05:45.221217+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (86, 'I', '大型案件の進め方', '複雑な意思決定への対応', 30, '上級', '{"goal": "複数のステークホルダーが関わる大型案件を戦略的に進め、成約率を高められるようになる", "quote": {"text": "大型案件を成功させるには、一人の味方ではなく、組織全体を味方につける必要がある。", "author": "ニール・ラッカム（SPIN Selling著者）"}, "purpose": "複数の意思決定者が関わる大型案件において、組織的な営業活動を行うスキルを習得します。複雑な意思決定プロセスを理解し、案件を確実にクロージングまで導きます。", "summary": ["大型案件は複数の意思決定者、複雑なプロセス、長い検討期間が特徴", "チャンピオン（社内推進者）の確保が成功の鍵", "意思決定者ごとに関心事が異なる。それぞれに合わせたアプローチが必要"], "sections": [{"type": "list", "title": "大型案件の特徴", "content": ["意思決定者が複数：担当者、上司、経営層、財務、IT部門など", "意思決定プロセスが複雑：稟議、会議、承認フローが多い", "検討期間が長い：数ヶ月〜1年以上かかることも", "競合が本気で狙ってくる：価格競争、提案競争が激化", "リスクが大きい：顧客も失敗できないプレッシャーを抱えている"]}, {"type": "list", "title": "大型案件を進める5つのステップ", "content": ["1. 意思決定マップの作成：誰が意思決定に関わるか、それぞれの関心事・懸念点を把握する", "2. 推進者の確保：社内で案件を推進してくれる「チャンピオン」を見つけ、育てる", "3. 競合分析：競合の強み・弱みを把握し、差別化ポイントを明確にする", "4. リスク対策：顧客の不安・懸念を先回りして解消する。導入実績、保証、サポート体制など", "5. タイムラインの管理：顧客の意思決定スケジュールに合わせて、適切なタイミングで情報提供・提案を行う"]}, {"type": "text", "title": "意思決定者別のアプローチ", "content": "経営層（社長・役員）：ROI、競争優位性、リスクに関心 → ビジネス成果を強調\n財務担当：コスト、投資回収期間に関心 → 費用対効果を数字で示す\n現場担当：使いやすさ、業務改善に関心 → デモ、トライアルで体験させる\nIT担当：技術仕様、セキュリティ、連携に関心 → 技術資料、検証環境を提供\n\n→ それぞれの「関心事」に合わせて、メッセージをカスタマイズする"}]}'::jsonb, 86, '2026-01-21T18:05:45.7726+00:00', '2026-01-21T18:05:45.7726+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (87, 'I', '紹介営業の極意', '口コミを生む仕組み', 25, '上級', '{"goal": "既存顧客から継続的に紹介を獲得する仕組みを構築し、紹介による売上を増加させる", "quote": {"text": "最高の広告は、満足した顧客である。", "author": "フィリップ・コトラー"}, "purpose": "既存顧客からの紹介を獲得する仕組みを構築し、効率的に新規顧客を開拓するスキルを習得します。紹介は最も成約率が高く、信頼も得やすい貴重なリード獲得方法です。", "summary": ["紹介は成約率が高く、信頼も得やすい最強のリード獲得方法", "圧倒的な顧客満足 + 紹介しやすい状況 + きっかけの提供が条件", "正面からお願いし、紹介者の顔を潰さない対応を徹底する"], "sections": [{"type": "list", "title": "紹介営業のメリット", "content": ["成約率が高い：紹介案件の成約率は通常の2〜3倍", "信頼のスタート：紹介者の信頼が引き継がれる", "営業コストが低い：広告費、テレアポ工数が不要", "質の高い見込み客：紹介者がスクリーニングしてくれている", "価格競争になりにくい：信頼で選ばれるため値引き交渉が少ない"]}, {"type": "list", "title": "紹介を生む3つの条件", "content": ["1. 圧倒的な顧客満足：期待を上回る価値提供。「この営業は良い」と思ってもらうことが前提", "2. 紹介しやすい状況：紹介者にリスクがないこと。紹介先にメリットがあること", "3. きっかけの提供：満足していても、きっかけがないと紹介は生まれない。こちらからお願いする"]}, {"type": "text", "title": "紹介依頼の5ステップ", "content": "① タイミングを見極める：顧客満足が高まっている時（導入成功、成果報告、感謝の言葉をいただいた時）\n② 正面からお願いする：「ご紹介いただけませんか」と直接依頼。遠慮すると伝わらない\n③ 具体的に依頼する：「○○業界の方」「○○にお困りの方」など、紹介しやすい条件を伝える\n④ ハードルを下げる：「名前だけ教えていただければ」「一度話を聞いてもらえれば」\n⑤ 紹介者を守る：紹介先へは丁寧に対応し、紹介者の顔を潰さない。結果を必ず報告する"}]}'::jsonb, 87, '2026-01-21T18:05:46.812939+00:00', '2026-01-21T18:05:46.812939+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (88, 'I', '失注分析と勝率向上', NULL, 25, '上級', '{"goal": "失注原因を体系的に分析し、具体的な改善策を実行して勝率を向上させる", "quote": {"text": "負けから学ぶ者は、いつか必ず勝つ。勝ちから何も学ばない者は、いつか必ず負ける。", "author": "孫子の兵法より"}, "purpose": "失注した案件を徹底的に分析し、勝率向上につなげるスキルを習得します。失注は「次に活かせる貴重なデータ」です。感情的にならず、冷静に分析することで、営業力を継続的に向上させます。", "summary": ["失注原因を「価格・製品・営業・タイミング・組織」の5つに分類して分析", "「なぜ」を繰り返して、表面的な理由から本質的な原因を探る", "失注しても関係を維持し、再提案の機会を待つ"], "sections": [{"type": "list", "title": "失注原因の分類", "content": ["価格要因：競合より高い、予算オーバー、費用対効果が不明確", "製品要因：機能不足、ニーズとのミスマッチ、使い勝手の懸念", "営業要因：提案内容、対応スピード、信頼関係構築の不足", "タイミング要因：検討時期が早すぎた/遅すぎた、他の優先事項", "組織要因：意思決定者へのアプローチ不足、チャンピオン不在"]}, {"type": "text", "title": "失注分析の3ステップ", "content": "① 事実の収集：失注直後に顧客にヒアリング。「差し支えなければ、今回見送られた理由を教えていただけますか？」本音を聞くために、非難せず、感謝の姿勢で聞く\n\n② 原因の深掘り：「なぜ」を繰り返して本質的な原因を探る。表面的な理由（価格が高い）→ 本質的な原因（価値が伝わっていなかった）\n\n③ 改善策の立案：原因ごとに具体的な改善策を決め、次の案件で実行する。改善策は「自分がコントロールできること」に絞る"}, {"type": "list", "title": "失注後のフォロー", "content": ["感謝を伝える：検討いただいたことへのお礼。ドアを閉めない", "関係を維持する：定期的な情報提供、業界動向の共有", "再提案の機会を探る：状況が変わった時、再度チャンスがある", "競合の動向を観察：採用された競合の対応をウォッチ"]}]}'::jsonb, 88, '2026-01-21T18:05:47.353682+00:00', '2026-01-21T18:05:47.353682+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (89, 'I', 'ハイパフォーマーの習慣', NULL, 20, '上級', '{"goal": "ハイパフォーマーの習慣を理解し、自分の営業スタイルに取り入れて成果を向上させる", "quote": {"text": "私たちは繰り返し行うことの結果である。したがって、優秀さとは行為ではなく、習慣なのだ。", "author": "アリストテレス"}, "purpose": "トップセールスが共通して持っている習慣・思考パターンを学び、自身の営業スタイルに取り入れます。才能ではなく「習慣」が結果を生むことを理解し、再現性のある成功パターンを構築します。", "summary": ["ハイパフォーマーの成功要因は「才能」ではなく「習慣」", "徹底した準備、高い行動量、速いレスポンス、継続的な学習が共通点", "小さく始めて、1つずつ習慣化していくことが大切"], "sections": [{"type": "list", "title": "ハイパフォーマーの7つの習慣", "content": ["1. 徹底した準備：商談前の情報収集、シナリオ想定、質問の準備。準備に時間の50%を使う", "2. 高い行動量：量が質を生む。打席に立つ回数が多いから、ヒットも多い", "3. 速いレスポンス：顧客からの問い合わせに即レス。スピード＝信頼", "4. 継続的な学習：業界知識、製品知識、営業スキルを常にアップデート", "5. 振り返りの習慣：毎日/毎週の振り返りで、小さな改善を積み重ねる", "6. 健康管理：体調管理、睡眠、運動。心身のコンディションが成果に直結", "7. ポジティブ思考：困難を成長の機会と捉え、前向きに行動する"]}, {"type": "text", "title": "「才能」ではなく「習慣」", "content": "トップセールスの成功要因を調査すると、「才能」よりも「習慣」の影響が大きいことがわかっています。\n\n才能（変えられない）：10〜20%\n習慣・行動（変えられる）：80〜90%\n\n→ 正しい習慣を身につければ、誰でもハイパフォーマーになれる！"}, {"type": "list", "title": "習慣化の3つのコツ", "content": ["1. 小さく始める：いきなり大きな変化を求めず、まず1つの習慣から", "2. トリガーを設定：「○○したら、△△する」というルールを作る", "3. 記録する：習慣の実行を記録し、可視化する。達成感がモチベーションになる"]}]}'::jsonb, 89, '2026-01-21T18:05:48.049892+00:00', '2026-01-21T18:05:48.049892+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (90, 'I', 'スランプ脱出法', '不調期の乗り越え方', 20, '上級', '{"goal": "スランプに陥った時に冷静に原因を分析し、具体的な脱出策を実行できるようになる", "quote": {"text": "成功は最終的なものではなく、失敗は致命的ではない。大切なのは続ける勇気だ。", "author": "ウィンストン・チャーチル"}, "purpose": "営業にはスランプがつきものです。不調期に陥った時の原因分析と脱出方法を学び、早期に回復するスキルを身につけます。スランプを「成長の機会」として捉え直すマインドセットも習得します。", "summary": ["スランプの原因は、行動量・スキル・メンタル・外部環境・運の5つ", "感覚ではなく数字で現状を把握し、原因を特定することが脱出の第一歩", "基本に立ち返り、小さな成功を積み重ねて自信を回復する"], "sections": [{"type": "text", "title": "スランプの正体", "content": "スランプとは、努力しているのに成果が出ない状態のことです。原因を理解することが脱出の第一歩です。\n\n行動量の低下：忙しさを言い訳に、行動量が減っている\nスキルの停滞：同じやり方を繰り返し、成長が止まっている\nメンタルの低下：自信喪失、モチベーション低下\n外部環境の変化：市場の変化、競合の台頭に対応できていない\n運の要素：短期的には運に左右されることもある"}, {"type": "list", "title": "スランプ脱出の5ステップ", "content": ["1. 数字で現状を把握する：感覚ではなく、ファクトで状況を確認。行動量、商談数、成約率などを数値化", "2. 原因を特定する：どの数字が悪いのか？行動量？成約率？それはなぜか？", "3. 基本に立ち返る：複雑なことを考えず、営業の基本動作を徹底する。量をこなす", "4. 小さな成功を積む：大きな成約を狙わず、小さな成功体験を積み重ねて自信を回復", "5. 環境を変える：担当エリア、アプローチ方法、時間帯などを変えてみる"]}, {"type": "list", "title": "スランプ時のメンタルケア", "content": ["自分を責めすぎない：スランプは誰にでも起こる。自分だけではない", "過去の成功を思い出す：以前成功した時の自分を思い出し、自信を取り戻す", "人に話す：上司、同僚、メンターに相談する。客観的な意見をもらう", "休息を取る：心身の疲労がスランプの原因のこともある。思い切って休む"]}]}'::jsonb, 90, '2026-01-21T18:05:48.600398+00:00', '2026-01-21T18:05:48.600398+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (91, 'I', 'セルフブランディング', '選ばれる営業になる', 25, '上級', '{"goal": "自分の強み・専門性を明確にし、顧客から指名される「セルフブランド」を確立する", "quote": {"text": "ブランドとは、あなたがいない部屋で人々があなたについて何を言うかである。", "author": "ジェフ・ベゾス"}, "purpose": "「あの営業さんから買いたい」と指名される営業になるために、自分自身をブランドとして確立する方法を学びます。商品力だけでなく「人」で選ばれる営業を目指します。", "summary": ["商品力だけでなく「人」で選ばれる時代。セルフブランドが差別化の鍵", "専門性（What）+ 人柄（Who）+ 約束（Promise）の3要素で構成", "一貫したメッセージを発信し続け、実績で裏付ける"], "sections": [{"type": "list", "title": "なぜセルフブランディングが重要か", "content": ["商品の差別化が難しい時代：同じような商品・サービスが溢れている", "「誰から買うか」が決め手になる：信頼できる人から買いたい", "価格競争から脱却できる：「この人から買いたい」は価格を超える", "紹介が増える：「○○さんに相談するといいよ」と言われる存在になれる"]}, {"type": "list", "title": "セルフブランドの3要素", "content": ["1. 専門性（What）：何の専門家か？「中古車販売店のIT導入なら○○さん」", "2. 人柄（Who）：どんな人か？誠実、親身、明るい、頼りになる", "3. 約束（Promise）：何を約束するか？「必ず成果を出す」「最後まで責任を持つ」"]}, {"type": "text", "title": "セルフブランディングの実践方法", "content": "① 自分の強みを棚卸しする：過去の成功体験、顧客からの感謝、得意な領域を書き出す\n② 一言で表現する：「○○の専門家」「△△ならお任せください」というキャッチフレーズを作る\n③ 一貫性を持つ：名刺、メール署名、SNS、会話で一貫したメッセージを発信\n④ 発信する：業界知識、ノウハウ、成功事例を発信。メール、SNS、勉強会などで\n⑤ 実績を積む：ブランドは実績で裏付けられる。成功事例を増やし、信頼を高める"}]}'::jsonb, 91, '2026-01-21T18:05:49.138056+00:00', '2026-01-21T18:05:49.138056+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (92, 'I', '高度な交渉シミュレーション', '実践的な交渉力強化', 25, '上級', '{"goal": "困難な交渉場面でも冷静に対応し、Win-Winの結果を導き出す交渉力を身につける", "quote": {"text": "交渉において最も重要なのは、相手の靴を履いてみることだ。相手の立場を理解して初めて、Win-Winの解決策が見えてくる。", "author": "ハーバード流交渉術より"}, "purpose": "複雑な交渉シナリオを想定したシミュレーションを通じて、実践的な交渉スキルを磨きます。価格交渉、条件交渉、クレーム対応など、さまざまな場面で使える高度な交渉技術を習得します。", "summary": ["交渉は「人と問題を分離」し「利害に焦点」を当てることが基本", "シナリオ別（価格、競合、クレーム、条件）の対応パターンを身につける", "BATNA（交渉の代替案）を把握することで、交渉を有利に進められる"], "sections": [{"type": "list", "title": "交渉の基本原則", "content": ["1. 人と問題を分離する：相手を攻撃するのではなく、問題に焦点を当てる", "2. 立場ではなく利害に焦点を当てる：「何が欲しいか」ではなく「なぜ欲しいか」を探る", "3. お互いの利益になる選択肢を生み出す：パイを奪い合うのではなく、パイを大きくする", "4. 客観的な基準を使う：感情ではなく、市場価格、前例、公平な基準で判断"]}, {"type": "text", "title": "交渉シナリオ別の対応", "content": "価格交渉：「高い」と言われたら、価格の根拠（価値）を説明。単純な値引きではなく、条件交換（長期契約で割引など）を提案\n\n競合比較：競合の悪口は言わない。自社の強み、顧客の課題との適合性で勝負。「競合さんも良い製品ですが、御社の課題には弊社の方が...」\n\nクレーム対応：まず謝罪と共感。原因と対策を説明し、信頼回復に努める。逃げずに向き合う姿勢が大切\n\n納期・条件交渉：できないことは正直に伝える。代替案を提示。「その納期は難しいですが、○○なら可能です」"}, {"type": "text", "title": "BATNA（交渉の代替案）", "content": "BATNAとは「Best Alternative To a Negotiated Agreement」の略で、交渉が決裂した場合の最善の代替案のことです。\n\n自分のBATNAが強い：強気の交渉ができる\n自分のBATNAが弱い：譲歩が必要になる\n\n→ 交渉前に自分と相手のBATNAを把握しておくことで、交渉を有利に進められる"}]}'::jsonb, 92, '2026-01-21T18:05:50.01564+00:00', '2026-01-21T18:05:50.01564+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (93, 'J', '1on1面談設計', NULL, 25, 'MGR', '{"goal": "部下一人ひとりに合わせた1on1を設計し、成長支援と信頼構築ができるようになる", "quote": {"text": "人は話を聞いてもらえたと感じた時、初めて心を開く。", "author": "スティーブン・R・コヴィー"}, "purpose": "部下との1on1面談を効果的に設計・実施するスキルを習得します。1on1は単なる進捗確認ではなく、部下の成長を支援し、信頼関係を構築する重要な機会です。", "summary": ["1on1は業務報告ではなく、部下のための時間", "週1回または隔週、30分以上を確保する", "上司は聞き役に徹し、部下が8割話す"], "sections": [{"type": "text", "title": "1on1面談とは何か", "content": "1on1面談とは、上司と部下が定期的に1対1で行う面談のことです。業務報告の場ではなく、部下のための時間です。\n\n1on1の目的：\n・部下の成長支援（キャリア、スキル）\n・信頼関係の構築\n・早期の問題発見と対処\n・モチベーション向上\n・心理的安全性の醸成"}, {"type": "list", "title": "効果的な1on1の設計", "content": ["頻度：週1回または隔週。月1回では少なすぎる", "時間：30分〜1時間。短すぎると深い話ができない", "場所：個室やオンライン。周囲を気にせず話せる環境", "アジェンダ：部下が主体的に設定。上司は聞き役に徹する", "記録：話した内容と次のアクションを記録。継続性を持たせる"]}, {"type": "list", "title": "1on1で話すべきテーマ", "content": ["業務の進捗・課題：困っていることはないか", "キャリア・成長：どんなスキルを伸ばしたいか", "人間関係：チームメンバーとの関係はどうか", "体調・メンタル：最近の調子はどうか", "会社・チームへの意見：改善してほしいことはあるか"]}, {"type": "comparison", "title": "1on1での上司の姿勢", "content": "NG：「最近どう？」で始まり、上司が8割話す / 業務報告を求める / アドバイスをすぐにする / スマホを見ながら聞く\n\nOK：「今日話したいことは？」で始まり、部下が8割話す / 傾聴に徹する / 質問で考えを引き出す / 目を見て聴く"}]}'::jsonb, 93, '2026-01-21T18:05:50.80019+00:00', '2026-01-21T18:05:50.80019+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (94, 'J', '評価・フィードバックの技術', NULL, 25, 'MGR', '{"goal": "部下が納得し、成長につながる評価・フィードバックができるようになる", "quote": {"text": "フィードバックは朝食のチャンピオンである。", "author": "ケン・ブランチャード"}, "purpose": "部下の成長を促進する評価とフィードバックの技術を習得します。評価は「査定」ではなく「育成」のツールとして活用することが重要です。", "summary": ["評価は「査定」ではなく「育成」のツール", "フィードバックはタイムリー・具体的・行動に焦点", "SBI法（状況・行動・影響）で具体的に伝える"], "sections": [{"type": "list", "title": "評価の目的", "content": ["育成：強みを伸ばし、弱みを改善する機会を提供", "動機づけ：努力と成果を認め、モチベーションを高める", "期待の明確化：何を求められているかを明確にする", "処遇決定：昇給・昇格・賞与の根拠とする（二次的）"]}, {"type": "list", "title": "フィードバックの基本原則", "content": ["タイムリー：できごとの直後に伝える。時間が経つと効果が薄れる", "具体的：「良かった」ではなく「○○の場面で△△したのが良かった」", "行動に焦点：人格ではなく行動を対象にする", "バランス：ポジティブとネガティブのバランスを取る（3:1以上）", "双方向：一方的に伝えるのではなく、対話する"]}, {"type": "text", "title": "SBI法（フィードバックの型）", "content": "S（Situation）状況：いつ、どこで、どんな場面で\n「先週の商談で」「今日の会議で」\n\nB（Behavior）行動：具体的に何をしたか\n「顧客の質問に対して、事例を交えて説明していた」\n\nI（Impact）影響：その行動がどんな影響を与えたか\n「顧客が納得し、契約に繋がった」\n\n→ 具体的な状況・行動・影響を伝えることで、納得感が高まる"}, {"type": "list", "title": "ネガティブフィードバックの伝え方", "content": ["人前ではなく、1対1で伝える", "人格否定ではなく、行動の改善を求める", "「なぜできないのか」ではなく「どうすればできるか」", "期待していることを伝える（あなたならできると信じている）", "改善のサポートを約束する"]}]}'::jsonb, 94, '2026-01-21T18:05:51.357214+00:00', '2026-01-21T18:05:51.357214+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (95, 'J', '個別育成計画（IDP）の策定', 'Individual Development Plan', 25, 'MGR', '{"goal": "部下の強み・課題・キャリア志向を踏まえた個別育成計画を策定できるようになる", "quote": {"text": "優れたリーダーは、部下の強みを活かし、弱みを無力化する。", "author": "ピーター・ドラッカー"}, "purpose": "部下一人ひとりの成長を計画的に支援するための「個別育成計画（IDP）」の策定方法を習得します。場当たり的な育成から、戦略的な育成へと転換します。", "summary": ["IDPは部下一人ひとりの成長を計画的に支援するツール", "現状把握→目標設定→ギャップ分析→施策立案→実行振り返り", "育成の70%は経験から。挑戦的なアサインメントが重要"], "sections": [{"type": "text", "title": "IDPとは", "content": "IDP（Individual Development Plan）とは、部下一人ひとりの成長を計画的に支援するための育成計画です。\n\n含める要素：\n・現状の強み・課題\n・目指す姿（6ヶ月後、1年後）\n・必要なスキル・経験\n・具体的な育成施策\n・マイルストーン・振り返りタイミング"}, {"type": "list", "title": "IDP策定の5ステップ", "content": ["1. 現状把握：強み、課題、スキルレベルを客観的に評価", "2. 目標設定：本人のキャリア志向と組織ニーズをすり合わせ", "3. ギャップ分析：現状と目標のギャップを明確化", "4. 施策立案：ギャップを埋めるための具体的施策を決定", "5. 実行・振り返り：定期的に進捗を確認し、計画を修正"]}, {"type": "text", "title": "育成施策の70:20:10の法則", "content": "人の成長は以下の割合で起こると言われています：\n\n70%：経験（OJT）\n実際の仕事を通じた学び。挑戦的なアサインメント、プロジェクト参加など\n\n20%：他者からの学び\n上司・先輩からのフィードバック、メンタリング、ロールモデルの観察\n\n10%：研修・自己学習\n集合研修、eラーニング、読書、資格取得など\n\n→ 研修だけでは育たない。経験と他者からの学びが重要"}, {"type": "list", "title": "IDP面談の進め方", "content": ["本人の自己評価を聞く（強み、課題、やりたいこと）", "上司からの評価を伝える（客観的な視点）", "目指す姿を一緒に描く（本人の意志を尊重）", "具体的な施策を決める（経験・人・研修のバランス）", "振り返りのタイミングを決める（月1回の進捗確認）"]}]}'::jsonb, 95, '2026-01-21T18:05:52.068633+00:00', '2026-01-21T18:05:52.068633+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (96, 'J', '採用基準とオンボーディング', NULL, 25, 'MGR', '{"goal": "明確な採用基準を持ち、新メンバーを90日で戦力化できるオンボーディングを設計できる", "quote": {"text": "採用で妥協してはならない。Aクラスの人材がAクラスを連れてくる。Bクラスの人材はCクラスを連れてくる。", "author": "スティーブ・ジョブズ"}, "purpose": "チームに適した人材を採用し、早期に戦力化するためのオンボーディング（受け入れ）の設計方法を習得します。採用のミスマッチを防ぎ、定着率を高めます。", "summary": ["採用基準はMust/Want/Negativeで明確に設計する", "新入社員の30%は90日以内に離職を決意。オンボーディングが鍵", "90日で戦力化する計画を立て、メンターをアサインする"], "sections": [{"type": "list", "title": "採用基準の設計", "content": ["Must（必須）：これがないと採用しない。最低限の要件", "Want（あれば望ましい）：あれば加点。なくても育成可能", "Negative（不採用要件）：これがあると採用しない"]}, {"type": "list", "title": "営業職の採用で見るべきポイント", "content": ["コミュニケーション力：質問に的確に答えられるか、傾聴できるか", "ストレス耐性：断られることへの耐性、ネガティブな経験からの学び", "目標達成意欲：過去に目標を追いかけた経験があるか", "誠実さ：嘘をつかない、約束を守る姿勢があるか", "成長意欲：学び続ける姿勢があるか"]}, {"type": "text", "title": "オンボーディングの重要性", "content": "新入社員の30%は入社90日以内に離職を決意すると言われています。オンボーディングの質が定着率を左右します。\n\nオンボーディングの目的：\n・早期戦力化（成果を出せる状態にする）\n・組織への適応（文化・人間関係の理解）\n・心理的安全性の確保（質問・相談しやすい環境）"}, {"type": "list", "title": "90日オンボーディングプラン", "content": ["1週目：会社・チーム・製品の基礎理解。メンターのアサイン", "2-4週目：OJT開始。先輩同行、ロールプレイ、基礎研修", "2ヶ月目：一人立ち開始。サポート付きで実践。週次振り返り", "3ヶ月目：完全一人立ち。目標設定、定期1on1の開始"]}]}'::jsonb, 96, '2026-01-21T18:05:52.671144+00:00', '2026-01-21T18:05:52.671144+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (97, 'J', 'コーチング・メンタリング', NULL, 25, 'MGR', '{"goal": "ティーチング、コーチング、メンタリングを状況に応じて使い分け、部下の成長を支援できる", "quote": {"text": "コーチングとは、人が自分自身の答えを見つける手助けをすることである。", "author": "ジョン・ウィットモア"}, "purpose": "部下の成長を引き出すコーチングとメンタリングの技術を習得します。「教える」のではなく「引き出す」アプローチで、自律的な人材を育成します。", "summary": ["ティーチング（教える）、コーチング（引き出す）、メンタリング（経験共有）を使い分ける", "GROWモデル（目標→現状→選択肢→意志）でコーチングする", "部下のスキルと意欲に応じてアプローチを変える"], "sections": [{"type": "text", "title": "3つの育成アプローチ", "content": "ティーチング（Teaching）：知識・スキルを教える。新人や未経験者に効果的\n「これはこうやるんだよ」\n\nコーチング（Coaching）：質問で気づきを引き出す。経験者の成長に効果的\n「どうすればうまくいくと思う？」\n\nメンタリング（Mentoring）：経験を共有し、キャリアを支援する。長期的な成長に効果的\n「私はこんな経験をしたよ」"}, {"type": "list", "title": "コーチングの基本スキル：GROWモデル", "content": ["G（Goal）目標：何を達成したいか？「どんな状態を目指している？」", "R（Reality）現状：今どんな状況か？「今の状況を教えて」", "O（Options）選択肢：どんな方法があるか？「他にどんな方法がある？」", "W（Will）意志：何をするか？「いつまでに、何をする？」"]}, {"type": "list", "title": "コーチング質問例", "content": ["オープンクエスチョン：「どう思う？」「何が原因だと思う？」", "スケーリング：「10点満点で今何点？」「あと2点上げるには？」", "仮定の質問：「もし失敗を恐れないとしたら？」「もし何でもできるとしたら？」", "リフレーミング：「別の見方をするとどうなる？」「それを強みと捉えると？」"]}, {"type": "text", "title": "状況に応じた使い分け", "content": "スキル低×意欲高（新人）：ティーチング中心。丁寧に教える\nスキル中×意欲中（若手）：コーチング中心。質問で引き出す\nスキル高×意欲低（ベテラン）：メンタリング。新しい挑戦を促す\nスキル高×意欲高（エース）：権限委譲。任せて見守る"}]}'::jsonb, 97, '2026-01-21T18:05:54.238077+00:00', '2026-01-21T18:05:54.238077+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (98, 'J', '心理的安全性の醸成', NULL, 20, 'MGR', '{"goal": "チームの心理的安全性を高め、メンバーが本音で話し、失敗を恐れず挑戦できる環境を作る", "quote": {"text": "心理的安全性は、ぬるま湯ではない。むしろ、率直に意見を言い合える厳しい環境である。", "author": "エイミー・エドモンドソン"}, "purpose": "チームメンバーが安心して発言・挑戦できる「心理的安全性」の高い環境を作る方法を習得します。心理的安全性は高業績チームの共通要素です。", "summary": ["心理的安全性は高業績チームの最重要要素（Google研究）", "自ら弱みを見せ、発言に感謝し、失敗を学びに変える", "「責める」から「学ぶ」へ、「否定」から「好奇心」へ"], "sections": [{"type": "text", "title": "心理的安全性とは", "content": "心理的安全性（Psychological Safety）とは、チームの中で自分の意見を言っても、質問をしても、失敗しても、罰せられたり恥をかいたりしないと感じられる状態のことです。\n\nGoogleの研究「Project Aristotle」で、高業績チームの最も重要な要素として特定されました。\n\n心理的安全性が高いチームでは：\n・本音で議論できる\n・失敗を恐れず挑戦できる\n・わからないことを聞ける\n・ミスを隠さず報告できる"}, {"type": "list", "title": "心理的安全性を下げる行動", "content": ["発言を否定・無視する：「それは違う」「そんなことより...」", "失敗を責める：「なんでできないの？」「誰の責任？」", "質問を馬鹿にする：「そんなことも知らないの？」", "意見を言った人を攻撃する：人格否定、陰口", "完璧主義を強要する：「失敗は許されない」"]}, {"type": "list", "title": "心理的安全性を高める行動", "content": ["自ら弱みを見せる：「私も昔失敗した」「わからないから教えて」", "発言に感謝する：「意見をくれてありがとう」「指摘してくれて助かった」", "失敗を学びに変える：「何を学んだ？」「次はどうする？」", "全員に発言機会を作る：「○○さんはどう思う？」", "批判ではなく好奇心で聞く：「なぜそう思った？」「もっと教えて」"]}, {"type": "list", "title": "心理的安全性チェックリスト", "content": ["チームでミスをしても、責められない", "メンバー同士で異なる意見を言い合える", "リスクを取ることが許容されている", "助けを求めることができる", "誰もメンバーの努力を無駄にしようとしない"]}]}'::jsonb, 98, '2026-01-21T18:05:55.468542+00:00', '2026-01-21T18:05:55.468542+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (99, 'J', 'チーム目標設計とKPI運用', NULL, 25, 'MGR', '{"goal": "チームの目標をKGI/KPIで設計し、PDCAサイクルで継続的に改善できるようになる", "quote": {"text": "測定できないものは管理できない。管理できないものは改善できない。", "author": "ピーター・ドラッカー"}, "purpose": "チーム全体の目標を設計し、KPIで進捗を管理・改善する技術を習得します。目標がなければ成果は出ません。正しい目標設定がチームを動かします。", "summary": ["KGI（最終目標）とKPI（先行指標）を明確に設計する", "KPIは測定可能・コントロール可能・先行指標であること", "週次・月次でPDCAを回し、継続的に改善する"], "sections": [{"type": "text", "title": "KGIとKPI", "content": "KGI（Key Goal Indicator）：最終目標指標。達成すべきゴール\n例：年間売上1億円、新規契約50件\n\nKPI（Key Performance Indicator）：重要業績評価指標。KGI達成のための先行指標\n例：月間商談数、アポ獲得率、成約率\n\nKGIが「結果」、KPIは「過程」。KPIを管理することでKGI達成の確度を高める"}, {"type": "list", "title": "良いKPIの条件", "content": ["測定可能：数値で測定できる", "コントロール可能：自分たちの行動で変えられる", "先行指標：結果が出る前に状況がわかる", "シンプル：3〜5個に絞る。多すぎると管理できない", "KGIとの因果関係：KPIが上がればKGIも上がる関係"]}, {"type": "list", "title": "営業チームのKPI例", "content": ["行動量KPI：テレアポ数、訪問数、商談数", "効率KPI：アポ獲得率、商談化率、成約率", "金額KPI：平均単価、1件あたり売上", "顧客KPI：新規顧客数、リピート率、紹介数"]}, {"type": "text", "title": "KPI運用のPDCAサイクル", "content": "Plan（計画）：KGI/KPIを設定し、アクションプランを立てる\n\nDo（実行）：計画に基づいて行動する。日々の活動を記録する\n\nCheck（評価）：週次・月次でKPIを確認。目標との差異を分析する\n「なぜ達成できたか」「なぜ未達か」を深掘り\n\nAct（改善）：分析結果を踏まえて、次のアクションを決める\n成功パターンは横展開、失敗パターンは改善策を実行"}]}'::jsonb, 99, '2026-01-21T18:05:56.381131+00:00', '2026-01-21T18:05:56.381131+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (100, 'J', '営業カルチャーの浸透', NULL, 25, 'MGR', '{"goal": "チームの営業カルチャーを言語化し、日常の行動に浸透させる仕組みを作れるようになる", "quote": {"text": "企業文化は、採用と解雇によって決まる。", "author": "マーク・ザッカーバーグ"}, "purpose": "チームに望ましい営業カルチャー（文化・価値観）を浸透させる方法を習得します。カルチャーは戦略を食べると言われるほど、組織の成果に影響を与えます。", "summary": ["カルチャーは「上司がいなくても、どう行動するか」を決める", "言語化し、リーダーが体現し、評価に組み込む", "「言行一致」が最も重要。例外を許さない"], "sections": [{"type": "text", "title": "カルチャーとは何か", "content": "カルチャー（文化）とは、組織やチームで共有される「価値観」「信念」「行動規範」のことです。「上司がいなくても、メンバーがどう判断・行動するか」を決めるもの。\n\nドラッカーの言葉：「Culture eats strategy for breakfast（カルチャーは戦略を朝食に食べる）」\n→ どんなに良い戦略も、カルチャーが伴わなければ機能しない"}, {"type": "list", "title": "営業カルチャーの要素", "content": ["顧客志向：顧客の成功を第一に考える", "誠実さ：嘘をつかない、約束を守る", "成果へのこだわり：目標達成に執念を持つ", "チームワーク：個人プレーではなく、協力し合う", "学習・成長：常に学び、改善し続ける", "挑戦：失敗を恐れず、新しいことに挑戦する"]}, {"type": "list", "title": "カルチャーを浸透させる方法", "content": ["言語化する：価値観を明文化し、チームで共有する", "リーダーが体現する：自らが価値観に沿った行動を取る", "評価に組み込む：カルチャーに沿った行動を評価する", "ストーリーを語る：良い行動の事例を共有・称賛する", "採用で選ぶ：カルチャーフィットする人を採用する", "儀式を作る：朝礼、週次MTG、表彰などで繰り返し伝える"]}, {"type": "list", "title": "カルチャーを壊す行動", "content": ["言行不一致：言っていることとやっていることが違う", "例外を許す：カルチャーに反する行動を見逃す", "成果至上主義：結果さえ出せば、やり方は問わない", "属人化：特定の人だけに適用される/適用されない"]}]}'::jsonb, 100, '2026-01-21T18:05:56.945117+00:00', '2026-01-21T18:05:56.945117+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (101, 'K', 'マーケティングとは何か', NULL, 20, '新卒', '{"goal": "マーケティングの定義を説明でき、営業との連携の重要性を認識できるようになる", "quote": {"text": "マーケティングを知る営業は、戦略を持って戦える", "author": "Symphony Training Academy"}, "purpose": "マーケティングの定義と目的を理解し、営業との役割分担と連携の重要性を学びます。現代の営業活動はマーケティングとの連携なしには成り立ちません。", "summary": ["マーケティングは「売れる仕組み」を作る活動", "マーケティングと営業は「対立」ではなく「連携」の関係", "営業がマーケティングを理解することで、戦略的な営業活動が可能になる"], "sections": [{"type": "text", "title": "マーケティングの定義", "content": "【ピーター・ドラッカーの定義】\n「マーケティングの目的は、セールスを不要にすることである」\n→ 顧客が「欲しい」と思う状態を作り出すこと\n→ 営業が「売り込む」必要がない状態が理想\n\n【フィリップ・コトラーの定義】\n「マーケティングとは、ターゲット市場を選択し、優れた顧客価値を創造・伝達・提供することによって、顧客を獲得・維持・拡大する技術と科学である」\n→ 「誰に」「何を」「どう届けるか」を設計すること"}, {"type": "comparison", "title": "マーケティングと営業の役割分担", "content": ["マーケティングの役割：市場調査・分析（誰が顧客か？）、製品企画・価格設定、認知獲得・リード創出、ブランド構築", "営業の役割：顧客との直接対話（ニーズの深掘り）、提案・クロージング、関係構築・維持、市場情報のフィードバック"]}, {"type": "list", "title": "営業がマーケティングを学ぶ意義", "content": ["戦略の理解：「なぜこのターゲットか」「なぜこの価格か」を理解し、提案に説得力が生まれる", "共通言語の獲得：マーケティング部門と円滑にコミュニケーションできる（MQL、CVR等の用語理解）", "顧客視点の強化：「売り手目線」から「顧客目線」への転換ができる", "フィードバックの質向上：現場の声を適切な形でマーケティングに還元できる"]}]}'::jsonb, 101, '2026-01-21T18:05:57.493909+00:00', '2026-01-21T18:05:57.493909+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (102, 'K', '市場分析の基本 - 3C分析', NULL, 20, '新卒', '{"goal": "3C分析を使って自社と顧客の市場環境を整理し、商談に活かせるようになる", "quote": {"text": "敵を知り己を知れば百戦危うからず", "author": "孫子"}, "purpose": "3C分析のフレームワークを理解し、市場環境を体系的に分析する方法を学びます。商談前に顧客の3Cを調べる習慣を身につけます。", "summary": ["3C分析で市場環境を体系的に理解する", "商談前に顧客の3Cを調べる習慣を持つ", "3Cの交点（顧客ニーズ×競合弱み×自社強み）に勝機がある"], "sections": [{"type": "text", "title": "3C分析とは", "content": "市場環境を3つの視点から分析するフレームワーク（出典：大前研一 1982年）\n\nCustomer（顧客）：市場のニーズ、購買行動、意思決定プロセス\nCompetitor（競合）：競合他社の強み・弱み、戦略\nCompany（自社）：自社の強み・弱み、リソース\n\n3Cの「交点」に勝機がある：顧客ニーズを満たし、競合より優れている自社の強み"}, {"type": "list", "title": "Customer（顧客）分析のポイント", "content": ["顧客は誰か？（業種、規模、地域）", "顧客のニーズは何か？（課題、欲求）", "購買の意思決定者は誰か？", "購買プロセスはどうなっているか？", "購買基準は何か？（価格、機能、サポート等）"]}, {"type": "list", "title": "Competitor（競合）分析のポイント", "content": ["競合は誰か？（直接競合、間接競合）", "競合の強みは何か？", "競合の弱みは何か？", "競合のシェア、価格帯は？", "競合の戦略は？"]}, {"type": "list", "title": "Company（自社）分析のポイント", "content": ["自社の強みは何か？（業界特化、製品連携、価格競争力）", "自社の弱みは何か？（知名度、営業リソース）", "自社のリソース（人材、資金、技術）は？", "自社の独自性は何か？"]}]}'::jsonb, 102, '2026-01-21T18:05:58.191067+00:00', '2026-01-21T18:05:58.191067+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (103, 'K', 'STP戦略 - 誰に売るかを決める技術', NULL, 20, '新卒', '{"goal": "STP戦略を説明でき、自社のターゲット顧客とポジショニングを顧客に説明できるようになる", "quote": {"text": "全員に好かれようとすれば、誰にも好かれない", "author": "マーケティングの格言"}, "purpose": "STP（セグメンテーション・ターゲティング・ポジショニング）のフレームワークを理解し、ターゲット顧客と自社のポジショニングを言語化できるようになります。", "summary": ["セグメンテーションで市場を細分化し、ターゲティングで狙う市場を選ぶ", "ポジショニングで競合との違いを明確にする", "「誰にでも売る」ではなく「誰に売るか」を決めることが重要"], "sections": [{"type": "text", "title": "STP戦略とは", "content": "マーケティング戦略の基本フレームワーク（出典：Philip Kotler）\n「誰に」「どんな価値を」届けるかを決める\n\nS: Segmentation（セグメンテーション）→ 市場を細分化する\nT: Targeting（ターゲティング）→ 狙う市場を選ぶ\nP: Positioning（ポジショニング）→ 競合との違いを明確にする"}, {"type": "list", "title": "セグメンテーションの軸", "content": ["地理的変数（Geographic）：地域、都市規模、気候など", "人口統計的変数（Demographic）：業種、企業規模、従業員数など", "心理的変数（Psychographic）：価値観、課題意識、導入意欲など", "行動変数（Behavioral）：購買頻度、使用状況、ロイヤルティなど"]}, {"type": "list", "title": "ターゲット選定の基準", "content": ["市場規模：十分な売上が見込めるか？", "成長性：今後伸びる市場か？", "競合状況：勝てる余地があるか？", "自社適合性：自社の強みが活きるか？", "アクセス可能性：アプローチできるか？"]}, {"type": "text", "title": "ポジショニングとは", "content": "顧客の頭の中で、自社製品を競合とは異なる独自の位置に置くこと\n\n【ポジショニングマップ】\n縦軸：高機能 ←→ シンプル\n横軸：低価格 ←→ 高価格\n\n【Symphonyのポジショニング例】\n「中古車業界特化×コストパフォーマンス」\n→ 業界に詳しく、手頃な価格で、必要十分な機能を提供"}]}'::jsonb, 103, '2026-01-21T18:05:58.838212+00:00', '2026-01-21T18:05:58.838212+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (104, 'K', 'マーケティングミックス - 4Pと4C', NULL, 20, '新卒', '{"goal": "4P/4Cを説明でき、営業活動の位置づけを理解した上で活動できるようになる", "quote": {"text": "マーケティングは4Pではなく、4Cで考えよ", "author": "Robert Lauterborn"}, "purpose": "4P（Product, Price, Place, Promotion）と4C（顧客視点）のフレームワークを理解し、営業活動がマーケティングミックスのどこに位置するかを認識します。", "summary": ["4Pは「売り手視点」、4Cは「買い手視点」のフレームワーク", "営業は「Promotion/Communication」の最前線に位置する", "顧客と直接対話し、価値を伝え、フィードバックを得る重要な役割"], "sections": [{"type": "text", "title": "マーケティングミックス（4P）とは", "content": "マーケティング戦略を実行するための4つの要素（出典：E. Jerome McCarthy 1960年）\n\nProduct（製品）：何を売る？\nPrice（価格）：いくらで売る？\nPlace（流通）：どこで売る？\nPromotion（販促）：どう伝える？\n\nこの4つを統合的に設計することで、効果的なマーケティングが実現する"}, {"type": "comparison", "title": "4P → 4Cへの転換（顧客視点）", "content": ["Product（製品）→ Customer Value（顧客価値）：顧客にとっての価値は？", "Price（価格）→ Cost（顧客コスト）：顧客の総負担は？", "Place（流通）→ Convenience（利便性）：顧客にとって便利か？", "Promotion（販促）→ Communication（コミュニケーション）：顧客との対話は？"]}, {"type": "text", "title": "Symphonyの4P/4C", "content": "【Product → Customer Value】\n製品：Symphony販売管理、整備請求、ワンプラ\n顧客価値：業務効率化、在庫回転向上、コスト削減\n\n【Price → Cost】\n価格：月額○○円\n顧客コスト：初期費用＋月額＋学習コスト＋移行コスト → TCO（総所有コスト）で考える\n\n【Place → Convenience】\n流通：直販営業、WEB経由\n利便性：オンラインデモ、クラウド型で即導入可能\n\n【Promotion → Communication】\n販促：展示会、WEB広告、テレアポ\n対話：営業による課題ヒアリング、導入後サポート"}]}'::jsonb, 104, '2026-01-21T18:06:00.018813+00:00', '2026-01-21T18:06:00.018813+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (105, 'K', '顧客理解の深め方 - ペルソナとジャーニー', NULL, 25, '中堅', '{"goal": "ターゲット顧客のペルソナを描き、購買プロセスに応じたアプローチを設計できるようになる", "quote": {"text": "顧客を知ることは、売ることの始まりである", "author": "Symphony Training Academy"}, "purpose": "ペルソナ（理想顧客像）とカスタマージャーニーマップの概念を理解し、顧客の購買プロセスに応じた営業アプローチを設計できるようになります。", "summary": ["ペルソナを思い浮かべながら商談に臨む", "顧客のジャーニー（購買プロセス）に応じたアプローチを設計する", "営業は主に「検討」「購入」フェーズを担当する"], "sections": [{"type": "text", "title": "ペルソナとは", "content": "ターゲット顧客を具体的な「1人の人物」として描いたもの\n→ 抽象的な「ターゲット」を、生きた人間として想像する\n\n【ペルソナの要素】\n• 基本情報：年齢、役職、会社規模、地域\n• 性格・価値観：慎重派か積極派か、何を大切にするか\n• 課題・悩み：何に困っているか、何を解決したいか\n• 情報収集方法：どこで情報を得るか\n• 意思決定のポイント：何があれば決断するか"}, {"type": "text", "title": "Symphonyのペルソナ例", "content": "【田中 誠一（52歳）】\n役職：代表取締役（創業者）\n会社：田中自動車販売（創業25年、従業員5名、在庫30台）\n地域：埼玉県郊外\n\n性格：堅実で慎重、新しいものには懐疑的。人情に厚く、長年の顧客を大切にする。息子への事業承継を考え始めている。\n\n課題：紙とExcelでの管理が限界。若手社員がすぐ辞める（業務が非効率）。業販を増やしたいがネットワークがない。\n\n情報収集：同業者の口コミを重視。展示会には年1回参加。スマホは持っているがあまり使わない。\n\n意思決定のポイント：信頼できる人からの紹介。「同業者も使っている」という安心感。導入後のサポート体制。"}, {"type": "text", "title": "カスタマージャーニーマップ", "content": "顧客が「認知」から「購入」「継続利用」に至るまでの体験を時系列で可視化したもの\n\n【フェーズ】認知 → 興味 → 検討 → 購入 → 継続\n【行動】展示会・口コミ → WEB検索 → デモ・比較 → 契約・導入 → 利用・サポート\n【感情】？ → 期待 → 不安 → 決断 → 安心/不満\n【接点】広告・紹介 → HP・資料 → 営業訪問 → 営業・契約 → CS・サポート\n【課題】知らない → よくわからない → 比較が難しい → 本当に大丈夫？ → 使いこなせるか不安\n\n営業がアプローチするのは主に「検討」「購入」フェーズ。それ以前はマーケティングの役割。"}]}'::jsonb, 105, '2026-01-21T18:06:00.54698+00:00', '2026-01-21T18:06:00.54698+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (106, 'K', 'ブランディングの基礎 - 選ばれる理由を作る', NULL, 20, '中堅', '{"goal": "ブランドの重要性を理解し、日々の営業活動でブランドを体現できるようになる", "quote": {"text": "ブランドとは、約束を守り続けた結果である", "author": "マーケティングの格言"}, "purpose": "ブランドとは何かを理解し、営業活動を通じてブランドを体現する方法を学びます。営業担当者は「歩くブランド」であることを認識します。", "summary": ["ブランドは顧客の頭の中にあるイメージ", "営業担当者は「歩くブランド」として会社を代表する", "「Symphonyの営業は信頼できる」が最高のブランド資産"], "sections": [{"type": "text", "title": "ブランドとは", "content": "「顧客の頭の中にある、その企業・製品に対するイメージ」\n\nブランド = ロゴ + 製品 + 体験 + 評判 + 感情\n\n【ブランドがあると】\n✅ 価格競争に巻き込まれにくい\n✅ 指名買いされる（検討期間が短い）\n✅ 紹介が生まれやすい\n✅ 優秀な人材が集まる\n✅ 営業しやすい（話を聞いてもらえる）\n\n【ブランドがないと】\n❌ 常に価格で比較される\n❌ 説明に時間がかかる\n❌ 信頼獲得に時間がかかる"}, {"type": "text", "title": "営業がブランドを「体現」する", "content": "営業担当者は「歩くブランド」\n顧客にとって、営業の印象 = 会社の印象\n\n【ブランドを体現する行動】\n■ 約束を守る\n「明日までに資料を送ります」→ 必ず送る\n\n■ 一貫性を持つ\n言うことが毎回違う → ブランド毀損\n\n■ プロフェッショナルであり続ける\n身だしなみ、言葉遣い、知識 すべてがブランド\n\n■ 顧客の成功にコミットする\n売って終わりではなく、成果が出るまで支援"}]}'::jsonb, 106, '2026-01-21T18:06:01.58631+00:00', '2026-01-21T18:06:01.58631+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (107, 'K', '競合分析の技術 - SWOT分析', NULL, 20, '新卒', '{"goal": "SWOT分析を使って自社の勝ち筋を整理し、商談で活用できるようになる", "quote": {"text": "強みを活かせる場所で戦え", "author": "戦略の格言"}, "purpose": "SWOT分析のフレームワークを理解し、自社と競合の強み・弱みを整理して営業戦略に活かす方法を学びます。", "summary": ["SWOT分析で内部環境と外部環境を整理する", "「強み × 機会」の交点が攻めどころ", "商談では「顧客の課題 × 自社の強み」をマッチングさせる"], "sections": [{"type": "text", "title": "SWOT分析とは", "content": "自社の内部環境と外部環境を4つの視点で分析するフレームワーク\n\n【内部環境（自社でコントロール可能）】\nStrengths（強み）：競合に対する優位性\nWeaknesses（弱み）：競合に対する劣位性\n\n【外部環境（自社でコントロール不可）】\nOpportunities（機会）：市場のチャンス\nThreats（脅威）：市場のリスク"}, {"type": "text", "title": "SymphonyのSWOT分析例", "content": "【Strengths（強み）】\n• 中古車業界に特化した機能設計\n• 販売管理・整備・業販の連携\n• 競争力のある価格設定\n• 導入後のサポート体制\n\n【Weaknesses（弱み）】\n• 大手競合に比べて知名度が低い\n• 営業リソースが限られている\n• 大規模企業向けの機能が弱い\n\n【Opportunities（機会）】\n• 中古車業界のDX化ニーズの高まり\n• 人手不足による業務効率化需要\n• クラウドサービスへの移行トレンド\n\n【Threats（脅威）】\n• 大手ITベンダーの参入\n• 無料・低価格ツールの台頭\n• 中古車市場の縮小リスク"}, {"type": "list", "title": "SWOT → 戦略への落とし込み", "content": ["強み × 機会 → 攻めの戦略：「業界特化×DX需要」で中規模店を積極開拓", "強み × 脅威 → 差別化戦略：「サポート力」で大手にない安心感を訴求", "弱み × 機会 → 改善戦略：認知度向上のためWEBマーケティング強化", "弱み × 脅威 → 防衛戦略：既存顧客の満足度向上で離反防止"]}]}'::jsonb, 107, '2026-01-21T18:06:02.167892+00:00', '2026-01-21T18:06:02.167892+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (108, 'K', '価格戦略の基本 - なぜこの価格なのか', NULL, 20, '中堅', '{"goal": "価格設定の背景を理解し、「なぜこの価格か」を顧客に説明できるようになる", "quote": {"text": "価格は忘れられるが、品質は記憶される", "author": "経営の格言"}, "purpose": "価格設定の3つのアプローチを理解し、特に「価値ベース価格設定」の考え方を身につけて、価格交渉で自信を持って対応できるようになります。", "summary": ["価格設定には3つのアプローチがある", "Symphony営業は「価値ベース」で提案する", "「高い」と言われたら、価値を再説明する"], "sections": [{"type": "text", "title": "価格設定の3つのアプローチ", "content": "【1. コストベース価格設定】\n原価 + 利益 = 価格\n✅ メリット：計算しやすい、赤字になりにくい\n❌ デメリット：顧客価値を反映していない\n\n【2. 競合ベース価格設定】\n競合価格を参考に、同等 or 安く設定\n✅ メリット：市場相場に合う、比較されやすい\n❌ デメリット：価格競争に巻き込まれやすい\n\n【3. 価値ベース価格設定】★おすすめ\n顧客が感じる「価値」に基づいて価格設定\n✅ メリット：高い利益率、差別化につながる\n❌ デメリット：価値の説明が必要"}, {"type": "text", "title": "価値ベース価格設定の実践", "content": "【価値の可視化トーク例】\n「御社の場合、月20時間の業務削減が見込めます。\n時給1,500円で計算すると、月30,000円のコスト削減。\n年間にすると360,000円の効果です。\n\nSymphonyの月額費用は28,000円ですから、\n年間336,000円のご負担で、360,000円の効果。\n初年度から投資回収できる計算になります」\n\n【価格ではなく「価値」で勝負する】\n❌「うちは他社より安いです」→ 価格競争に巻き込まれる\n✅「この価格で、これだけの価値が得られます」→ 価値で選んでもらえる"}]}'::jsonb, 108, '2026-01-21T18:06:02.730161+00:00', '2026-01-21T18:06:02.730161+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (109, 'K', 'プロモーション戦略 - 認知から購買まで', NULL, 15, '新卒', '{"goal": "顧客の購買プロセスを理解し、営業活動がどの段階で価値を発揮するか認識できるようになる", "quote": {"text": "最高のマーケティングは、満足した顧客の口コミである", "author": "マーケティングの格言"}, "purpose": "AIDMA/AISASモデルを理解し、顧客の購買行動プロセスの各段階でのプロモーション施策と営業の役割を認識します。", "summary": ["顧客は認知→興味→検索→購入→共有のプロセスを辿る", "営業は主に「Action（購入）」段階で価値を発揮する", "顧客満足による「Share」が次の顧客獲得につながる"], "sections": [{"type": "text", "title": "AIDMA / AISASモデル", "content": "消費者の購買行動プロセスを段階的に示したモデル\n\n【AIDMA（伝統的モデル）】\nA: Attention（注意）→ 知る\nI: Interest（興味）→ 興味を持つ\nD: Desire（欲求）→ 欲しくなる\nM: Memory（記憶）→ 覚えておく\nA: Action（行動）→ 購入する\n\n【AISAS（デジタル時代モデル）】\nA: Attention（注意）→ 知る\nI: Interest（興味）→ 興味を持つ\nS: Search（検索）→ 調べる ★WEBで情報収集\nA: Action（行動）→ 購入する\nS: Share（共有）→ 口コミする ★SNSで拡散"}, {"type": "text", "title": "各段階での施策と営業の役割", "content": "【Attention】施策：広告、展示会、PR → 認知獲得はマーケ主導\n【Interest】施策：HP、資料、セミナー → 問い合わせ対応\n【Search】施策：SEO、比較サイト → 検索で見つかる情報提供\n【Action】施策：営業提案、デモ、見積、契約 → ★営業の主戦場\n【Share】施策：導入事例、口コミ → 顧客満足→紹介依頼\n\n営業は主に「Action」段階だが、「Share」を生み出すことで次の「Attention」に繋げる"}]}'::jsonb, 109, '2026-01-21T18:06:03.345139+00:00', '2026-01-21T18:06:03.345139+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (110, 'K', 'マーケティングと営業の連携 - リード管理', NULL, 20, '中堅', '{"goal": "リードの分類を理解し、マーケティング部門と連携したリード管理ができるようになる", "quote": {"text": "マーケが悪い、営業が悪い、ではなく、一緒に改善する", "author": "Symphony Training Academy"}, "purpose": "MQL/SQLの違いを理解し、リードナーチャリングの概念とマーケティング部門との効果的な連携方法を学びます。", "summary": ["リードはMQL → SQL → 商談 → 受注のステージを辿る", "「今すぐ客」は3%、残り97%はナーチャリングで育てる", "マーケと営業は「対立」ではなく「連携」で改善していく"], "sections": [{"type": "text", "title": "リード（見込み客）の分類", "content": "【リードのステージ】\nリード（Lead）：何らかの接点を持った見込み客\n↓\nMQL（Marketing Qualified Lead）：マーケティングが「営業対象」と判断\n例：資料DL、セミナー参加、問い合わせ\n↓\nSQL（Sales Qualified Lead）：営業が「商談化可能」と判断\n例：予算あり、時期明確、決裁者アクセス可\n↓\n商談（Opportunity）：具体的な提案・見積段階\n↓\n受注（Customer）"}, {"type": "text", "title": "リードナーチャリング（見込み客育成）", "content": "すぐに購入しない見込み客を、継続的にフォローし、購買意欲が高まった時に商談化する活動\n\n【ナーチャリングの手法】\n• メールマガジン配信\n• セミナー・ウェビナー案内\n• 事例・コンテンツ提供\n• 定期的な情報提供（業界ニュース等）\n\n【営業がやるべきこと】\n✅ 顧客の検討段階を見極める\n✅ 検討段階に合った情報を提供する\n✅ 「売り込み」ではなく「役立つ存在」になる\n✅ 購買意欲が高まったタイミングを逃さない\n\n「今すぐ客」は全体の3%。残り97%を育てる視点が重要"}, {"type": "comparison", "title": "マーケティングと営業の連携ポイント", "content": ["マーケ → 営業：リード情報の共有（いつ、何に興味を持ったか）、MQLの定義を明確に、コンテンツ・ツールの提供", "営業 → マーケ：商談結果のフィードバック（なぜ受注/失注したか）、顧客の生の声、リードの質に対するフィードバック"]}]}'::jsonb, 110, '2026-01-21T18:06:04.320756+00:00', '2026-01-21T18:06:04.320756+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (111, 'L', 'WEBマーケティング概論 - なぜ営業がWEBを理解すべきか', NULL, 20, '新卒', '{"goal": "WEBマーケティングの全体像を説明でき、営業活動との関係性を理解できるようになる", "quote": {"text": "顧客はすでにWEBで学んでいる。営業はその先を提供せよ", "author": "Symphony Training Academy"}, "purpose": "WEBマーケティングの全体像を理解し、B2B購買行動の変化を踏まえて、営業がWEBマーケティングを理解する意義を認識します。", "summary": ["B2B購買者の57%は営業に会う前にWEBで情報収集を完了", "顧客はすでにWEBで学んでいる。営業はその先を提供する", "WEBマーケを理解することで、より効果的な営業活動が可能になる"], "sections": [{"type": "text", "title": "WEBマーケティングとは", "content": "インターネットを活用したマーケティング活動の総称\n\n【WEBマーケティングの手法】\n集客：SEO、広告、SNS、PR → 見込み客を集める\n接客：WEBサイト、LP、コンテンツ、チャット → 興味を持ってもらう\n追客：メール、リマーケティング、MA → 継続的にフォロー"}, {"type": "text", "title": "B2B購買行動の変化", "content": "【衝撃のデータ】\nB2B購買者の57%は、営業に会う前にWEBで情報収集を完了している（出典：CEB/Gartner調査）\n\n【購買プロセスの変化】\n以前：課題認識 → 営業に相談 → 情報収集 → 比較検討 → 購入\n　　　（営業が主導）\n現在：課題認識 → WEBで検索 → 情報収集 → 比較検討 → 営業に相談\n　　　（営業の出番は後半）\n\n顧客は営業に会う前に、かなりの情報を持っている"}, {"type": "list", "title": "営業がWEBマーケを理解する意義", "content": ["顧客の情報レベルを把握できる：「この顧客はどこまで調べているか？」→ 説明の深さを調整", "顧客の流入経路がわかる：「何を検索してうちに来たか？」→ 関心ポイントを予測", "WEBコンテンツを営業に活用できる：「この事例記事、参考になりますよ」→ 説得力のある提案", "マーケ部門と連携しやすくなる：「こういうコンテンツがあると助かる」→ 改善提案"]}]}'::jsonb, 111, '2026-01-21T18:06:05.283331+00:00', '2026-01-21T18:06:05.283331+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (112, 'L', 'SEOの基礎 - 検索エンジン最適化の仕組み', NULL, 20, '新卒', '{"goal": "SEOの仕組みを理解し、顧客の検索行動を営業活動に活かせるようになる", "quote": {"text": "検索されなければ、存在しないのと同じ", "author": "WEBマーケティングの格言"}, "purpose": "SEO（検索エンジン最適化）の基本的な仕組みを理解し、顧客がどのようなキーワードで検索するかを想像できるようになります。", "summary": ["SEOは検索結果で上位表示されるための施策", "顧客は課題系→解決策系→比較系の順で検索する傾向がある", "商談で流入経路を聞くことがマーケへのフィードバックになる"], "sections": [{"type": "text", "title": "SEOとは", "content": "SEO = Search Engine Optimization（検索エンジン最適化）\nGoogleやYahooなどの検索結果で、自社サイトを上位に表示させるための施策\n\n【なぜSEOが重要か？】\n• 検索結果の1位 → クリック率 約30%\n• 検索結果の2位 → クリック率 約15%\n• 検索結果の3位 → クリック率 約10%\n• 2ページ目以降 → ほぼ見られない\n\n検索上位 = 見込み客との接点が増える"}, {"type": "text", "title": "検索エンジンの仕組み", "content": "【3つのステップ】\n1. クロール（Crawl）：Googleのロボットがサイトを巡回・発見\n2. インデックス（Index）：発見したページの内容をデータベースに登録\n3. ランキング（Ranking）：検索クエリに対して、関連性の高い順に表示\n\n【Googleが評価するポイント】\n• コンテンツの質（ユーザーの疑問に答えているか）\n• E-E-A-T（経験・専門性・権威性・信頼性）\n• ユーザー体験（読みやすさ、表示速度、モバイル対応）\n• 被リンク（他サイトからリンクされているか）"}, {"type": "text", "title": "営業視点でのSEO理解", "content": "【顧客はどんなキーワードで検索するか？】\n■ 課題系キーワード\n「中古車 在庫管理 効率化」「中古車販売店 業務改善」「エクセル 在庫管理 限界」\n\n■ 解決策系キーワード\n「中古車 販売管理システム」「中古車 業販 プラットフォーム」「自動車販売店 DX」\n\n■ 比較系キーワード\n「中古車 販売管理 比較」「Symphony 評判」「A社 vs B社」\n\n商談で「どうやってうちを知りましたか？」と聞くと、顧客の検索キーワードがわかる → マーケ部門へのフィードバックになる"}]}'::jsonb, 112, '2026-01-21T18:06:05.900528+00:00', '2026-01-21T18:06:05.900528+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (113, 'L', 'コンテンツマーケティング - 価値ある情報発信', NULL, 20, '新卒', '{"goal": "各種コンテンツの役割を理解し、商談前後でコンテンツを活用できるようになる", "quote": {"text": "コンテンツは営業の最強の武器である", "author": "Symphony Training Academy"}, "purpose": "コンテンツマーケティングの概念と各種コンテンツの役割を理解し、営業活動でコンテンツを効果的に活用できるようになります。", "summary": ["コンテンツマーケティングは「売り込み」ではなく「役立つ情報提供」", "購買段階に応じて適切なコンテンツを活用する", "自分で説明するより、良質なコンテンツを見せた方が説得力がある場合も多い"], "sections": [{"type": "text", "title": "コンテンツマーケティングとは", "content": "価値あるコンテンツを作成・配信することで、見込み客を引きつけ、信頼を構築し、最終的に購買につなげるマーケティング手法\n\n「売り込む」のではなく「役立つ情報を提供する」\n\n【コンテンツの種類と役割】\nブログ記事：認知・興味（初期）\nホワイトペーパー：興味・検討（中期）\n導入事例：検討・比較（中〜後期）\n製品資料：比較・購入（後期）\nウェビナー：興味・検討（中期）\n動画：全段階"}, {"type": "text", "title": "営業がコンテンツを活用する方法", "content": "【商談前】\n事前に関連コンテンツを送付\n「商談の前に、こちらの事例をご覧いただけると話が早いと思います」\n\n【商談中】\n口頭説明の代わりにコンテンツを見せる\n「この課題については、こちらの記事が詳しいです」\n\n【商談後】\nフォローメールでコンテンツを添付\n「本日お話しした件、こちらの事例も参考になります」\n\n【検討中顧客へ】\n定期的に役立つコンテンツを送る\n「業界動向のレポートを作成しましたのでお送りします」"}]}'::jsonb, 113, '2026-01-21T18:06:06.479524+00:00', '2026-01-21T18:06:06.479524+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (114, 'L', 'SNSマーケティング - 各プラットフォームの特性', NULL, 20, '新卒', '{"goal": "各SNSの特性を理解し、営業活動にSNSを活用する視点を持てるようになる", "quote": {"text": "SNSは営業の延長線上にある", "author": "Symphony Training Academy"}, "purpose": "各SNSプラットフォームの特性とB2BにおけるSNS活用の実態を理解し、営業個人としてのSNS活用のポイントを学びます。", "summary": ["各SNSには特性があり、B2B活用も進んでいる", "LinkedInはB2Bに特に有効", "営業個人のSNS活用が信頼構築につながる"], "sections": [{"type": "text", "title": "各SNSプラットフォームの特性", "content": "【X（旧Twitter）】\n特性：リアルタイム、拡散力、業界情報収集\nB2B活用：業界ニュース発信、専門家としてのブランディング\n\n【Facebook】\n特性：実名制、コミュニティ、中高年層\nB2B活用：企業ページ運営、広告配信、グループ活用\n\n【LinkedIn】\n特性：ビジネス特化、B2Bに強い、決裁者へのアクセス\nB2B活用：企業ブランディング、リード獲得、採用\n\n【YouTube】\n特性：動画、検索エンジン（Google傘下）、長期資産\nB2B活用：製品紹介動画、ハウツー動画、ウェビナーアーカイブ"}, {"type": "list", "title": "営業個人のSNS活用", "content": ["業界情報をキャッチ：顧客との会話のネタになる", "専門家としての発信：信頼性の構築", "顧客との関係維持：ゆるやかなつながり", "競合の動向を把握：情報収集ツールとして"]}]}'::jsonb, 114, '2026-01-21T18:06:07.146308+00:00', '2026-01-21T18:06:07.146308+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (115, 'L', 'リスティング広告の基礎 - Google/Yahoo広告', NULL, 20, '中堅', '{"goal": "リスティング広告の仕組みを理解し、広告経由のリードの特性を把握できるようになる", "quote": {"text": "検索している人は、今すぐ客の可能性が高い", "author": "WEBマーケティングの格言"}, "purpose": "検索連動型広告（リスティング広告）の仕組みと、広告経由の問い合わせの特徴を理解します。", "summary": ["リスティング広告は検索キーワードに連動した広告", "広告経由のリードは比較検討中が多い", "初回連絡のスピードが成約率に影響する"], "sections": [{"type": "text", "title": "リスティング広告とは", "content": "検索キーワードに連動して表示される広告（Google広告、Yahoo広告）\n\n【仕組み】\n1. 広告主がキーワードを設定\n2. ユーザーがそのキーワードで検索\n3. 検索結果の上部・下部に広告が表示\n4. クリックされると課金（CPC: Cost Per Click）\n\n【特徴】\n• 検索意図が明確なユーザーにアプローチ\n• クリック課金型（表示されただけでは費用がかからない）\n• 即効性がある（SEOより早く効果が出る）\n• 費用をかければ上位表示可能"}, {"type": "text", "title": "広告経由のリードの特徴", "content": "【広告経由リードの傾向】\n• 検索意図が明確 → ニーズが顕在化している\n• 比較検討中が多い → 競合も見ている可能性大\n• スピード勝負 → 早めの対応が重要\n\n【営業の対応ポイント】\n• 問い合わせ後の初回連絡を早く（24時間以内目標）\n• 「何を検索して来たか」を確認 → 関心ポイントを把握\n• 競合との比較を想定した提案準備"}]}'::jsonb, 115, '2026-01-21T18:06:08.311526+00:00', '2026-01-21T18:06:08.311526+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (116, 'L', 'ディスプレイ広告とリマーケティング', NULL, 20, '中堅', '{"goal": "ディスプレイ広告の仕組みを理解し、顧客視点でのWEB体験を想像できるようになる", "quote": {"text": "広告は顧客体験の一部である", "author": "WEBマーケティングの格言"}, "purpose": "バナー広告とリマーケティング（追跡型広告）の仕組みを理解し、顧客がどのような体験をしているかを把握します。", "summary": ["ディスプレイ広告はWEBサイト上のバナー広告", "リマーケティングは一度訪問した人を追跡する広告", "顧客は「追われている」感覚を持つことを理解する"], "sections": [{"type": "text", "title": "ディスプレイ広告とは", "content": "WEBサイトやアプリ上に表示されるバナー広告\n\n【リスティング広告との違い】\nリスティング：検索している人に表示（プル型）\nディスプレイ：ブラウジング中の人に表示（プッシュ型）\n\n【ターゲティング方法】\n• コンテンツターゲット：関連するサイトに表示\n• オーディエンスターゲット：特定の興味関心を持つ人に表示\n• リマーケティング：過去にサイトを訪問した人に表示"}, {"type": "text", "title": "リマーケティング（追跡型広告）", "content": "一度サイトを訪問したユーザーに、その後も広告を表示する手法\n\n【仕組み】\n1. ユーザーがサイトを訪問\n2. Cookie（追跡情報）が保存される\n3. 他のサイトを見ている時にも広告が表示される\n\n【効果】\n• 検討中の顧客に再アプローチ\n• ブランド想起の維持\n• 検討期間の長いB2Bに有効\n\n【顧客心理の理解】\n「あのサイトを見た後、広告が追いかけてくる」\n→ 顧客は追われている感覚を持つことも\n→ しつこすぎると逆効果"}]}'::jsonb, 116, '2026-01-21T18:06:08.884042+00:00', '2026-01-21T18:06:08.884042+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (117, 'L', 'ランディングページ（LP）の設計', NULL, 25, '中堅', '{"goal": "LPの役割を理解し、LP改善の視点を持って営業活動に活かせるようになる", "quote": {"text": "LPは24時間働く営業マンである", "author": "WEBマーケティングの格言"}, "purpose": "ランディングページの役割と構成要素を理解し、CVR（コンバージョン率）向上のポイントと営業への影響を学びます。", "summary": ["LPは特定のアクションに導くための1枚完結型ページ", "CVR向上には「顧客視点」での設計が重要", "営業の顧客知見をLPにフィードバックすることで改善に貢献できる"], "sections": [{"type": "text", "title": "ランディングページ（LP）とは", "content": "広告やメールからの流入を受け、特定のアクション（問い合わせ、資料請求等）に導くための1枚完結型のページ\n\n【LPの特徴】\n• 1ページで完結（他ページへの遷移を減らす）\n• 1つの目的（問い合わせ、資料DL等）に特化\n• 訴求力のあるデザイン・コピー\n\n【LP構成の基本】\nファーストビュー：キャッチコピー、メインビジュアル\n課題提起：「こんなお悩みありませんか？」\n解決策：製品・サービスの紹介\n実績・事例：信頼性の証明\nCTA：問い合わせボタン、フォーム"}, {"type": "list", "title": "CVR向上のポイント", "content": ["ファーストビューで離脱させない：何のページか3秒で伝わるか", "ベネフィットを明確に：「何ができるか」ではなく「どう良くなるか」", "信頼性の証明：導入実績、顧客の声、メディア掲載", "CTAの最適化：ボタンの文言、色、位置", "フォームの最適化：入力項目は最小限に"]}, {"type": "text", "title": "営業視点でのLP改善提案", "content": "【営業がフィードバックできること】\n• 顧客からよく聞く課題 → LPの課題提起に反映\n• 刺さるトーク → キャッチコピーに反映\n• よくある質問 → FAQに追加\n• 競合との比較ポイント → 差別化訴求に反映\n\n営業の知見がLP改善 → CVR向上 → リード増加 → 営業機会増加 という好循環を生む"}]}'::jsonb, 117, '2026-01-21T18:06:09.557123+00:00', '2026-01-21T18:06:09.557123+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (118, 'L', 'メールマーケティング - リードナーチャリング', NULL, 20, '新卒', '{"goal": "メールマーケティングの種類と効果を理解し、営業活動と連携できるようになる", "quote": {"text": "メールは許可を得た顧客との対話である", "author": "WEBマーケティングの格言"}, "purpose": "メルマガ、ステップメールの違いと役割を理解し、営業からの個別メールとの使い分けを学びます。", "summary": ["メルマガは関係維持、ステップメールは購買促進が目的", "営業の個別メールとマーケのメールは役割が異なる", "開封率・クリック率の改善ポイントを理解する"], "sections": [{"type": "text", "title": "メールマーケティングの種類", "content": "【メルマガ（メールマガジン）】\n定期的に配信する情報発信型メール\n目的：関係維持、情報提供、ブランディング\n例：月1回の業界ニュース、新機能のお知らせ\n\n【ステップメール】\n特定のアクション後に自動配信されるシナリオ型メール\n目的：リードナーチャリング、購買促進\n例：資料DL後 → 3日後に事例紹介 → 7日後にセミナー案内\n\n【営業からの個別メール】\n1対1のパーソナライズされたメール\n目的：関係構築、商談化、フォロー\n例：商談後のお礼、個別の情報提供"}, {"type": "list", "title": "開封率・クリック率の改善", "content": ["件名：短く、メリットを明確に、数字を入れる", "配信時間：B2Bは平日午前中が効果的", "パーソナライズ：名前、会社名を入れる", "CTA：1メール1アクションに絞る", "配信頻度：多すぎると解除される、少なすぎると忘れられる"]}]}'::jsonb, 118, '2026-01-21T18:06:10.196614+00:00', '2026-01-21T18:06:10.196614+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (119, 'L', 'アクセス解析の基礎 - データの見方', NULL, 25, '中堅', '{"goal": "主要なWEB指標を理解し、マーケティング部門との会話ができるようになる", "quote": {"text": "データは顧客の声なき声である", "author": "WEBマーケティングの格言"}, "purpose": "Google Analyticsの基本的な見方と重要指標を理解し、データから顧客行動を読み解く視点を身につけます。", "summary": ["PV、UU、CVR等の主要指標を理解する", "データから顧客の関心ポイントを読み解ける", "マーケティング部門との共通言語になる"], "sections": [{"type": "text", "title": "アクセス解析の重要指標", "content": "【トラフィック系指標】\nPV（Page View）：ページが閲覧された回数\nUU（Unique User）：訪問したユーザー数（重複除く）\nセッション：サイト訪問の回数\n\n【エンゲージメント系指標】\n直帰率：1ページだけ見て離脱した割合\n平均滞在時間：サイト内にいた時間\nページ/セッション：1回の訪問で見たページ数\n\n【コンバージョン系指標】\nCV（Conversion）：目標達成数（問い合わせ、資料DL等）\nCVR（Conversion Rate）：訪問者のうちCVした割合\nCPA（Cost Per Acquisition）：1件のCV獲得にかかった費用"}, {"type": "text", "title": "データから顧客行動を読み解く", "content": "【流入元の分析】\nどこから来たか？（検索、広告、SNS、直接）\n→ 効果的なチャネルを把握\n\n【閲覧ページの分析】\nどのページを見たか？\n→ 顧客の関心ポイントを把握\n\n【コンバージョン経路の分析】\nどのルートでCVに至ったか？\n→ 効果的な導線を把握\n\n【営業への活用】\n「この顧客は○○ページを見てから問い合わせた」\n→ 関心ポイントを予測して商談に臨める"}]}'::jsonb, 119, '2026-01-21T18:06:10.752365+00:00', '2026-01-21T18:06:10.752365+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (120, 'L', 'MA（マーケティングオートメーション）と営業連携', NULL, 20, '中堅', '{"goal": "MAの仕組みを理解し、MA情報を活用した営業アプローチができるようになる", "quote": {"text": "MAは魔法の杖ではない。使いこなす人間が重要", "author": "WEBマーケティングの格言"}, "purpose": "MAツールの概念と機能を理解し、リードスコアリングの仕組みとMA情報を活用した営業アプローチを学びます。", "summary": ["MAはマーケティング活動を自動化・効率化するツール", "スコアリングで見込み度合いを数値化する", "MA情報を活用することで、的確なアプローチが可能になる"], "sections": [{"type": "text", "title": "MA（マーケティングオートメーション）とは", "content": "マーケティング活動を自動化・効率化するためのツール\n\n【主な機能】\n• リード管理：見込み客情報の一元管理\n• メール配信：自動でのステップメール配信\n• スコアリング：見込み度合いの数値化\n• 行動追跡：WEB上での行動を記録\n• レポート：効果測定・分析\n\n【代表的なMAツール】\nHubSpot、Marketo、Pardot、SATORI等"}, {"type": "text", "title": "リードスコアリング", "content": "見込み客の「購買意欲」を数値化する仕組み\n\n【スコアリングの例】\n属性スコア：\n• 役職が部長以上 → +20点\n• 従業員数50人以上 → +10点\n\n行動スコア：\n• 資料をダウンロード → +15点\n• 価格ページを閲覧 → +20点\n• 3回以上サイト訪問 → +10点\n\n【スコアの活用】\n• 50点以上 → MQL（マーケ認定リード）として営業にパス\n• 80点以上 → 優先度高として即アプローチ"}, {"type": "text", "title": "MA情報を活用した営業アプローチ", "content": "【MAから得られる情報】\n• いつサイトを訪問したか\n• どのページを見たか\n• どの資料をダウンロードしたか\n• メールを開封したか、クリックしたか\n\n【営業での活用例】\n「先日、価格ページをご覧いただいたようですが、ご検討状況はいかがでしょうか？」\n「○○の事例をダウンロードいただきましたが、同様の課題をお持ちでしょうか？」\n\n顧客の行動を把握した上でアプローチ → 的確な提案が可能に"}]}'::jsonb, 120, '2026-01-21T18:06:11.560316+00:00', '2026-01-21T18:06:11.560316+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (121, 'M', 'SaaSビジネスモデルの基礎', NULL, 25, '若手', '{"goal": "SaaSビジネスモデルの特徴を説明でき、なぜ「継続」が重要かを理解できるようになる", "quote": {"text": "SaaSでは、契約がゴールではなくスタートである", "author": "SaaSビジネスの格言"}, "purpose": "SaaS（Software as a Service）のビジネスモデルを理解し、従来の売り切りモデルとの違いを把握します。SaaS営業として必要な基礎知識を身につけます。", "summary": ["SaaSは継続課金のビジネスモデル", "新規獲得と同じくらい「解約防止」が重要", "SaaS営業は売って終わりではなく、顧客の成功を支援する"], "sections": [{"type": "text", "title": "SaaSとは何か", "content": "SaaS = Software as a Service\nインターネット経由でソフトウェアを提供し、利用料（サブスクリプション）を得るビジネスモデル\n\n【従来モデル（売り切り）との違い】\n従来：ライセンス販売 → 一括購入 → 保守費用\nSaaS：月額/年額課金 → 継続利用 → アップデート込み\n\n【SaaSの特徴】\n• 初期費用が低い（顧客の導入障壁が低い）\n• 継続課金（毎月/毎年の収益）\n• 常に最新版を提供\n• 利用状況をデータで把握可能\n• 解約されるリスクがある"}, {"type": "text", "title": "SaaSビジネスの収益構造", "content": "【ストック型収益の魅力】\nSaaSは「積み上げ型」のビジネス\n毎月の新規獲得 + 既存顧客の継続 = 月次収益\n\n解約がなければ、収益は積み上がっていく\n→ だから「解約防止」が最重要\n\n【例：月額1万円のSaaS】\n1月：新規10社 → MRR 10万円\n2月：新規10社 → MRR 20万円（解約0の場合）\n3月：新規10社 → MRR 30万円（解約0の場合）\n...\n12月：MRR 120万円（解約0の場合）\n\n1社でも解約があれば、その分が減る\n→ 「穴の空いたバケツ」に水を入れるようなもの"}, {"type": "list", "title": "SaaS営業の役割", "content": ["新規獲得：新しい顧客を獲得する（従来の営業と同じ）", "オンボーディング支援：導入初期の定着を支援する", "アップセル/クロスセル：既存顧客の契約拡大", "解約防止：顧客の成功を支援し、継続利用を促す", "顧客の声のフィードバック：製品改善につなげる"]}]}'::jsonb, 121, '2026-01-21T18:06:12.108716+00:00', '2026-01-21T18:06:12.108716+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (122, 'M', 'SaaSの重要指標 - MRR/ARR', NULL, 20, '若手', '{"goal": "MRR/ARRの計算方法と構成要素を説明でき、自社の数字を理解できるようになる", "quote": {"text": "MRRはSaaSビジネスの心臓の鼓動である", "author": "SaaSビジネスの格言"}, "purpose": "SaaSビジネスの最重要指標であるMRR（月次経常収益）とARR（年次経常収益）を理解し、自社の収益状況を把握できるようになります。", "summary": ["MRRは月次、ARRは年次の経常収益", "Net New MRR = 新規 + 拡大 - 縮小 - 解約", "SaaS企業の価値はARRで評価される"], "sections": [{"type": "text", "title": "MRR（Monthly Recurring Revenue）", "content": "MRR = 月次経常収益\n毎月繰り返し得られる収益の合計\n\n【計算方法】\nMRR = 月額単価 × 顧客数\n\n例：月額1万円 × 100社 = MRR 100万円\n\n【MRRの構成要素】\n• New MRR：新規顧客からの収益\n• Expansion MRR：既存顧客のアップグレードによる増加\n• Contraction MRR：既存顧客のダウングレードによる減少\n• Churn MRR：解約による減少\n\n【Net New MRR】\nNet New MRR = New MRR + Expansion MRR - Contraction MRR - Churn MRR\n→ 純増分を示す最重要指標"}, {"type": "text", "title": "ARR（Annual Recurring Revenue）", "content": "ARR = 年次経常収益\nMRR × 12 = ARR\n\n例：MRR 100万円 × 12 = ARR 1,200万円\n\n【ARRが使われる場面】\n• 年間契約が主流の場合\n• 投資家への報告（企業価値評価）\n• 中長期の事業計画\n\n【SaaS企業の評価】\nSaaS企業の企業価値は「ARR × 倍率」で評価されることが多い\n例：ARR 10億円 × 10倍 = 企業価値 100億円\n→ ARRの成長が企業価値に直結"}, {"type": "list", "title": "営業がMRR/ARRを意識する意義", "content": ["自分の貢献を数字で把握：「今月○○万円のMRRを獲得した」", "解約の影響を理解：「1社解約 = ○○万円のMRR減少」", "アップセルの価値を理解：「プランアップグレード = Expansion MRR」", "会社の成長を実感：「MRRが前月比○%成長」"]}]}'::jsonb, 122, '2026-01-21T18:06:13.336351+00:00', '2026-01-21T18:06:13.336351+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (123, 'M', '顧客獲得コスト - CAC', NULL, 20, '若手', '{"goal": "CACの計算方法を理解し、効率的な営業活動の重要性を認識できるようになる", "quote": {"text": "効率的に獲得した顧客は、ビジネスを健全にする", "author": "SaaSビジネスの格言"}, "purpose": "CAC（顧客獲得コスト）の概念を理解し、効率的な顧客獲得の重要性と営業活動がCACに与える影響を認識します。", "summary": ["CACは1社獲得にかかる費用", "CAC = (営業コスト + マーケコスト) ÷ 新規獲得数", "営業効率の向上がCAC削減につながる"], "sections": [{"type": "text", "title": "CAC（Customer Acquisition Cost）とは", "content": "CAC = 顧客獲得コスト\n1社の新規顧客を獲得するためにかかった費用\n\n【計算方法】\nCAC = (営業コスト + マーケティングコスト) ÷ 新規獲得顧客数\n\n例：\n営業人件費：500万円/月\nマーケティング費用：200万円/月\n新規獲得：10社/月\nCAC = 700万円 ÷ 10社 = 70万円/社"}, {"type": "list", "title": "CACに含まれるコスト", "content": ["営業人件費：給与、社会保険、交通費等", "マーケティング費用：広告費、展示会費、コンテンツ制作費", "ツール費用：CRM、MA、営業支援ツール等", "その他：採用費、研修費等"]}, {"type": "text", "title": "CACを下げる方法", "content": "【営業効率の向上】\n• 商談数を増やす（アポ獲得率向上）\n• 成約率を上げる（提案力向上）\n• 商談サイクルを短縮する\n\n【マーケティング効率の向上】\n• リードの質を上げる\n• コンバージョン率を改善\n• 低コストチャネルの活用（紹介等）\n\n【営業としてできること】\n• 効率的な商談活動（無駄な訪問を減らす）\n• 成約率の向上（提案スキル向上）\n• 紹介の獲得（CACゼロの新規獲得）"}]}'::jsonb, 123, '2026-01-21T18:06:13.916946+00:00', '2026-01-21T18:06:13.916946+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (124, 'M', '顧客生涯価値 - LTV', NULL, 20, '若手', '{"goal": "LTVの計算方法を理解し、顧客維持の重要性を認識できるようになる", "quote": {"text": "LTVを高めることは、顧客を幸せにすることと同義である", "author": "SaaSビジネスの格言"}, "purpose": "LTV（顧客生涯価値）の概念を理解し、1社の顧客から長期的に得られる収益の重要性を認識します。", "summary": ["LTVは顧客から得られる収益の総額", "LTV = 月額単価 × 平均継続月数", "LTV > CAC が健全なSaaSビジネスの条件"], "sections": [{"type": "text", "title": "LTV（Lifetime Value）とは", "content": "LTV = 顧客生涯価値\n1社の顧客から、取引期間全体で得られる収益の総額\n\n【計算方法（簡易版）】\nLTV = 月額単価 × 平均継続月数\n\n例：月額1万円 × 平均36ヶ月 = LTV 36万円\n\n【計算方法（詳細版）】\nLTV = ARPA ÷ 月次解約率\n※ARPA = Average Revenue Per Account（顧客あたり平均収益）\n\n例：ARPA 1万円 ÷ 解約率3% = LTV 33.3万円"}, {"type": "list", "title": "LTVを高める方法", "content": ["解約率を下げる：継続期間を延ばす → LTV増加", "ARPA（単価）を上げる：アップセル、クロスセル → LTV増加", "顧客満足度を高める：サポート品質向上 → 継続率向上", "オンボーディング強化：初期定着 → 長期継続"]}, {"type": "text", "title": "LTVの重要性", "content": "【LTV > CAC が健全なビジネス】\nLTV（顧客から得られる収益）> CAC（獲得コスト）\nでなければ、獲得すればするほど赤字になる\n\n【LTV/CAC比率の目安】\n• LTV/CAC = 1未満：赤字（獲得しない方がマシ）\n• LTV/CAC = 1〜3：要改善\n• LTV/CAC = 3以上：健全\n\n例：LTV 36万円、CAC 10万円の場合\nLTV/CAC = 3.6 → 健全\n\n【営業への示唆】\n• 解約しそうな顧客を獲得しても意味がない\n• 長く使ってくれる顧客を獲得することが重要\n• 契約後のフォローがLTVを左右する"}]}'::jsonb, 124, '2026-01-21T18:06:14.512447+00:00', '2026-01-21T18:06:14.512447+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (125, 'M', '解約率 - チャーンレート', NULL, 25, '中堅', '{"goal": "チャーンレートを説明でき、解約防止の重要性を数字で理解できるようになる", "quote": {"text": "解約は穴の空いたバケツ。新規を入れる前に穴を塞げ", "author": "SaaSビジネスの格言"}, "purpose": "チャーンレート（解約率）の種類と計算方法を理解し、解約がビジネスに与える影響の大きさを認識します。", "summary": ["チャーンレートは解約の割合を示す指標", "月次3%の解約で年間31%の顧客を失う", "ネガティブチャーン（拡大 > 解約）が理想状態"], "sections": [{"type": "text", "title": "チャーンレートとは", "content": "Churn Rate = 解約率\n一定期間内に解約した顧客の割合\n\n【カスタマーチャーン（顧客数ベース）】\n月次解約率 = 当月解約顧客数 ÷ 月初顧客数 × 100\n\n例：月初100社、当月解約3社\n月次解約率 = 3 ÷ 100 × 100 = 3%\n\n【レベニューチャーン（収益ベース）】\n月次MRR解約率 = 当月解約MRR ÷ 月初MRR × 100\n\n例：月初MRR 1,000万円、当月解約MRR 30万円\n月次MRR解約率 = 30 ÷ 1,000 × 100 = 3%"}, {"type": "text", "title": "チャーンの影響（複利効果）", "content": "【月次3%解約の年間影響】\n月初100社 × (1-0.03)^12 = 69社\n→ 年間で31%の顧客を失う\n\n【月次5%解約の年間影響】\n月初100社 × (1-0.05)^12 = 54社\n→ 年間で46%の顧客を失う\n\n【チャーン率の目安（BtoB SaaS）】\n• 月次1%以下：優秀\n• 月次2-3%：平均的\n• 月次5%以上：危険水準\n\n解約率のわずかな差が、長期的には大きな差になる"}, {"type": "text", "title": "ネガティブチャーンとは", "content": "【Net Revenue Churn】\nNet Revenue Churn = (解約MRR + 縮小MRR - 拡大MRR) ÷ 月初MRR\n\n拡大MRR > 解約MRR + 縮小MRR の場合\n→ ネガティブチャーン（マイナスの解約率）\n→ 既存顧客だけで成長できる理想状態\n\n例：\n解約MRR：30万円\n縮小MRR：10万円\n拡大MRR：50万円\nNet Revenue Churn = (30 + 10 - 50) ÷ 1,000 = -1%\n→ 既存顧客からの収益が純増している"}]}'::jsonb, 125, '2026-01-21T18:06:15.067769+00:00', '2026-01-21T18:06:15.067769+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (126, 'M', 'ユニットエコノミクス - 事業の健全性', NULL, 25, '中堅', '{"goal": "ユニットエコノミクスを説明でき、自社の事業健全性を判断できるようになる", "quote": {"text": "ユニットエコノミクスが成り立たなければ、成長は砂上の楼閣", "author": "SaaSビジネスの格言"}, "purpose": "ユニットエコノミクス（1顧客あたりの経済性）を理解し、LTV/CAC比率やCAC回収期間など、事業の健全性を判断する指標を学びます。", "summary": ["ユニットエコノミクスは1顧客あたりの経済性", "LTV/CAC比率は3以上が健全", "CAC回収期間は12ヶ月以内が目安"], "sections": [{"type": "text", "title": "ユニットエコノミクスとは", "content": "Unit Economics = 1顧客あたりの経済性\n1社の顧客を獲得・維持することが、経済的に成り立っているかを判断する指標群\n\n【主要指標】\n• LTV（顧客生涯価値）\n• CAC（顧客獲得コスト）\n• LTV/CAC比率\n• CAC回収期間（Payback Period）"}, {"type": "text", "title": "LTV/CAC比率", "content": "LTV/CAC = 顧客生涯価値 ÷ 顧客獲得コスト\n\n【目安】\n• 1未満：赤字（投資回収できない）\n• 1〜3：要改善（効率が悪い）\n• 3以上：健全（投資対効果が良い）\n• 5以上：優秀（成長投資の余地あり）\n\n例：LTV 36万円、CAC 12万円\nLTV/CAC = 36 ÷ 12 = 3.0 → 健全\n\n【注意点】\nLTV/CACが高すぎる場合（10以上など）\n→ 成長投資が足りない可能性\n→ もっとマーケ/営業に投資して成長を加速すべき"}, {"type": "text", "title": "CAC回収期間（Payback Period）", "content": "CAC Payback = CAC ÷ 月額ARPA\n顧客獲得コストを何ヶ月で回収できるか\n\n【目安】\n• 6ヶ月以内：優秀\n• 12ヶ月以内：健全\n• 18ヶ月以上：要改善\n\n例：CAC 12万円、月額ARPA 1万円\nCAC Payback = 12 ÷ 1 = 12ヶ月\n→ 12ヶ月で投資回収、それ以降が利益\n\n【営業への示唆】\n• 回収期間が長い = キャッシュフローが厳しい\n• 早期解約されると投資回収できない\n• 契約後の定着支援が重要"}]}'::jsonb, 126, '2026-01-21T18:06:15.952968+00:00', '2026-01-21T18:06:15.952968+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (127, 'M', 'カスタマーサクセスと営業の連携', NULL, 25, '中堅', '{"goal": "カスタマーサクセスの役割を理解し、CSと連携した顧客支援ができるようになる", "quote": {"text": "顧客が成功しなければ、私たちも成功しない", "author": "SaaSビジネスの格言"}, "purpose": "カスタマーサクセス（CS）の役割を理解し、営業との連携ポイントを学びます。「売って終わり」ではなく、顧客の成功を支援する姿勢を身につけます。", "summary": ["カスタマーサクセスは顧客の成功を能動的に支援する活動", "営業からCSへの丁寧な引き継ぎが重要", "顧客の成功が解約防止・収益拡大につながる"], "sections": [{"type": "text", "title": "カスタマーサクセスとは", "content": "Customer Success = 顧客の成功を支援する活動\n\n【カスタマーサポートとの違い】\nサポート：顧客からの問い合わせに「受動的」に対応\nサクセス：顧客の成功に向けて「能動的」に働きかける\n\n【カスタマーサクセスの目的】\n• 顧客の成功（導入目的の達成）\n• 解約防止（チャーン削減）\n• 収益拡大（アップセル/クロスセル）\n• 顧客の声の収集（製品改善）"}, {"type": "list", "title": "カスタマーサクセスの活動", "content": ["オンボーディング：導入初期の定着支援", "ヘルススコア管理：顧客の利用状況を監視", "定期的なタッチポイント：QBR（四半期ビジネスレビュー）等", "解約防止：解約リスクの早期検知と対応", "アップセル/クロスセル：拡大提案"]}, {"type": "text", "title": "営業とカスタマーサクセスの連携", "content": "【営業 → CS への引き継ぎ】\n• 顧客の導入目的・期待値\n• 意思決定者・キーパーソン\n• 商談で出た懸念・リスク\n• 特別な約束事項\n\n【CS → 営業 へのフィードバック】\n• アップセル/クロスセルの機会\n• 顧客の新たなニーズ\n• 解約リスクの情報\n• 製品改善の要望\n\n【連携のポイント】\n• 引き継ぎを丁寧に行う（「売ったら終わり」にしない）\n• 定期的に顧客状況を共有\n• アップセル機会は営業が対応\n• 顧客の成功を共通のゴールにする"}]}'::jsonb, 127, '2026-01-21T18:06:16.512379+00:00', '2026-01-21T18:06:16.512379+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (128, 'M', 'SaaS営業のセールスファネル', NULL, 20, '若手', '{"goal": "セールスファネルの各ステージを説明でき、自分の活動を適切に管理できるようになる", "quote": {"text": "ファネルを管理できる者が、売上を管理できる", "author": "SaaS営業の格言"}, "purpose": "SaaS営業特有のセールスファネル（商談プロセス）を理解し、各ステージでの活動と重要指標を把握します。", "summary": ["ファネルはリードから受注、継続までの流れ", "各ステージでの定義と活動を明確にする", "コンバージョン率と商談期間を管理する"], "sections": [{"type": "text", "title": "SaaSセールスファネルの構造", "content": "【ファネル（漏斗）のイメージ】\n多くのリードから、段階的に絞り込まれて受注に至る\n\nリード（見込み客）\n  ↓\nMQL（マーケ認定リード）\n  ↓\nSQL（営業認定リード）\n  ↓\n商談（Opportunity）\n  ↓\n提案・見積\n  ↓\n受注（契約）\n  ↓\nオンボーディング\n  ↓\n継続利用・拡大"}, {"type": "text", "title": "各ステージの定義と活動", "content": "【MQL → SQL】\n定義：営業がアプローチすべきと判断したリード\n活動：初回コンタクト、ニーズ確認、商談化判断\n\n【SQL → 商談】\n定義：具体的な検討が始まったリード\n活動：課題ヒアリング、提案準備、デモ実施\n\n【商談 → 提案】\n定義：提案・見積を行う段階\n活動：提案書作成、見積提示、条件交渉\n\n【提案 → 受注】\n定義：契約締結の段階\n活動：最終交渉、契約書締結、決済処理\n\n【受注 → オンボーディング】\n定義：導入・定着支援の段階\n活動：初期設定、研修、定着フォロー"}, {"type": "list", "title": "ファネル管理の重要指標", "content": ["コンバージョン率：各ステージから次への移行率（例：商談→受注 30%）", "平均商談期間：初回接触から受注までの平均日数", "パイプライン金額：進行中の商談の合計金額", "パイプラインカバレッジ：目標に対するパイプラインの倍率（3倍以上が目安）"]}]}'::jsonb, 128, '2026-01-21T18:06:17.265482+00:00', '2026-01-21T18:06:17.265482+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (129, 'M', 'SaaSの価格戦略と契約形態', NULL, 20, '中堅', '{"goal": "SaaSの価格モデルを説明でき、顧客に合った契約形態を提案できるようになる", "quote": {"text": "適切な価格は、顧客にとっても会社にとってもWin-Winである", "author": "SaaSビジネスの格言"}, "purpose": "SaaSの価格設定モデルと契約形態（月額/年額、席数課金など）を理解し、顧客に最適な提案ができるようになります。", "summary": ["SaaSには複数の価格設定モデルがある", "年額契約は解約率低下とキャッシュフロー改善に有効", "アップセル/クロスセルがLTV向上のカギ"], "sections": [{"type": "text", "title": "SaaSの価格設定モデル", "content": "【フラットレート（定額制）】\n月額○○円で全機能利用可能\nメリット：シンプル、予算が立てやすい\nデメリット：顧客規模に応じた価格設定ができない\n\n【ユーザー数課金（Per Seat）】\n1ユーザーあたり○○円\nメリット：利用者数に応じた公平な課金\nデメリット：ユーザー追加の障壁になることも\n\n【利用量課金（Usage Based）】\n利用量に応じて課金（API呼び出し数、データ量など）\nメリット：使った分だけ支払い\nデメリット：予算が立てにくい\n\n【ティアード（段階制）】\n機能や容量に応じた複数プラン（Basic/Pro/Enterprise）\nメリット：顧客のニーズに合わせて選択可能\nデメリット：プラン設計が複雑"}, {"type": "text", "title": "契約期間と割引", "content": "【月額契約 vs 年額契約】\n月額：柔軟性が高い、解約しやすい\n年額：割引あり（10-20%）、キャッシュフロー改善、解約防止\n\n【年額契約を推奨する理由】\n• 解約率の低下（1年は使ってもらえる）\n• キャッシュフローの改善（前払い）\n• 顧客のコミットメント向上\n\n【営業としての提案】\n「年額契約なら○○%割引になります」\n「年間でのお支払いで、月あたり○○円お得です」"}, {"type": "list", "title": "アップセル・クロスセルの機会", "content": ["プランアップグレード：Basic → Pro → Enterprise", "ユーザー数追加：利用者が増えた時", "オプション追加：追加機能、追加サポート", "関連製品のクロスセル：他製品の提案"]}]}'::jsonb, 129, '2026-01-21T18:06:17.8363+00:00', '2026-01-21T18:06:17.8363+00:00');
INSERT INTO trainings (id, category_id, title, subtitle, duration, level, detail, display_order, created_at, updated_at) VALUES (130, 'M', 'SaaS営業の成功指標とKPI', NULL, 25, '中堅', '{"goal": "SaaS営業のKPIを説明でき、自分の活動を数字で振り返り改善できるようになる", "quote": {"text": "測定できるものは改善できる。KPIは成長の羅針盤である", "author": "SaaSビジネスの格言"}, "purpose": "SaaS営業として追うべきKPIを総合的に理解し、自分の活動を数字で管理・改善できるようになります。", "summary": ["SaaS営業のKPIは活動→成果→効率の階層構造", "KPIを分解することで課題が見える", "週次・月次で振り返り、PDCAを回す"], "sections": [{"type": "text", "title": "SaaS営業のKPI一覧", "content": "【活動指標（Input）】\n• コール数/メール数\n• アポイント獲得数\n• 商談数\n• デモ実施数\n\n【成果指標（Output）】\n• 新規MRR/ARR\n• 受注件数\n• 受注金額\n• 成約率（CVR）\n\n【効率指標】\n• 平均商談単価\n• 平均商談期間\n• CAC\n• 営業1人あたり生産性"}, {"type": "text", "title": "KPIの階層構造", "content": "【最終目標】新規MRR ○○万円\n↑\n【成果指標】受注件数 × 平均単価\n↑\n【プロセス指標】商談数 × 成約率\n↑\n【活動指標】アポ数 × 商談化率\n↑\n【行動指標】コール数 × アポ獲得率\n\n各指標を分解することで、どこに課題があるかが見える\n\n例：新規MRRが足りない場合\n→ 受注件数が少ない？単価が低い？\n→ 商談数が少ない？成約率が低い？\n→ アポが取れていない？商談化できていない？"}, {"type": "text", "title": "KPIの振り返りと改善", "content": "【週次で振り返るべき指標】\n• 活動量（コール数、アポ数、商談数）\n• パイプライン状況（商談進捗）\n• 今週の受注見込み\n\n【月次で振り返るべき指標】\n• 新規MRR達成率\n• 各ステージのコンバージョン率\n• 平均商談単価・期間\n\n【改善のPDCA】\nPlan：目標設定、仮説立案\nDo：営業活動の実行\nCheck：KPIの振り返り\nAct：改善アクションの実行\n\n「数字を見て、原因を分析し、行動を変える」サイクルを回す"}]}'::jsonb, 130, '2026-01-21T18:06:18.482372+00:00', '2026-01-21T18:06:18.482372+00:00');
INSERT INTO category_tests (id, category_id, category_name, total_questions, passing_score, time_limit, created_at, updated_at) VALUES (1, 'A', '基礎マインドセット編', 50, 80, 30, '2026-01-23T10:21:08.534175+00:00', '2026-01-23T10:21:08.161+00:00');
