INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (1, 1, 1, '顧客から「御社の製品について詳しく教えてください」と言われた時の対応として最も適切なのは？', '["すぐにカタログを出して製品の機能を説明する", "まず顧客の現状や課題についてヒアリングする", "競合製品との比較表を見せて優位性を伝える", "導入事例を紹介して信頼性をアピールする"]'::jsonb, 1, '問題解決型営業では、製品説明の前に顧客の課題を理解することが重要です。課題がわからなければ、適切な提案はできません。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (2, 1, 2, 'SPIN話法における「示唆質問（Implication）」の目的として正しいのは？', '["顧客の現状を詳しく把握すること", "顧客に問題の深刻さを自ら気づかせること", "自社製品の優位性を伝えること", "顧客のニーズを直接確認すること"]'::jsonb, 1, '示唆質問は、問題を放置した場合の影響を考えさせることで、顧客自身が問題の大きさに気づくことを促します。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (3, 1, 3, '「うちは特に困っていることはないんだけど...」と言う顧客への対応として適切なのは？', '["そうですか、と引き下がり次の機会を待つ", "実は御社にはこういう課題があるはずだと指摘する", "質問を通じて顧客が気づいていない課題を引き出す", "他社の導入事例を紹介して必要性を訴える"]'::jsonb, 2, '顧客は自分の課題に気づいていないことがあります（潜在ニーズ）。質問を通じて顕在化させることが営業の役割です。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (4, 1, 4, '「棚卸しに毎月3日かかっている」と顧客が言った場合、次に聞くべき質問は？', '["その3日間で、業務にどんな影響が出ていますか？", "弊社システムなら1日で終わりますよ。いかがですか？", "他の会社はもっと短い時間で終わっていますよ", "改善したいとお考えですか？"]'::jsonb, 0, '示唆質問で問題の影響を考えさせることで、顧客自身が問題の大きさに気づきます。すぐに解決策を提示しないことがポイントです。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (5, 1, 5, '問題解決型営業における「信頼構築→課題把握→解決策提案」の順序について正しいのは？', '["効率を考えると課題把握と解決策提案を同時に行うべき", "信頼がなければ顧客は本当の課題を話してくれない", "解決策を先に提示した方が顧客の興味を引ける", "信頼構築は提案後のフォローで行えば十分である"]'::jsonb, 1, '信頼関係がなければ、顧客は本当の課題を話してくれません。信頼構築→課題把握→解決策提案の順序が重要です。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (6, 1, 6, '初回商談での「ヒアリング7：提案3」という比率が推奨される理由は？', '["営業が話しすぎると顧客が飽きてしまうから", "課題を十分に理解してから提案しないと的外れになるから", "提案の時間を短くするとクロージングしやすくなるから", "顧客に話させることで購買意欲が高まるから"]'::jsonb, 1, '初回商談では、顧客の話を聞くことが優先です。課題を十分に理解してから提案しないと、的外れな提案になってしまいます。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (7, 1, 7, '大型商談でクロージングテクニック（強引な契約促進）を多用すると何が起こるか？', '["顧客の決断が早まり成約率が上がる", "顧客の抵抗を招き逆効果になる", "短期的には成約率が上がる", "特に影響はない"]'::jsonb, 1, '大型商談では、クロージングテクニックの多用は逆効果です。顧客が自ら「買いたい」と思う状態を作ることが重要です。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (8, 1, 8, '「御社より安い競合があります」と言われた時、問題解決型営業としての対応は？', '["競合に負けないよう値引きを提案する", "価格ではなく課題解決への貢献度で比較を促す", "競合製品の欠点を指摘して差別化する", "価格では勝てないと正直に伝える"]'::jsonb, 1, '問題解決型営業では、価格ではなく「価値」で勝負します。顧客の課題解決にどれだけ貢献できるかを軸に話を進めます。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (9, 1, 9, '「営業が説明するより、顧客が自分で気づく方が効果的」と言われる理由は？', '["顧客は営業の話を信用しないことが多いから", "自分で発見した問題しか本気で解決しようとしないから", "営業が説明すると押し売りに感じられるから", "顧客の方が自社の状況をよく知っているから"]'::jsonb, 1, '人は他人から言われたことより、自分で気づいたことに強く動機づけられます（自己説得効果）。営業の役割は「気づかせる」ことです。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (10, 1, 10, '問題解決型営業において最も重要な姿勢は？', '["自社製品の優位性を最大限アピールする", "顧客の成功に貢献することを最優先にする", "競合に勝つための戦略を常に考える", "ノルマ達成のために効率的に動く"]'::jsonb, 1, '問題解決型営業では、顧客の成功に貢献することが最優先です。それが結果として売上につながります。', '研修1: 営業とは問題解決である', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (11, 1, 11, '第一印象が形成されるまでの時間と、その対策として正しいのは？', '["約10秒で形成されるため、自己紹介の言葉を準備する", "約0.1秒で形成されるため、登場の瞬間の表情を準備する", "約1分で形成されるため、最初の話題を準備する", "約5分で形成されるため、最初の提案内容を準備する"]'::jsonb, 1, '第一印象は0.1秒で形成されます。言葉を発する前の「登場の瞬間」が勝負です。笑顔とアイコンタクトを準備しましょう。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (12, 1, 12, '「初頭効果」を正しく理解した上で、商談で意識すべきことは？', '["最後に伝える情報が最も記憶に残るので結論は最後に言う", "最初に伝える情報がその後の解釈の枠組みになる", "中盤に重要な情報を伝えると注目されやすい", "情報の順序は特に影響しないので内容を重視する"]'::jsonb, 1, '初頭効果により、最初に伝えた情報がその後の情報の解釈の枠組みになります。ポジティブな情報から伝えることで、好意的な印象を形成できます。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (13, 1, 13, '「確証バイアス」が営業に与える影響として正しいのは？', '["顧客は常に客観的に営業を評価する", "良い第一印象を持つとその後も好意的に解釈される", "第一印象が悪くても挽回は容易である", "印象は会うたびにリセットされる"]'::jsonb, 1, '確証バイアスにより、最初の印象に合う情報を選択的に集め、解釈する傾向があります。良い第一印象は、その後の商談を有利に進めます。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (14, 1, 14, '「メラビアンの法則」の正しい理解と、商談での活用法は？', '["言葉は7%しか伝わらないので内容より態度を重視する", "言葉・声・表情が矛盾しないことが信頼につながる", "非言語を大げさにすれば説得力が増す", "言葉の内容は重要ではないので簡潔に話す"]'::jsonb, 1, 'メラビアンの法則は「言葉と態度が矛盾した時」の研究です。言葉・声・表情が一致していることが信頼につながります。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (15, 1, 15, 'オンライン商談で第一印象を良くするための最も重要な準備は？', '["話す内容を完璧に暗記しておく", "資料を画面共有ですぐ出せるようにしておく", "カメラ位置・照明・背景を整え、接続時に笑顔で待機する", "チャットで事前に詳細な挨拶を送っておく"]'::jsonb, 2, 'オンラインでも第一印象は重要です。接続した瞬間の見た目が印象を決めるため、カメラ、照明、背景、そして笑顔を準備します。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (16, 1, 16, '第一印象で失敗した場合の挽回について正しいのは？', '["一度ついた印象は絶対に変えられない", "挽回可能だが最初から良い印象より何倍もの努力が必要", "次回会った時に自動的にリセットされる", "言葉で説明すれば簡単に印象は変わる"]'::jsonb, 1, '第一印象は挽回可能ですが、確証バイアスがあるため、最初から良い印象を与えるより多くの努力が必要です。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (17, 1, 17, '電話での第一印象を決める最も重要な要素は？', '["話す内容の正確さと専門知識", "敬語の正しさと丁寧な言葉遣い", "声のトーンと話し方のハキハキさ", "電話をかける時間帯の適切さ"]'::jsonb, 2, '電話では視覚情報がないため、声のトーンと話し方が第一印象を決めます。明るく、ハキハキと話すことが重要です。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (18, 1, 18, '初対面の顧客に対して、最初の数分間で最も意識すべきことは？', '["自社製品の優位性を全て伝えること", "ラポール（信頼関係）を築くことに集中する", "顧客の課題を素早くヒアリングすること", "次回のアポイントを確保すること"]'::jsonb, 1, '最初の数分は第一印象を固定する重要な時間です。いきなり商談に入るのではなく、アイスブレイクと信頼関係構築に集中します。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (19, 1, 19, '清潔感のある身だしなみが重要な理由として正しいのは？', '["会社のルールで定められているから", "視覚情報が第一印象に大きく影響するから", "顧客がファッションに敏感な人が多いから", "競合他社の営業と差別化するため"]'::jsonb, 1, '第一印象は視覚情報の影響が大きいです。話す前に「見た目」で判断されるため、清潔感のある身だしなみが信頼につながります。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (20, 1, 20, '名刺交換で意識すべき非言語コミュニケーションとして適切なのは？', '["スムーズに済ませて早く本題に入る", "自分の名刺の内容を詳しく説明する", "相手の目を見て笑顔で丁寧に両手で受け取る", "受け取った名刺はすぐに名刺入れにしまう"]'::jsonb, 2, '名刺交換は第一印象を形成する重要な瞬間です。アイコンタクト、笑顔、丁寧な所作が信頼感につながります。', '研修2: 第一印象の科学', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (21, 1, 21, '「学習性無力感」を正しく理解した上で、断られた時に避けるべき思考は？', '["今回の案件は合わなかったと考える", "どうせ自分には営業の才能がないと考える", "次はアプローチを変えてみようと考える", "この顧客には別の提案をしようと考える"]'::jsonb, 1, '学習性無力感は「何をやっても無駄」という状態です。「永続的・全般的・内的」な解釈を避け、「一時的・限定的・外的」と捉え直すことが重要です。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (22, 1, 22, '「楽観的説明スタイル」の特徴として正しいのは？', '["失敗を「永続的・全般的・内的」に捉える", "失敗を「一時的・限定的・外的」に捉える", "失敗を「運命」として受け入れる", "失敗を「他人のせい」にする"]'::jsonb, 1, '楽観的説明スタイルでは、失敗を「一時的（今回だけ）・限定的（この案件だけ）・外的（状況要因）」と捉えます。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (23, 1, 23, '「成長マインドセット」と「固定マインドセット」の違いとして正しいのは？', '["成長マインドセットは失敗を避け、固定マインドセットは挑戦する", "成長マインドセットは能力は伸ばせると考え、固定マインドセットは才能で決まると考える", "成長マインドセットは他者と比較し、固定マインドセットは自分と比較する", "成長マインドセットは結果重視、固定マインドセットはプロセス重視"]'::jsonb, 1, '成長マインドセットは「能力は努力で伸ばせる」という信念で、固定マインドセットは「能力は生まれつき決まっている」という信念です。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (24, 1, 24, '断られることが怖くてテレアポに手が伸びない時、「自己効力感」を高めるための対応は？', '["恐怖心が消えるまで他の仕事をする", "まず5件だけかけるという小さな目標を設定する", "成功している先輩の真似をする", "テレアポは向いていないと割り切る"]'::jsonb, 1, '自己効力感は「達成体験」で高まります。小さな目標を設定し、達成することで「自分にもできる」という感覚が生まれます。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (25, 1, 25, '断られた理由を分析する際、「帰属理論」に基づく建設的な視点は？', '["自分の性格や才能に原因を求める", "運やタイミングの問題として処理する", "変えられる具体的な行動に原因を求める", "顧客の問題として考える"]'::jsonb, 2, '帰属理論では「統制可能な要因」に帰属することが重要です。変えられない要因ではなく、変えられる要因（行動、準備）に焦点を当てます。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (26, 1, 26, '10件連続で断られた時の思考として、楽観的説明スタイルに該当するのは？', '["自分には営業のセンスがないようだ", "営業という仕事自体が向いていないのかも", "今日はたまたまタイミングが悪かったのだろう", "どうせ何をやっても結果は同じだ"]'::jsonb, 2, '楽観的説明スタイルでは、失敗を「一時的・限定的・外的」と捉えます。「今日はたまたま」は一時的かつ外的な解釈です。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (27, 1, 27, '「お前は営業に向いていない」と言われた時、成長マインドセットの対応は？', '["その通りだと認めて営業以外の仕事を探す", "今は未熟だが努力すれば成長できると捉える", "言った人の評価能力を疑う", "反論して自分の実力を証明しようとする"]'::jsonb, 1, '成長マインドセットは「能力は努力で伸ばせる」という信念です。現時点の評価は出発点であり、どう成長するかを考えます。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (28, 1, 28, 'テレアポで100件中5件のアポが取れた結果について、自己効力感を高める捉え方は？', '["95件も断られたことを反省する", "5件のアポを獲得できたことに焦点を当てる", "他の人と比較して評価する", "今回はたまたま運が良かっただけ"]'::jsonb, 1, '成功体験に焦点を当てることで自己効力感が高まります。断られることを前提に、成功を積み重ねる視点が重要です。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (29, 1, 29, '断られた後に「また明日頑張ろう」と思える人と「もうダメだ」と思う人の違いは何か？', '["生まれつきの性格の違い", "経験年数の違い", "失敗の捉え方（説明スタイル）の違い", "会社のサポート体制の違い"]'::jsonb, 2, '楽観的か悲観的かは、失敗をどう説明するか（説明スタイル）の違いです。これは訓練で変えることができます。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (30, 1, 30, 'チームメンバーが断られて落ち込んでいる時、成長マインドセットを促す声かけは？', '["気にするな、次があるよ", "営業はそういうものだから慣れるしかない", "何がうまくいかなかったか一緒に分析してみよう", "今日は早く帰ってゆっくり休んだら"]'::jsonb, 2, '失敗を「学びの機会」として一緒に分析することで、成長マインドセットを促進できます。具体的な改善点を見つけることが次につながります。', '研修3: 断られることへの正しい向き合い方', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (31, 1, 31, '「今月はたくさん売る」という目標がSMART目標として不十分な理由は？', '["期限が短すぎるから", "具体性と測定可能性が欠けているから", "達成困難だから", "チーム目標になっていないから"]'::jsonb, 1, 'SMART目標のS（Specific：具体的）とM（Measurable：測定可能）が欠けています。「10件成約する」のように具体的にする必要があります。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (32, 1, 32, '目標設定理論において「適度に困難な目標」が効果的な理由は？', '["簡単すぎると退屈になり努力しなくなるから", "難しすぎると諦めてしまうから", "適度な困難さが努力と集中を引き出すから", "上記すべて"]'::jsonb, 3, '目標設定理論では、簡単すぎず難しすぎない「適度に困難な目標」が最も高いパフォーマンスを引き出すことが示されています。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (33, 1, 33, '「年間売上1億円」という目標を効果的にするために追加すべきことは？', '["目標金額をさらに高く設定する", "四半期・月・週ごとの中間マイルストーンを設定する", "達成できなかった時のペナルティを決める", "他の営業と競争させる仕組みを作る"]'::jsonb, 1, '年間目標だけでは遠すぎてモチベーションが続きません。中間目標を設定することで、進捗を管理し達成感を得られます。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (34, 1, 34, '目標とフィードバックの関係について正しいのは？', '["目標を設定すればフィードバックは不要", "目標とフィードバックの組み合わせが最も効果的", "フィードバックは月に一度程度で十分", "フィードバックは上司からもらうものである"]'::jsonb, 1, '目標とフィードバックの組み合わせが効果を高めます。毎日記録することで進捗が見え、モチベーションと改善につながります。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (35, 1, 35, '上司から与えられた目標が達成できそうにない場合、目標設定理論に基づく対応は？', '["言われた通りに受け入れて努力する", "達成可能な根拠と必要なサポートについて対話する", "最初から達成を諦めて最低限の努力をする", "目標を無視して自分なりの目標を設定する"]'::jsonb, 1, '目標へのコミットメントが重要です。達成できると思えない目標は動機づけになりません。上司と対話し、現実的な計画を立てましょう。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (36, 1, 36, '「内発的動機」と「外発的動機」について正しいのは？', '["外発的動機（報酬）の方が持続性が高い", "内発的動機（意味・価値）の方が困難な時も持続できる", "営業は外発的動機だけで十分に機能する", "両者に大きな違いはない"]'::jsonb, 1, '目標が自分の価値観や意味と結びついていると、内発的動機が高まります。「なぜ」を明確にすることで、困難な時も持続できます。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (37, 1, 37, '大きな目標を達成するための「目標分解」の効果として正しいのは？', '["目標が小さくなるので挑戦しがいがなくなる", "小さな達成感を積み重ねて自己効力感が高まる", "管理が複雑になりかえって非効率になる", "分解しすぎると全体像が見えなくなる"]'::jsonb, 1, '大きな目標は小さな目標に分解することで取り組みやすくなり、小さな達成感を積み重ねることで自己効力感が高まります。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (38, 1, 38, '目標を紙に書いて見える場所に貼ることの効果について正しいのは？', '["科学的な効果は証明されていない迷信である", "視覚化により常に意識し行動が目標に向かいやすくなる", "他人に見られると恥ずかしいので逆効果", "義務感が増してストレスになる"]'::jsonb, 1, '研究によると、目標を書き出す人は達成率が高いです。視覚化することで常に意識し、日々の行動が目標に向かいやすくなります。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (39, 1, 39, '目標を同僚と共有することの効果について正しいのは？', '["競争心が生まれて人間関係が悪化する", "説明責任（アカウンタビリティ）が生まれ達成率が高まる", "達成できなかった時に恥ずかしいので避けるべき", "情報漏洩のリスクがあるので控えるべき"]'::jsonb, 1, '目標を他者と共有すると「説明責任」が生まれ、達成率が高まることが研究で示されています。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (40, 1, 40, 'SMART目標の「R（Relevant）」が重要な理由は？', '["会社の方針と整合性を取るため", "自分の役割や価値観と関連しないと動機づけにならないから", "上司に説明しやすくするため", "評価制度と連動させるため"]'::jsonb, 1, '目標が自分の役割、価値観、キャリア目標と関連していると、意味を感じられ、内発的動機が高まります。', '研修4: 目標設定の技術', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (41, 1, 41, 'アイゼンハワー・マトリクスの「第2象限」に該当するタスクはどれか？', '["今日締切の提案書作成", "来月のセミナーの準備", "上司から急ぎで依頼された資料作成", "SNSのチェックと返信"]'::jsonb, 1, '第2象限は「重要だが緊急でない」タスクです。来月のセミナー準備は重要ですが、今すぐの締切はありません。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (42, 1, 42, '「効果的な人と非効果的な人の最大の違い」として正しいのは？', '["第1象限（緊急で重要）に費やす時間の量", "第2象限（重要だが緊急でない）に費やす時間の量", "第3象限（緊急だが重要でない）を処理する速さ", "全体の仕事量とその処理スピード"]'::jsonb, 1, '効果的な人は第2象限（計画、準備、関係構築、スキルアップ）に時間を投資し、長期的に高い成果を上げます。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (43, 1, 43, '「パーキンソンの法則」を正しく理解した上での時間管理の対策は？', '["時間に余裕を持たせて品質を高める", "タスクに締切を設定して時間を区切る", "完璧を目指して時間をかける", "締切は設けず柔軟に対応する"]'::jsonb, 1, '「仕事は利用可能な時間を満たすまで膨張する」というパーキンソンの法則を踏まえ、タスクに締切を設けることで効率が上がります。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (44, 1, 44, '「80/20の法則（パレートの法則）」を営業に適用した場合の示唆は？', '["全ての顧客に均等に時間を使うべき", "成果の80%は活動の20%から生まれるので重要な活動に集中する", "80%の顧客は切り捨てるべき", "20%の時間で仕事を終わらせるべき"]'::jsonb, 1, '成果の80%は活動の20%から生まれます。重要な顧客、重要な活動を特定し、そこに時間を集中投下することが効果的です。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (45, 1, 45, '「緊急」と「重要」の違いについて正しい理解は？', '["緊急なことは全て重要なことでもある", "重要なことが緊急であることはめったにない", "緊急なことを優先すれば重要なことも達成できる", "緊急と重要に本質的な違いはない"]'::jsonb, 1, '「重要なことが緊急であることはめったにないし、緊急なことが重要であることもめったにない」という原則があります。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (46, 1, 46, '急ぎのメール返信と重要顧客への提案書作成が重なった時、優先すべきは？', '["緊急性が高いメール返信を先に済ませる", "重要度が高い提案書作成を優先する", "両方を同時並行で進める", "どちらも後回しにして考える時間を取る"]'::jsonb, 1, '緊急と重要は異なります。「重要」を優先し、「緊急だが重要でない」タスクに振り回されないことが効果的な時間管理です。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (47, 1, 47, '第2象限への投資が重要な理由として正しいのは？', '["緊急なタスクがないので気楽に取り組める", "第2象限に投資することで第1象限の危機が減少する", "第2象限のタスクは評価されやすい", "第2象限は短時間で終わるものが多い"]'::jsonb, 1, '第2象限（計画、準備、スキルアップ）に投資することで、準備不足による第1象限の「危機」が減少します。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (48, 1, 48, '「効率」と「効果性」の違いについて正しいのは？', '["効率と効果性は同じ意味である", "効率は物事を正しく行い、効果性は正しいことを行う", "効率は速さを表し、効果性は量を表す", "効率は個人の能力、効果性はチームの成果"]'::jsonb, 1, '効率は「物事を正しく行う（How）」、効果性は「正しいことを行う（What）」です。間違ったことを効率的にやっても意味がありません。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (49, 1, 49, '週次計画を立てることの効果として正しいのは？', '["計画通りに進まないのでストレスになる", "重要なタスクを意識し緊急なことに流されにくくなる", "上司へのアピールになる", "計画を立てる時間が無駄になる"]'::jsonb, 1, '週次計画を立てることで、第2象限のタスクに意識的に時間を確保できます。「緊急」に流されず「重要」に集中できます。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (50, 1, 50, '時間管理において最も重要な問いかけは？', '["この作業をもっと早くできないか", "このタスクは本当に重要か（やるべきことか）", "誰かに任せられないか", "締切までにどれくらい時間があるか"]'::jsonb, 1, '効果的な時間管理の第一歩は「正しいことを行っているか」を問うことです。「効率」の前に「効果性」を考えます。', '研修5: 時間管理の基本', '2026-01-23T10:21:09.760732+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (51, 2, 1, '日本の中古車市場の規模について正しいのはどれか？', '["新車市場と同程度の約4兆円規模である", "新車市場を上回る約7兆円規模である", "新車市場の半分程度の約2兆円規模である", "新車市場の2倍以上の約10兆円規模である"]'::jsonb, 1, '日本の中古車市場は約7兆円規模で、新車市場（約4兆円）を大きく上回っています。', '研修23: 中古車流通の全体像', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (52, 2, 2, '中古車の主な仕入れ先として最も取扱量が多いのはどれか？', '["個人間売買による直接買取", "新車ディーラーの下取り車", "オートオークション（業者間取引）", "海外からの逆輸入車"]'::jsonb, 2, '中古車の仕入れ先として最も多いのはオートオークション（AA）で、業者間取引の中心となっています。', '研修23: 中古車流通の全体像', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (53, 2, 3, 'オートオークション（AA）の特徴として正しいのはどれか？', '["一般消費者も自由に参加できる", "古物商許可があれば参加可能である", "落札手数料は売り手のみが負担する", "出品された車両は必ず落札される"]'::jsonb, 1, 'AAは古物商許可を持つ業者のみが参加できる業者間市場です。買い手・売り手双方に手数料がかかります。', '研修24: 仕入れ構造の詳細分析', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (54, 2, 4, '下取りと買取の違いについて正しいのはどれか？', '["下取りは新車購入が条件となる取引である", "買取は新車ディーラーのみが行える", "下取りの方が査定額が高くなる傾向がある", "買取は車検が残っていないとできない"]'::jsonb, 0, '下取りは新車購入時に現在の車を引き取る取引で、新車購入が前提となります。買取は車両のみの取引です。', '研修24: 仕入れ構造の詳細分析', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (55, 2, 5, '中古車販売における「商品化」に含まれないのはどれか？', '["内外装のクリーニング", "点検整備と消耗品交換", "販売価格の設定と値付け", "ナンバープレートの取得"]'::jsonb, 3, 'ナンバープレートの取得は販売後の登録業務であり、商品化（仕入れ後の車両を販売可能な状態にする作業）には含まれません。', '研修25: 在庫から販売までのプロセス', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (56, 2, 6, '中古車の在庫回転率について正しいのはどれか？', '["回転率が高いほど資金効率が悪い", "一般的に45〜60日が目安とされる", "高額車ほど回転率を高くすべきである", "回転率は売上高で計算される"]'::jsonb, 1, '在庫回転率は資金効率を示す指標で、一般的に45〜60日が適正とされています。回転率が高いほど資金効率は良くなります。', '研修25: 在庫から販売までのプロセス', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (57, 2, 7, '中古車業界における情報の非対称性とは何を指すか？', '["店舗間で価格情報が共有されないこと", "売り手と買い手で車の状態に関する情報量が異なること", "オークション結果が非公開であること", "整備記録が電子化されていないこと"]'::jsonb, 1, '情報の非対称性とは、売り手（業者）が車の状態を詳しく知っている一方、買い手（消費者）は限られた情報しか持たない状況を指します。', '研修26: 流通における課題と変革', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (58, 2, 8, '中古車流通のDX化がもたらす変化として正しいのはどれか？', '["対面販売の重要性が増している", "オンライン商談や非対面取引が増加している", "紙の書類手続きが増えている", "仕入れ先がオークションに限定されている"]'::jsonb, 1, 'DX化により、オンライン商談、バーチャル内覧、電子契約など非対面での取引が増加しています。', '研修26: 流通における課題と変革', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (59, 2, 9, 'フランチャイズ系中古車販売店の特徴として正しいのはどれか？', '["独自のブランドで自由に経営できる", "本部のブランドとノウハウを活用できる", "仕入れは全て本部が一括で行う", "加盟金や月額費用は発生しない"]'::jsonb, 1, 'フランチャイズ系は本部のブランド力とノウハウを活用できますが、加盟金やロイヤリティなどの費用が発生します。', '研修27: 販売店の類型と特徴', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (60, 2, 10, 'ディーラー系中古車販売店（認定中古車店）の強みはどれか？', '["価格が最も安い傾向にある", "メーカー保証や品質基準がある", "どのメーカーの車も取り扱える", "即日納車が可能である"]'::jsonb, 1, 'ディーラー系は自社ブランドの車両を中心に、メーカー保証や厳格な品質基準を強みとしています。', '研修27: 販売店の類型と特徴', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (61, 2, 11, '中古車販売店の主な収益源として正しくないのはどれか？', '["車両販売の粗利（車両利益）", "整備・点検サービス収入", "保険代理店手数料", "オークション開催手数料"]'::jsonb, 3, 'オークション開催手数料はAA運営会社の収益であり、一般の中古車販売店の収益源ではありません。', '研修28: 経営課題の類型別分析', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (62, 2, 12, '中古車販売店が抱える人材に関する課題として最も多いのはどれか？', '["人件費が高すぎること", "採用難と人材の定着率の低さ", "営業スタッフの高齢化", "資格保有者の不足"]'::jsonb, 1, '中古車業界では採用難と離職率の高さが課題となっており、人材の確保と育成が経営上の重要課題です。', '研修28: 経営課題の類型別分析', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (63, 2, 13, '電気自動車（EV）の中古車市場における課題はどれか？', '["需要が高すぎて供給が追いつかない", "バッテリー劣化と残価評価の不確実性", "充電インフラが完備されている", "メンテナンスが容易すぎる"]'::jsonb, 1, 'EV中古車はバッテリーの劣化状態の把握と残価評価が難しく、市場形成の課題となっています。', '研修29: 業界トレンドと市場動向', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (64, 2, 14, 'サブスクリプション（定額利用サービス）が中古車業界に与える影響はどれか？', '["中古車の需要が完全になくなる", "所有から利用へという消費者意識の変化に対応できる", "新車販売だけが増加する", "整備需要が減少する"]'::jsonb, 1, 'サブスクリプションは「所有から利用へ」という消費トレンドに対応したサービスで、中古車も活用されています。', '研修29: 業界トレンドと市場動向', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (65, 2, 15, '中古車販売に必要な許認可として正しいのはどれか？', '["飲食店営業許可", "古物商許可", "宅地建物取引業免許", "貸金業登録"]'::jsonb, 1, '中古車販売には古物商許可が必要です。これは中古品の売買を行う際に必要な許可です。', '研修30: 法規制と業界ルール', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (66, 2, 16, '自動車公正競争規約で定められている表示義務に含まれるのはどれか？', '["前所有者の個人情報", "走行距離と修復歴の有無", "仕入れ価格と利益率", "過去の事故の詳細内容"]'::jsonb, 1, '自動車公正競争規約では、走行距離と修復歴の有無の表示が義務付けられています。', '研修30: 法規制と業界ルール', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (67, 2, 17, '中古車価格に影響する要因として最も大きいのはどれか？', '["ボディカラーの人気度", "年式・走行距離・車種の需給バランス", "タイヤの残り溝の深さ", "カーナビの有無"]'::jsonb, 1, '中古車価格は主に年式、走行距離、車種の需給バランスによって決まります。人気車種は高値を維持します。', '研修31: 中古車価格のメカニズム', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (68, 2, 18, '「修復歴あり」の車両について正しいのはどれか？', '["ドアの板金修理をした車両のこと", "フレーム（骨格）部分を修理した車両のこと", "エンジンを載せ替えた車両のこと", "全塗装をした車両のこと"]'::jsonb, 1, '修復歴とは、車体のフレーム（骨格）部分を修正・交換した履歴を指します。外装の板金修理は含まれません。', '研修31: 中古車価格のメカニズム', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (69, 2, 19, '中古車購入時に顧客が最も不安に感じることはどれか？', '["納車までの期間が長いこと", "品質・状態に対する不確実性", "値引き交渉が難しいこと", "試乗ができないこと"]'::jsonb, 1, '中古車は一点モノであり、品質や状態が車両ごとに異なるため、顧客は「本当に大丈夫か」という不安を感じやすいです。', '研修32: 顧客心理と購買行動', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (70, 2, 20, '中古車購入における「認知的不協和」を軽減する方法として適切なのはどれか？', '["購入後は連絡しないようにする", "購入後も丁寧なフォローで選択の正しさを確認させる", "他の車両の良い点を伝える", "値引きをさらに提案する"]'::jsonb, 1, '認知的不協和（買った後の不安）を軽減するには、購入後のフォローで「良い選択だった」と確認させることが重要です。', '研修32: 顧客心理と購買行動', '2026-01-27T09:14:37.487356+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (72, 2, 29, '「諸費用」を適正に設定することの重要性は？', '["利益を最大化するため高く設定すべき", "顧客の信頼獲得と法令遵守のため適正に設定", "諸費用はゼロにすべき", "諸費用は価格に含めて表示すべき"]'::jsonb, 1, '諸費用を不透明にすると顧客の不信感につながります。適正な諸費用設定が信頼獲得と健全な取引につながります。', '研修28: 価格設定の考え方', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (73, 4, 13, '「たとえ話」を使う効果は？', '["話が長くなる", "複雑な内容を身近なものに置き換えて理解しやすくする", "専門性を示せる", "正確性が上がる"]'::jsonb, 1, 'たとえ話は複雑な概念を聞き手の知っている身近なものに置き換え、理解を促進します。', '研修45: 効果的な説明技法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (74, 4, 14, '説明で「数字」を使う際のポイントは？', '["できるだけ多くの数字を並べる", "聞き手にとって意味のある比較で示す", "小数点以下まで正確に伝える", "専門的な統計用語を使う"]'::jsonb, 1, '数字は「前年比〇%増」など聞き手にとって意味のある比較で示すと理解されやすくなります。', '研修45: 効果的な説明技法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (75, 4, 15, '説明の「チャンク化」とは？', '["情報を大きくまとめること", "情報を適切な大きさに分割すること", "情報を削除すること", "情報を暗記すること"]'::jsonb, 1, 'チャンク化は情報を理解しやすい適切な大きさに分割し、段階的に伝えるテクニックです。', '研修45: 効果的な説明技法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (76, 4, 16, 'メラビアンの法則で、言語情報が占める割合は？', '["7%", "38%", "55%", "70%"]'::jsonb, 0, 'メラビアンの法則では、矛盾したメッセージの場合、言語7%、聴覚38%、視覚55%の影響を受けます。', '研修46: 非言語コミュニケーション', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (77, 4, 17, '非言語コミュニケーションに含まれないのは？', '["表情", "姿勢", "メールの文面", "声のトーン"]'::jsonb, 2, 'メールの文面は言語コミュニケーションです。非言語は表情、姿勢、声のトーンなどです。', '研修46: 非言語コミュニケーション', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (78, 4, 18, '「ミラーリング」の効果は？', '["自分を大きく見せる", "相手に親近感・安心感を与える", "相手を威圧する", "話の主導権を握る"]'::jsonb, 1, 'ミラーリング（相手の姿勢や動作を真似る）は、無意識に親近感や安心感を生み出します。', '研修46: 非言語コミュニケーション', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (79, 4, 19, 'アイコンタクトの適切な取り方は？', '["常に相手の目を見続ける", "適度に視線を外しながら要所で合わせる", "目を合わせない", "相手の額を見る"]'::jsonb, 1, '常に見続けると威圧的になります。適度に視線を外しながら、重要な場面で合わせるのが効果的です。', '研修46: 非言語コミュニケーション', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (80, 4, 20, '声の「トーン」が与える印象として正しいのは？', '["内容より重要ではない", "感情や信頼性の判断に大きく影響する", "聞き取りやすさだけに影響する", "年齢の印象だけに影響する"]'::jsonb, 1, '声のトーンは話の内容以上に、感情や信頼性の判断に影響を与えます。', '研修46: 非言語コミュニケーション', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (81, 4, 21, '報連相の「報告」の基本は？', '["結果だけ伝える", "結論から先に伝える", "詳細から説明する", "口頭のみで行う"]'::jsonb, 1, '報告は結論から先に伝え、必要に応じて詳細を補足するのが基本です。', '研修47: 報告・連絡・相談', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (82, 4, 22, '「悪い報告」をする際のポイントは？', '["できるだけ後回しにする", "早めに報告し、対策案も添える", "メールだけで済ませる", "上司の機嫌が良い時を待つ"]'::jsonb, 1, '悪い報告ほど早く伝え、現状と対策案を添えることで、早期対応が可能になります。', '研修47: 報告・連絡・相談', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (83, 4, 23, '「連絡」と「報告」の違いは？', '["違いはない", "連絡は情報共有、報告は結果報告", "連絡は口頭、報告は文書", "連絡は社外、報告は社内"]'::jsonb, 1, '連絡は関係者への情報共有、報告は上司への経過・結果の報告という違いがあります。', '研修47: 報告・連絡・相談', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (84, 4, 24, '「相談」をする際のポイントは？', '["とにかく早く相談する", "自分の考えを持った上で相談する", "結論が出るまで相談しない", "複数人に同時に相談する"]'::jsonb, 1, '「自分はこう考えているが」と自分の考えを持った上で相談することで、建設的な議論ができます。', '研修47: 報告・連絡・相談', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (85, 4, 25, '報連相で「5W1H」を意識する理由は？', '["文字数を増やすため", "情報の抜け漏れを防ぎ正確に伝えるため", "上司に好印象を与えるため", "報告書の形式を整えるため"]'::jsonb, 1, '5W1H（いつ、どこで、誰が、何を、なぜ、どのように）を意識することで、情報の抜け漏れを防げます。', '研修47: 報告・連絡・相談', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (86, 4, 26, 'ビジネスメールの件名で重要なのは？', '["できるだけ短くする", "内容が一目でわかる具体的な件名にする", "挨拶を入れる", "感嘆符を使う"]'::jsonb, 1, '件名は「〇〇のご提案」「△△会議の日程調整」など、内容が一目でわかる具体的な表現が重要です。', '研修48: メール・チャットの作法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (87, 4, 27, 'メールの「CC」の使い方として正しいのは？', '["全員に返信する際に使う", "情報共有が必要な関係者を入れる", "秘密にしたい宛先を入れる", "自分を入れる"]'::jsonb, 1, 'CCは直接の宛先ではないが、情報共有が必要な関係者を入れるために使用します。', '研修48: メール・チャットの作法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (88, 4, 28, 'ビジネスチャットで避けるべきことは？', '["短文で返信する", "重要な決定事項をチャットだけで済ませる", "絵文字を適度に使う", "スレッドを活用する"]'::jsonb, 1, '重要な決定事項は記録が残るメールや会議で行い、チャットだけで済ませないことが重要です。', '研修48: メール・チャットの作法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (89, 4, 29, 'メールの返信で「引用」を使う目的は？', '["文字数を増やすため", "どの内容への返答かを明確にするため", "相手の間違いを指摘するため", "フォーマルに見せるため"]'::jsonb, 1, '引用を使うことで、どの質問・内容に対する回答かが明確になり、誤解を防げます。', '研修48: メール・チャットの作法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (90, 4, 30, 'メールで「お忙しいところ恐れ入りますが」などの表現を使う目的は？', '["文章を長くするため", "相手への配慮を示すため", "断りやすくするため", "フォーマルに見せるため"]'::jsonb, 1, 'クッション言葉は相手への配慮を示し、依頼や質問を柔らかく伝える効果があります。', '研修48: メール・チャットの作法', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (91, 4, 31, '電話を受ける際、何コール以内に出るのが望ましい？', '["1コール", "3コール", "5コール", "何コールでもよい"]'::jsonb, 1, '一般的に3コール以内に出ることが望ましいとされています。それ以上は「お待たせしました」と添えます。', '研修49: 電話応対の基本', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (92, 2, 21, '中古車仕入れの主要チャネルとして正しいのは？', '["メーカーからの直接仕入れのみ", "オークション、買取、下取りなど複数", "輸入車のみ", "業者間取引は禁止されている"]'::jsonb, 1, '中古車の仕入れはオートオークション、買取、下取り、業販など複数のチャネルがあります。', '研修27: 仕入れと在庫管理', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (93, 2, 22, '「適正在庫」を維持することが重要な理由は？', '["見栄えが良くなるから", "過剰在庫は資金固定、過少在庫は機会損失になるから", "税金対策になるから", "従業員のモチベーション向上のため"]'::jsonb, 1, '過剰在庫は資金が固定され、過少在庫は販売機会を逃すため、適正な在庫水準の維持が経営効率に直結します。', '研修27: 仕入れと在庫管理', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (94, 2, 23, '在庫の「経年劣化リスク」として正しいのは？', '["在庫期間が長いほど価値が上がる", "在庫期間が長いほど価格下落と状態悪化のリスクが高まる", "在庫期間は価値に影響しない", "3年以上保管すると価値が上がる"]'::jsonb, 1, '中古車は時間経過とともに市場価格が下落し、状態も悪化するため、早期販売が重要です。', '研修27: 仕入れと在庫管理', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (95, 2, 24, '仕入れにおける「相場観」を養う方法として適切なのは？', '["感覚だけを頼りにする", "オークション相場や市場動向を継続的に分析する", "他店の価格だけを参考にする", "メーカー希望小売価格を基準にする"]'::jsonb, 1, 'オークション相場、季節変動、市場トレンドなどを継続的に分析することで、適正な仕入れ判断ができるようになります。', '研修27: 仕入れと在庫管理', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (96, 2, 25, '「不良在庫」を発生させないための対策として正しいのは？', '["とにかく安く仕入れる", "販売データを分析し需要予測に基づいて仕入れる", "人気車種だけを大量に仕入れる", "仕入れを減らして在庫を持たない"]'::jsonb, 1, '過去の販売データや市場トレンドを分析し、需要予測に基づいた計画的な仕入れが不良在庫防止につながります。', '研修27: 仕入れと在庫管理', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (97, 2, 26, '中古車の価格設定で最も重要な要素は？', '["仕入れ価格のみ", "市場相場、車両状態、需要と供給のバランス", "新車価格からの値引き率", "販売店の希望利益額"]'::jsonb, 1, '中古車価格は市場相場、個別の車両状態、その時点での需給バランスなど複合的な要素で決定されます。', '研修28: 価格設定の考え方', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (98, 2, 27, '「相場連動型」の価格設定の特徴として正しいのは？', '["市場価格に関係なく固定価格で販売", "市場相場に合わせて柔軟に価格を調整", "常に最安値で販売する方法", "顧客の言い値で販売する方法"]'::jsonb, 1, '相場連動型では市場動向を常に監視し、競争力のある価格設定を維持することで販売効率を高めます。', '研修28: 価格設定の考え方', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (99, 2, 28, '価格設定における「プライシング戦略」として正しいのは？', '["価格は一度決めたら変更しない", "在庫期間や市場動向に応じて価格を調整する", "常に競合より10%安く設定する", "利益率を50%以上に設定する"]'::jsonb, 1, '在庫期間が長くなると価格を下げる、需要期には価格を維持するなど、状況に応じた価格調整が重要です。', '研修28: 価格設定の考え方', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (100, 2, 30, '価格競争に巻き込まれないための戦略として正しいのは？', '["常に最安値を維持する", "価格以外の付加価値（サービス・保証）で差別化", "価格を非公開にする", "競合と価格協定を結ぶ"]'::jsonb, 1, '価格競争だけでは消耗戦になります。整備品質、保証、アフターサービスなど価格以外の価値で差別化することが重要です。', '研修28: 価格設定の考え方', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (101, 2, 31, '中古車の品質評価で重要な項目として正しいのは？', '["車両の色のみ", "走行距離、修復歴、整備状態などの総合評価", "製造年月日のみ", "前オーナーの情報のみ"]'::jsonb, 1, '中古車の品質は走行距離、修復歴の有無、整備状態、内外装の状態など多角的に評価する必要があります。', '研修29: 車両品質と保証', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (102, 2, 32, '「修復歴あり」の定義として正しいのは？', '["どんな傷でも修理したことがある車", "骨格部分を修正または交換した車", "エンジンを交換した車のみ", "塗装を塗り直した車すべて"]'::jsonb, 1, '修復歴とは車両の骨格（フレーム）部分を修正または交換した履歴を指し、業界統一の基準があります。', '研修29: 車両品質と保証', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (103, 2, 33, '中古車保証の目的として最も適切なのは？', '["販売店の責任を限定するため", "顧客の安心と信頼を提供し満足度を高めるため", "法律で義務付けられているから", "価格を高く設定するため"]'::jsonb, 1, '中古車保証は購入後の故障リスクへの不安を軽減し、顧客満足度とリピート率向上につながります。', '研修29: 車両品質と保証', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (104, 2, 34, '「法定整備」と「販売店独自整備」の違いとして正しいのは？', '["違いはない", "法定整備は法律で定められた項目、独自整備は販売店の付加価値", "法定整備は無料、独自整備は有料", "法定整備は新車のみ、独自整備は中古車のみ"]'::jsonb, 1, '法定整備は車検時などに法律で定められた項目、販売店独自整備はそれ以上の品質を提供するための付加価値サービスです。', '研修29: 車両品質と保証', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (105, 2, 35, '品質管理が経営に与える影響として正しいのは？', '["品質管理にはコストがかかるだけでメリットはない", "クレーム削減、顧客満足度向上、リピート率アップにつながる", "品質より価格が重要なので影響は少ない", "品質管理は大手企業のみに必要"]'::jsonb, 1, '適切な品質管理はクレーム対応コストの削減、顧客満足度向上、口コミによる新規顧客獲得など経営全体にプラスの影響を与えます。', '研修29: 車両品質と保証', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (106, 2, 36, '中古車購入者の購買行動として正しいのは？', '["衝動買いが大半を占める", "ネット検索から始まり、複数店舗を比較検討する", "価格だけで即決する人が多い", "販売店の言いなりになる人が多い"]'::jsonb, 1, '現代の消費者はまずネットで情報収集し、複数の選択肢を比較検討してから来店・購入する傾向があります。', '研修30: 顧客分析と販売戦略', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (107, 2, 37, '「顧客セグメンテーション」の目的として正しいのは？', '["顧客を差別するため", "顧客層ごとに最適なアプローチを行うため", "顧客数を減らすため", "競合に情報を隠すため"]'::jsonb, 1, '顧客を特性ごとにグループ化することで、それぞれに最適な商品提案やマーケティングが可能になります。', '研修30: 顧客分析と販売戦略', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (108, 2, 38, '「顧客生涯価値（LTV）」の考え方として正しいのは？', '["1回の取引利益だけを重視する", "長期的な関係から得られる総利益を重視する", "顧客の年齢が高いほど価値が高い", "新規顧客だけに注力する"]'::jsonb, 1, 'LTVは顧客との長期的な関係から得られる総利益を指し、リピート購入や紹介なども含めた価値を考えます。', '研修30: 顧客分析と販売戦略', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (109, 2, 39, '販売戦略における「差別化」として適切なのは？', '["価格を下げることのみ", "サービス品質、専門性、アフターケアなど独自の強みを打ち出す", "競合と同じことをする", "広告を大量に出す"]'::jsonb, 1, '持続的な競争優位を築くには、価格以外の独自の価値（専門性、サービス、保証など）で差別化することが重要です。', '研修30: 顧客分析と販売戦略', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (110, 2, 40, '「データドリブン」な販売戦略とは？', '["勘と経験だけで判断する方法", "データ分析に基づいて意思決定を行う方法", "データを収集するだけで活用しない方法", "ITシステムを導入することだけを指す"]'::jsonb, 1, 'データドリブンとは、売上データ、顧客データ、市場データなどを分析し、根拠に基づいた意思決定を行うアプローチです。', '研修30: 顧客分析と販売戦略', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (111, 2, 41, '中古車業界のDX（デジタルトランスフォーメーション）として進んでいるのは？', '["紙の書類を増やすこと", "在庫管理、顧客管理、オンライン商談などのデジタル化", "対面販売のみに特化すること", "電話営業の強化"]'::jsonb, 1, '中古車業界では在庫・顧客管理のシステム化、オンライン商談、Web集客などデジタル化が急速に進んでいます。', '研修31: 業界のデジタル化動向', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (112, 2, 42, '「オンライン商談」が普及した背景として正しいのは？', '["対面販売が法律で禁止されたから", "コロナ禍をきっかけに非接触ニーズが高まったから", "オンラインの方が成約率が高いから", "全ての顧客がオンラインを希望するから"]'::jsonb, 1, 'コロナ禍を契機に非接触でのコミュニケーション手段としてオンライン商談が普及し、遠方顧客への対応も可能になりました。', '研修31: 業界のデジタル化動向', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (113, 2, 43, '中古車販売におけるWeb集客の重要性として正しいのは？', '["Web集客は効果がないので不要", "顧客の多くがネット検索から購入プロセスを始めるから重要", "Web集客は大手のみに有効", "チラシの方が効果的"]'::jsonb, 1, '現代の消費者の多くはまずネットで情報収集を行うため、Webでの存在感を高めることが集客に直結します。', '研修31: 業界のデジタル化動向', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (114, 2, 44, '「DMS（ディーラーマネジメントシステム）」の役割として正しいのは？', '["車両の修理を自動で行うシステム", "在庫・顧客・売上などを一元管理する業務システム", "自動運転を制御するシステム", "競合の情報を収集するシステム"]'::jsonb, 1, 'DMSは販売店の業務（在庫管理、顧客管理、売上管理など）を一元的に管理するシステムです。', '研修31: 業界のデジタル化動向', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (115, 2, 45, 'デジタル化による業務効率化のメリットとして正しいのは？', '["従業員を全員解雇できる", "人的ミスの削減と業務時間の短縮", "顧客対応が不要になる", "利益が自動的に増える"]'::jsonb, 1, 'デジタル化により手作業によるミスが減少し、業務処理時間が短縮されることで、より付加価値の高い業務に時間を使えます。', '研修31: 業界のデジタル化動向', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (116, 2, 46, '中古車業界の将来トレンドとして予想されるのは？', '["市場の完全な消滅", "EV化、サブスク、デジタル化のさらなる進展", "紙媒体への回帰", "海外市場の完全撤退"]'::jsonb, 1, '電気自動車の普及、サブスクリプションモデル、デジタル化は今後も中古車業界に大きな変化をもたらすと予想されます。', '研修32: 将来展望とキャリア', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (117, 2, 47, '中古車業界でのキャリア形成において重要なスキルは？', '["車の運転技術のみ", "商品知識、顧客対応力、デジタルスキル、経営感覚", "力仕事ができること", "長時間労働ができること"]'::jsonb, 1, '中古車業界では商品知識に加え、顧客対応力、デジタルツール活用力、経営的な視点が求められます。', '研修32: 将来展望とキャリア', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (118, 2, 48, '「サブスクリプション型」の自動車利用が増えている理由は？', '["法律で義務化されたから", "所有から利用へという消費者意識の変化", "サブスクの方が必ず安いから", "自動車メーカーが販売をやめたから"]'::jsonb, 1, '若年層を中心に「所有」より「利用」を重視する価値観が広がり、サブスクリプション型サービスの需要が増えています。', '研修32: 将来展望とキャリア', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (119, 2, 49, 'EV（電気自動車）の普及が中古車市場に与える影響として考えられるのは？', '["中古車市場には影響がない", "バッテリー評価など新たな査定基準が必要になる", "ガソリン車の中古車価格が上がる", "中古車市場が消滅する"]'::jsonb, 1, 'EVの普及により、バッテリーの劣化度評価など従来のガソリン車とは異なる査定基準や知識が必要になります。', '研修32: 将来展望とキャリア', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (120, 2, 50, '中古車ビジネスで長期的に成功するために最も重要なことは？', '["とにかく安く仕入れて高く売ること", "市場変化に適応し、顧客価値を提供し続けること", "競合を排除すること", "現状維持を続けること"]'::jsonb, 1, '市場環境は常に変化するため、変化に適応しながら顧客に価値を提供し続けることが持続的な成功につながります。', '研修32: 将来展望とキャリア', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (121, 3, 1, 'チャルディーニの「影響力の6原則」に含まれないものは？', '["返報性", "一貫性", "論理性", "希少性"]'::jsonb, 2, 'チャルディーニの6原則は返報性、一貫性、社会的証明、好意、権威、希少性です。論理性は含まれません。', '研修33: 影響力の6原則', '2026-02-17T06:00:22.987306+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (122, 3, 2, '「返報性の原理」を営業で活用する例として適切なのは？', '["契約を急かして決断を迫る", "業界レポートを先に提供して関係構築する", "競合の悪口を言って自社を持ち上げる", "値引きを最初から提示する"]'::jsonb, 1, '返報性の原理は「もらったら返したくなる」心理です。価値ある情報を先に提供することで関係構築につながります。', '研修33: 影響力の6原則', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (123, 3, 3, '「社会的証明」の原理が働く状況として正しいのは？', '["専門家の意見を聞いた時", "他の多くの人が同じ選択をしている時", "好きな人から勧められた時", "限定商品と言われた時"]'::jsonb, 1, '社会的証明は「みんながやっているなら正しい」と感じる心理です。導入実績や事例で安心感を提供できます。', '研修33: 影響力の6原則', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (124, 3, 4, '影響力の原則を「倫理的に活用」する判断基準は？', '["売上目標を達成できるかどうか", "1年後もこの顧客と良い関係でいられるか", "上司に怒られないかどうか", "競合に勝てるかどうか"]'::jsonb, 1, '長期的な信頼関係を築けない手法は最終的に自分を傷つけます。「1年後も良い関係でいられるか」が判断基準です。', '研修33: 影響力の6原則', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (125, 3, 5, '「権威の原理」を営業で正しく活用する方法は？', '["偽の肩書きを名乗る", "業界知識を惜しみなく提供する", "高圧的な態度で接する", "難しい専門用語を多用する"]'::jsonb, 1, '権威の原理は「専門家の言うことは正しい」と感じる心理です。本物の専門知識を提供することで信頼を得られます。', '研修33: 影響力の6原則', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (126, 3, 6, '「一貫性の原理」が働く条件として正しくないのは？', '["自発的に発言・行動した", "公に表明した", "強制的にやらされた", "努力を伴った"]'::jsonb, 2, '一貫性は自発的・公的・努力を伴う場合に強く働きます。強制されたものは一貫性を感じません。', '研修34: 一貫性の原理とフット・イン・ザ・ドア', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (127, 3, 7, 'フット・イン・ザ・ドア・テクニックの原理は？', '["大きな要求をして断らせ、小さな要求を通す", "小さなYESを積み重ねて大きなYESに導く", "複数の選択肢を提示して選ばせる", "期限を設けて決断を急がせる"]'::jsonb, 1, 'フット・イン・ザ・ドアは小さなYESから始めて、徐々に大きなYESに導くテクニックです。', '研修34: 一貫性の原理とフット・イン・ザ・ドア', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (128, 3, 8, 'フット・イン・ザ・ドアの実験で、最初に小さな依頼をした場合の承諾率は？', '["17%から76%に上昇", "50%から60%に上昇", "30%から40%に上昇", "10%から20%に上昇"]'::jsonb, 0, 'Freedman & Fraser(1966)の実験では、最初に小さなステッカーを貼る依頼をした群は、大きな看板の承諾率が17%から76%に上昇しました。', '研修34: 一貫性の原理とフット・イン・ザ・ドア', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (129, 3, 9, '「YESの階段」設計で重要なポイントは？', '["各ステップの間隔を大きくする", "各ステップでNOと言いにくい小ささにする", "最初から大きな要求をする", "ステップ数を最小限にする"]'::jsonb, 1, '各ステップは顧客がNOと言いにくい小ささに設計することで、自然に次のステップに進めます。', '研修34: 一貫性の原理とフット・イン・ザ・ドア', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (130, 3, 10, '一貫性の原理を活用した質問として適切なのは？', '["弊社製品を買っていただけますか？", "業務効率化って、関心おありですか？", "他社の方が安いですが、どうしますか？", "今すぐ決めないと在庫がなくなります"]'::jsonb, 1, '「業務効率化に関心がある」という小さなYESを引き出すことで、一貫性の原理が働きます。', '研修34: 一貫性の原理とフット・イン・ザ・ドア', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (131, 3, 11, '返報性の原理が働くメカニズムとして正しいのは？', '["相手より優位に立ちたいという心理", "もらったものは返さなければという義務感", "損をしたくないという心理", "みんなと同じでいたいという心理"]'::jsonb, 1, '返報性は「もらったら返さなければ」という社会的義務感から生じる心理です。', '研修35: 返報性の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (132, 3, 12, '営業で「先に与える」ことの効果として正しいのは？', '["顧客に借りを作らせて断りにくくする", "信頼関係を構築し、情報を得やすくなる", "値引き交渉を有利に進められる", "競合を排除できる"]'::jsonb, 1, '価値ある情報を先に提供することで信頼関係が構築され、顧客も本音を話しやすくなります。', '研修35: 返報性の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (133, 3, 13, '返報性を活用して「先に与える」ものとして適切なのは？', '["値引きの約束", "業界情報や市場動向レポート", "契約書のひな形", "競合の悪口"]'::jsonb, 1, '業界情報や市場動向など、顧客にとって価値ある情報を先に提供することが効果的です。', '研修35: 返報性の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (134, 3, 14, '返報性の「ドア・イン・ザ・フェイス」テクニックとは？', '["小さな要求から始めて大きな要求へ", "大きな要求を断らせてから小さな要求を通す", "選択肢を与えて選ばせる", "期限を設けて決断を促す"]'::jsonb, 1, 'ドア・イン・ザ・フェイスは、大きな要求を断らせた後に小さな要求をすると、「譲歩してくれた」という返報性が働きます。', '研修35: 返報性の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (135, 3, 15, '返報性の原理を悪用した例として正しいのは？', '["業界レポートを無料で提供する", "試用期間を設けて体験してもらう", "無理やり贈り物を押し付けて契約を迫る", "顧客の課題を一緒に考える"]'::jsonb, 2, '返報性を悪用して無理やり借りを作らせる行為は、長期的な信頼関係を損ないます。', '研修35: 返報性の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (136, 3, 16, '社会的証明が最も効果的に働く状況は？', '["顧客が明確な判断基準を持っている時", "顧客が不確実な状況で判断に迷っている時", "顧客が急いで決断したい時", "顧客が専門知識を持っている時"]'::jsonb, 1, '社会的証明は、不確実な状況で「他の人はどうしているか」を参考にしたくなる心理です。', '研修36: 社会的証明の活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (137, 3, 17, '導入事例を紹介する際に効果的な要素は？', '["できるだけ有名な大企業の事例", "顧客と似た規模・業種の事例", "最も古い導入事例", "最も値引きした事例"]'::jsonb, 1, '社会的証明は「自分と似た人」の行動に最も影響を受けるため、顧客と似た属性の事例が効果的です。', '研修36: 社会的証明の活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (138, 3, 18, '「みんな使っています」という表現の問題点は？', '["具体性がなく信頼性に欠ける", "法律で禁止されている", "顧客を不快にさせる", "競合に情報が漏れる"]'::jsonb, 0, '「みんな」は曖昧で具体性がありません。具体的な数字や事例を示すことで信頼性が増します。', '研修36: 社会的証明の活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (139, 3, 19, '社会的証明を効果的に使うための数字の示し方は？', '["できるだけ大きな数字を示す", "顧客にとって意味のある比較対象と共に示す", "数字は示さず印象で伝える", "競合の数字と比較して示す"]'::jsonb, 1, '「〇〇業界の△△%が導入」など、顧客にとって意味のある文脈で数字を示すと効果的です。', '研修36: 社会的証明の活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (140, 3, 20, '口コミ・レビューが購買行動に与える影響として正しいのは？', '["購買決定にほとんど影響しない", "購買決定の重要な参考情報となる", "否定的な口コミは無視される", "口コミより広告の方が信頼される"]'::jsonb, 1, '第三者の口コミやレビューは、企業の宣伝より信頼性が高く、購買決定に大きく影響します。', '研修36: 社会的証明の活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (141, 3, 21, '「好意の原理」で好意が生まれる要因として正しくないのは？', '["外見の魅力", "類似性", "権威性", "称賛"]'::jsonb, 2, '好意の原理では外見の魅力、類似性、称賛、接触回数、協力関係が好意を生む要因です。権威性は別の原理です。', '研修37: 好意の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (142, 3, 22, '顧客との「共通点」を見つけることが重要な理由は？', '["会話のネタになるから", "人は自分と似た人に好意を持つから", "営業トークが楽になるから", "上司への報告がしやすいから"]'::jsonb, 1, '人は自分と似た人（同郷、同じ趣味など）に好意を持ちやすい傾向があります。', '研修37: 好意の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (143, 3, 23, '顧客を「褒める」際のポイントとして正しいのは？', '["とにかく大げさに褒める", "具体的な事実に基づいて褒める", "外見だけを褒める", "他の顧客と比較して褒める"]'::jsonb, 1, '具体的な事実に基づいた褒め言葉は誠実さが伝わり、信頼関係構築につながります。', '研修37: 好意の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (144, 3, 24, '「単純接触効果」とは？', '["一度会えば好きになる効果", "接触回数が増えると好意が増す効果", "プレゼントをすると好かれる効果", "共通点があると好かれる効果"]'::jsonb, 1, '単純接触効果は、繰り返し接触するだけで親しみや好意が増す心理現象です。', '研修37: 好意の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (145, 3, 25, '好意の原理を営業で活用する際の注意点は？', '["好かれることだけを目的にしない", "できるだけ短時間で好かれようとする", "プライベートな話題は避ける", "笑顔を見せない"]'::jsonb, 0, '好かれることは手段であり目的ではありません。顧客の課題解決という本質を忘れないことが重要です。', '研修37: 好意の原理', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (146, 3, 26, '希少性の原理が働く理由として正しいのは？', '["人は多いものを好むから", "手に入りにくいものは価値があると感じるから", "安いものが好きだから", "新しいものが好きだから"]'::jsonb, 1, '希少性の原理は「手に入りにくいものは価値がある」と感じる心理に基づいています。', '研修38: 希少性と緊急性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (147, 3, 27, '希少性を営業で「倫理的に」活用する例は？', '["嘘の在庫切れ情報を伝える", "本当の期限やキャンペーン終了日を伝える", "架空の競合顧客がいると言う", "毎回「今日だけ」と言う"]'::jsonb, 1, '本当の期限や条件を正直に伝えることが倫理的な希少性の活用です。嘘は信頼を失います。', '研修38: 希少性と緊急性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (148, 4, 33, '電話で「少々お待ちください」と言う際の適切な待ち時間は？', '["30秒以内", "1分以内", "3分以内", "特に制限はない"]'::jsonb, 0, '「少々」は30秒程度が目安です。それ以上かかる場合は折り返しを提案します。', '研修49: 電話応対の基本', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (149, 3, 28, '「緊急性」を作る際の注意点は？', '["できるだけ短い期限を設ける", "顧客にとって合理的な理由がある期限にする", "期限を過ぎても延長する", "期限は曖昧にしておく"]'::jsonb, 1, '緊急性は顧客にとって納得できる合理的な理由がなければ、逆に不信感を招きます。', '研修38: 希少性と緊急性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (150, 3, 29, '希少性の悪用例として正しいのは？', '["決算期の特別価格を案内する", "「残り1台」と嘘をついて焦らせる", "キャンペーン終了日を伝える", "先着特典を案内する"]'::jsonb, 1, '嘘の情報で焦らせる行為は希少性の悪用であり、発覚すると信頼を完全に失います。', '研修38: 希少性と緊急性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (151, 3, 30, '「損失回避」の心理を活用したメッセージは？', '["導入すると〇〇が得られます", "導入しないと〇〇を失う可能性があります", "多くの企業が導入しています", "専門家が推奨しています"]'::jsonb, 1, '人は同じ価値でも「得る」より「失う」ことに強く反応します。これが損失回避の心理です。', '研修38: 希少性と緊急性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (152, 3, 31, '権威性の原理が働くメカニズムは？', '["偉い人の言うことは絶対という服従心理", "専門家の判断は正しいという認知的省略", "有名人を真似したいという心理", "目立つ人に注目する心理"]'::jsonb, 1, '権威性は、すべてを自分で判断するのではなく、専門家の判断を信頼するという認知的省略です。', '研修39: 権威性と専門性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (153, 3, 32, '営業担当者が「権威性」を構築する方法は？', '["高圧的な態度を取る", "業界知識と専門性を示す", "高価なスーツを着る", "難しい言葉を多用する"]'::jsonb, 1, '本物の業界知識と専門性を示すことで、信頼できる専門家としての権威性が構築できます。', '研修39: 権威性と専門性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (154, 3, 33, '「権威の象徴」として効果があるものは？', '["派手な服装", "資格・認定・実績などの客観的証拠", "大きな声で話すこと", "顧客より上の立場を示すこと"]'::jsonb, 1, '資格、認定、実績、専門的な知識などの客観的な証拠が権威性を高めます。', '研修39: 権威性と専門性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (155, 3, 34, '第三者の権威を借りる方法として適切なのは？', '["有名人が使っていると嘘をつく", "業界団体の認証や専門家の推薦を紹介する", "大企業の名前を無断で使う", "競合の悪口を言う"]'::jsonb, 1, '業界団体の認証や専門家の推薦など、正当な第三者の権威を紹介することは効果的です。', '研修39: 権威性と専門性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (156, 3, 35, '権威性と信頼性の関係について正しいのは？', '["権威があれば信頼は不要", "権威性は信頼を得るための一つの手段", "信頼があれば権威は不要", "権威と信頼は無関係"]'::jsonb, 1, '権威性は信頼を得るための手段の一つであり、最終的には顧客のための行動が信頼を築きます。', '研修39: 権威性と専門性', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (157, 3, 36, 'アンカリング効果とは？', '["船を固定する効果", "最初に提示された情報が基準になる効果", "最後の印象が残る効果", "繰り返し聞くと信じる効果"]'::jsonb, 1, 'アンカリング効果は、最初に提示された数字や情報が「アンカー（錨）」となり、その後の判断に影響する心理です。', '研修40: アンカリング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (158, 3, 37, '価格提示でアンカリング効果を活用する方法は？', '["最初に最も安い価格を提示する", "最初に高めの価格や価値を提示する", "価格は最後まで隠す", "競合価格を先に伝える"]'::jsonb, 1, '最初に高い価格や価値を示すことで、それがアンカーとなり、実際の価格が割安に感じられます。', '研修40: アンカリング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (159, 3, 38, 'アンカリング効果が最も強く働く条件は？', '["顧客が専門知識を持っている時", "顧客が判断基準を持っていない時", "顧客が急いでいる時", "顧客が比較検討している時"]'::jsonb, 1, '判断基準がない状況では、最初に提示された情報に強く影響を受けやすくなります。', '研修40: アンカリング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (160, 3, 39, '「松竹梅」の価格設定でアンカリング効果を使う方法は？', '["最も安いプランを最初に見せる", "最も高いプランを最初に見せる", "真ん中のプランだけを見せる", "価格差をなくす"]'::jsonb, 1, '高いプラン（松）を最初に見せることで、中間のプラン（竹）がお得に感じられます。', '研修40: アンカリング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (161, 3, 40, 'アンカリング効果の注意点として正しいのは？', '["嘘の数字でも効果がある", "現実離れしたアンカーは逆効果になる", "アンカーは低い方が効果的", "一度設定したアンカーは変えられない"]'::jsonb, 1, '現実離れした非合理的なアンカーは信頼を損ない、逆効果になります。', '研修40: アンカリング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (162, 3, 41, 'フレーミング効果とは？', '["写真を額縁に入れると価値が上がる効果", "同じ情報でも伝え方で印象が変わる効果", "枠組みを設けると理解しやすくなる効果", "フレームワークを使うと説得力が増す効果"]'::jsonb, 1, 'フレーミング効果は、同じ内容でも表現の仕方（フレーム）によって受け手の印象や判断が変わる心理です。', '研修41: フレーミング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (163, 3, 42, '「成功率90%」と「失敗率10%」は同じ情報だが、どちらが印象が良い？', '["成功率90%の方が印象が良い", "失敗率10%の方が印象が良い", "両方同じ印象", "状況による"]'::jsonb, 0, '人はポジティブなフレーム（成功率90%）の方に好印象を持ちます。同じ情報でも伝え方が重要です。', '研修41: フレーミング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (164, 3, 43, '価格のフレーミングで「1日あたり〇〇円」と表現する効果は？', '["総額が分かりにくくなる", "金額が小さく感じられ負担感が軽減される", "計算が面倒になる", "専門的に見える"]'::jsonb, 1, '大きな金額を小さな単位（1日あたり）で表現すると、心理的な負担感が軽減されます。', '研修41: フレーミング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (165, 3, 44, '「問題」を「課題」と言い換える効果は？', '["意味が変わる", "ネガティブな印象が軽減される", "専門用語に見える", "責任が曖昧になる"]'::jsonb, 1, '「問題」は否定的、「課題」は前向きなニュアンスがあり、同じ状況でも印象が変わります。', '研修41: フレーミング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (166, 4, 32, '電話で相手の名前を聞き取れなかった場合の対応は？', '["聞こえたふりをする", "丁寧に聞き返す", "電話を切る", "メールで確認する"]'::jsonb, 1, '「恐れ入りますが、もう一度お名前をお聞かせいただけますか」と丁寧に聞き返すのが正しい対応です。', '研修49: 電話応対の基本', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (167, 3, 45, 'フレーミング効果を営業で活用する際の原則は？', '["常にポジティブに言い換える", "顧客の関心や価値観に合わせてフレームを選ぶ", "事実を歪めてでも良く見せる", "専門用語を多用する"]'::jsonb, 1, '顧客が何を重視しているか（コスト削減、効率化、リスク回避など）に合わせてフレームを選ぶことが効果的です。', '研修41: フレーミング効果', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (168, 3, 46, '複数の心理テクニックを組み合わせる際の注意点は？', '["できるだけ多くのテクニックを使う", "自然な流れで顧客の利益になる形で使う", "テクニックを使っていることを隠す", "同じテクニックを繰り返す"]'::jsonb, 1, '心理テクニックは顧客の利益になる形で、自然な流れの中で活用することが重要です。', '研修42: 心理テクニックの統合活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (169, 3, 47, '心理テクニックを使う「前提条件」として最も重要なのは？', '["テクニックを完璧に覚えていること", "顧客にとって本当に価値のある提案であること", "競合より先に提案すること", "上司の許可を得ていること"]'::jsonb, 1, '心理テクニックは、顧客に本当に価値のある提案を伝わりやすくするための手段です。', '研修42: 心理テクニックの統合活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (170, 3, 48, '商談の流れで心理テクニックを統合的に活用する順序は？', '["希少性→社会的証明→好意→返報性", "好意→返報性→社会的証明→希少性", "権威→アンカリング→フレーミング→好意", "一貫性→希少性→返報性→権威"]'::jsonb, 1, 'まず好意（関係構築）→返報性（価値提供）→社会的証明（安心感）→希少性（決断促進）の流れが自然です。', '研修42: 心理テクニックの統合活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (171, 3, 49, '心理テクニックが「逆効果」になる状況は？', '["顧客が心理学に詳しい時", "顧客がテクニックに気づき不信感を持った時", "複数のテクニックを使った時", "オンライン商談の時"]'::jsonb, 1, 'テクニックが露骨で「操作されている」と感じると、顧客の不信感を招き逆効果になります。', '研修42: 心理テクニックの統合活用', '2026-02-17T06:00:23.158507+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (172, 3, 50, '営業心理学を学ぶ最終的な目的は？', '["顧客を思い通りに動かすこと", "顧客に価値を伝え、適切な決断を支援すること", "競合に勝つこと", "売上目標を達成すること"]'::jsonb, 1, '心理テクニックは顧客を操作するためではなく、価値を正しく伝え、顧客の適切な決断を支援するためのものです。', '研修42: 心理テクニックの統合活用', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (173, 4, 1, '「傾聴」の定義として最も適切なのは？', '["相手の話を黙って聞くこと", "相手の言葉と感情を理解しようと積極的に聴くこと", "相手の話を要約すること", "相手にアドバイスすること"]'::jsonb, 1, '傾聴とは単に黙って聞くのではなく、相手の言葉の背景にある感情や意図まで理解しようと積極的に聴く姿勢です。', '研修43: 傾聴の技術', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (174, 4, 2, '傾聴の「3つのレベル」として正しくないのは？', '["内的傾聴", "集中的傾聴", "全方位的傾聴", "批判的傾聴"]'::jsonb, 3, '傾聴の3レベルは内的傾聴、集中的傾聴、全方位的傾聴です。批判的傾聴は傾聴ではありません。', '研修43: 傾聴の技術', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (175, 4, 3, '傾聴を妨げる行動として正しいのは？', '["相槌を打つ", "話の途中で自分の意見を言う", "アイコンタクトを取る", "メモを取る"]'::jsonb, 1, '話の途中で自分の意見を言うと、相手は「聴いてもらえていない」と感じ、本音を話さなくなります。', '研修43: 傾聴の技術', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (176, 4, 4, '「アクティブリスニング」の要素として正しくないのは？', '["相槌・うなずき", "オウム返し", "アドバイス", "要約"]'::jsonb, 2, 'アクティブリスニングは相槌、オウム返し、要約、質問などで構成されます。アドバイスは傾聴の段階では不要です。', '研修43: 傾聴の技術', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (177, 4, 5, '傾聴が営業で重要な理由は？', '["話す時間を減らせるから", "顧客の本当のニーズや課題を理解できるから", "顧客に好かれるから", "商談時間が短くなるから"]'::jsonb, 1, '傾聴によって顧客の本当のニーズや課題を理解でき、的確な提案につながります。', '研修43: 傾聴の技術', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (178, 4, 6, '「オープンクエスチョン」の特徴は？', '["はい/いいえで答えられる質問", "自由に回答できる質問", "選択肢から選ぶ質問", "数字で答える質問"]'::jsonb, 1, 'オープンクエスチョンは「どのように」「なぜ」など自由に回答できる質問で、詳細な情報を引き出せます。', '研修44: 質問力の向上', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (179, 4, 7, '「クローズドクエスチョン」が適している場面は？', '["詳細な情報を引き出したい時", "事実確認や選択肢を絞りたい時", "顧客の気持ちを聞きたい時", "商談を始める時"]'::jsonb, 1, 'クローズドクエスチョンは「はい/いいえ」や選択式で、事実確認や選択肢を絞る際に効果的です。', '研修44: 質問力の向上', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (180, 4, 8, '「深掘り質問」のテクニックとして適切なのは？', '["なぜを5回繰り返す", "相手の回答に対して具体的に聞く", "矢継ぎ早に質問する", "答えを誘導する"]'::jsonb, 1, '深掘り質問は相手の回答に対して「具体的には？」「例えば？」と掘り下げていくテクニックです。', '研修44: 質問力の向上', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (181, 4, 9, '質問で避けるべきパターンは？', '["オープンクエスチョンから始める", "答えを誘導する質問をする", "相手の回答を確認する", "沈黙を恐れない"]'::jsonb, 1, '「〇〇ですよね？」など答えを誘導する質問は、顧客の本音を引き出せません。', '研修44: 質問力の向上', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (182, 4, 10, 'SPIN話法の「S」が意味するのは？', '["Solution（解決策）", "Situation（状況）", "Strategy（戦略）", "Success（成功）"]'::jsonb, 1, 'SPINのSはSituation（状況質問）で、顧客の現状を把握するための質問です。', '研修44: 質問力の向上', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (183, 4, 11, 'PREP法の正しい順序は？', '["Point→Reason→Example→Point", "Problem→Reason→Example→Point", "Point→Result→Example→Plan", "Plan→Reason→Execution→Point"]'::jsonb, 0, 'PREP法はPoint（結論）→Reason（理由）→Example（例）→Point（結論）の順で説明する技法です。', '研修45: 効果的な説明技法', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (184, 4, 12, '説明の最初に「結論」を述べるメリットは？', '["時間が短縮できる", "聞き手が話の全体像を把握しやすい", "説明を省略できる", "反論されにくい"]'::jsonb, 1, '最初に結論を述べることで、聞き手は話の方向性を理解し、詳細を理解しやすくなります。', '研修45: 効果的な説明技法', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (185, 4, 34, '電話を取り次ぐ際に確認すべきことは？', '["相手の用件だけ", "相手の名前・会社名・用件", "相手の電話番号だけ", "確認は不要"]'::jsonb, 1, '取り次ぐ際は相手の名前、会社名、用件を確認し、正確に伝えることが重要です。', '研修49: 電話応対の基本', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (186, 4, 35, '電話の「クロージング」として適切なのは？', '["すぐに切る", "要点を復唱し、挨拶して相手が切るのを待つ", "「では」とだけ言って切る", "相手より先に切る"]'::jsonb, 1, '確認事項を復唱し、挨拶の後、相手が切るのを待ってから静かに受話器を置くのがマナーです。', '研修49: 電話応対の基本', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (187, 4, 36, '名刺交換の基本として正しいのは？', '["座ったまま交換する", "立って両手で渡し、両手で受け取る", "片手で素早く交換する", "テーブル越しに交換する"]'::jsonb, 1, '名刺交換は立って行い、両手で胸の高さで渡し、両手で受け取るのが基本マナーです。', '研修50: 名刺交換とビジネスマナー', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (188, 4, 37, '受け取った名刺の扱いとして正しいのは？', '["すぐにポケットにしまう", "テーブルの上に丁寧に置く", "名刺入れにすぐしまう", "メモを書き込む"]'::jsonb, 1, '商談中は受け取った名刺をテーブルの上（上座側）に丁寧に置き、終了後に名刺入れにしまいます。', '研修50: 名刺交換とビジネスマナー', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (189, 4, 38, '複数人と名刺交換する際の順序は？', '["年齢順", "役職が上の人から順に", "近い人から順に", "順序は気にしなくてよい"]'::jsonb, 1, '役職が上の人から順に交換するのが基本マナーです。相手の組織構造を把握しておくと良いでしょう。', '研修50: 名刺交換とビジネスマナー', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (190, 4, 39, '商談時の席順として「上座」はどこ？', '["入口に近い席", "入口から遠い奥の席", "窓際の席", "真ん中の席"]'::jsonb, 1, '上座は入口から遠い奥の席です。お客様は上座に案内するのがマナーです。', '研修50: 名刺交換とビジネスマナー', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (191, 4, 40, 'お辞儀の角度で「敬礼」は何度？', '["15度", "30度", "45度", "90度"]'::jsonb, 1, '敬礼は30度が目安です。会釈は15度、最敬礼は45度です。', '研修50: 名刺交換とビジネスマナー', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (192, 4, 41, 'オンライン商談で最も重要な事前準備は？', '["部屋を片付ける", "通信環境・音声・映像の確認", "スーツを着る", "資料を印刷する"]'::jsonb, 1, 'オンライン商談では通信トラブルが致命的になるため、事前の接続・音声・映像テストが最重要です。', '研修51: オンライン商談のコツ', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (193, 4, 42, 'オンライン商談でカメラを見て話す効果は？', '["自分が映らない", "相手にアイコンタクトしている印象を与える", "画面共有しやすい", "通信が安定する"]'::jsonb, 1, 'カメラを見て話すと、相手の画面では目が合っているように見え、アイコンタクトの効果が得られます。', '研修51: オンライン商談のコツ', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (194, 4, 43, 'オンライン商談で「リアクション」が重要な理由は？', '["沈黙が怖いから", "対面より非言語情報が伝わりにくいから", "録画されているから", "上司が見ているから"]'::jsonb, 1, 'オンラインでは非言語情報が伝わりにくいため、意識的にうなずきや相槌などのリアクションが必要です。', '研修51: オンライン商談のコツ', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (195, 4, 44, 'オンライン商談の「画面共有」で注意すべきことは？', '["できるだけ長く共有する", "共有前にデスクトップを整理し、必要なもののみ表示", "全画面を共有する", "通知をオンにしておく"]'::jsonb, 1, '不要なウィンドウや通知が見えないよう、事前にデスクトップを整理し、必要な画面のみ共有します。', '研修51: オンライン商談のコツ', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (196, 4, 45, 'オンライン商談の照明として適切なのは？', '["後ろから光を当てる", "顔の正面やや上から光を当てる", "暗い方が落ち着く", "照明は関係ない"]'::jsonb, 1, '顔の正面やや上から光を当てると、表情が明るく見え、好印象を与えられます。', '研修51: オンライン商談のコツ', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (197, 4, 46, 'プレゼンの「序論」で行うべきことは？', '["詳細なデータを示す", "聴衆の関心を引き、話の全体像を示す", "結論を詳しく説明する", "自己紹介を長くする"]'::jsonb, 1, '序論では聴衆の関心を引き、「何を話すのか」という話の全体像（アジェンダ）を示します。', '研修52: プレゼンテーションスキル', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (198, 4, 47, 'プレゼンで「1スライド1メッセージ」が推奨される理由は？', '["スライド枚数が増えるから", "聴衆が理解しやすく、印象に残りやすいから", "作成が楽だから", "時間が稼げるから"]'::jsonb, 1, '情報を詰め込みすぎると理解が難しくなります。1スライド1メッセージで明確に伝えることが効果的です。', '研修52: プレゼンテーションスキル', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (199, 4, 48, 'プレゼンの緊張を和らげる方法として効果的なのは？', '["原稿を丸暗記する", "十分な準備とリハーサルを行う", "聴衆を見ない", "早口で話す"]'::jsonb, 1, '十分な準備とリハーサルが自信につながり、緊張を和らげる最も効果的な方法です。', '研修52: プレゼンテーションスキル', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (200, 4, 49, 'プレゼンの「間（ま）」の効果は？', '["時間稼ぎになる", "聴衆に考える時間を与え、重要なポイントを強調する", "緊張を隠せる", "特に効果はない"]'::jsonb, 1, '適切な間は聴衆に情報を咀嚼する時間を与え、重要なポイントを強調する効果があります。', '研修52: プレゼンテーションスキル', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (201, 4, 50, 'プレゼンの「質疑応答」で想定外の質問を受けた場合の対応は？', '["知ったかぶりをする", "正直に分からないと伝え、後日回答することを約束する", "質問を無視する", "話題を変える"]'::jsonb, 1, '分からないことは正直に伝え、「確認して後日ご連絡します」と対応するのが誠実です。', '研修52: プレゼンテーションスキル', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (202, 5, 1, '営業プロセスを標準化するメリットとして正しくないのは？', '["成果のばらつきを減らせる", "新人教育がしやすくなる", "個人の創意工夫が不要になる", "改善ポイントが明確になる"]'::jsonb, 2, 'プロセス標準化は基盤であり、その上で個人の創意工夫を活かすことが重要です。', '研修53: 営業プロセス概論', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (203, 5, 20, 'ヒアリング中に「沈黙」が生じた場合の対応は？', '["すぐに次の質問をする", "相手が考える時間として待つ", "話題を変える", "商談を終了する"]'::jsonb, 1, '沈黙は相手が考えている時間かもしれません。焦らず待つことで、深い回答が得られることがあります。', '研修56: ニーズヒアリング', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (204, 5, 2, '一般的な営業プロセスの流れとして正しいのは？', '["提案→リード獲得→商談→クロージング", "リード獲得→アプローチ→ヒアリング→提案→クロージング", "クロージング→提案→ヒアリング→リード獲得", "商談→リード獲得→提案→アプローチ"]'::jsonb, 1, '営業プロセスはリード獲得→アプローチ→ヒアリング→提案→クロージング→フォローの流れが一般的です。', '研修53: 営業プロセス概論', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (205, 5, 3, '営業活動における「KPI」の役割は？', '["売上目標を達成すること", "プロセスの進捗を数値で可視化すること", "顧客満足度を測ること", "競合を分析すること"]'::jsonb, 1, 'KPI（重要業績評価指標）は営業プロセスの各段階の進捗を数値で可視化し、改善に活かすものです。', '研修53: 営業プロセス概論', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (206, 5, 4, '「パイプライン管理」とは？', '["配管工事の管理", "商談の進捗状況を段階別に管理すること", "顧客の苦情を管理すること", "在庫を管理すること"]'::jsonb, 1, 'パイプライン管理は商談を段階別に整理し、各段階の件数や金額を把握して売上予測に活用します。', '研修53: 営業プロセス概論', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (207, 5, 5, '営業プロセスにおける「ボトルネック」とは？', '["最も成果が出ている段階", "全体の流れを滞らせている段階", "最初の段階", "最後の段階"]'::jsonb, 1, 'ボトルネックは全体の流れを滞らせている段階で、ここを改善することで全体効率が向上します。', '研修53: 営業プロセス概論', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (208, 5, 6, '「リード」の定義として正しいのは？', '["既存顧客", "自社商品に興味を持つ可能性のある見込み客", "契約済みの顧客", "競合他社"]'::jsonb, 1, 'リードとは自社商品やサービスに興味を持つ可能性のある見込み客のことです。', '研修54: リード獲得と見込み客管理', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (209, 5, 7, 'リードの「質」を判断する基準として適切なのは？', '["名刺の枚数", "予算・権限・ニーズ・タイミング（BANT）", "会社の知名度", "担当者の年齢"]'::jsonb, 1, 'BANT（Budget, Authority, Need, Timeline）はリードの質を判断する代表的なフレームワークです。', '研修54: リード獲得と見込み客管理', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (210, 5, 8, '「リードナーチャリング」の目的は？', '["リードを即座に契約させる", "見込み客を育成し購買意欲を高める", "リードを削除する", "競合からリードを奪う"]'::jsonb, 1, 'リードナーチャリングは情報提供などを通じて見込み客との関係を育て、購買意欲を高めていくプロセスです。', '研修54: リード獲得と見込み客管理', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (211, 5, 9, '「ホットリード」と「コールドリード」の違いは？', '["温度が違う", "購買意欲の高さが違う", "業種が違う", "地域が違う"]'::jsonb, 1, 'ホットリードは購買意欲が高く、コールドリードは購買意欲が低い状態の見込み客を指します。', '研修54: リード獲得と見込み客管理', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (212, 5, 10, 'リード管理で「CRM」を活用するメリットは？', '["営業コストを削減できる", "顧客情報を一元管理し、履歴を追跡できる", "リードを自動で獲得できる", "競合情報を入手できる"]'::jsonb, 1, 'CRM（顧客関係管理システム）で顧客情報を一元管理し、対応履歴を追跡することで効率的な営業が可能になります。', '研修54: リード獲得と見込み客管理', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (213, 5, 11, '初回アプローチで最も重要なことは？', '["商品の詳細説明", "価格の提示", "相手の興味を引き、次のステップにつなげる", "契約を取る"]'::jsonb, 2, '初回アプローチの目的は相手の興味を引き、次のステップ（商談設定など）につなげることです。', '研修55: アプローチと初回接触', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (214, 5, 12, '電話でのアプローチで「最初の15秒」が重要な理由は？', '["法律で決まっている", "相手が話を聞くか判断する時間だから", "電話料金が高いから", "上司が見ているから"]'::jsonb, 1, '最初の15秒で相手は「話を聞く価値があるか」を判断します。この間に興味を引くことが重要です。', '研修55: アプローチと初回接触', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (215, 5, 13, 'アプローチで「事前準備」として調べるべきことは？', '["相手の趣味", "相手企業の事業内容・課題・ニュース", "相手の家族構成", "相手の休日の過ごし方"]'::jsonb, 1, '事前に相手企業の事業内容、業界動向、最近のニュースなどを調べておくことで、的確なアプローチができます。', '研修55: アプローチと初回接触', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (216, 5, 14, '「ゲートキーパー」を突破するコツは？', '["強引に話を進める", "丁寧に目的を伝え、担当者につないでもらう価値を示す", "ゲートキーパーを無視する", "嘘をつく"]'::jsonb, 1, 'ゲートキーパー（受付や秘書）には丁寧に対応し、担当者につなぐ価値を感じてもらうことが重要です。', '研修55: アプローチと初回接触', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (217, 5, 15, '初回アプローチのメールで効果的なのは？', '["長文で詳細を説明する", "件名で興味を引き、短く価値を伝える", "添付ファイルを多数つける", "価格表を送る"]'::jsonb, 1, 'メールは件名で開封を促し、本文は短く相手にとっての価値を伝え、次のアクションを明確にします。', '研修55: アプローチと初回接触', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (218, 5, 16, 'ヒアリングの目的として最も重要なのは？', '["自社商品を説明する時間を作る", "顧客の課題・ニーズ・状況を深く理解する", "顧客と仲良くなる", "競合情報を収集する"]'::jsonb, 1, 'ヒアリングの目的は顧客の課題・ニーズ・状況を深く理解し、最適な提案につなげることです。', '研修56: ニーズヒアリング', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (219, 5, 17, '「顕在ニーズ」と「潜在ニーズ」の違いは？', '["金額の違い", "顧客が自覚しているかどうかの違い", "業種の違い", "緊急性の違い"]'::jsonb, 1, '顕在ニーズは顧客が自覚しているニーズ、潜在ニーズは顧客自身も気づいていないニーズです。', '研修56: ニーズヒアリング', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (220, 5, 18, '潜在ニーズを引き出す質問として効果的なのは？', '["はい/いいえで答える質問", "なぜ？どうして？と深掘りする質問", "価格についての質問", "競合についての質問"]'::jsonb, 1, '「なぜそう思われますか？」「具体的には？」と深掘りすることで、潜在ニーズが見えてきます。', '研修56: ニーズヒアリング', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (221, 5, 19, 'SPIN話法の「P」は何を意味する？', '["Price（価格）", "Problem（問題）", "Product（製品）", "Person（人）"]'::jsonb, 1, 'SPINのPはProblem（問題質問）で、顧客の抱える問題や不満を明らかにする質問です。', '研修56: ニーズヒアリング', '2026-02-17T06:00:23.307448+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (222, 5, 21, '提案書の構成で最初に置くべきものは？', '["価格表", "会社概要", "顧客の課題と提案の概要", "製品の詳細仕様"]'::jsonb, 2, '提案書は顧客の課題認識から始め、それに対する解決策（提案）の概要を最初に示すのが効果的です。', '研修57: 提案書の作成', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (223, 5, 22, '提案書で「顧客の課題」を明記する理由は？', '["ページ数を増やすため", "顧客が課題を認識し、解決への関心を高めるため", "会社のルールだから", "競合と差別化するため"]'::jsonb, 1, '課題を明確にすることで顧客は「理解されている」と感じ、解決策への関心が高まります。', '研修57: 提案書の作成', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (224, 5, 23, '提案書の「導入効果」を示す際のポイントは？', '["曖昧な表現で期待を持たせる", "具体的な数字や事例で示す", "競合の悪口を書く", "効果は書かない"]'::jsonb, 1, '「コスト30%削減」「作業時間50%短縮」など具体的な数字や事例で示すと説得力が増します。', '研修57: 提案書の作成', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (225, 5, 24, '提案書のデザインで重要なのは？', '["できるだけ多くの色を使う", "読みやすさと視覚的な分かりやすさ", "文字を小さくして情報を詰め込む", "アニメーションを多用する"]'::jsonb, 1, '提案書は読みやすさが重要です。適切な余白、フォントサイズ、図表の活用で分かりやすくします。', '研修57: 提案書の作成', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (226, 5, 25, '提案書を「カスタマイズ」することの重要性は？', '["作業時間が減る", "顧客固有の課題に対応した提案で響きやすくなる", "テンプレートが不要になる", "上司の承認が得やすい"]'::jsonb, 1, '汎用的な提案書より、顧客固有の課題・状況に合わせた提案の方が響き、採用されやすくなります。', '研修57: 提案書の作成', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (227, 5, 26, 'プレゼンの冒頭で効果的な「つかみ」は？', '["自己紹介を長くする", "顧客の課題に共感する問いかけ", "価格を最初に伝える", "競合の批判"]'::jsonb, 1, '「〇〇でお困りではありませんか？」など顧客の課題に触れることで、関心を引きつけられます。', '研修58: プレゼンテーション実践', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (228, 5, 27, 'プレゼン中に聴衆の反応を確認する方法は？', '["反応は気にしない", "質問を投げかけたり、アイコンタクトで確認する", "資料を読み上げることに集中する", "早く終わらせる"]'::jsonb, 1, '「ここまでよろしいですか？」と確認したり、聴衆の表情を見てペースを調整することが重要です。', '研修58: プレゼンテーション実践', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (229, 5, 28, 'プレゼンで「ストーリーテリング」を使う効果は？', '["時間が長くなる", "論理より感情に訴え、記憶に残りやすくなる", "専門的に見える", "質問が減る"]'::jsonb, 1, '事例や体験談をストーリーとして語ることで、感情に訴え、記憶に残りやすくなります。', '研修58: プレゼンテーション実践', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (230, 5, 29, 'プレゼンの「クロージング」で行うべきことは？', '["新しい情報を追加する", "要点を整理し、次のアクションを明確にする", "質疑応答を省略する", "すぐに退出する"]'::jsonb, 1, '最後に要点を整理し、「次回は〇〇について」など具体的な次のアクションを提示します。', '研修58: プレゼンテーション実践', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (231, 5, 30, 'プレゼン中に技術トラブルが発生した場合の対応は？', '["パニックになる", "冷静に対処し、口頭で説明を続ける", "プレゼンを中止する", "相手のせいにする"]'::jsonb, 1, 'トラブル時は冷静に対処し、資料なしでも説明できる準備をしておくことがプロの対応です。', '研修58: プレゼンテーション実践', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (232, 5, 31, '見積書で最も重要なのは？', '["できるだけ安い価格を提示する", "価格の根拠と提供価値を明確にする", "競合より高い価格を提示する", "詳細を曖昧にする"]'::jsonb, 1, '見積書は価格だけでなく、その価格の根拠と顧客が得られる価値を明確にすることが重要です。', '研修59: 見積・価格交渉', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (233, 5, 32, '価格交渉で「値引き」を求められた場合の対応は？', '["すぐに値引きに応じる", "価値を再度説明し、条件交渉を検討する", "交渉を拒否する", "競合の価格を聞く"]'::jsonb, 1, '安易な値引きは価値を下げます。価値を再説明した上で、条件（期間、数量など）の交渉を検討します。', '研修59: 見積・価格交渉', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (234, 5, 33, '「松竹梅」の価格設定の効果は？', '["顧客を混乱させる", "中間プランが選ばれやすくなる", "最安プランが選ばれやすくなる", "最高プランが選ばれやすくなる"]'::jsonb, 1, '3つの選択肢を提示すると、人は極端を避けて中間を選ぶ傾向があります（松竹梅効果）。', '研修59: 見積・価格交渉', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (235, 5, 34, '価格交渉における「BATNA」とは？', '["最良の代替案", "最高の提案", "最低価格", "最終期限"]'::jsonb, 0, 'BATNA（Best Alternative to a Negotiated Agreement）は交渉が成立しない場合の最良の代替案です。', '研修59: 見積・価格交渉', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (236, 5, 35, '価格交渉で避けるべきことは？', '["価値を説明する", "一方的に譲歩し続ける", "条件を提示する", "沈黙を使う"]'::jsonb, 1, '一方的な譲歩は「もっと引き出せる」という印象を与え、際限のない値引き要求につながります。', '研修59: 見積・価格交渉', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (237, 5, 36, 'クロージングの適切なタイミングは？', '["商談の最初", "顧客が購買シグナルを出した時", "値引きを提示した後", "競合が出てきた時"]'::jsonb, 1, '購買シグナル（質問が具体的になる、導入後の話をするなど）が出たらクロージングのタイミングです。', '研修60: クロージング技法', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (238, 5, 37, '「テストクロージング」の目的は？', '["契約を取る", "顧客の購買意欲や懸念点を確認する", "価格を提示する", "競合を排除する"]'::jsonb, 1, 'テストクロージングは「もし導入されるとしたら」など仮定の質問で購買意欲や懸念を確認するものです。', '研修60: クロージング技法', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (239, 5, 38, '「二者択一クロージング」の例は？', '["買いますか？買いませんか？", "月額プランと年額プランどちらがよろしいですか？", "いつでも良いですよ", "検討してください"]'::jsonb, 1, '「買う/買わない」ではなく「AかBか」という選択肢を提示することで、決断を促すテクニックです。', '研修60: クロージング技法', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (240, 10, 9, '「3C分析」の3つのCとは？', '["Cost, Customer, Company", "Customer, Competitor, Company", "Channel, Cost, Customer", "Company, Channel, Competitor"]'::jsonb, 1, '3CはCustomer（顧客）、Competitor（競合）、Company（自社）の3つの視点で分析します。', '研修102: 市場調査と分析', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (241, 5, 39, 'クロージングで「沈黙」を使う効果は？', '["相手を困らせる", "相手に考える時間を与え、決断を促す", "時間を稼ぐ", "会話を終わらせる"]'::jsonb, 1, 'クロージング後の沈黙は、相手に考える時間を与え、自ら答えを出すよう促す効果があります。', '研修60: クロージング技法', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (242, 5, 40, '「今決める理由」を作るために有効なのは？', '["嘘の期限を設ける", "本当の期限や特典を明確に伝える", "毎回「今日だけ」と言う", "決断を急かす"]'::jsonb, 1, 'キャンペーン期限、決算、在庫状況など、本当の理由に基づく期限を伝えることが誠実で効果的です。', '研修60: クロージング技法', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (243, 5, 41, '契約書を交わす前に確認すべきことは？', '["上司の機嫌", "契約内容、条件、双方の認識の一致", "競合の動向", "天気"]'::jsonb, 1, '契約前に内容・条件・納期などを双方で確認し、認識の相違がないことを確認することが重要です。', '研修61: 契約と事務手続き', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (244, 5, 42, '契約書の「瑕疵担保責任」とは？', '["支払い義務", "欠陥があった場合の売り手の責任", "守秘義務", "解約条件"]'::jsonb, 1, '瑕疵担保責任は、商品やサービスに欠陥（瑕疵）があった場合の売り手の責任を定めるものです。', '研修61: 契約と事務手続き', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (245, 5, 43, '契約後の「社内手続き」として重要なのは？', '["何もしない", "受注報告、関連部署への連携、システム登録", "すぐに次の商談に移る", "顧客に連絡しない"]'::jsonb, 1, '契約後は受注報告、関連部署（納品、請求など）への連携、CRM等への登録を確実に行います。', '研修61: 契約と事務手続き', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (246, 5, 44, '契約書で「自動更新条項」がある場合の注意点は？', '["何もしなくてよい", "更新時期と解約条件を把握しておく", "顧客に知らせない", "条項を無視する"]'::jsonb, 1, '自動更新条項がある場合、更新時期と解約条件を把握し、顧客にも説明しておくことが重要です。', '研修61: 契約と事務手続き', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (247, 5, 45, '「発注書」と「契約書」の違いは？', '["同じもの", "発注書は個別注文、契約書は基本的な取引条件を定める", "発注書の方が法的効力が強い", "契約書は不要"]'::jsonb, 1, '契約書は取引の基本条件を定め、発注書はその枠組みの中での個別注文を行うものです。', '研修61: 契約と事務手続き', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (248, 5, 46, '契約後のフォローアップが重要な理由は？', '["契約したら終わりだから", "顧客満足度向上とリピート・紹介につながるから", "法律で義務付けられているから", "上司に報告するため"]'::jsonb, 1, '契約後のフォローアップは顧客満足度を高め、継続利用や紹介につながる重要な活動です。', '研修62: フォローアップと関係構築', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (249, 5, 47, '「オンボーディング」とは？', '["船に乗ること", "顧客が製品・サービスを使いこなせるよう支援すること", "契約を解除すること", "新規開拓すること"]'::jsonb, 1, 'オンボーディングは顧客が製品やサービスを円滑に使い始められるよう支援するプロセスです。', '研修62: フォローアップと関係構築', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (250, 5, 48, '顧客との関係構築で「定期接触」が重要な理由は？', '["暇つぶしになる", "課題の早期発見とアップセル機会の把握ができる", "義務だから", "競合を排除するため"]'::jsonb, 1, '定期的な接触により、顧客の変化や課題を早期に発見し、追加提案の機会を把握できます。', '研修62: フォローアップと関係構築', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (251, 5, 49, '「NPS（Net Promoter Score）」とは？', '["売上指標", "顧客が他者に推奨する意向を測る指標", "利益率", "在庫回転率"]'::jsonb, 1, 'NPSは「この製品を友人に勧めますか」という質問で顧客ロイヤルティを測る指標です。', '研修62: フォローアップと関係構築', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (252, 5, 50, '「アップセル」と「クロスセル」の違いは？', '["同じ意味", "アップセルは上位プラン、クロスセルは関連商品の提案", "アップセルは値下げ、クロスセルは値上げ", "どちらも新規開拓"]'::jsonb, 1, 'アップセルは上位プランへの移行提案、クロスセルは関連する別商品の提案です。', '研修62: フォローアップと関係構築', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (253, 6, 1, '顧客の「反論」を正しく捉えた考え方は？', '["拒絶のサインなので諦める", "関心の表れであり、対話のチャンス", "営業が下手な証拠", "価格が高すぎる証拠"]'::jsonb, 1, '反論は顧客が真剣に検討している証拠であり、懸念を解消すれば成約につながるチャンスです。', '研修65: 反論の種類と心理', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (254, 6, 2, '「本音の反論」と「建前の反論」を見分けるポイントは？', '["声の大きさ", "具体性と一貫性があるかどうか", "反論の回数", "顧客の年齢"]'::jsonb, 1, '本音の反論は具体的で一貫性があります。建前は曖昧で、掘り下げると別の懸念が出てきます。', '研修65: 反論の種類と心理', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (255, 6, 3, '顧客が反論する心理的背景として正しくないのは？', '["リスクへの不安", "現状維持バイアス", "営業を困らせたい", "情報不足による判断保留"]'::jsonb, 2, '反論の多くはリスク不安、現状維持の心理、情報不足などが原因で、営業を困らせたいわけではありません。', '研修65: 反論の種類と心理', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (256, 6, 4, '「価格が高い」という反論の本当の意味として考えられるのは？', '["本当に予算がない", "価値が伝わっていない", "他社と比較している", "すべてありえる"]'::jsonb, 3, '「価格が高い」の裏には予算の問題、価値の理解不足、競合比較など様々な理由が隠れている可能性があります。', '研修65: 反論の種類と心理', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (257, 6, 5, '反論に対する最初の対応として適切なのは？', '["すぐに反論を否定する", "まず受け止めて共感を示す", "値引きを提案する", "上司を呼ぶ"]'::jsonb, 1, '反論にはまず「おっしゃる通りです」「ご懸念はもっともです」と受け止め、共感を示すことが重要です。', '研修65: 反論の種類と心理', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (258, 6, 6, '「高い」と言われた時、最初に確認すべきことは？', '["どこが高いか", "何と比較して高いのか", "いくらなら買うか", "競合の価格"]'::jsonb, 1, '「何と比較して高いのか」を確認することで、競合比較か予算の問題かなど、真の懸念が分かります。', '研修66: 価格への反論対処', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (259, 6, 7, '価格の反論に対して「価値」で応える方法は？', '["価格を下げる", "導入効果やROIを具体的に示す", "競合の悪口を言う", "「安いですよ」と言う"]'::jsonb, 1, '「この投資で年間〇〇円のコスト削減が見込めます」など、具体的なROIを示すことが効果的です。', '研修66: 価格への反論対処', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (260, 6, 8, '「予算がない」と言われた場合の対応として適切なのは？', '["諦める", "分割払いや段階的導入など代替案を提案する", "無理に押し切る", "上司に値引き相談する"]'::jsonb, 1, '予算の問題には分割払い、段階導入、時期の調整など、柔軟な代替案を提案することが有効です。', '研修66: 価格への反論対処', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (261, 6, 9, '「安値競争」に巻き込まれないためのポイントは？', '["常に最安値を提示する", "価格以外の価値（品質・サポート）で差別化する", "価格交渉を拒否する", "競合を批判する"]'::jsonb, 1, '価格だけの勝負は消耗戦になります。品質、サポート、実績など価格以外の価値で差別化することが重要です。', '研修66: 価格への反論対処', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (262, 6, 10, '「もう少し安くならないか」への効果的な応答は？', '["「無理です」と断る", "「何か条件を変更できればご検討いただけますか」と条件を探る", "即座に値引く", "黙って帰る"]'::jsonb, 1, '値引きの代わりに条件（期間、数量、支払い条件など）の変更を提案し、Win-Winを探ります。', '研修66: 価格への反論対処', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (263, 6, 11, '「他社の方が安い」と言われた時の対応として適切なのは？', '["競合の悪口を言う", "価格差の理由と自社の優位性を説明する", "すぐに値引く", "「それならそちらで」と言う"]'::jsonb, 1, '価格差がある理由（品質、サポート、実績など）と、その差に見合う価値があることを説明します。', '研修67: 競合比較への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (264, 6, 12, '競合製品の悪口を言うことのデメリットは？', '["効果的なので特にない", "自社の品格を下げ、信頼を失う", "競合に情報が漏れる", "法律違反になる"]'::jsonb, 1, '競合批判は自社の品格を下げ、「この営業は信頼できない」と思われる原因になります。', '研修67: 競合比較への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (265, 6, 13, '「競合と比較検討中」と言われた時の質問として適切なのは？', '["競合はどこですか？", "選定で重視されるポイントは何ですか？", "競合の価格はいくらですか？", "なぜ競合を検討するのですか？"]'::jsonb, 1, '選定基準を聞くことで、顧客が何を重視しているかが分かり、自社の強みをアピールできます。', '研修67: 競合比較への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (266, 6, 14, '自社の「弱み」を聞かれた場合の対応は？', '["弱みはないと言う", "正直に認めた上で、どう補っているかを説明する", "話題を変える", "競合の弱みを話す"]'::jsonb, 1, '弱みを正直に認め、その弱みをどう補っているか、他の強みで十分カバーできることを説明します。', '研修67: 競合比較への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (267, 6, 15, '競合との「差別化ポイント」を伝える際のコツは？', '["すべての優位点を列挙する", "顧客にとって重要なポイントに絞って伝える", "技術的な詳細を長く説明する", "価格だけを強調する"]'::jsonb, 1, '顧客の課題や重視するポイントに関連した差別化要素を絞って伝えることで、響きやすくなります。', '研修67: 競合比較への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (268, 6, 16, '「検討します」と言われた時、まず確認すべきことは？', '["いつまでに返事をもらえるか", "何を検討されるのか、懸念点は何か", "他に決裁者がいるか", "予算はあるか"]'::jsonb, 1, '「検討します」の中身を確認することで、本当の懸念が分かり、適切な対応ができます。', '研修68: 「検討します」への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (269, 6, 17, '「検討します」が「断り文句」である可能性が高いのは？', '["具体的な検討項目を挙げる場合", "曖昧で次のアクションが決まらない場合", "上司に相談すると言う場合", "資料を求める場合"]'::jsonb, 1, '具体的な検討項目や次のアクションが出てこない場合は、断り文句の可能性があります。', '研修68: 「検討します」への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (270, 6, 18, '「社内で検討する」と言われた場合の対応は？', '["待つだけ", "検討に必要な資料や情報を提供し、次回接点を設定する", "毎日電話する", "諦める"]'::jsonb, 1, '社内検討をサポートする資料を提供し、「〇日後に状況をお伺いします」と次の接点を設定します。', '研修68: 「検討します」への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (271, 6, 19, '検討中の顧客へのフォローで避けるべきことは？', '["定期的な情報提供", "新しい事例の共有", "執拗な催促や圧力", "導入効果の再説明"]'::jsonb, 2, '執拗な催促は顧客に不快感を与え、関係を悪化させます。価値ある情報提供で関係を維持します。', '研修68: 「検討します」への対応', '2026-02-17T06:00:23.478024+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (272, 6, 20, '「検討します」を減らすための事前対策は？', '["提案を急ぐ", "商談中に懸念を引き出し、その場で解消する", "値引きを先に提示する", "決裁者以外とは会わない"]'::jsonb, 1, '商談中に懸念や不安を引き出し、その場で解消することで「検討します」を減らせます。', '研修68: 「検討します」への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (273, 6, 21, '「今は忙しい」と言われた時の対応として適切なのは？', '["諦める", "いつなら都合が良いか確認し、次回アポを設定する", "「5分だけ」と粘る", "何度も電話する"]'::jsonb, 1, '今が忙しいのは事実かもしれません。いつなら良いか確認し、具体的な次回接点を設定します。', '研修69: タイミングの反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (274, 6, 22, '「来期に検討する」と言われた場合の対応は？', '["来期まで連絡しない", "来期の検討に向けた準備として今できることを提案する", "今期中に決めるよう圧力をかける", "諦めて次の顧客に行く"]'::jsonb, 1, '「来期の導入に向けて今から情報収集されませんか」など、今できるアクションを提案します。', '研修69: タイミングの反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (275, 6, 23, 'タイミングの反論が「本音」か「建前」かを見分ける方法は？', '["見分けられない", "具体的な理由や時期を確認する質問をする", "直接「本音ですか」と聞く", "諦める"]'::jsonb, 1, '「いつ頃なら検討できそうですか」「何がクリアになれば検討できますか」と具体的に聞きます。', '研修69: タイミングの反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (276, 6, 24, '「導入時期を決められない」という顧客への対応は？', '["強引に時期を決めさせる", "導入しない場合のリスクや機会損失を示す", "諦める", "値引きで誘導する"]'::jsonb, 1, '「今導入しないと〇〇の機会を逃す」など、先延ばしのリスクや機会損失を具体的に示します。', '研修69: タイミングの反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (277, 6, 25, '「急いでいない」という反論への効果的な質問は？', '["なぜ急がないのですか", "現状の課題で困っていることはありませんか", "競合は急いでいますよ", "いつまでに決めてください"]'::jsonb, 1, '現状の課題を再確認することで、解決の必要性を感じてもらい、優先度を上げてもらいます。', '研修69: タイミングの反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (278, 6, 26, '「私では決められない」と言われた時の対応は？', '["諦める", "決裁者は誰か、どうすれば会えるか確認する", "担当者に決裁権を持つよう説得する", "決裁者に直接電話する"]'::jsonb, 1, '「どなたがご決裁されますか」「お会いする機会をいただけますか」と次のステップを確認します。', '研修70: 決裁者・組織への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (279, 6, 27, '担当者を「社内の味方」にするメリットは？', '["特にない", "社内での推進役となり、決裁プロセスを進めてくれる", "値引きしてくれる", "競合情報を教えてくれる"]'::jsonb, 1, '担当者が社内で推進役になってくれると、決裁者への説明や根回しを助けてもらえます。', '研修70: 決裁者・組織への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (280, 6, 28, '「上司の承認が必要」と言われた場合に用意すべき資料は？', '["詳細な技術資料", "上司向けの要点をまとめた説明資料", "競合比較表", "値引き提案書"]'::jsonb, 1, '上司（決裁者）向けに要点を絞った資料を用意し、担当者が社内説明しやすいようサポートします。', '研修70: 決裁者・組織への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (281, 6, 29, '複数の決裁者がいる場合の対応として適切なのは？', '["一人だけに集中する", "それぞれの関心事を把握し、個別にアプローチする", "全員に同じ説明をする", "最も偉い人だけに会う"]'::jsonb, 1, '決裁者ごとに関心事（コスト、効果、リスクなど）が異なるため、個別に対応することが効果的です。', '研修70: 決裁者・組織への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (282, 6, 30, '「稟議が通らないかもしれない」への対応は？', '["諦める", "稟議を通すための情報や資料を提供し、サポートする", "稟議なしで契約を迫る", "他の顧客を探す"]'::jsonb, 1, '稟議に必要な情報（ROI、リスク、事例など）を提供し、稟議書の書き方もサポートします。', '研修70: 決裁者・組織への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (283, 6, 31, '「御社をよく知らない」と言われた時の対応は？', '["怒る", "会社概要、実績、事例などを丁寧に説明する", "「調べてください」と言う", "諦める"]'::jsonb, 1, '会社の沿革、実績、導入事例、顧客の声などを丁寧に説明し、信頼を構築します。', '研修71: 信頼への反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (284, 6, 32, '「実績はありますか」への効果的な回答は？', '["「たくさんあります」と言う", "具体的な導入事例と成果を数字で示す", "「実績より提案内容を見てください」", "競合の実績を批判する"]'::jsonb, 1, '「〇〇業界で△社に導入、□□の成果を実現」など、具体的な事例と数字で示すと説得力があります。', '研修71: 信頼への反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (285, 6, 33, '信頼を構築するための日常的な行動として正しいのは？', '["大きな約束をする", "小さな約束を確実に守る", "できないことも「できる」と言う", "連絡を最小限にする"]'::jsonb, 1, '「〇日までにご連絡します」など小さな約束を確実に守ることで、信頼が積み重なります。', '研修71: 信頼への反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (286, 6, 34, '「以前、御社で嫌な経験があった」と言われた場合の対応は？', '["言い訳する", "まず真摯に謝罪し、改善点を説明して再チャンスをお願いする", "「それは他の担当です」と言う", "無視する"]'::jsonb, 1, '過去の問題を真摯に受け止め謝罪した上で、改善した点を説明し、再度の機会をいただけるようお願いします。', '研修71: 信頼への反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (287, 6, 35, '「第三者の信頼」を活用する方法として適切なのは？', '["有名人の名前を無断で使う", "顧客の紹介や業界団体の認証を活用する", "架空の事例を作る", "競合の悪評を広める"]'::jsonb, 1, '既存顧客からの紹介、業界認証、第三者機関の評価など、客観的な信頼の証を活用します。', '研修71: 信頼への反論', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (288, 6, 36, '「導入に失敗したらどうしよう」という不安への対応は？', '["「失敗しません」と断言する", "サポート体制や保証制度を具体的に説明する", "「自己責任です」と言う", "不安を無視する"]'::jsonb, 1, '導入支援、研修、保証制度など、失敗リスクを軽減する仕組みを具体的に説明します。', '研修72: リスク懸念への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (289, 6, 37, '「現状でも特に困っていない」という反論への対応は？', '["「困るべきです」と言う", "将来のリスクや機会損失を具体的に示す", "諦める", "「困っているはずです」と否定する"]'::jsonb, 1, '現状維持のリスク（競合に遅れる、コスト上昇など）や、得られる機会を具体的に示します。', '研修72: リスク懸念への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (290, 6, 38, '「他社で失敗した事例を聞いた」への対応は？', '["「嘘です」と否定する", "失敗の原因と自社での対策を説明する", "話題を変える", "その事例を批判する"]'::jsonb, 1, '失敗事例を否定せず、なぜ失敗したか分析し、自社では同様の問題が起きない理由を説明します。', '研修72: リスク懸念への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (291, 6, 39, '「現場が反対している」という反論への対応は？', '["現場を無視して決裁者に進める", "現場の懸念を聞き、導入メリットを現場視点で説明する", "諦める", "現場を批判する"]'::jsonb, 1, '現場の具体的な懸念を聞き、現場にとってのメリット（業務効率化など）を丁寧に説明します。', '研修72: リスク懸念への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (292, 6, 40, 'リスク懸念を軽減する「トライアル」提案のメリットは？', '["無料で提供するので損", "小さなリスクで価値を実感してもらえる", "本契約が遠のく", "顧客に負担がかかる"]'::jsonb, 1, 'トライアルにより小さなリスクで価値を体験してもらい、本格導入への不安を解消できます。', '研修72: リスク懸念への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (293, 6, 41, '交渉における「Win-Win」の考え方として正しいのは？', '["自分だけが勝つこと", "双方が満足できる結果を目指すこと", "相手に譲ること", "引き分けを目指すこと"]'::jsonb, 1, 'Win-Winは双方が価値を得られる結果を目指す考え方で、長期的な関係構築につながります。', '研修73: 交渉の基本原則', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (294, 6, 42, '交渉前の「準備」として重要なことは？', '["相手を調べない", "自社の譲れない条件と譲歩可能な条件を明確にする", "その場で考える", "最初から譲歩する"]'::jsonb, 1, '交渉前に自社のボトムライン（譲れない条件）と譲歩可能な範囲を明確にしておくことが重要です。', '研修73: 交渉の基本原則', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (295, 6, 43, '交渉で「沈黙」を使う効果は？', '["相手を困らせる", "相手に考える時間を与え、譲歩を引き出す可能性がある", "時間稼ぎ", "効果はない"]'::jsonb, 1, '沈黙は相手に考える時間を与え、相手から譲歩や提案を引き出す効果があります。', '研修73: 交渉の基本原則', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (296, 6, 44, '交渉における「アンカリング」とは？', '["船を固定すること", "最初に提示した条件が基準になる効果", "相手を騙すこと", "交渉を終わらせること"]'::jsonb, 1, '最初に提示された条件（アンカー）が交渉の基準となり、その後の判断に影響を与えます。', '研修73: 交渉の基本原則', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (297, 6, 45, '交渉で「感情的にならない」ことが重要な理由は？', '["相手に嫌われるから", "冷静な判断ができなくなり、不利な条件を受け入れてしまうから", "上司に怒られるから", "マナー違反だから"]'::jsonb, 1, '感情的になると冷静な判断ができず、本来避けるべき条件を受け入れてしまうリスクがあります。', '研修73: 交渉の基本原則', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (298, 6, 46, '「譲歩」をする際のポイントは？', '["最初から大きく譲歩する", "小さく段階的に譲歩し、見返りを求める", "絶対に譲歩しない", "相手の言いなりになる"]'::jsonb, 1, '譲歩は小さく段階的に行い、「これを譲る代わりに、〇〇をお願いできますか」と見返りを求めます。', '研修74: 交渉の実践テクニック', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (299, 6, 47, '「ドア・イン・ザ・フェイス」テクニックとは？', '["最初に小さな要求をする", "最初に大きな要求をして断らせ、本命の小さな要求を通す", "ドアを閉める", "顔を見せない"]'::jsonb, 1, '最初に断られる前提の大きな要求をし、その後の小さな要求を「譲歩」として受け入れてもらいやすくします。', '研修74: 交渉の実践テクニック', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (300, 6, 48, '交渉で「第三の選択肢」を提案する効果は？', '["混乱させる", "対立を避け、双方が受け入れやすい解決策を見つけられる", "時間稼ぎになる", "交渉を長引かせる"]'::jsonb, 1, 'AかBかで対立している時、第三の選択肢Cを提案することで、新たな合意点を見つけられます。', '研修74: 交渉の実践テクニック', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (301, 6, 49, '交渉の「デッドロック（行き詰まり）」を打開する方法は？', '["交渉を打ち切る", "争点を変える、時間を置く、第三者を入れるなど", "相手を攻撃する", "全面的に譲歩する"]'::jsonb, 1, '行き詰まりには争点の変更、クールダウン期間、第三者の仲介など、打開策を試みます。', '研修74: 交渉の実践テクニック', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (302, 6, 50, '交渉の「クロージング」で確認すべきことは？', '["相手の私生活", "合意内容を双方で確認し、文書化する", "次の交渉の日程", "相手の弱み"]'::jsonb, 1, '交渉の最後に合意内容を双方で確認し、認識の相違がないよう文書化することが重要です。', '研修74: 交渉の実践テクニック', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (303, 7, 1, '顧客タイプ分析を行う目的として最も適切なのは？', '["顧客を差別するため", "顧客に合わせたコミュニケーションで成約率を上げるため", "営業を楽にするため", "顧客を分類して管理するため"]'::jsonb, 1, '顧客タイプ分析は、タイプに応じた最適なアプローチでコミュニケーション効率と成約率を高めるために行います。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (304, 7, 2, '顧客タイプを見極める際に観察すべきポイントは？', '["外見だけ", "話し方、質問内容、意思決定のスタイル", "年齢と性別", "会社の規模"]'::jsonb, 1, '顧客のコミュニケーションスタイル、重視するポイント、意思決定の傾向などを観察します。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (305, 7, 3, '顧客タイプ分析における「DISC理論」の4タイプに含まれないのは？', '["D（主導型）", "I（感化型）", "S（安定型）", "E（感情型）"]'::jsonb, 3, 'DISC理論はD（Dominance）、I（Influence）、S（Steadiness）、C（Conscientiousness）の4タイプです。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (306, 7, 4, '顧客タイプ分析の注意点として正しいのは？', '["一度判断したら変えない", "タイプは目安であり、個人差を考慮する", "タイプに完全に合わせる", "タイプ分析だけで判断する"]'::jsonb, 1, 'タイプ分析は傾向を把握するツールであり、個人差があることを忘れず柔軟に対応することが重要です。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (307, 7, 5, '顧客タイプを早期に見極めるメリットは？', '["営業時間を短縮できる", "最初から適切なアプローチで信頼関係を構築しやすい", "値引きを避けられる", "競合に勝てる"]'::jsonb, 1, '早期にタイプを把握することで、最初から相手に合ったコミュニケーションが取れ、信頼構築が早まります。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (308, 7, 6, '顧客の「行動パターン」から読み取れることは？', '["年収", "意思決定スタイルや重視する価値観", "家族構成", "趣味"]'::jsonb, 1, '質問の仕方、検討の仕方、反応の速さなどから、意思決定スタイルや重視するポイントが読み取れます。', '研修75: 顧客タイプ分析の基礎', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (309, 7, 7, '論理型顧客の特徴として正しいのは？', '["感情で判断する", "データや根拠に基づいて判断する", "即決する", "人間関係を重視する"]'::jsonb, 1, '論理型顧客は感情より論理、データ、根拠を重視して意思決定を行う傾向があります。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (310, 7, 8, '論理型顧客への提案で効果的なのは？', '["感情に訴える", "具体的な数字やデータで説明する", "急かす", "雑談を多くする"]'::jsonb, 1, 'ROI、具体的な数値、比較データなど、客観的な根拠を示すことが効果的です。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (311, 7, 9, '論理型顧客が質問をたくさんする理由は？', '["文句を言いたい", "判断材料を集めて納得したい", "時間稼ぎ", "興味がない"]'::jsonb, 1, '論理型顧客は十分な情報を集め、納得した上で判断したいという欲求があります。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (312, 7, 10, '論理型顧客への説明で避けるべきことは？', '["詳細なデータを示す", "曖昧な表現や根拠のない主張", "比較表を用意する", "質問に丁寧に答える"]'::jsonb, 1, '「たぶん」「だいたい」など曖昧な表現や、根拠のない主張は論理型顧客の不信感を招きます。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (313, 7, 11, '論理型顧客の意思決定を早めるには？', '["急かす", "必要な情報をすべて提供し、検討に必要な時間を与える", "値引きする", "感情に訴える"]'::jsonb, 1, '論理型顧客には十分な情報と検討時間を与えることで、納得した上での決断が早まります。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (314, 7, 12, '論理型顧客との商談で準備すべき資料は？', '["感動的なストーリー", "詳細なスペック、比較表、ROI計算", "お客様の声だけ", "写真中心の資料"]'::jsonb, 1, 'スペック詳細、競合比較、費用対効果計算など、客観的に判断できる資料を準備します。', '研修76: 論理型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (315, 7, 13, '感情型顧客の特徴として正しいのは？', '["データだけで判断する", "人間関係や感覚、フィーリングを重視する", "即決しない", "細かい質問が多い"]'::jsonb, 1, '感情型顧客は論理より感覚、営業担当者との相性、商品への「好き嫌い」で判断する傾向があります。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (316, 7, 14, '感情型顧客への対応で重要なのは？', '["データを並べる", "共感と信頼関係の構築", "専門用語を使う", "淡々と説明する"]'::jsonb, 1, '感情型顧客には共感を示し、信頼関係を構築することが商談成功の鍵です。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (317, 7, 15, '感情型顧客に効果的なプレゼンテーションは？', '["数字だけの資料", "ストーリー性のある事例や体験談", "専門的な技術説明", "比較表"]'::jsonb, 1, '実際の顧客体験談やストーリー性のある事例など、感情に響く内容が効果的です。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (318, 7, 16, '感情型顧客が「いい感じ」と言った時の対応は？', '["無視する", "その感覚を大切にし、何が良いと感じたか掘り下げる", "すぐにクロージングする", "データで補強する"]'::jsonb, 1, '感情型顧客の「感覚」を尊重し、「どこが良いと感じましたか」と掘り下げることで関係が深まります。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (319, 7, 17, '感情型顧客との雑談は？', '["時間の無駄", "信頼関係構築に重要な時間", "最小限にすべき", "ビジネスの話だけにすべき"]'::jsonb, 1, '感情型顧客にとって雑談は信頼関係を築く重要なプロセスです。適度な雑談で距離を縮めます。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (320, 7, 18, '感情型顧客が不安を示した時の対応は？', '["データで説得する", "不安に共感し、安心感を与える対応をする", "不安を否定する", "早く決断を促す"]'::jsonb, 1, 'まず不安に共感し、「そうですよね、ご不安ですよね」と受け止めた上で、安心材料を提供します。', '研修77: 感情型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (321, 7, 19, '即決型顧客の特徴として正しいのは？', '["時間をかけて慎重に検討する", "スピーディーに判断し、結論を急ぐ", "質問が多い", "リスクを過度に心配する"]'::jsonb, 1, '即決型顧客は判断が早く、長い検討を好まず、スピーディーに物事を進めたい傾向があります。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.6438+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (322, 7, 20, '即決型顧客への提案で重要なのは？', '["詳細な説明を長くする", "要点を簡潔に伝え、決断しやすい選択肢を提示する", "考える時間を多く与える", "リスクを強調する"]'::jsonb, 1, '即決型顧客には要点を簡潔に伝え、「AとB、どちらがよいですか」と決断しやすい形で提案します。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (323, 7, 21, '即決型顧客が「早く結論を」と言う時の対応は？', '["もっと説明を続ける", "結論を先に伝え、詳細は後から補足する", "「もう少しお待ちください」と言う", "資料を読むよう促す"]'::jsonb, 1, '即決型顧客にはまず結論を伝え、必要に応じて詳細を後から説明するスタイルが効果的です。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (324, 7, 22, '即決型顧客へのメール対応で適切なのは？', '["長文で詳細を送る", "要点を箇条書きで簡潔に", "返信を急がない", "添付ファイルを多数付ける"]'::jsonb, 1, '即決型顧客には長文より要点を絞った簡潔なメールが好まれます。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (325, 7, 23, '即決型顧客の注意点として正しいのは？', '["ゆっくり対応しても問題ない", "決断は早いが、後から不満が出ないよう確認が必要", "詳細説明を省略してよい", "リスク説明は不要"]'::jsonb, 1, '即決型は決断が早い分、後から「聞いていない」とならないよう、重要事項は確認が必要です。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (326, 7, 24, '即決型顧客の商談で「ペース」はどうすべき？', '["ゆっくり進める", "顧客のペースに合わせてスピーディーに進める", "自分のペースを守る", "できるだけ長引かせる"]'::jsonb, 1, '即決型顧客は待つことを嫌うため、顧客のスピーディーなペースに合わせることが重要です。', '研修78: 即決型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (327, 7, 25, '慎重型顧客の特徴として正しいのは？', '["即決する", "リスクを避け、じっくり検討してから決断する", "感情で判断する", "細かいことを気にしない"]'::jsonb, 1, '慎重型顧客はリスクを慎重に評価し、十分な検討の上で判断する傾向があります。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (328, 7, 26, '慎重型顧客への対応で重要なのは？', '["急かす", "十分な情報提供と検討時間を確保する", "リスクを隠す", "すぐにクロージングする"]'::jsonb, 1, '慎重型顧客には急かさず、必要な情報を提供し、検討する時間を十分に与えることが重要です。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (329, 7, 27, '慎重型顧客の「もう少し考えたい」への対応は？', '["「今決めてください」と押す", "検討に必要な追加情報を提供し、次回の接点を設定する", "諦める", "値引きを提案する"]'::jsonb, 1, '検討を尊重しつつ、判断に必要な情報を提供し、次のフォロー日程を決めておきます。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (330, 7, 28, '慎重型顧客にリスク情報を伝える際のポイントは？', '["リスクを隠す", "リスクを正直に伝え、対策も併せて説明する", "リスクを誇張する", "リスクは聞かれるまで言わない"]'::jsonb, 1, '慎重型顧客にはリスクを隠さず伝え、そのリスクへの対策や保証も併せて説明します。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (331, 7, 29, '慎重型顧客が比較検討している場合の対応は？', '["比較をやめさせる", "比較検討に役立つ情報を提供し、判断をサポートする", "競合の悪口を言う", "待つだけ"]'::jsonb, 1, '比較検討を尊重し、自社製品の強みが分かる比較資料など、判断に役立つ情報を提供します。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (332, 7, 30, '慎重型顧客への「保証」の提案が効果的な理由は？', '["法律で義務だから", "リスクへの不安を軽減できるから", "値引きの代わりになるから", "競合と差別化できるから"]'::jsonb, 1, '保証や返金制度は、慎重型顧客の「失敗したらどうしよう」という不安を軽減する効果があります。', '研修79: 慎重型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (333, 7, 31, '価格重視型顧客の特徴として正しいのは？', '["品質を最優先する", "コストパフォーマンスを重視し、価格比較を行う", "ブランドにこだわる", "即決する"]'::jsonb, 1, '価格重視型顧客は費用対効果を重視し、複数社の価格を比較して判断する傾向があります。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (334, 7, 32, '価格重視型顧客への対応として適切なのは？', '["すぐに最安値を提示する", "価格に見合う価値を説明し、コスパの良さを示す", "価格交渉を拒否する", "高級感をアピールする"]'::jsonb, 1, '単に安さではなく、この価格でこれだけの価値が得られるというコストパフォーマンスを示します。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (335, 7, 33, '価格重視型顧客の「もっと安くならない？」への対応は？', '["即座に値引く", "価値を再説明し、条件変更での価格調整を検討する", "「これ以上は無理です」と断る", "黙る"]'::jsonb, 1, 'まず価値を再確認し、スペック変更や数量条件など、条件を変えての価格調整を検討します。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (336, 7, 34, '価格重視型顧客に「総所有コスト（TCO）」を説明するメリットは？', '["話が長くなる", "初期費用だけでなくトータルでの経済性を示せる", "専門的に見える", "競合を批判できる"]'::jsonb, 1, '初期費用が高くても、ランニングコストや耐久性を含めた総コストで有利なことを示せます。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (337, 7, 35, '価格重視型顧客に「安さだけ」で勝負するリスクは？', '["リスクはない", "利益が減り、価格競争に巻き込まれる", "顧客が増えすぎる", "品質が上がる"]'::jsonb, 1, '価格だけの勝負は利益を圧迫し、さらなる値下げ要求を招く悪循環に陥るリスクがあります。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (338, 7, 36, '価格重視型顧客に効果的な「松竹梅」提案とは？', '["最安プランだけ提示する", "3段階のプランを提示し、価値と価格のバランスを選ばせる", "最高プランだけ提示する", "価格を隠す"]'::jsonb, 1, '価格帯の異なる選択肢を提示し、顧客が予算と価値のバランスで選べるようにします。', '研修80: 価格重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (339, 7, 37, '品質重視型顧客の特徴として正しいのは？', '["最安値を求める", "品質・性能・信頼性を最優先で判断する", "即決する", "ブランドは気にしない"]'::jsonb, 1, '品質重視型顧客は価格より品質、性能、信頼性、アフターサポートを重視して判断します。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (340, 7, 38, '品質重視型顧客への提案で強調すべきは？', '["価格の安さ", "品質保証、実績、アフターサポート体制", "納期の早さ", "営業担当の人柄"]'::jsonb, 1, '品質基準、検査体制、保証内容、サポート体制、導入実績など品質を証明する要素を強調します。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (341, 7, 39, '品質重視型顧客が「価格が高い」と言った場合の対応は？', '["すぐに値引く", "高い理由（品質の裏付け）を丁寧に説明する", "「高くないです」と否定する", "諦める"]'::jsonb, 1, '品質重視型顧客には「なぜこの価格なのか」という品質の裏付けを丁寧に説明します。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (342, 7, 40, '品質重視型顧客に効果的な「第三者評価」の活用とは？', '["口コミを捏造する", "業界認証、受賞歴、専門家評価を提示する", "ランキングを自作する", "競合の低評価を見せる"]'::jsonb, 1, 'ISO認証、業界賞、専門誌の評価など、客観的な第三者評価が品質の証明になります。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (343, 7, 41, '品質重視型顧客との関係構築で重要なのは？', '["価格交渉", "長期的な信頼関係と安定した品質の提供", "頻繁な営業訪問", "新商品の紹介"]'::jsonb, 1, '品質重視型顧客は長期的なパートナーシップを好む傾向があり、安定した品質提供が関係構築の鍵です。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (344, 7, 42, '品質重視型顧客に「アフターサポート」を説明する重要性は？', '["説明不要", "購入後も安心して使えることが品質の一部だから", "値引き交渉に使える", "話を長くできる"]'::jsonb, 1, '品質重視型顧客にとって購入後のサポートも「品質」の一部であり、重要な判断材料です。', '研修81: 品質重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (345, 7, 43, '関係性重視型顧客の特徴として正しいのは？', '["価格だけで判断する", "信頼できる営業担当者や企業との関係を重視する", "品質を気にしない", "即決する"]'::jsonb, 1, '関係性重視型顧客は「誰から買うか」を重視し、信頼関係のある相手との取引を好みます。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (346, 7, 44, '関係性重視型顧客への対応で最も重要なのは？', '["価格を下げる", "継続的なコミュニケーションと信頼構築", "最新技術をアピールする", "スピード対応"]'::jsonb, 1, '関係性重視型顧客には定期的な接触、誠実な対応、約束を守ることで信頼関係を築きます。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (347, 7, 45, '関係性重視型顧客が担当者変更を嫌がる理由は？', '["面倒だから", "築いた信頼関係がリセットされることを懸念するから", "新しい人が嫌いだから", "特に理由はない"]'::jsonb, 1, '関係性重視型顧客にとって信頼関係は重要な資産であり、それが失われることを懸念します。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (348, 7, 46, '関係性重視型顧客の「紹介」を得るメリットは？', '["特にない", "信頼の連鎖で新規顧客獲得と既存顧客との関係強化ができる", "値引きしなくて済む", "営業活動が不要になる"]'::jsonb, 1, '関係性重視型顧客からの紹介は信頼の証であり、質の高い新規顧客獲得につながります。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (349, 7, 47, '関係性重視型顧客との「定期接触」で避けるべきは？', '["近況報告", "売り込みばかりの連絡", "情報提供", "御礼の連絡"]'::jsonb, 1, '売り込みばかりでは「利用されている」と感じさせます。有益な情報提供や御礼など、価値ある接触を心がけます。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (350, 7, 48, '関係性重視型顧客への「誕生日メッセージ」などの効果は？', '["効果なし", "一人の人間として大切にされていると感じてもらえる", "ビジネスマナー違反", "時間の無駄"]'::jsonb, 1, 'ビジネスを超えた人としての関心を示すことで、信頼関係がより深まります。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (351, 7, 49, '関係性重視型顧客が「御社とずっと取引したい」と言った時の対応は？', '["当然だと思う", "感謝を伝え、期待に応える姿勢を示す", "値上げを提案する", "他の顧客を紹介してもらう"]'::jsonb, 1, '信頼の表明に感謝し、その期待に応え続ける姿勢を明確に伝えることが重要です。', '研修82: 関係性重視型顧客への対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (352, 7, 50, '顧客タイプ別対応の最終的な目標は？', '["タイプを完璧に分類すること", "顧客一人ひとりに合った対応で満足度と成約率を高めること", "営業効率を上げること", "マニュアル通りに対応すること"]'::jsonb, 1, 'タイプ分析は手段であり、目的は顧客に合った対応で満足度を高め、長期的な関係を築くことです。', '研修82: 顧客タイプ別対応', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (353, 8, 1, '「戦略的アカウント管理」の目的として最も適切なのは？', '["すべての顧客に同じ対応をする", "重要顧客との長期的な関係構築と取引拡大", "新規顧客獲得に集中する", "コスト削減"]'::jsonb, 1, '戦略的アカウント管理は重要顧客を特定し、長期的なパートナーシップを通じて相互の成長を目指すものです。', '研修83: 戦略的アカウント管理', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (354, 8, 2, '「キーアカウント」を選定する基準として適切なのは？', '["社長と知り合いかどうか", "売上規模、成長性、戦略的重要性", "社員数だけ", "業界だけ"]'::jsonb, 1, 'キーアカウントは現在の売上、将来の成長性、戦略的な重要性など複合的な基準で選定します。', '研修83: 戦略的アカウント管理', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (355, 8, 3, 'アカウントプランに含めるべき要素は？', '["価格表のみ", "顧客の目標、課題、自社の提供価値、アクションプラン", "営業の目標だけ", "競合情報だけ"]'::jsonb, 1, 'アカウントプランには顧客理解、目標設定、提供価値、具体的なアクションプランを含めます。', '研修83: 戦略的アカウント管理', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (356, 8, 4, 'アカウント管理における「シェア・オブ・ウォレット」とは？', '["財布の大きさ", "顧客の総支出における自社シェア", "市場シェア", "利益率"]'::jsonb, 1, 'シェア・オブ・ウォレットは顧客の当該分野の総支出における自社の占有率を指します。', '研修83: 戦略的アカウント管理', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (357, 8, 5, '戦略的アカウントとの「定期レビュー」の目的は？', '["形式的な報告", "関係性の確認と新たなビジネス機会の発見", "クレーム対応", "値上げ交渉"]'::jsonb, 1, '定期レビューで成果を確認し、顧客の新たな課題やビジネス機会を発見することが目的です。', '研修83: 戦略的アカウント管理', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (358, 8, 6, '「ソリューション営業」と「プロダクト営業」の違いは？', '["同じもの", "ソリューションは顧客の課題解決、プロダクトは製品機能を売る", "価格の違い", "業界の違い"]'::jsonb, 1, 'ソリューション営業は顧客の課題を理解し、その解決策を提案する営業スタイルです。', '研修84: ソリューション営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (359, 8, 7, 'ソリューション営業で最も重要なスキルは？', '["製品知識だけ", "顧客の課題を深く理解するヒアリング力", "価格交渉力", "プレゼン力だけ"]'::jsonb, 1, 'ソリューション営業では顧客の課題を深く理解するヒアリング力が最も重要です。', '研修84: ソリューション営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (360, 8, 8, 'ソリューション提案の構成として正しい順序は？', '["製品説明→課題→効果", "課題の明確化→解決策→導入効果", "価格→製品→サポート", "効果→課題→製品"]'::jsonb, 1, 'まず課題を明確化し、その解決策として提案し、導入効果を示す流れが効果的です。', '研修84: ソリューション営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (361, 8, 9, 'ソリューション営業における「ペインポイント」とは？', '["価格", "顧客が抱える課題や痛み", "競合", "納期"]'::jsonb, 1, 'ペインポイントは顧客が抱える課題、不満、痛みを指し、これを解決することが提案の核です。', '研修84: ソリューション営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (362, 8, 10, 'ソリューション営業で「ROI」を示す重要性は？', '["形式的なもの", "投資対効果を示すことで意思決定を後押しする", "競合と差別化するため", "法律で義務付けられている"]'::jsonb, 1, 'ROI（投資対効果）を具体的に示すことで、投資判断を論理的に後押しできます。', '研修84: ソリューション営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (363, 8, 11, '「コンサルティング営業」の特徴は？', '["製品を売り込む", "顧客のビジネス課題を診断し、最適な解決策を提案する", "価格を下げる", "短期的な成果を重視"]'::jsonb, 1, 'コンサルティング営業は顧客のビジネス全体を理解し、専門家として最適な解決策を提案します。', '研修85: コンサルティング営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (364, 8, 12, 'コンサルティング営業で必要な「診断力」とは？', '["病気を診断する能力", "顧客のビジネス状況を分析し課題を特定する能力", "製品の故障を診断する能力", "競合を分析する能力"]'::jsonb, 1, '診断力は顧客のビジネス状況を多角的に分析し、本質的な課題を特定する能力です。', '研修85: コンサルティング営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (365, 8, 13, 'コンサルティング営業における「仮説検証」アプローチとは？', '["勘で提案する", "事前に仮説を立て、ヒアリングで検証・修正する", "顧客に仮説を立てさせる", "仮説は不要"]'::jsonb, 1, '事前に顧客の課題や解決策の仮説を立て、商談で検証・修正しながら提案を磨きます。', '研修85: コンサルティング営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (366, 8, 14, 'コンサルティング営業で「業界知識」が重要な理由は？', '["話のネタになる", "顧客以上に業界を理解することで信頼と価値を提供できる", "自慢できる", "資格取得に必要"]'::jsonb, 1, '業界動向や課題を深く理解することで、顧客にとって価値ある提案ができます。', '研修85: コンサルティング営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (367, 8, 15, 'コンサルティング営業の「信頼されるアドバイザー」になるには？', '["とにかく売る", "顧客の利益を第一に考え、時には自社製品以外も提案する姿勢", "価格を下げる", "頻繁に訪問する"]'::jsonb, 1, '顧客の利益を第一に考え、誠実なアドバイスを続けることで信頼されるアドバイザーになれます。', '研修85: コンサルティング営業', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (368, 8, 16, '大型案件の特徴として正しいのは？', '["意思決定者が一人", "複数の関係者と長期間の検討プロセスがある", "即決される", "価格だけで決まる"]'::jsonb, 1, '大型案件は複数の関係者が関与し、検討プロセスが長期化する傾向があります。', '研修86: 大型案件の攻略', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (369, 8, 17, '大型案件で「DMU（意思決定単位）」を把握する理由は？', '["形式的に必要", "関係者全員に適切なアプローチをするため", "競合に情報を渡すため", "上司への報告のため"]'::jsonb, 1, 'DMUを把握し、各関係者の役割・関心事に合わせたアプローチが大型案件成功の鍵です。', '研修86: 大型案件の攻略', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (370, 8, 18, '大型案件における「チャンピオン」とは？', '["競合に勝った営業", "社内で自社を推進してくれる顧客側のキーパーソン", "最も偉い人", "価格交渉の専門家"]'::jsonb, 1, 'チャンピオンは顧客社内で自社を支持し、推進してくれるキーパーソンです。', '研修86: 大型案件の攻略', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (371, 8, 19, '大型案件の「競合対策」で重要なのは？', '["競合の悪口を言う", "競合との差別化ポイントを明確にし、顧客価値で勝負する", "価格を下げる", "競合を無視する"]'::jsonb, 1, '競合批判ではなく、自社の差別化ポイントと顧客にとっての価値を明確に示します。', '研修86: 大型案件の攻略', '2026-02-17T06:00:23.79419+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (372, 8, 20, '大型案件の「受注確度管理」で重要な指標は？', '["営業の直感", "予算確保状況、意思決定者の支持、競合状況、タイムライン", "訪問回数", "提案書の枚数"]'::jsonb, 1, 'BANT情報、意思決定者の反応、競合状況などを総合的に評価して受注確度を判断します。', '研修86: 大型案件の攻略', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (373, 8, 21, '経営層（Cレベル）へのアプローチで重要なのは？', '["製品の詳細機能を説明する", "経営課題やビジネスインパクトの観点で話す", "価格の安さを強調する", "技術的な詳細を話す"]'::jsonb, 1, '経営層は機能より経営課題の解決、ROI、戦略的価値に関心があります。', '研修87: 経営層へのアプローチ', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (374, 8, 22, '経営層との面談で「準備」として重要なのは？', '["製品カタログを読む", "相手企業の経営戦略、業界動向、経営者の関心事を調査する", "値引き幅を確認する", "雑談ネタを考える"]'::jsonb, 1, '経営層との面談前に、企業の経営方針、業界課題、経営者の発言などを徹底的に調査します。', '研修87: 経営層へのアプローチ', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (375, 8, 23, '経営層が重視する「時間軸」は？', '["今日明日", "中長期的な視点（3〜5年）", "過去の実績だけ", "時間は気にしない"]'::jsonb, 1, '経営層は短期だけでなく、中長期的な視点で投資や取り組みを評価します。', '研修87: 経営層へのアプローチ', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (376, 8, 24, '経営層への提案で「数字」を使う際のポイントは？', '["細かい数字を並べる", "経営インパクト（売上貢献、コスト削減、リスク軽減）で示す", "数字は使わない", "業界平均との比較だけ"]'::jsonb, 1, '経営層には経営指標への影響（売上、利益、コスト）を明確な数字で示すことが効果的です。', '研修87: 経営層へのアプローチ', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (377, 8, 25, '経営層との面談で避けるべきことは？', '["結論から話す", "長々と機能説明をする", "質問する", "事例を話す"]'::jsonb, 1, '経営層は多忙です。機能の詳細説明より、結論と経営価値を簡潔に伝えることが重要です。', '研修87: 経営層へのアプローチ', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (378, 8, 26, '「チーム営業」のメリットは？', '["責任が曖昧になる", "専門性の組み合わせで顧客に多角的な価値を提供できる", "コストが下がる", "一人で楽になる"]'::jsonb, 1, '営業、技術、サポートなど異なる専門性を組み合わせ、顧客に包括的な価値を提供できます。', '研修88: チーム営業の進め方', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (379, 8, 27, 'チーム営業で「役割分担」を明確にする理由は？', '["形式的に必要", "責任と期待を明確にし、連携をスムーズにするため", "人数を減らすため", "評価のため"]'::jsonb, 1, '役割分担を明確にすることで、各メンバーの責任が明確になり、チームの連携が向上します。', '研修88: チーム営業の進め方', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (380, 8, 28, 'チーム営業での「商談前ミーティング」で確認すべきことは？', '["雑談", "目的、各自の役割、想定質問への対応、ゴール", "服装", "昼食の場所"]'::jsonb, 1, '商談前に目的、役割分担、想定される質問への回答、達成したいゴールを確認します。', '研修88: チーム営業の進め方', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (381, 8, 29, 'チーム営業で「SE（セールスエンジニア）」の役割は？', '["価格交渉", "技術的な質問への対応や提案のサポート", "契約書作成", "クレーム対応"]'::jsonb, 1, 'SEは技術的な質問への対応、デモ、技術提案など専門的な側面をサポートします。', '研修88: チーム営業の進め方', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (382, 8, 30, 'チーム営業での「振り返り」の重要性は？', '["不要", "成功・改善点を共有し、チームの成長につなげる", "犯人探し", "上司への報告のため"]'::jsonb, 1, '商談後の振り返りで成功点と改善点を共有し、チーム全体のスキル向上につなげます。', '研修88: チーム営業の進め方', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (383, 8, 31, '「営業戦略」と「営業戦術」の違いは？', '["同じもの", "戦略は方向性と優先順位、戦術は具体的な実行方法", "戦略は短期、戦術は長期", "戦略は現場、戦術は経営"]'::jsonb, 1, '戦略は「何を狙うか」という方向性、戦術は「どう実行するか」という具体的方法です。', '研修89: 営業戦略の立案', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (384, 8, 32, '営業戦略立案で「市場分析」を行う目的は？', '["レポート作成のため", "機会と脅威を把握し、注力すべき領域を特定するため", "競合を攻撃するため", "上司への説明のため"]'::jsonb, 1, '市場分析により成長機会、競合状況、顧客ニーズを把握し、戦略の方向性を決定します。', '研修89: 営業戦略の立案', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (385, 8, 33, '「SWOT分析」の4つの要素は？', '["Sales, Work, Opportunity, Team", "強み、弱み、機会、脅威", "戦略、戦術、運用、技術", "製品、価格、場所、販促"]'::jsonb, 1, 'SWOTは強み(S)、弱み(W)、機会(O)、脅威(T)の4つの観点で分析するフレームワークです。', '研修89: 営業戦略の立案', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (386, 8, 34, '営業戦略における「ターゲットセグメント」を絞る理由は？', '["手抜きのため", "限られたリソースを効果的に集中させるため", "競合を避けるため", "報告を楽にするため"]'::jsonb, 1, 'リソースは有限なので、最も成果が期待できるセグメントに集中することで効率が上がります。', '研修89: 営業戦略の立案', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (387, 8, 35, '営業戦略の「KGI」と「KPI」の関係は？', '["同じもの", "KGIは最終目標、KPIはその達成度を測る中間指標", "KPIが上位目標", "関係ない"]'::jsonb, 1, 'KGI（最終目標）を達成するための進捗を測る指標がKPI（重要業績評価指標）です。', '研修89: 営業戦略の立案', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (388, 8, 36, '営業データ分析の目的は？', '["報告書を作るため", "データに基づいた意思決定と営業活動の改善", "ITスキルを見せるため", "数字遊び"]'::jsonb, 1, 'データ分析により、勘や経験だけでなく客観的な根拠に基づいた営業改善が可能になります。', '研修90: 営業データ分析', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (389, 8, 37, '「ファネル分析」で把握できることは？', '["競合情報", "営業プロセスの各段階での転換率と課題", "製品の品質", "市場規模"]'::jsonb, 1, 'ファネル分析で各段階の転換率を把握し、ボトルネックを特定して改善につなげます。', '研修90: 営業データ分析', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (390, 8, 38, '「リードタイム分析」で分かることは？', '["リードの数", "商談開始から成約までにかかる時間とその要因", "製品の納期", "顧客の年齢"]'::jsonb, 1, 'リードタイム分析で商談期間を把握し、長期化の要因を特定して短縮策を検討できます。', '研修90: 営業データ分析', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (391, 8, 39, '営業データで「相関分析」を行う意義は？', '["グラフがきれいになる", "活動と成果の関係性を発見し、効果的な行動を特定する", "報告が楽になる", "競合に勝てる"]'::jsonb, 1, '訪問回数と成約率など、活動と成果の相関を分析し、効果的な行動パターンを発見します。', '研修90: 営業データ分析', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (392, 8, 40, 'データ分析の結果を活用する際の注意点は？', '["データを絶対視する", "データは参考とし、現場の知見と組み合わせて判断する", "データより勘を優先", "分析結果を隠す"]'::jsonb, 1, 'データは重要な参考情報ですが、現場の知見や状況と組み合わせて総合的に判断します。', '研修90: 営業データ分析', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (393, 8, 41, '部下育成で「OJT」が効果的な理由は？', '["コストがかからない", "実務を通じて実践的なスキルが身につく", "座学より楽", "評価しやすい"]'::jsonb, 1, 'OJT（On the Job Training）は実際の業務を通じて学ぶため、実践的なスキルが習得できます。', '研修91: 部下・後輩の育成', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (394, 8, 42, '部下へのフィードバックで重要なのは？', '["欠点だけを指摘する", "具体的な行動に対して、良い点と改善点をバランスよく伝える", "抽象的に伝える", "他の部下と比較する"]'::jsonb, 1, '具体的な行動に対して、良い点を認めつつ改善点も伝えることで成長につながります。', '研修91: 部下・後輩の育成', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (395, 8, 43, '部下の「同行営業」で指導者が意識すべきことは？', '["すべて自分でやる", "適度に任せながら、後で振り返りを行う", "黙って見ているだけ", "代わりに商談する"]'::jsonb, 1, '同行では部下に実践させ、商談後に良い点と改善点を一緒に振り返ることが育成につながります。', '研修91: 部下・後輩の育成', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (396, 8, 44, '部下の「モチベーション管理」で重要なのは？', '["常に監視する", "目標の意味を共有し、成長を実感させる機会を作る", "競争させる", "報酬だけを与える"]'::jsonb, 1, '目標の意義を理解させ、小さな成功体験や成長の実感がモチベーション維持につながります。', '研修91: 部下・後輩の育成', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (397, 8, 45, '部下が失敗した時の対応として適切なのは？', '["厳しく叱責する", "原因を一緒に分析し、次に活かせる学びを引き出す", "無視する", "他の人に任せる"]'::jsonb, 1, '失敗を責めるのではなく、原因分析と次への学びに変えるサポートが育成につながります。', '研修91: 部下・後輩の育成', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (398, 8, 46, '営業パーソンの「自己成長」に必要な姿勢は？', '["現状維持", "常に学び続け、自分の成長に投資する姿勢", "会社任せ", "資格を取るだけ"]'::jsonb, 1, '市場環境は変化し続けるため、常に学び、自己研鑽を続ける姿勢が成長につながります。', '研修92: 自己成長とキャリア開発', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (399, 8, 47, '営業キャリアの「横展開」と「縦展開」の違いは？', '["同じもの", "横は領域拡大、縦は専門性深化やマネジメントへの昇進", "横が昇進、縦が異動", "違いはない"]'::jsonb, 1, '横展開は扱う領域や業界の拡大、縦展開は専門性の深化やマネジメント職への昇進を指します。', '研修92: 自己成長とキャリア開発', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (400, 8, 48, '営業スキル向上のための「振り返り」の効果は？', '["時間の無駄", "成功・失敗パターンを認識し、再現性のある成長につながる", "上司へのアピール", "特にない"]'::jsonb, 1, '定期的な振り返りで自分の行動パターンを認識し、改善点を見つけることで成長が加速します。', '研修92: 自己成長とキャリア開発', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (401, 8, 49, '「メンター」を持つメリットは？', '["責任を転嫁できる", "経験者の知見を借りて、成長を加速させられる", "仕事が減る", "評価が上がる"]'::jsonb, 1, '経験豊富なメンターから学ぶことで、自分だけでは気づけない視点や成長のヒントを得られます。', '研修92: 自己成長とキャリア開発', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (402, 8, 50, '上級営業パーソンに求められる最終的な姿勢は？', '["売上だけを追求する", "顧客の成功に貢献し、自らも成長し続ける姿勢", "楽をする方法を見つける", "競合を排除する"]'::jsonb, 1, '上級営業パーソンは顧客の成功をサポートしながら、自らも学び成長し続ける姿勢が求められます。', '研修92: 自己成長とキャリア開発', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (403, 9, 1, '営業マネージャーの最も重要な役割は？', '["自分で売上を上げる", "チーム全体の成果を最大化する", "報告書を作成する", "会議に出席する"]'::jsonb, 1, 'マネージャーはプレイヤーではなく、チーム全体の成果を最大化することが最重要の役割です。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (404, 9, 40, '「オンボーディング」の目的は？', '["研修を終わらせる", "新人が早期に活躍できるよう支援する", "評価するため", "ルールを教えるだけ"]'::jsonb, 1, 'オンボーディングは新人が組織に馴染み、早期に力を発揮できるよう支援するプロセスです。', '研修99: 人材採用と配置', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (405, 9, 2, '営業マネージャーに求められる「視座」とは？', '["目の前の案件だけ見る", "チーム全体と中長期的な視点で考える", "競合だけを見る", "上司の顔色を見る"]'::jsonb, 1, 'マネージャーは個別案件だけでなく、チーム全体の状況と中長期的な目標を見据えて判断します。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (406, 9, 3, '「プレイングマネージャー」の課題として正しいのは？', '["売上が上がりすぎる", "自分の案件に時間を取られ、マネジメントが疎かになりやすい", "部下が頼りすぎる", "評価が高くなりすぎる"]'::jsonb, 1, 'プレイングマネージャーは自身の営業活動とマネジメントのバランスが課題になります。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (407, 9, 4, 'マネージャーの「権限委譲」のメリットは？', '["責任を逃れられる", "部下の成長と自分の時間確保につながる", "仕事が減る", "評価が上がる"]'::jsonb, 1, '適切な権限委譲は部下の成長機会を作り、マネージャーはより重要な業務に集中できます。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (408, 9, 5, '営業マネージャーが「経営視点」を持つ意義は？', '["出世するため", "会社の方向性を理解し、チームの活動を経営戦略に沿わせるため", "経営者に気に入られるため", "報告が楽になるため"]'::jsonb, 1, '経営視点を持つことで、チームの活動を会社の戦略に沿った形で方向付けられます。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (409, 9, 6, 'マネージャーの「意思決定」で重要なことは？', '["常に上司に確認する", "根拠を持って判断し、結果に責任を持つ", "部下に任せる", "先延ばしにする"]'::jsonb, 1, 'マネージャーはデータや状況を踏まえて判断し、その結果に責任を持つことが求められます。', '研修93: 営業マネージャーの役割', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (410, 9, 7, 'チーム目標設定で「SMART」の原則の「M」は何を意味する？', '["Motivating（動機づけ）", "Measurable（測定可能）", "Maximum（最大）", "Mandatory（必須）"]'::jsonb, 1, 'SMARTのMはMeasurable（測定可能）で、達成度を客観的に測定できることを意味します。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (411, 9, 8, 'チーム目標を「個人目標」に分解する際のポイントは？', '["均等に割り振る", "各メンバーの強みと成長機会を考慮して設定する", "エースに集中させる", "新人には目標を与えない"]'::jsonb, 1, 'メンバーの経験、スキル、成長段階を考慮し、挑戦的かつ達成可能な目標を設定します。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (412, 9, 9, '目標の「進捗管理」で重要なことは？', '["月末にだけ確認する", "定期的にモニタリングし、早期に課題を発見・対処する", "部下に任せる", "結果だけ見る"]'::jsonb, 1, '定期的な進捗確認により、問題を早期に発見し、軌道修正のアクションを取れます。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (413, 9, 10, '目標達成が困難な状況での対応として適切なのは？', '["目標を下げる", "原因を分析し、打ち手を考えてチームで実行する", "諦める", "誰かのせいにする"]'::jsonb, 1, '未達の原因を分析し、リカバリーの施策をチームで考え実行することが重要です。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (414, 9, 11, '「ストレッチ目標」を設定する目的は？', '["達成できないようにする", "成長と挑戦を促し、高い成果を引き出す", "評価を下げる", "プレッシャーをかける"]'::jsonb, 1, '適度に挑戦的な目標は、メンバーの成長意欲を刺激し、より高い成果につながります。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (415, 9, 12, '目標達成後の「振り返り」で確認すべきことは？', '["誰が一番貢献したか", "成功要因、改善点、次への学びを整理する", "打ち上げの場所", "次の目標だけ"]'::jsonb, 1, '達成・未達に関わらず、要因を分析し学びを次に活かすことがチームの成長につながります。', '研修94: チーム目標設定と管理', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (416, 9, 13, '1on1ミーティングの主な目的は？', '["業績報告を受ける", "部下の成長支援と信頼関係構築", "指示を出す", "評価を伝える"]'::jsonb, 1, '1on1は部下の成長を支援し、信頼関係を築くための対話の場です。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (417, 9, 14, '1on1ミーティングの「主役」は誰？', '["マネージャー", "部下", "両方均等", "会社"]'::jsonb, 1, '1on1は部下が主役であり、部下の話を聴き、成長を支援することが目的です。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (418, 9, 15, '1on1で「話を聴く」際のポイントは？', '["すぐにアドバイスする", "まず傾聴し、部下自身の考えを引き出す", "自分の経験を語る", "結論を急ぐ"]'::jsonb, 1, 'まず傾聴して部下の考えや気持ちを理解し、自ら解決策を見つけるサポートをします。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (419, 9, 16, '1on1で扱うテーマとして適切なのは？', '["業績数字の詳細だけ", "業務、キャリア、悩み、成長など幅広いテーマ", "プライベートの詳細", "他の部下の評価"]'::jsonb, 1, '1on1では業務の進捗だけでなく、キャリア、悩み、成長課題など幅広く対話します。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (420, 9, 17, '1on1の「頻度」として推奨されるのは？', '["年1回", "週1回〜隔週程度の定期開催", "問題が起きた時だけ", "部下が希望した時だけ"]'::jsonb, 1, '週1回〜隔週程度の定期開催により、継続的な関係構築と早期の課題発見が可能です。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (421, 9, 18, '1on1で部下が「特に話すことはない」と言った場合の対応は？', '["すぐに終わる", "こちらから質問を投げかけ、対話のきっかけを作る", "叱る", "次回に延期する"]'::jsonb, 1, '「最近どう？」「困っていることは？」など、話しやすい質問で対話を促します。', '研修95: 1on1ミーティング', '2026-02-17T06:00:23.94279+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (422, 9, 19, '効果的なフィードバックの条件は？', '["人格を評価する", "具体的な行動に対してタイムリーに伝える", "曖昧に伝える", "まとめて年1回伝える"]'::jsonb, 1, 'フィードバックは具体的な行動に対して、できるだけ早く伝えることで効果が高まります。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (423, 9, 20, '「ポジティブフィードバック」の効果は？', '["甘やかす", "良い行動を強化し、モチベーションを高める", "評価を上げる", "関係を良くするだけ"]'::jsonb, 1, '良い行動を具体的に認めることで、その行動が強化され、モチベーション向上につながります。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (424, 9, 21, '「改善フィードバック」を伝える際のポイントは？', '["人前で伝える", "行動と改善点を具体的に、建設的な姿勢で伝える", "感情的に伝える", "人格を否定する"]'::jsonb, 1, '改善点は個別に、具体的な行動に焦点を当て、成長への期待を込めて伝えます。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (425, 9, 22, '「SBI」フィードバックモデルの「S」は何を意味する？', '["Solution（解決策）", "Situation（状況）", "Success（成功）", "Style（スタイル）"]'::jsonb, 1, 'SBIはSituation（状況）、Behavior（行動）、Impact（影響）の順でフィードバックするモデルです。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (426, 9, 23, 'フィードバックを受ける側の姿勢として重要なのは？', '["言い訳をする", "防御せず、学びとして受け止める", "反論する", "無視する"]'::jsonb, 1, 'フィードバックは成長の機会であり、防御せずオープンに受け止めることが重要です。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (427, 9, 24, 'フィードバックが「批判」になってしまう原因は？', '["頻度が多い", "人格否定や曖昧な表現、感情的な伝え方", "具体的すぎる", "タイミングが早い"]'::jsonb, 1, '人格を否定したり、感情的に伝えると、フィードバックではなく批判になってしまいます。', '研修96: フィードバックの技術', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (428, 9, 25, '「内発的動機づけ」と「外発的動機づけ」の違いは？', '["同じもの", "内発的は内面からの意欲、外発的は報酬や評価など外部要因", "内発的が報酬、外発的が興味", "違いはない"]'::jsonb, 1, '内発的動機づけは興味や成長意欲など内面から、外発的動機づけは報酬や評価など外部から生じます。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (429, 9, 26, '部下のモチベーション低下のサインとして注意すべきは？', '["売上が上がる", "発言が減る、遅刻が増える、消極的になる", "質問が増える", "残業が減る"]'::jsonb, 1, '行動や態度の変化（消極的、コミュニケーション減少など）はモチベーション低下のサインです。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (430, 9, 27, '「マズローの欲求段階説」で最上位の欲求は？', '["安全欲求", "所属欲求", "承認欲求", "自己実現欲求"]'::jsonb, 3, 'マズローの欲求段階説では、自己実現欲求が最上位に位置します。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (431, 9, 28, '「承認」がモチベーションに与える効果は？', '["効果なし", "自分の存在価値を感じ、意欲が向上する", "給料が上がる", "仕事が減る"]'::jsonb, 1, '適切な承認は自己効力感を高め、さらなる貢献への意欲を引き出します。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (432, 9, 29, 'チーム全体のモチベーションを高める施策として効果的なのは？', '["競争を激化させる", "目標の意義を共有し、成功体験を積み重ねる", "報酬を上げるだけ", "監視を強化する"]'::jsonb, 1, '目標の意義を理解し、チームで成功体験を共有することで、内発的動機づけが高まります。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (433, 9, 30, '部下の「強み」を活かすマネジメントの効果は？', '["弱みが放置される", "得意分野で成果を出しやすく、モチベーションが高まる", "偏りが出る", "評価が難しくなる"]'::jsonb, 1, '強みを活かせる仕事では成果が出やすく、自信とモチベーションの向上につながります。', '研修97: モチベーション管理', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (434, 9, 31, '営業会議の目的として適切なのは？', '["報告を聞くだけ", "情報共有、課題解決、アクション決定", "叱責の場", "時間を潰す"]'::jsonb, 1, '営業会議は情報共有、課題の議論、次のアクション決定のために行います。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (435, 9, 32, '会議の「アジェンダ」を事前共有する効果は？', '["形式的なもの", "参加者が準備でき、議論が効率化する", "責任が明確になる", "欠席者が減る"]'::jsonb, 1, 'アジェンダの事前共有により、参加者が準備して臨め、会議の生産性が向上します。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (436, 9, 33, '会議で「発言が偏る」問題への対処法は？', '["放置する", "ファシリテーターが発言を促し、全員が参加できる工夫をする", "発言者だけに任せる", "会議を短くする"]'::jsonb, 1, '指名して意見を求めたり、少人数での議論を挟むなど、全員参加を促す工夫が必要です。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (437, 9, 34, '会議の「時間管理」で重要なことは？', '["時間を気にしない", "開始・終了時間を守り、議題ごとの時間配分を意識する", "早く終わればよい", "延長しても良い"]'::jsonb, 1, '時間を守ることで参加者の予定を尊重し、議論の集中度も高まります。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (438, 9, 35, '会議の「決定事項」を明確にする重要性は？', '["議事録のため", "誰が何をいつまでにやるかを明確にし、実行につなげる", "上司への報告のため", "形式的に必要"]'::jsonb, 1, '決定事項と担当者、期限を明確にすることで、会議の結果が確実に実行されます。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (439, 9, 36, '「会議が多すぎる」問題への対処として適切なのは？', '["全部出席する", "目的と必要性を見直し、統合・削減を検討する", "会議を無視する", "代理を出す"]'::jsonb, 1, '各会議の目的と効果を見直し、統合できるもの、不要なものを整理することが重要です。', '研修98: 営業会議の運営', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (440, 9, 37, '営業人材の採用で「求める人物像」を明確にする理由は？', '["形式的に必要", "採用基準を統一し、ミスマッチを防ぐため", "応募者を減らすため", "面接が楽になるため"]'::jsonb, 1, '求める人物像を明確にすることで、採用基準が統一され、入社後のミスマッチを防げます。', '研修99: 人材採用と配置', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (441, 9, 38, '採用面接で「行動面接」が効果的な理由は？', '["時間が短い", "過去の具体的な行動から将来の行動を予測できる", "質問が簡単", "候補者が楽"]'::jsonb, 1, '過去の具体的な行動事例を聞くことで、実際の仕事での行動パターンを予測できます。', '研修99: 人材採用と配置', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (442, 9, 39, '新人の「配置」を決める際に考慮すべきことは？', '["空いているところに入れる", "本人の適性、成長機会、チームバランス", "上司の好み", "年齢順"]'::jsonb, 1, '本人の強み、成長させたい領域、チーム全体のバランスを考慮して配置を決めます。', '研修99: 人材採用と配置', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (443, 9, 41, 'チームの「適材適所」を実現するために必要なことは？', '["全員同じ仕事をさせる", "各メンバーの強み・弱み・志向を把握する", "本人の希望は無視する", "ローテーションしない"]'::jsonb, 1, 'メンバー一人ひとりの特性を理解し、強みを活かせる役割に配置することが重要です。', '研修99: 人材採用と配置', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (444, 9, 42, '「採用ミスマッチ」を防ぐために効果的なのは？', '["良いことだけ伝える", "仕事の現実を正直に伝え、相互理解を深める", "すぐに採用を決める", "条件だけで決める"]'::jsonb, 1, '仕事の魅力だけでなく大変な面も伝え、候補者との相互理解を深めることがミスマッチ防止になります。', '研修99: 人材採用と配置', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (445, 9, 43, '「組織文化」がチーム成果に影響する理由は？', '["関係ない", "メンバーの行動規範となり、意思決定や協力に影響する", "見えないから", "経営者が決めるから"]'::jsonb, 1, '組織文化は「当たり前」の行動基準となり、日々の判断や協力の仕方に大きく影響します。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (446, 9, 44, '「心理的安全性」の高いチームの特徴は？', '["競争が激しい", "失敗を恐れず意見を言え、挑戦できる", "ルールが厳しい", "成果プレッシャーがない"]'::jsonb, 1, '心理的安全性が高いと、失敗を恐れず発言や挑戦ができ、イノベーションが生まれやすくなります。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (447, 9, 45, 'チームの「信頼関係」を構築する方法は？', '["放置する", "オープンなコミュニケーションと約束を守る行動の積み重ね", "飲み会だけ", "競争させる"]'::jsonb, 1, '日々のオープンなコミュニケーションと、約束を守る行動の積み重ねが信頼を築きます。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (448, 9, 46, '「多様性」のあるチームのメリットは？', '["まとまりにくい", "多角的な視点で創造性と問題解決力が高まる", "意見が対立する", "管理が難しい"]'::jsonb, 1, '多様なバックグラウンドや視点を持つメンバーがいることで、創造性や問題解決の幅が広がります。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (449, 9, 47, 'チームの「共通目標」を持つ意義は？', '["形式的に必要", "方向性を揃え、一体感と協力を促進する", "評価のため", "報告しやすい"]'::jsonb, 1, '共通目標があることで、メンバーの方向性が揃い、協力して達成しようという一体感が生まれます。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (450, 9, 48, 'チームビルディングで「成功体験の共有」が重要な理由は？', '["自慢するため", "チームの自信と一体感を高め、次の挑戦への意欲を生む", "記録のため", "報告のため"]'::jsonb, 1, '成功体験を共有することで、チームの自信と絆が深まり、次の挑戦への意欲が高まります。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (451, 9, 49, 'マネージャーが「チーム文化」に与える影響として正しいのは？', '["影響しない", "マネージャーの言動がチーム文化の手本となる", "人事部が決める", "メンバーだけで決まる"]'::jsonb, 1, 'マネージャーの言動、意思決定、価値観がチームの文化形成に大きな影響を与えます。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (452, 9, 50, 'マネジメント・育成の最終的な目標は？', '["自分の評価を上げる", "メンバーと組織の成長を通じて、持続的な成果を生み出す", "売上だけを上げる", "楽をする"]'::jsonb, 1, 'マネジメントの本質は、メンバーの成長と組織の発展を通じて、持続的な成果を創出することです。', '研修100: 組織文化とチームビルディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (453, 10, 1, 'マーケティングの定義として最も適切なのは？', '["広告を出すこと", "顧客のニーズを満たし、価値を提供して利益を得る活動全体", "安く売ること", "営業活動のこと"]'::jsonb, 1, 'マーケティングは顧客ニーズの理解から価値提供、関係構築まで含む包括的な活動です。', '研修101: マーケティングの基本概念', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (454, 10, 2, '「マーケティング・ミックス」の4Pに含まれないのは？', '["Product（製品）", "Price（価格）", "People（人材）", "Place（流通）"]'::jsonb, 2, '4PはProduct、Price、Place、Promotionです。Peopleは7Pの拡張版で追加される要素です。', '研修101: マーケティングの基本概念', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (455, 10, 3, '「顧客志向」のマーケティングとは？', '["顧客の言いなりになること", "顧客のニーズを起点に製品・サービスを設計すること", "顧客を選ばないこと", "価格を下げること"]'::jsonb, 1, '顧客志向は顧客のニーズや課題を深く理解し、それを解決する価値を提供する考え方です。', '研修101: マーケティングの基本概念', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (456, 10, 4, '「プロダクトアウト」と「マーケットイン」の違いは？', '["同じ意味", "プロダクトアウトは製品起点、マーケットインは市場・顧客起点", "プロダクトアウトが新しい考え方", "違いはない"]'::jsonb, 1, 'プロダクトアウトは作れるものを売る発想、マーケットインは顧客が求めるものを作る発想です。', '研修101: マーケティングの基本概念', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (457, 10, 5, 'マーケティングと営業の関係として正しいのは？', '["同じもの", "マーケティングが需要を創出し、営業が顧客との関係を構築・成約する", "営業だけで十分", "マーケティングが上位"]'::jsonb, 1, 'マーケティングは市場創造と見込み客育成、営業は個別顧客との関係構築と成約を担います。', '研修101: マーケティングの基本概念', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (458, 10, 6, '「一次データ」と「二次データ」の違いは？', '["同じもの", "一次は自社で収集、二次は既存の公開データ", "一次が古いデータ", "二次の方が正確"]'::jsonb, 1, '一次データは調査目的に合わせて自社で収集、二次データは既に存在する公開データです。', '研修102: 市場調査と分析', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (459, 10, 7, '「定量調査」と「定性調査」の違いは？', '["同じもの", "定量は数値で測定、定性は深い洞察を得る", "定量の方が常に優れている", "定性は不正確"]'::jsonb, 1, '定量調査は数値データで傾向を把握、定性調査はインタビュー等で深い理解を得ます。', '研修102: 市場調査と分析', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (460, 10, 8, '「PEST分析」で分析する外部環境は？', '["競合のみ", "政治、経済、社会、技術", "自社の強み弱み", "顧客のみ"]'::jsonb, 1, 'PESTはPolitical、Economic、Social、Technologicalの4つのマクロ環境要因を分析します。', '研修102: 市場調査と分析', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (461, 10, 10, '市場調査で「バイアス」を避けることが重要な理由は？', '["時間がかかるから", "偏った結果から誤った意思決定をしてしまうから", "コストがかかるから", "上司に怒られるから"]'::jsonb, 1, '調査にバイアスがあると正確な市場理解ができず、誤った戦略判断につながります。', '研修102: 市場調査と分析', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (462, 10, 11, '「STP」とは何の略？', '["Sales, Target, Profit", "Segmentation, Targeting, Positioning", "Strategy, Tactics, Plan", "Survey, Test, Promote"]'::jsonb, 1, 'STPはSegmentation（市場細分化）、Targeting（標的市場選定）、Positioning（位置づけ）です。', '研修103: STPマーケティング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (463, 10, 12, '「セグメンテーション」の目的は？', '["顧客を差別する", "市場を同質なグループに分け、効果的なアプローチを可能にする", "顧客を減らす", "競合を分析する"]'::jsonb, 1, 'セグメンテーションにより、似たニーズを持つ顧客グループに効果的にアプローチできます。', '研修103: STPマーケティング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (464, 10, 13, 'セグメンテーションの基準として適切でないのは？', '["地理的変数", "人口統計変数", "心理的変数", "競合の戦略"]'::jsonb, 3, 'セグメントは地理、人口統計、心理、行動などの顧客特性で分けます。競合戦略は基準ではありません。', '研修103: STPマーケティング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (465, 10, 14, '「ターゲティング」で重視すべき基準は？', '["セグメントの大きさだけ", "市場規模、成長性、競争状況、自社適合性", "自社の都合だけ", "競合がいないこと"]'::jsonb, 1, 'ターゲット選定は市場の魅力度と自社の強みを活かせるかを総合的に判断します。', '研修103: STPマーケティング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (466, 10, 15, '「ポジショニング」とは？', '["店舗の位置を決めること", "顧客の心の中での自社の位置づけを確立すること", "価格を決めること", "組織の配置を決めること"]'::jsonb, 1, 'ポジショニングは競合との差別化を図り、顧客の心の中で独自の位置を確立することです。', '研修103: STPマーケティング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (467, 10, 16, '「ブランド」とは何か？', '["ロゴのこと", "顧客が抱く製品・企業への認識や感情の総体", "商品名のこと", "広告のこと"]'::jsonb, 1, 'ブランドはロゴや名前だけでなく、顧客が抱くイメージ、感情、信頼の総体です。', '研修104: ブランディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (468, 10, 17, '「ブランドエクイティ」とは？', '["ブランドの公平性", "ブランドが持つ資産価値", "ブランドの平等性", "ブランドの歴史"]'::jsonb, 1, 'ブランドエクイティはブランドが持つ資産価値で、認知度、連想、知覚品質、ロイヤルティなどで構成されます。', '研修104: ブランディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (469, 10, 18, '「ブランドアイデンティティ」と「ブランドイメージ」の違いは？', '["同じもの", "アイデンティティは企業が意図するもの、イメージは顧客が認識するもの", "イメージが先", "違いはない"]'::jsonb, 1, 'アイデンティティは企業が伝えたいブランド像、イメージは顧客が実際に受け取る認識です。', '研修104: ブランディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (470, 10, 19, '強いブランドを構築するメリットは？', '["広告費が増える", "価格競争を避け、顧客ロイヤルティを高められる", "競合が増える", "コストが下がる"]'::jsonb, 1, '強いブランドは価格プレミアムを実現し、顧客の信頼とロイヤルティを獲得できます。', '研修104: ブランディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (471, 10, 20, '「ブランドの一貫性」が重要な理由は？', '["変化を嫌うから", "すべての接点で同じ体験を提供し、信頼を構築するため", "コスト削減のため", "管理が楽だから"]'::jsonb, 1, '一貫したブランド体験が信頼を築き、強固なブランドイメージを形成します。', '研修104: ブランディング', '2026-02-17T06:00:24.105904+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (472, 10, 21, 'デジタルマーケティングの特徴として正しいのは？', '["効果測定が難しい", "双方向性があり、効果測定が容易", "コストが高い", "ターゲティングが難しい"]'::jsonb, 1, 'デジタルマーケティングは双方向のコミュニケーションが可能で、効果を数値で測定できます。', '研修105: デジタルマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (473, 10, 22, '「SEO」とは何の略？', '["Sales Enhancement Operation", "Search Engine Optimization", "Social Engagement Optimization", "Strategic Entry Objective"]'::jsonb, 1, 'SEOはSearch Engine Optimization（検索エンジン最適化）の略で、検索結果上位表示を目指す施策です。', '研修105: デジタルマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (474, 10, 23, '「コンテンツマーケティング」の目的は？', '["すぐに売る", "価値ある情報を提供し、見込み客との信頼関係を構築する", "広告を増やす", "競合を攻撃する"]'::jsonb, 1, 'コンテンツマーケティングは有益な情報提供で見込み客を育成し、長期的な関係を構築します。', '研修105: デジタルマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (475, 10, 24, '「リスティング広告」の特徴は？', '["全員に表示される", "検索キーワードに連動して表示される", "無料で掲載できる", "効果測定できない"]'::jsonb, 1, 'リスティング広告は検索キーワードに連動して表示され、ニーズが顕在化した顧客にアプローチできます。', '研修105: デジタルマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (476, 10, 25, 'デジタルマーケティングの「KPI」として適切なのは？', '["社員数", "サイト訪問数、コンバージョン率、顧客獲得単価", "オフィスの広さ", "会議の回数"]'::jsonb, 1, 'デジタルマーケティングではPV、CVR、CPA、LTVなど数値で測定可能なKPIを設定します。', '研修105: デジタルマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (477, 10, 26, 'SNSマーケティングの特徴として正しいのは？', '["一方通行の発信", "双方向のコミュニケーションと拡散力", "コストが高い", "効果測定が難しい"]'::jsonb, 1, 'SNSは顧客との双方向コミュニケーションが可能で、シェアによる拡散効果があります。', '研修106: SNSマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (478, 10, 27, 'SNS運用で「エンゲージメント」が重要な理由は？', '["フォロワー数だけが重要", "ブランドとの関係の深さを示し、拡散やロイヤルティにつながる", "数字が増えるから", "広告費が減る"]'::jsonb, 1, 'エンゲージメントは顧客との関係の深さを示し、高いエンゲージメントは拡散と信頼につながります。', '研修106: SNSマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (479, 10, 28, 'SNSでの「炎上」を防ぐために重要なことは？', '["何も発信しない", "投稿前のチェック体制と誠実な対応姿勢", "批判を無視する", "アカウントを削除する"]'::jsonb, 1, '投稿前の確認体制を整え、問題が起きた場合は誠実かつ迅速に対応することが重要です。', '研修106: SNSマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (480, 10, 29, '「インフルエンサーマーケティング」の効果は？', '["効果がない", "インフルエンサーの信頼性を借りて認知拡大と信頼構築ができる", "コストがかからない", "炎上しない"]'::jsonb, 1, 'インフルエンサーの影響力と信頼を活用し、ターゲット層への認知拡大が期待できます。', '研修106: SNSマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (481, 10, 30, 'SNSマーケティングで「ペルソナ」を設定する理由は？', '["流行りだから", "ターゲットを明確にし、響くコンテンツを作成するため", "上司への報告のため", "競合と同じにするため"]'::jsonb, 1, 'ペルソナを設定することで、ターゲットに響く内容やトーンでのコミュニケーションが可能になります。', '研修106: SNSマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (482, 10, 31, '「リードジェネレーション」とは？', '["リードを削除すること", "見込み客を獲得・創出する活動", "既存顧客への販売", "競合分析"]'::jsonb, 1, 'リードジェネレーションは将来の顧客となる可能性のある見込み客を獲得・創出する活動です。', '研修107: リードジェネレーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (483, 10, 32, 'リード獲得の「インバウンド」と「アウトバウンド」の違いは？', '["同じもの", "インバウンドは顧客から来る、アウトバウンドは企業から働きかける", "アウトバウンドが新しい", "違いはない"]'::jsonb, 1, 'インバウンドは顧客が自ら情報を求めて来る手法、アウトバウンドは企業から積極的にアプローチする手法です。', '研修107: リードジェネレーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (484, 10, 33, '「ホワイトペーパー」をリード獲得に使う方法は？', '["無条件で配布する", "ダウンロード時に連絡先を取得する", "印刷して配る", "社内で共有する"]'::jsonb, 1, '価値ある資料をダウンロード提供する代わりに連絡先を取得し、リードを獲得します。', '研修107: リードジェネレーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (485, 10, 34, 'リードの「スコアリング」とは？', '["リードを採点して削除する", "リードの見込み度合いを数値化して優先順位をつける", "リードの点数を下げる", "営業成績を評価する"]'::jsonb, 1, 'スコアリングはリードの行動や属性を評価し、営業がアプローチすべき優先度を判断します。', '研修107: リードジェネレーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (486, 10, 35, 'リードジェネレーションで「CPL」とは？', '["Cost Per Lead（リード獲得単価）", "Customer Profit Level", "Campaign Planning List", "Content Production Level"]'::jsonb, 0, 'CPL（Cost Per Lead）は1件のリードを獲得するためにかかったコストを示す指標です。', '研修107: リードジェネレーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (487, 10, 36, '「マーケティングオートメーション（MA）」の目的は？', '["人員削減", "マーケティング活動を自動化・効率化し、効果を高める", "すべてを機械に任せる", "コストをゼロにする"]'::jsonb, 1, 'MAはリード育成やメール配信などを自動化し、効率的かつ効果的なマーケティングを実現します。', '研修108: マーケティングオートメーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (488, 10, 37, 'MAで「シナリオ」を設定する目的は？', '["物語を作るため", "顧客の行動に応じた最適なコミュニケーションを自動実行するため", "システムの都合", "報告のため"]'::jsonb, 1, 'シナリオ設定により、顧客の行動やステージに応じた適切なアプローチを自動で実行できます。', '研修108: マーケティングオートメーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (489, 10, 38, 'MA導入の前提として必要なことは？', '["高価なツールを買う", "カスタマージャーニーとコンテンツの整備", "大量の人員", "すべてを自動化する"]'::jsonb, 1, 'MA活用にはカスタマージャーニーの設計と、各段階で配信するコンテンツの準備が必要です。', '研修108: マーケティングオートメーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (490, 10, 39, 'MAと「CRM」の連携が重要な理由は？', '["流行りだから", "マーケティングと営業の情報を統合し、一貫した顧客対応が可能になる", "コスト削減のため", "システム部門の要望"]'::jsonb, 1, 'MAとCRMの連携により、マーケティングから営業まで顧客情報を一元管理し、シームレスな対応が可能になります。', '研修108: マーケティングオートメーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (491, 10, 40, 'MAの効果測定で重要な指標は？', '["ツールの利用時間", "リード育成率、商談化率、ROI", "メール送信数のみ", "ログイン回数"]'::jsonb, 1, 'MAの効果はリードの質向上、商談化率の改善、投資対効果で測定します。', '研修108: マーケティングオートメーション', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (492, 10, 41, '「LTV（顧客生涯価値）」とは？', '["顧客の年齢", "一人の顧客が取引期間全体で企業にもたらす価値の総計", "最初の購入額", "値引き額"]'::jsonb, 1, 'LTVは一人の顧客との取引期間全体で得られる利益の合計で、顧客価値を評価する重要指標です。', '研修109: 顧客分析とLTV', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (493, 10, 42, 'LTVを高める方法として適切なのは？', '["新規顧客だけに注力する", "顧客維持率向上、購買頻度増加、単価向上", "値引きを続ける", "広告を増やす"]'::jsonb, 1, 'LTV向上には顧客との関係を長く維持し、購買頻度や単価を上げる施策が効果的です。', '研修109: 顧客分析とLTV', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (494, 10, 43, '「RFM分析」の3つの指標は？', '["Revenue, Frequency, Marketing", "Recency, Frequency, Monetary", "Rate, Factor, Margin", "Reach, Focus, Method"]'::jsonb, 1, 'RFMはRecency（最終購買日）、Frequency（購買頻度）、Monetary（購買金額）の3指標で顧客を分析します。', '研修109: 顧客分析とLTV', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (495, 10, 44, '「チャーン（解約）」を防ぐことが重要な理由は？', '["形式的に必要", "新規獲得より既存維持の方がコスト効率が良いから", "上司に怒られるから", "競合のため"]'::jsonb, 1, '新規顧客獲得は既存顧客維持の5倍のコストがかかると言われ、解約防止は収益に直結します。', '研修109: 顧客分析とLTV', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (496, 10, 45, '「コホート分析」とは？', '["競合分析", "同じ時期に獲得した顧客グループの行動を追跡分析する手法", "コストの分析", "製品分析"]'::jsonb, 1, 'コホート分析は同時期に獲得した顧客群の行動を追跡し、施策の効果や傾向を分析します。', '研修109: 顧客分析とLTV', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (497, 10, 46, '営業とマーケティングの連携が重要な理由は？', '["上司の指示だから", "リードの質向上と成約率の向上につながるから", "コスト削減のため", "組織図のため"]'::jsonb, 1, '連携により質の高いリードが営業に渡り、顧客体験が一貫することで成約率が向上します。', '研修110: 営業とマーケティングの連携', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (498, 10, 47, '営業とマーケティングの「SLA（サービスレベル合意）」とは？', '["給与の合意", "リードの定義や引き渡し基準、対応期限などの取り決め", "売上目標", "休暇の取り決め"]'::jsonb, 1, 'SLAはリードの質の定義、引き渡しタイミング、フォロー期限など両者の合意事項を明確にします。', '研修110: 営業とマーケティングの連携', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (499, 10, 48, '「MQL」と「SQL」の違いは？', '["同じもの", "MQLはマーケティング認定リード、SQLは営業認定リード", "MQLが上位", "違いはない"]'::jsonb, 1, 'MQL（Marketing Qualified Lead）はマーケ基準、SQL（Sales Qualified Lead）は営業基準を満たしたリードです。', '研修110: 営業とマーケティングの連携', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (500, 10, 49, '営業からマーケティングへのフィードバックが重要な理由は？', '["文句を言うため", "リードの質や施策の効果を改善するため", "責任を押し付けるため", "会議のネタになる"]'::jsonb, 1, '営業からのフィードバックにより、マーケティングはリードの質や施策を改善できます。', '研修110: 営業とマーケティングの連携', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (501, 10, 50, '営業とマーケティング連携の最終的な目標は？', '["部門間の競争", "顧客に一貫した価値を提供し、売上と顧客満足を最大化する", "コスト削減", "人員削減"]'::jsonb, 1, '連携の目的は顧客視点での一貫した体験を提供し、売上と顧客満足度を最大化することです。', '研修110: 営業とマーケティングの連携', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (502, 11, 1, '企業Webサイトの主な役割として正しいのは？', '["デザインを見せること", "情報発信、リード獲得、ブランディング、顧客サポート", "競合と同じにすること", "社員向け情報発信"]'::jsonb, 1, '企業Webサイトは情報発信、見込み客獲得、ブランド構築、顧客サポートなど多機能を担います。', '研修111: Webサイト戦略', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (503, 11, 2, 'Webサイトの「コンバージョン」とは？', '["アクセス数", "訪問者が目標となる行動を完了すること", "ページ数", "デザイン変更"]'::jsonb, 1, 'コンバージョンは資料請求、問い合わせ、購入など、サイトの目標となる行動の完了を指します。', '研修111: Webサイト戦略', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (504, 11, 3, '「カスタマージャーニー」に基づいたWebサイト設計の利点は？', '["ページ数が減る", "顧客の検討段階に応じた適切な情報提供ができる", "デザインが簡単になる", "コストが下がる"]'::jsonb, 1, 'カスタマージャーニーを意識することで、各段階の顧客に必要な情報を適切に提供できます。', '研修111: Webサイト戦略', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (505, 11, 4, 'Webサイトの「ユーザビリティ」とは？', '["美しさ", "使いやすさ、目的達成のしやすさ", "情報量", "更新頻度"]'::jsonb, 1, 'ユーザビリティは訪問者がサイトを使いやすく、目的を達成しやすいかどうかを示します。', '研修111: Webサイト戦略', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (506, 11, 5, '「レスポンシブデザイン」の目的は？', '["読み込みを速くする", "デバイスの画面サイズに応じて最適な表示を提供する", "コストを下げる", "SEOには関係ない"]'::jsonb, 1, 'レスポンシブデザインはPC、タブレット、スマホなど様々なデバイスで最適な閲覧体験を提供します。', '研修111: Webサイト戦略', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (507, 11, 6, 'SEOの目的として最も適切なのは？', '["広告費を使うこと", "検索結果で上位表示され、自然流入を増やすこと", "サイトを美しくすること", "SNSフォロワーを増やすこと"]'::jsonb, 1, 'SEOは検索エンジンで上位表示されることで、広告費をかけずに見込み客を獲得することが目的です。', '研修112: SEO対策', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (508, 11, 7, '「内部SEO」に含まれる施策は？', '["被リンク獲得", "タイトルタグ最適化、サイト構造改善、コンテンツ充実", "SNS投稿", "広告出稿"]'::jsonb, 1, '内部SEOはサイト内で行う施策で、タイトル、メタ情報、構造、コンテンツなどの最適化です。', '研修112: SEO対策', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (509, 11, 8, '「E-E-A-T」とは何を評価する基準？', '["食事の品質", "経験、専門性、権威性、信頼性", "サイトの速度", "デザインの美しさ"]'::jsonb, 1, 'E-E-A-TはExperience、Expertise、Authoritativeness、TrustworthinessでGoogleが品質を評価する基準です。', '研修112: SEO対策', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (510, 11, 9, '「キーワード選定」で重要な観点は？', '["競合が使っているから", "検索ボリューム、競合度、自社との関連性", "文字数が多いから", "流行りだから"]'::jsonb, 1, 'キーワードは検索需要、競争の激しさ、自社ビジネスとの関連性を考慮して選定します。', '研修112: SEO対策', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (511, 11, 10, '「モバイルファーストインデックス」とは？', '["モバイルサイトを作らないこと", "Googleがモバイル版を優先してインデックス・評価すること", "PCサイトが不要になること", "アプリを優先すること"]'::jsonb, 1, 'Googleはモバイル版のコンテンツを基準にインデックスと検索順位を決定しています。', '研修112: SEO対策', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (512, 11, 11, 'リスティング広告の課金方式は？', '["表示回数課金", "クリック課金（CPC）", "月額固定", "成果報酬"]'::jsonb, 1, 'リスティング広告は一般的にクリック課金（CPC：Cost Per Click）で、クリックされた時に費用が発生します。', '研修113: リスティング広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (513, 11, 12, 'リスティング広告の「品質スコア」に影響する要素は？', '["入札額だけ", "広告の関連性、クリック率、ランディングページの品質", "会社の規模", "広告の掲載期間"]'::jsonb, 1, '品質スコアは広告とキーワードの関連性、予想クリック率、LP体験などで決まります。', '研修113: リスティング広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (514, 11, 13, '「除外キーワード」を設定する目的は？', '["表示回数を減らすため", "関連性の低い検索での広告表示を防ぎ、無駄なコストを削減するため", "競合をブロックするため", "SEOのため"]'::jsonb, 1, '除外キーワードで意図しない検索での表示を防ぎ、関連性の高いクリックに予算を集中できます。', '研修113: リスティング広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (515, 11, 14, 'リスティング広告の「広告文」作成のポイントは？', '["長文で詳しく説明する", "検索意図に応え、メリットと行動喚起を簡潔に伝える", "専門用語を多用する", "競合の悪口を書く"]'::jsonb, 1, '限られた文字数で検索者のニーズに応え、クリックを促す明確なメッセージが重要です。', '研修113: リスティング広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (516, 11, 33, 'メールの「CTA（Call To Action）」とは？', '["会社名", "読者に取ってほしい行動を促すボタンやリンク", "配信停止リンク", "署名"]'::jsonb, 1, 'CTAは「詳細を見る」「申し込む」など、読者に具体的な行動を促す要素です。', '研修117: メールマーケティング', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (517, 11, 15, 'リスティング広告の「ROAS」とは？', '["広告の表示回数", "広告費用に対する売上の割合（広告投資対効果）", "クリック率", "コンバージョン数"]'::jsonb, 1, 'ROAS（Return On Ad Spend）は広告費に対してどれだけの売上が得られたかを示す指標です。', '研修113: リスティング広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (518, 11, 16, 'ディスプレイ広告の特徴は？', '["検索結果にのみ表示", "Webサイトやアプリ上に画像・動画で表示される", "テキストのみ", "SNS専用"]'::jsonb, 1, 'ディスプレイ広告はWebサイトやアプリの広告枠に画像、動画、テキストで表示されます。', '研修114: ディスプレイ広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (519, 11, 17, 'ディスプレイ広告が「認知拡大」に向いている理由は？', '["クリック率が高いから", "多くの人の目に触れ、視覚的なインパクトを与えられるから", "コストが安いから", "SEOに効くから"]'::jsonb, 1, 'ディスプレイ広告は多くのサイトに表示され、視覚的な訴求でブランド認知を高められます。', '研修114: ディスプレイ広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (520, 11, 18, '「リターゲティング広告」の仕組みは？', '["新規顧客だけに表示", "過去にサイトを訪問した人に再度広告を表示する", "競合サイト訪問者に表示", "ランダムに表示"]'::jsonb, 1, 'リターゲティングは過去の訪問者に再アプローチし、コンバージョンを促進する手法です。', '研修114: ディスプレイ広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (521, 11, 19, 'ディスプレイ広告の「バナーブラインドネス」とは？', '["バナーが見えなくなる病気", "ユーザーが広告を無意識に無視する現象", "広告の色が薄いこと", "表示エラー"]'::jsonb, 1, 'バナーブラインドネスは、ユーザーが広告を無意識にスルーしてしまう現象です。', '研修114: ディスプレイ広告', '2026-02-17T06:00:24.256776+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (522, 11, 20, 'ディスプレイ広告の「ビューアブルインプレッション」とは？', '["すべての表示回数", "実際にユーザーの画面に表示された広告の回数", "クリックされた回数", "購入につながった回数"]'::jsonb, 1, 'ビューアブルインプレッションは広告が実際に視認可能な状態で表示された回数を測定します。', '研修114: ディスプレイ広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (523, 11, 21, 'SNS広告の最大の特徴は？', '["無料で出稿できる", "詳細なターゲティングと高いエンゲージメント", "検索結果に表示される", "効果測定ができない"]'::jsonb, 1, 'SNS広告は年齢、興味、行動など詳細なターゲティングが可能で、双方向のエンゲージメントが期待できます。', '研修115: SNS広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (524, 11, 22, 'Facebook/Instagram広告の「類似オーディエンス」とは？', '["同じ人に何度も表示", "既存顧客と似た特徴を持つ新規ユーザーをターゲティング", "競合のフォロワー", "ランダムな人々"]'::jsonb, 1, '類似オーディエンスは既存顧客データを基に、似た属性を持つ新規見込み客を見つけ出します。', '研修115: SNS広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (525, 11, 23, 'SNS広告で「クリエイティブ」が重要な理由は？', '["規定があるから", "フィードに溶け込みながらも注目を引く必要があるから", "コストに関係ないから", "審査に通るため"]'::jsonb, 1, 'SNSでは多くの投稿の中で目を引きつつ、自然に受け入れられるクリエイティブが重要です。', '研修115: SNS広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (526, 11, 24, 'LinkedIn広告が特に効果的なターゲットは？', '["一般消費者", "BtoB企業、ビジネスプロフェッショナル", "学生のみ", "高齢者"]'::jsonb, 1, 'LinkedInはビジネス特化SNSのため、BtoB企業やビジネス層へのアプローチに効果的です。', '研修115: SNS広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (527, 11, 25, 'SNS広告の「A/Bテスト」の目的は？', '["予算を増やすため", "異なるクリエイティブや設定を比較し、効果の高いものを特定する", "審査を通すため", "上司への報告のため"]'::jsonb, 1, 'A/Bテストで複数のパターンを比較し、最も効果の高い広告を見つけ出して最適化します。', '研修115: SNS広告', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (528, 11, 26, 'コンテンツマーケティングの「ファネル」で最初の段階は？', '["購入", "認知・興味喚起", "比較検討", "リピート"]'::jsonb, 1, 'コンテンツマーケティングはまず認知・興味喚起の段階から顧客を育成していきます。', '研修116: コンテンツマーケティング実践', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (529, 11, 27, '「エバーグリーンコンテンツ」とは？', '["季節限定コンテンツ", "長期間にわたって価値を持ち続けるコンテンツ", "緑色のコンテンツ", "動画コンテンツ"]'::jsonb, 1, 'エバーグリーンコンテンツは時間が経っても価値が下がらず、継続的に集客効果のあるコンテンツです。', '研修116: コンテンツマーケティング実践', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (530, 11, 28, 'コンテンツの「再利用」の例として適切なのは？', '["同じ記事を何度も投稿", "ブログ記事をホワイトペーパーや動画に展開する", "他社のコンテンツをコピー", "古い記事を削除"]'::jsonb, 1, '一つのコンテンツを複数の形式に展開することで、効率的に多くのチャネルで活用できます。', '研修116: コンテンツマーケティング実践', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (531, 11, 29, 'コンテンツマーケティングの効果測定指標として適切なのは？', '["社員数", "PV、滞在時間、コンバージョン率、リード獲得数", "オフィスの広さ", "会議の回数"]'::jsonb, 1, 'コンテンツの効果はトラフィック、エンゲージメント、コンバージョンなどで測定します。', '研修116: コンテンツマーケティング実践', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (532, 11, 30, '「コンテンツカレンダー」を作成する目的は？', '["カレンダーを飾るため", "計画的なコンテンツ制作・公開で一貫性を保つため", "上司への報告のため", "競合に見せるため"]'::jsonb, 1, 'コンテンツカレンダーで計画的に制作・公開することで、一貫性と継続性を維持できます。', '研修116: コンテンツマーケティング実践', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (533, 11, 31, 'メールマーケティングの「開封率」を上げるポイントは？', '["本文を長くする", "魅力的な件名と適切な配信タイミング", "画像を多くする", "毎日送る"]'::jsonb, 1, '開封率は件名の魅力と送信タイミングに大きく影響されます。', '研修117: メールマーケティング', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (534, 11, 32, '「セグメントメール」の効果は？', '["配信数が減る", "受信者の属性や行動に合わせた関連性の高いメールで反応率が上がる", "コストが下がる", "手間が減る"]'::jsonb, 1, 'セグメントに応じた内容を送ることで、関連性が高まり開封率・クリック率が向上します。', '研修117: メールマーケティング', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (535, 11, 34, 'メールマーケティングで「配信停止」を簡単にすべき理由は？', '["法律遵守と、興味のない人への配信を止めてリストの質を保つため", "配信数を減らしたいから", "コスト削減のため", "特に理由はない"]'::jsonb, 0, '配信停止を簡単にすることは法律遵守であり、興味のある人だけに配信することでリストの質が向上します。', '研修117: メールマーケティング', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (536, 11, 35, '「ドリップキャンペーン」とは？', '["一度だけ送るメール", "あらかじめ設定したシナリオに沿って自動配信する一連のメール", "緊急メール", "全員同時配信"]'::jsonb, 1, 'ドリップキャンペーンは登録や行動をトリガーに、段階的にメールを自動配信する手法です。', '研修117: メールマーケティング', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (537, 11, 36, '「ランディングページ（LP）」の主な目的は？', '["会社情報を伝える", "特定のコンバージョン（問い合わせ、購入など）を獲得する", "SEO対策", "採用活動"]'::jsonb, 1, 'LPは広告やメールから訪問した人を、特定の行動（CV）に導くことに特化したページです。', '研修118: ランディングページ最適化', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (538, 11, 37, 'LPの「ファーストビュー」が重要な理由は？', '["法律で決まっている", "訪問者が最初に見る部分で、続きを読むか判断されるから", "SEOに影響するから", "デザイナーの好み"]'::jsonb, 1, 'ファーストビューで訪問者は数秒で「このページを読む価値があるか」を判断します。', '研修118: ランディングページ最適化', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (539, 11, 38, 'LPO（ランディングページ最適化）で行うことは？', '["ページを増やす", "A/Bテストなどでコンバージョン率を改善する", "広告費を増やす", "デザインを派手にする"]'::jsonb, 1, 'LPOはテストと分析を繰り返し、コンバージョン率を継続的に改善する取り組みです。', '研修118: ランディングページ最適化', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (540, 11, 39, 'LPで「社会的証明」を示す方法は？', '["自社の自慢をする", "顧客の声、導入実績、受賞歴などを掲載する", "価格を下げる", "文字を大きくする"]'::jsonb, 1, 'お客様の声、導入事例、実績数などの社会的証明は信頼性を高め、CVを促進します。', '研修118: ランディングページ最適化', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (541, 11, 40, 'LPの「フォーム」で入力項目を減らすメリットは？', '["情報が少なくなる", "入力の手間が減り、コンバージョン率が上がる", "デザインが良くなる", "セキュリティが向上する"]'::jsonb, 1, '入力項目が多いと離脱が増えるため、必要最低限に絞ることでCV率が向上します。', '研修118: ランディングページ最適化', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (542, 11, 41, '「Google Analytics」で分析できることは？', '["競合の売上", "自社サイトの訪問者数、行動、コンバージョン", "SNSのフォロワー数", "メールの開封率"]'::jsonb, 1, 'Google Analyticsは自社サイトへの訪問者の属性、行動、成果を分析できるツールです。', '研修119: アクセス解析', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (543, 11, 42, '「直帰率」とは？', '["リピート率", "最初のページだけ見て離脱した訪問の割合", "コンバージョン率", "クリック率"]'::jsonb, 1, '直帰率は1ページだけ見てサイトを離れた訪問の割合で、コンテンツの魅力や関連性の指標です。', '研修119: アクセス解析', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (544, 11, 43, '「流入経路」を分析する目的は？', '["道路を調べる", "どのチャネルから効果的に訪問者が来ているかを把握する", "競合を調べる", "デザインを決める"]'::jsonb, 1, '流入経路分析で効果的なチャネルを特定し、マーケティング投資を最適化できます。', '研修119: アクセス解析', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (545, 11, 44, '「コンバージョンファネル」分析で分かることは？', '["売上金額", "目標達成までのどの段階で離脱が多いか", "競合情報", "SNSの反応"]'::jsonb, 1, 'ファネル分析で離脱が多い段階を特定し、改善ポイントを明確にできます。', '研修119: アクセス解析', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (546, 11, 45, 'アクセス解析で「仮説検証」が重要な理由は？', '["数字を見るだけで十分", "データから仮説を立て検証することで、効果的な改善ができるから", "上司への報告のため", "レポートが長くなるから"]'::jsonb, 1, 'データを見るだけでなく、仮説を立てて検証・改善するサイクルが成果につながります。', '研修119: アクセス解析', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (547, 11, 46, '「アトリビューション分析」とは？', '["クリック数の分析", "コンバージョンに至るまでの各接点の貢献度を分析すること", "広告費の分析", "競合分析"]'::jsonb, 1, 'アトリビューション分析はCVまでの各接点（広告、検索など）の貢献度を評価します。', '研修120: Web広告効果測定', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (548, 11, 47, '「ラストクリック」モデルの問題点は？', '["問題はない", "最後の接点のみを評価し、認知段階の貢献を見落とす", "計算が難しい", "コストが高い"]'::jsonb, 1, 'ラストクリックは最終接点のみを評価するため、認知拡大に貢献した広告が過小評価されます。', '研修120: Web広告効果測定', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (549, 11, 48, '広告の「CPA」とは？', '["クリック単価", "1件のコンバージョン獲得にかかったコスト", "表示回数", "売上"]'::jsonb, 1, 'CPA（Cost Per Acquisition）は1件のCVを獲得するためにかかった広告費用です。', '研修120: Web広告効果測定', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (550, 11, 49, '広告効果測定で「UTMパラメータ」を使う目的は？', '["SEO対策", "広告やキャンペーンごとの流入を正確に計測するため", "サイトを速くするため", "セキュリティ対策"]'::jsonb, 1, 'UTMパラメータでURLに情報を付加し、どの広告から流入したかを正確に追跡できます。', '研修120: Web広告効果測定', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (551, 11, 50, 'Web広告効果測定の最終的な目的は？', '["レポートを作ること", "データに基づいて広告投資を最適化し、ROIを最大化すること", "上司への報告", "競合を分析すること"]'::jsonb, 1, '効果測定の目的は、データを基に広告配分を最適化し、投資対効果を最大化することです。', '研修120: Web広告効果測定', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (552, 12, 1, 'SaaSの正式名称は？', '["Software and a Service", "Software as a Service", "System as a Service", "Sales as a Service"]'::jsonb, 1, 'SaaSはSoftware as a Serviceの略で、クラウド経由でソフトウェアを提供するビジネスモデルです。', '研修121: SaaSビジネスモデルの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (553, 12, 2, 'SaaSビジネスの収益モデルの特徴は？', '["一括払いのみ", "サブスクリプション（継続課金）型", "広告収入のみ", "成果報酬型のみ"]'::jsonb, 1, 'SaaSは月額や年額のサブスクリプション型で、継続的な収益を得るモデルが一般的です。', '研修121: SaaSビジネスモデルの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (554, 12, 3, 'SaaSが従来のソフトウェア販売と異なる点は？', '["価格が高い", "導入・更新が容易で、初期コストが低い", "機能が少ない", "サポートがない"]'::jsonb, 1, 'SaaSはクラウド提供のため導入が容易で、初期投資を抑えて利用開始できます。', '研修121: SaaSビジネスモデルの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (555, 12, 4, 'SaaSビジネスにおける「マルチテナント」とは？', '["複数の建物を持つこと", "一つのシステムを複数の顧客が共有して利用する仕組み", "複数のサービスを提供すること", "複数の契約を結ぶこと"]'::jsonb, 1, 'マルチテナントは一つのインフラ・アプリケーションを複数顧客で共有し、効率的に運用する仕組みです。', '研修121: SaaSビジネスモデルの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (556, 12, 5, 'SaaSビジネスで「ストック型収益」が重要な理由は？', '["在庫管理のため", "継続課金により安定した収益基盤を構築できるから", "株式投資のため", "一時的に売上が上がるから"]'::jsonb, 1, 'ストック型収益は毎月の継続課金により、予測可能で安定した収益基盤を作れます。', '研修121: SaaSビジネスモデルの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (557, 12, 6, 'SaaSの「MRR」とは？', '["Maximum Revenue Rate", "Monthly Recurring Revenue（月次経常収益）", "Monthly Return Rate", "Marketing Response Rate"]'::jsonb, 1, 'MRRはMonthly Recurring Revenueの略で、毎月の定期的な収益を示す重要指標です。', '研修122: SaaS主要KPI', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (558, 12, 7, '「ARR」と「MRR」の関係は？', '["無関係", "ARR = MRR × 12（年間経常収益）", "ARR = MRR ÷ 12", "同じもの"]'::jsonb, 1, 'ARR（Annual Recurring Revenue）はMRRの12ヶ月分で、年間の経常収益を示します。', '研修122: SaaS主要KPI', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (559, 12, 8, 'SaaSの「チャーンレート」とは？', '["成長率", "解約率", "利益率", "稼働率"]'::jsonb, 1, 'チャーンレートは一定期間内に解約した顧客や収益の割合を示す指標です。', '研修122: SaaS主要KPI', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (560, 12, 9, '「NRR（Net Revenue Retention）」が100%を超える意味は？', '["赤字である", "既存顧客からの収益が拡大している", "新規顧客が多い", "解約がゼロ"]'::jsonb, 1, 'NRRが100%超は既存顧客のアップセル・クロスセルが解約を上回り、収益が拡大していることを示します。', '研修122: SaaS主要KPI', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (561, 12, 10, 'SaaSで「LTV/CAC比率」が重要な理由は？', '["法律で定められている", "顧客獲得の投資効率を測定し、持続可能な成長を判断するため", "競合比較のため", "採用のため"]'::jsonb, 1, 'LTV/CAC比率は顧客獲得コストに対する生涯価値を示し、3倍以上が健全とされます。', '研修122: SaaS主要KPI', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (562, 12, 11, '「カスタマーサクセス」の目的は？', '["クレーム対応", "顧客が製品で成功を実現し、継続利用と拡大を促すこと", "新規営業", "製品開発"]'::jsonb, 1, 'カスタマーサクセスは顧客の成功を支援し、解約防止とアップセルにつなげる活動です。', '研修123: カスタマーサクセスの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (563, 12, 12, 'カスタマーサクセスと「カスタマーサポート」の違いは？', '["同じもの", "サクセスは能動的に成功を支援、サポートは問題発生時に対応", "サポートの方が重要", "サクセスは営業活動"]'::jsonb, 1, 'カスタマーサクセスは能動的に顧客の成功を支援し、サポートは問題発生時に対応します。', '研修123: カスタマーサクセスの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (564, 12, 13, 'カスタマーサクセスにおける「ヘルススコア」とは？', '["顧客の健康状態", "顧客の利用状況や満足度を数値化し、解約リスクを予測する指標", "製品の品質スコア", "営業の成績"]'::jsonb, 1, 'ヘルススコアはログイン頻度、機能利用度などから顧客の健全性を数値化します。', '研修123: カスタマーサクセスの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (565, 12, 14, 'カスタマーサクセスで「オンボーディング」が重要な理由は？', '["形式的に必要", "初期の活用支援が定着率と長期的な成功に大きく影響するから", "コスト削減のため", "法律で義務付け"]'::jsonb, 1, '導入初期の支援が不十分だと早期解約につながるため、オンボーディングは極めて重要です。', '研修123: カスタマーサクセスの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (566, 12, 15, 'カスタマーサクセスの「QBR」とは？', '["Quality Business Review", "Quarterly Business Review（四半期ビジネスレビュー）", "Quick Business Report", "Quantitative Business Rate"]'::jsonb, 1, 'QBRは四半期ごとに顧客と成果を振り返り、次の目標を設定するミーティングです。', '研修123: カスタマーサクセスの基礎', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (567, 12, 16, 'SaaS営業が従来の営業と異なる点は？', '["契約して終わり", "契約後も継続利用と拡大を見据えた長期的な関係構築が必要", "価格交渉だけ", "一度の大型契約を狙う"]'::jsonb, 1, 'SaaS営業は契約がゴールではなく、継続利用とアップセルにつなげる関係構築が重要です。', '研修124: SaaS営業の特徴', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (568, 12, 17, 'SaaS営業における「ランド・アンド・エクスパンド」戦略とは？', '["土地を購入する戦略", "まず小さく導入し、成功を基に利用を拡大していく戦略", "大規模導入を狙う戦略", "競合を排除する戦略"]'::jsonb, 1, 'ランド・アンド・エクスパンドは小規模導入から始め、価値を実感してもらい拡大する戦略です。', '研修124: SaaS営業の特徴', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (569, 12, 18, 'SaaS営業で「無料トライアル」を提供する目的は？', '["売上を減らすため", "製品価値を体験してもらい、購入への障壁を下げるため", "競合対策のため", "開発テストのため"]'::jsonb, 1, '無料トライアルで価値を体験してもらい、購入判断を促進します。', '研修124: SaaS営業の特徴', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (570, 12, 19, 'SaaS営業の「ACV」とは？', '["Average Customer Value", "Annual Contract Value（年間契約金額）", "Actual Conversion Value", "Account Coverage Value"]'::jsonb, 1, 'ACV（Annual Contract Value）は1契約あたりの年間契約金額を示す指標です。', '研修124: SaaS営業の特徴', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (571, 12, 20, 'SaaS営業で「プロダクトレッドグロース（PLG）」とは？', '["製品の色を赤にすること", "製品自体が成長ドライバーとなり、ユーザー獲得・拡大を促す戦略", "営業主導の成長", "マーケティング主導の成長"]'::jsonb, 1, 'PLGは製品の使いやすさと価値で、ユーザーが自然に増えていく成長モデルです。', '研修124: SaaS営業の特徴', '2026-02-17T06:00:24.404604+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (572, 12, 21, 'サブスクリプションモデルの価格設定で重要な考え方は？', '["競合より安くする", "顧客が得る価値に見合った価格設定", "とにかく高くする", "原価だけで決める"]'::jsonb, 1, 'サブスクリプションでは顧客が継続的に得る価値に見合う価格設定が重要です。', '研修125: サブスクリプションセールス', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (573, 12, 22, '「年間契約」を推奨する営業上のメリットは？', '["作業が減る", "収益の安定化とチャーン抑制、キャッシュフロー改善", "顧客が喜ぶ", "競合対策"]'::jsonb, 1, '年間契約は収益を安定させ、解約の機会を減らし、先払いでキャッシュフローも改善します。', '研修125: サブスクリプションセールス', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (574, 12, 23, 'サブスクリプションで「フリーミアム」モデルとは？', '["すべて無料", "基本機能を無料で提供し、高度な機能で課金するモデル", "試用期間のみ無料", "紹介者だけ無料"]'::jsonb, 1, 'フリーミアムは基本機能を無料で提供し、追加機能や容量で有料化するモデルです。', '研修125: サブスクリプションセールス', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (575, 12, 24, 'サブスクリプション営業で「更新率」が重要な理由は？', '["新規営業に集中するため", "継続収益の基盤であり、事業の持続可能性に直結するから", "報告に必要だから", "競合比較のため"]'::jsonb, 1, '更新率は既存収益を維持できるかを示し、SaaSビジネスの基盤となる重要指標です。', '研修125: サブスクリプションセールス', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (576, 12, 25, 'サブスクリプションの「ティアード・プライシング」とは？', '["値引き戦略", "機能や利用量に応じて複数の価格帯を設定する方式", "競合価格に合わせる", "原価に基づく価格設定"]'::jsonb, 1, 'ティアード・プライシングは複数のプランを用意し、顧客のニーズに合った選択を可能にします。', '研修125: サブスクリプションセールス', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (577, 12, 26, 'エンタープライズSaaS営業の特徴は？', '["短期間で成約する", "長い販売サイクル、複数の意思決定者、カスタマイズ要望", "価格交渉がない", "一人で完結する"]'::jsonb, 1, 'エンタープライズは検討期間が長く、複数の関係者が関与し、要件も複雑になります。', '研修126: エンタープライズSaaS営業', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (578, 12, 27, 'エンタープライズ営業で「チャンピオン」を作ることの重要性は？', '["競争に勝つため", "顧客社内で自社を推進してくれるキーパーソンが成約を後押しするから", "表彰するため", "報告のため"]'::jsonb, 1, 'チャンピオンは顧客社内で自社製品を推進し、複雑な意思決定を支援してくれます。', '研修126: エンタープライズSaaS営業', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (579, 12, 28, 'エンタープライズ営業で「セキュリティ審査」への対応が重要な理由は？', '["形式的に必要", "大企業は情報セキュリティを重視し、審査をパスしないと導入されないから", "コスト削減のため", "法律で義務"]'::jsonb, 1, 'エンタープライズ顧客はセキュリティ要件が厳しく、審査対応は必須の営業プロセスです。', '研修126: エンタープライズSaaS営業', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (580, 12, 29, 'エンタープライズSaaS営業の「POC」とは？', '["Point of Contact", "Proof of Concept（概念実証）", "Price of Contract", "Plan of Campaign"]'::jsonb, 1, 'POC（Proof of Concept）は本格導入前に小規模で効果を検証する概念実証です。', '研修126: エンタープライズSaaS営業', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (581, 12, 30, 'エンタープライズ営業で「マルチスレッド」アプローチとは？', '["複数の製品を売る", "顧客組織の複数の関係者と同時に関係を構築するアプローチ", "複数の営業が担当する", "複数回訪問する"]'::jsonb, 1, 'マルチスレッドは複数の意思決定者や影響者と関係を築き、リスクを分散するアプローチです。', '研修126: エンタープライズSaaS営業', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (582, 12, 31, 'SaaSにおける「アップセル」とは？', '["新規顧客獲得", "既存顧客に上位プランへの移行を提案すること", "解約を防ぐこと", "値引きすること"]'::jsonb, 1, 'アップセルは既存顧客により高機能な上位プランへの移行を提案し、顧客単価を上げることです。', '研修127: SaaSのアップセル・クロスセル', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (583, 12, 32, 'アップセルの適切なタイミングは？', '["契約直後", "顧客が現プランの価値を実感し、さらなるニーズが生まれた時", "解約直前", "いつでも同じ"]'::jsonb, 1, '現プランで成功を実感し、次のステップへのニーズが顕在化したタイミングが効果的です。', '研修127: SaaSのアップセル・クロスセル', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (584, 12, 33, '「クロスセル」とアップセルの違いは？', '["同じもの", "クロスセルは関連する別製品、アップセルは上位プランの提案", "クロスセルの方が難しい", "アップセルは新規向け"]'::jsonb, 1, 'クロスセルは補完的な別製品・サービスの提案、アップセルは同製品の上位プランへの移行提案です。', '研修127: SaaSのアップセル・クロスセル', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (585, 12, 34, 'アップセル・クロスセルで「顧客の成功」を起点にする理由は？', '["売り込みやすいから", "成功している顧客は拡大ニーズがあり、提案を受け入れやすいから", "上司の指示だから", "競合対策のため"]'::jsonb, 1, '製品で成功を実感している顧客は、さらなる価値を求めて拡大提案を受け入れやすくなります。', '研修127: SaaSのアップセル・クロスセル', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (586, 12, 35, 'SaaSの「エクスパンション収益」とは？', '["新規顧客からの収益", "既存顧客からのアップセル・クロスセルによる追加収益", "広告収益", "投資収益"]'::jsonb, 1, 'エクスパンション収益は既存顧客基盤からの拡大収益で、効率的な成長を示す指標です。', '研修127: SaaSのアップセル・クロスセル', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (587, 12, 36, 'SaaSでチャーン（解約）防止が重要な理由は？', '["新規獲得の方が簡単だから", "新規獲得より既存維持の方がコスト効率が良く、収益基盤を守るため", "法律で決まっている", "競合のため"]'::jsonb, 1, '新規獲得は既存維持の5〜25倍のコストがかかり、チャーン防止は収益基盤の維持に直結します。', '研修128: チャーン防止戦略', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (588, 12, 37, 'チャーンの「先行指標」として注目すべきは？', '["解約の連絡", "ログイン頻度の低下、機能利用の減少などの行動変化", "契約更新日", "請求書の発行"]'::jsonb, 1, '解約前に利用頻度やエンゲージメントの低下が起こるため、これらを先行指標として監視します。', '研修128: チャーン防止戦略', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (589, 12, 38, '「プロアクティブ・リテンション」とは？', '["解約後の対応", "解約リスクを事前に検知し、能動的に対策を講じること", "値引きで引き止める", "自動更新にする"]'::jsonb, 1, 'プロアクティブ・リテンションは解約の兆候を早期に捉え、事前に対策を打つアプローチです。', '研修128: チャーン防止戦略', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (590, 12, 39, '解約理由の分析で重要なことは？', '["理由を聞かない", "真の解約理由を把握し、製品改善や営業プロセスに反映すること", "解約した顧客は忘れる", "競合のせいにする"]'::jsonb, 1, '解約理由を分析し、製品、オンボーディング、サポートなどの改善に活かすことが重要です。', '研修128: チャーン防止戦略', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (591, 12, 40, '「ネガティブチャーン」とは？', '["解約が多いこと", "既存顧客からの拡大収益が解約による減収を上回る状態", "悪いチャーン", "競合への流出"]'::jsonb, 1, 'ネガティブチャーンはエクスパンションが解約を上回り、既存顧客からの収益が純増する理想的な状態です。', '研修128: チャーン防止戦略', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (592, 12, 41, 'SaaS契約で「SLA」とは？', '["Sales Level Agreement", "Service Level Agreement（サービス品質保証）", "Software License Agreement", "Standard Legal Agreement"]'::jsonb, 1, 'SLA（Service Level Agreement）はサービスの稼働率や対応時間などの品質保証を定めたものです。', '研修129: SaaS契約と法務', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (593, 12, 42, 'SaaS契約における「データの所有権」で重要な点は？', '["すべてベンダーのもの", "顧客データは顧客に帰属し、解約時の取り扱いを明確にすること", "気にしなくてよい", "国が管理する"]'::jsonb, 1, '顧客データの所有権、解約時のデータ返却・削除方法を契約で明確にすることが重要です。', '研修129: SaaS契約と法務', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (594, 12, 43, 'SaaS契約の「自動更新条項」で営業が注意すべき点は？', '["何も注意不要", "更新時期と解約通知期限を把握し、適切なタイミングで更新活動を行う", "自動なので放置する", "解約を勧める"]'::jsonb, 1, '自動更新でも更新前に顧客と対話し、満足度確認や拡大提案の機会として活用します。', '研修129: SaaS契約と法務', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (595, 12, 44, 'SaaSにおける「GDPR」「個人情報保護法」対応の重要性は？', '["海外顧客だけ関係", "顧客の個人データを扱う場合、法令遵守は必須の要件だから", "技術部門だけの問題", "小さい会社は関係ない"]'::jsonb, 1, '個人データを扱うSaaSは各国の個人情報保護法令の遵守が必須であり、営業も理解が必要です。', '研修129: SaaS契約と法務', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (596, 12, 45, 'SaaS契約で「セキュリティ認証」を持つメリットは？', '["飾りになる", "顧客のセキュリティ審査をスムーズに通過でき、信頼獲得につながる", "価格を上げられる", "開発が楽になる"]'::jsonb, 1, 'ISO27001やSOC2などの認証は顧客のセキュリティ要件を満たす証明となり、営業を有利にします。', '研修129: SaaS契約と法務', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (597, 12, 46, 'SaaS市場の成長トレンドとして正しいのは？', '["縮小傾向", "世界的に継続的な成長が見込まれている", "横ばい", "一部地域のみ成長"]'::jsonb, 1, 'SaaS市場はDX推進やクラウド移行の加速により、世界的に継続成長が予測されています。', '研修130: SaaS市場動向と将来展望', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (598, 12, 47, '「バーティカルSaaS」と「ホリゾンタルSaaS」の違いは？', '["同じもの", "バーティカルは特定業界向け、ホリゾンタルは業界横断的な汎用型", "バーティカルが大きい", "ホリゾンタルが新しい"]'::jsonb, 1, 'バーティカルSaaSは特定業界に特化、ホリゾンタルSaaSは業界を問わず汎用的に利用されます。', '研修130: SaaS市場動向と将来展望', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (599, 12, 48, 'SaaSビジネスにおける「AI活用」のトレンドは？', '["関係ない", "AIを組み込んだ機能強化や効率化が競争力の源泉になっている", "AIは脅威", "AIは不要"]'::jsonb, 1, 'AIを活用した自動化、予測、パーソナライズなどがSaaS製品の差別化要因になっています。', '研修130: SaaS市場動向と将来展望', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (600, 12, 49, '「コンポーザブル・アーキテクチャ」がSaaSに与える影響は？', '["関係ない", "APIで連携し、複数SaaSを組み合わせて最適なシステムを構築する流れ", "SaaSが不要になる", "価格が下がる"]'::jsonb, 1, 'コンポーザブルは複数のSaaSをAPIで連携し、柔軟にシステムを構成するトレンドです。', '研修130: SaaS市場動向と将来展望', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO category_test_questions (id, category_test_id, question_number, question, options, correct_answer, explanation, source, created_at) VALUES (601, 12, 50, 'SaaS営業パーソンが市場動向を理解すべき理由は？', '["トレンドを話すため", "顧客の課題を業界文脈で理解し、将来を見据えた提案ができるから", "上司への報告のため", "転職のため"]'::jsonb, 1, '市場動向の理解により、顧客の課題を深く理解し、中長期的な価値提案が可能になります。', '研修130: SaaS市場動向と将来展望', '2026-02-17T06:00:24.545362+00:00');
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (2, 1, '営業とは問題解決である', '世界の営業研究が証明する「顧客中心主義」の真実', '自動車業界は今、100年に一度の大変革期を迎えています。電動化、自動運転、コネクテッド、シェアリング——いわゆるCASEの波が、従来のビジネスモデルを根底から揺さぶっています。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (3, 100, '営業カルチャーの浸透', '勝つ組織文化を構築する', '「文化は戦略を朝食に食べる（Culture eats strategy for breakfast）」——Peter Druckerに帰される（実際は不明）この言葉は、組織文化の重要性を端的に表しています。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (4, 2, '第一印象の科学', '学術研究から学ぶ第一印象のメカニズム', '第一印象は、ビジネスにおいて成功を左右する重要な要素です。この補足資料では、研修で学んだ「第一印象の科学」について、学術研究の知見を深掘りし、より深い理解と実践への応用を目指します。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (5, 3, '「断られる」ことへの正しい向き合い方', '学術研究が明かすレジリエンスの科学', '営業活動において「断られる」ことは日常茶飯事です。しかし、この「断り」に対する心理的反応は、営業パフォーマンスに大きな影響を与えます。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (6, 33, '影響力の6原則', 'チャルディーニの説得の心理学', 'Robert Cialdini（ロバート・チャルディーニ）は、アリゾナ州立大学の心理学教授であり、説得と影響力の研究における世界的権威です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (7, 34, '一貫性の原理とフット・イン・ザ・ドア', '小さなイエスから大きなイエスへ', '「一貫性の原理」は、チャルディーニの6原則の中でも特に営業活動に直結する原則です。人は一度「イエス」と言うと、その後も「イエス」と言い続けようとする傾向があります。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (8, 35, '返報性の原理', '「与える」ことの戦略的価値', '返報性の原理（Reciprocity）は、人類の社会的進化において最も重要な心理メカニズムの一つです。「受け取ったら返さなければならない」という感覚は、文化を超えて普遍的に存在します。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (9, 36, '社会的証明', '事例・実績の効果的な使い方', '「行列のできるラーメン店は美味しいに違いない」——私たちは無意識のうちに、他者の行動を意思決定の参考にしています。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (10, 37, '希少性の原理', '限定・期限の心理効果', '「残りわずか」「今日限り」——これらの言葉に心が動いた経験は誰にでもあるでしょう。希少性の原理は、人間の「失いたくない」という本能に訴えかける強力な心理メカニズムです。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (11, 38, 'アンカリング効果', '価格提示の順序戦略', '「最初に見た数字が、その後の判断に影響を与える」——これがアンカリング効果です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (12, 39, '損失回避バイアス', '「失う恐怖」の心理学', '「人は得ることの喜びより、失うことの痛みを約2倍強く感じる」——これがDaniel KahnemanとAmos Tverskyが発見した「損失回避バイアス」です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (13, 4, '目標設定の技術', '学術研究に基づく目標設定理論の完全ガイド', '本資料は、基礎マインドセット研修「目標設定の技術」で学んだSMARTゴールの概念をより深く理解するための補足教材です。SMARTゴールが単なる「フレームワーク」ではなく、40年以上にわたる心理学・経営学の研究に裏打ちされた科学的手法であることを理解することで、日々の営業活動における目標設定の質が飛躍的に向上します。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (14, 40, '認知的不協和', '決断後の心理サポート', '「本当にこれで良かったのだろうか」——大きな買い物をした後、このような不安を感じた経験はありませんか？これが「認知的不協和」の一形態である「購入後の後悔（Buyer''s Remorse）」です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (15, 41, 'ミラーリングとラポール構築', '信頼関係を築く非言語コミュニケーション', '「なんとなくこの人と話しやすい」「気が合う感じがする」——このような感覚は、しばしば非言語コミュニケーションのレベルで生まれています。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (16, 42, '選択のパラドックス', '選択肢の最適数と意思決定支援', '「選択肢が多いほど良い」——私たちはそう思いがちですが、実際には選択肢が多すぎると人は決断できなくなります。これが「選択のパラドックス」です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (17, 43, '傾聴の科学', 'アクティブリスニングの学術的基盤と実践への応用', '本資料は、コミュニケーション基礎研修「傾聴の技術（アクティブリスニング入門）」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (18, 44, '質問の科学', 'オープン質問とクローズド質問の心理学的基盤', '本資料は、コミュニケーション基礎研修「質問力① オープン/クローズド質問の使い分け」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (19, 45, 'SPIN話法の科学', '35,000件の商談分析から生まれた質問技法', '本資料は、コミュニケーション基礎研修「質問力② SPIN話法の基本」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (20, 46, '雑談の心理学', 'アイスブレイクと信頼構築の科学', '本資料は、コミュニケーション基礎研修「雑談力 アイスブレイクの技術」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (21, 47, '電話コミュニケーションの科学', '声だけで信頼を築く心理学', '本資料は、コミュニケーション基礎研修「電話応対の基本 声だけで信頼を築く」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (22, 48, 'ビジネスライティングの科学', '読まれ、伝わり、行動を促す文章術', '本資料は、コミュニケーション基礎研修「メール・チャットの書き方 簡潔で伝わる文章」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (23, 49, '非言語コミュニケーションの科学', 'ボディランゲージと印象形成の心理学', '本資料は、コミュニケーション基礎研修「非言語コミュニケーション 表情・姿勢・視線」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (24, 5, '時間管理の基本', '学術研究に基づく優先順位付けと時間管理の完全ガイド', '本資料は、基礎マインドセット研修「時間管理の基本」で学んだアイゼンハワー・マトリクスの概念をより深く理解するための補足教材です。「緊急×重要」のフレームワークが、単なるタスク整理術ではなく、数十年にわたる経営学・心理学の研究に裏付けられた科学的アプローチであることを理解することで、日々の時間の使い方が根本から変わります。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (25, 50, '説得的コミュニケーションの科学', 'PREP法と論理的思考の心理学', '本資料は、コミュニケーション基礎研修「説明力 PREP法で論理的に伝える」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (26, 51, '交渉の科学', 'ハーバード流交渉術とWin-Winの心理学', '本資料は、コミュニケーション基礎研修「交渉の基本 Win-Winを目指す姿勢」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (27, 52, 'クレーム対応の心理学', '顧客の怒りを信頼に変える科学', '本資料は、コミュニケーション基礎研修「クレーム対応の基本 怒りを鎮める技術」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (28, 53, '営業プロセスの科学', 'セールスファネルと予測可能な営業の構築', '本資料は、営業プロセス研修「営業プロセスの全体設計」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (29, 54, 'ターゲティングの科学', '理想顧客像（ICP）とABM戦略', '本資料は、営業プロセス研修「ターゲットリストの作り方」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (30, 55, 'テレアポの心理学', '電話でアポイントを獲得する科学', '本資料は、営業プロセス研修「テレアポの極意」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (31, 56, '飛び込み営業の心理学', '初対面で信頼を獲得する科学', '本資料は、営業プロセス研修「飛び込み営業の技術」で学んだ内容をより深く理解するための補足教材です。
INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (32, 57, 'ヒアリングの科学', '顧客の真のニーズを引き出す技術', '本資料は、営業プロセス研修「ヒアリング設計」で学んだ内容をより深く理解するための補足教材です。
