INSERT INTO deep_dive_contents (id, training_id, title, subtitle, introduction, sections, conclusion, reference_list, created_at, updated_at) VALUES (37, 62, '契約とオンボーディングの科学', '顧客成功への第一歩を設計する', '本資料は、営業プロセス研修「契約手続きとオンボーディング」で学んだ内容をより深く理解するための補足教材です。
